//==================================================================
//
// fwException.js
//
// Base class for Framework Exceptions
//
//==================================================================


function fwException(msg, rootCause)
{
	this.message = msg;
	this.m_rootCause = rootCause;
    this.exceptionHierarchy = new Array('Error'); 
}


fwException.prototype = new Error();
fwException.prototype.constructor = fwException;

/*
 * Default fatalExceptionHandler - can be overriden by the setter method below
 */
fwException.m_fatalExceptionHandler = function(exception){fwException._defaultFatalExceptionHandler(exception);};

/*
 * Print out the error from the current message, and any previous root cause exceptions
 */
fwException.prototype.toString = function()
{
	var str = "Exception message: " + this.message;
	
	if(null != this.m_rootCause)
	{
		str += "\n  Root cause: " + fwException.getErrorMessage(this.m_rootCause);
	}
	
	return str;
}


fwException.prototype.getRootCause = function()
{
	return this.m_rootCause;
}

/*
 * Allows the default functionality of a fatal exception
 * to be overriden
 */
fwException.setFatalExceptionHandler = function(handler)
{
    fwException.m_fatalExceptionHandler = handler;
}


/*
 * Utilitity function to get the correct error message when the type
 * of the object throw in unknown.
 *
 * @param ex - is an object (probably an fwException or an Error)
 */
fwException.getErrorMessage = function(ex)
{
    if (ex instanceof fwException)
    {
        return ex.toString();        
    }
    else if (ex instanceof Error)
    {
        return ex.message; 
    }

    // Just some random object - do the best we can
	return "Non Error based object thrown, .toString() result is: " + ex.toString();
}

/*
 * Is the default handler, basically just gets the message out of the exception,
 * tells the user before forcing them to quit
 */
fwException._defaultFatalExceptionHandler = function(exception)
{
    // Use complex mechanism to retrieve reference
    // to AppController as exception may be thrown
    // before instance of FormController has been instantiated.
    appC = top.AppController.getInstance();
    
    // Before reporting exception check if progress bar displayed
    if(appC.m_requestCount > 0)
    {
        // Hide progress bar
        appC._hideProgress();
    }
    
    // Synthesize general exception message
    var exMsg = fwException.getErrorMessage(exception);
    var alertMsg = null;

    if(exMsg != null && exMsg != "")
    {
        alertMsg = "An unexpected application error has occurred. The associated error message is shown below: \n\n'" +
                    exMsg +
                    "'\n\n Unfortunately the application may no longer work correctly. Therefore, the application \n" +
                    "will terminate when you close this alert message.";
    }
    else
    {
        alertMsg = "An unexpected application error has occurred. Unfortunately, the application may no longer work\n" +
                   "correctly. Therefore, the application will terminate when you close this alert message.";
    }
    
    // Display alert message
    
    alert(alertMsg);
    
    // Shut down application
    appC.shutdown();
    
}


fwException.invokeFatalExceptionHandler = function(exception)
{
    fwException.m_fatalExceptionHandler(exception);
}

//==================================================================
//
// String.js
//
// Contains utility functions for managing Strings.
//
//==================================================================




/**
 * Regexp used to trim whitespace from a beginning and end of a string
 *
 * @type RegExp
 * @private
 */
String.m_trimRegExp = /^\s*(.*?)\s*$/;


/**
 * Trim leading and trailing whitespace from a string.
 *
 * NOTE: This is implemented as a static method, rather than an
 * instance method as I don't want to bloat a string instance 
 * any further with another function - Each instance in JavaScript
 * will have it's own reference to each instance member.
 *
 * @param s the String to trim
 * @return the trimmed String
 * @type String
 */
String.trim = function(s)
{
	return s.replace(String.m_trimRegExp, "$1");
}


/**
 * Lexically compare two strings in the same way as C strcmp
 *
 * @param s1 First string
 * @param s2 Second string
 * @return -1 if s1 is "less" than s2, +1 if s1 is "greater" than s2
 *   and 0 if they are equal.
 * @type Integer
 */
String.strcmp = function(s1, s2)
{
	if(s1 > s2)
	{
		return 1;
	}
	else if(s1 < s2)
	{
		return -1;
	}
	return 0;
}
function Comparators(){};

Comparators.numericalSort = function(a, b)
{
	var n1 = parseInt(a);
	var n2 = parseInt(b);
	if(isNaN(n1)) n1 = 0;
	if(isNaN(n2)) n2 = 0;
	//return n1 - n2;
	// RWW - This is actually wrong, but it makes numerical sort consistent
	// with alphabetical sort!
	return n2 - n1;
}

Comparators.numericalFloatingPointSort = function(a, b)
{
    var returnValue = null;
    
    var f1 = parseFloat(a);
    var f2 = parseFloat(b);
    
    // Check for non-numeric values
    var isf1NaN = false;
    if(isNaN(f1))
    {
        isf1NaN = true;
    }
    
    var isf2NaN = false;
    if(isNaN(f2))
    {
        isf2NaN = true;
    }
    
    if(isf1NaN && isf2NaN)
    {
        // Both input values are not numbers, therefore, assume equality
        returnValue = 0;
    }
    else if(isf1NaN && !isf2NaN)
    {
        // Assume f2 > f1
        returnValue = 1;
    }
    else if(!isf1NaN && isf2NaN)
    {
        // Assume f1 > f2
        returnValue = -1;
    }
    else
    {
        // Two valid numbers
        if( f2 > f1 )
        {
            returnValue = 1;
        }
        else if( f1 > f2 )
        {
            returnValue = -1;
        }
        else
        {
            // Note that sometimes floating point numbers
            // do not easily manage equality.
            returnValue = 0;
        }
    }
    
    return returnValue;
}

Comparators.alphabeticalSort = function(a, b)
{
	if(a > b)
		return -1;
	else if(b > a)
		return 1;
	else
		return 0;
}

Comparators.alphabeticalSortLowToHigh = function(a, b)
{
	return (-1 * Comparators.alphabeticalSort(a,b));
}

Comparators.alphabeticalLocaleCompareSort = function(a, b)
{
	return a.localeCompare(b);
}

Comparators.alphabeticalCaseInsensitiveSort = function(a, b)
{
	var Ua = a.toUpperCase();
	var Ub = b.toUpperCase();
	if(Ua > Ub)
		return -1;
	else if(Ub > Ua)
		return 1;
	else
		return 0;
}
function ArrayUtils() {};

ArrayUtils.contains = function (array, object)
{
	for (var i = 0; i < array.length; i++)
	{
		if (array[i] == object)
		{
			return true;	
		}	
	}
	return false;
}



// Bunch of utility methods used to generate the precompile for the framework

SerialisationUtils = function(){};

// Takes an array of strings an turns them into string which
// when evaluated returns the original array.
SerialisationUtils.stringArrayToLiteral = function (array)
{
    str = "[";
    for (var i=0; i < array.length; i++)
    {
        str += array[i] + ",";
    }
    if (array.length > 0)
    {
      str = str.substring(0,str.length-1); 
    }
    str += "]";
    
    return str;
}

/*
 * Prints out the listener tree (including predicate nodes) 
 * starting at the passed in node
 */
SerialisationUtils.printListeners = function(node)
{
    var printString = "";
    printString +=  node.serialise() + "\n";

    for (var a in node.m_childNodes)
    {
        if (a != "__parent__" && a != "__proto__") // Mozilla
        {
            printString += SerialisationUtils.printListeners(node.m_childNodes[a]);    
        }
    }   
    
    for (var a in node.m_predicates)
    {
        if (a != "__parent__" && a != "__proto__")
        {
            printString += SerialisationUtils.printListeners(node.m_predicates[a]);    
        }
    }   
    
    return printString;
}

/*
 * Returns all of the data dependencies for each of the adaptors in the system
 *
 * Returned string has the form of :
 *
 * FormController.dataDepPreCompArray = new Array({adaptor_id},{parent_array},
 *                                                {children_array},{contained_children_array},
 *                                                {parent_container_id})
 *
 */
SerialisationUtils.printDataDep = function()
{
    var adaptors = FormController.getInstance().m_adaptors;
    
    str = "FormController.dataDepPreCompArray = new Array(";
    for (var i=0; i < adaptors.length; i++)
    {
        var m_parentsString = SerialisationUtils.convertObjectOfAdaptorsToStringArray(adaptors[i].m_parents);
        var m_childrenString = SerialisationUtils.convertArrayOfAdaptorsToString(adaptors[i].m_children);
        var m_containedChildren = SerialisationUtils.convertArrayOfAdaptorsToString(adaptors[i].m_containedChildren);
        
        var parentContainer = adaptors[i].m_parentContainer;
        var parentContainerStr = "";
        
        if (parentContainer == null)
        {
            parentContainerStr = "null";
        } 
        else
        {
            parentContainerStr = "'" + parentContainer.getId() + "'";
        }
        
        str += "new Array('" + adaptors[i].getId() + "'," 
               + m_parentsString + "," 
               + m_childrenString + "," 
               + m_containedChildren + ","
               + parentContainerStr
               + ")\n,";
    } 
    if (adaptors.length > 0)
    {
      str = str.substring(0,str.length-1); 
    }
    str += ");\n";
    return str;
}

/*
 * Display the precompile for the page in a window
 */
SerialisationUtils.printPrecompile = function()
{
    var resultsWindow = window.open("", "Results", "height=600,width=400,scrollbars=yes,resizable=yes");
    
    var preComp = SerialisationUtils.getPrecompile();
    
    resultsWindow.document.write("<DIV>" + preComp + "</DIV>");
}

/* 
 * Returns the full precompile for the page
 */
SerialisationUtils.getPrecompile = function()
{
    var dm = FormController.getInstance().getDataModel();
    var str = "FormController.regNodes = new Object();";
    var listenerString = SerialisationUtils.printListeners (dm.m_root);
    var dataDepString = SerialisationUtils.printDataDep();
    var tabOrderString = SerialisationUtils.getTabOrder();
                    
    return str + listenerString + dataDepString + tabOrderString;
}   

/*
 * Returns a string of id's corresponding the the adaptor tabbing
 * order on the page
 */
SerialisationUtils.getTabOrder = function()
{
    var tabArray = FormController.getInstance().m_tabbingManager.m_tabOrder;
    return "FormController.tabOrder = " + SerialisationUtils.convertArrayOfAdaptorsToString(tabArray) + ";";
}

/* 
 * Converts an array of adaptors to a string which will evaluate to a
 * string of adaptor id's
 */
SerialisationUtils.convertArrayOfAdaptorsToString = function(adaptorArray)
{
    if (adaptorArray == null)
    {
        return "new Array()"; 
    }
    var str = "new Array(";
    var foundAdaptor = false;
    
    for (var i=0; i < adaptorArray.length; i++)
    {
        str += "'" + adaptorArray[i].getId() + "',"; 
        foundAdaptor = true;
    }
    if (foundAdaptor)
    {
      str = str.substring(0,str.length-1); 
    }
    str += ")";
    return str;
}


/*
 * Converts an associative array of adaptors to a string which will evaluate to
 * an array of adaptor id's
 */  
SerialisationUtils.convertObjectOfAdaptorsToStringArray = function(adaptorObject)
{
    if (adaptorObject == null)
    {
        return "new Array()"; 
    }
    
    var str = "new Array(";
    var foundAdaptor = false;
    for (var a in adaptorObject)
    {
        str += "'" + adaptorObject[a].getId() + "',"; 
        foundAdaptor = true;
    }
    if (foundAdaptor)
    {
      str = str.substring(0,str.length-1); 
    }
    str += ")";
    return str;
}

/*
 *  Takes an array of adaptor ids and returns an array of adaptor
 *  references.
 */
SerialisationUtils.convertStringArrayToAdaptorArray = function(array)
{
    var newArray = new Array();
    var m_adaptors = FormController.getInstance().m_adaptors;
    for (var i=0,l=array.length; i<l;i++)
    {
        newArray.push(m_adaptors[array[i]]);     
    }
    return newArray;
}

/*
 *  Takes an array of adaptor ids and returns an associative array of adaptor
 *  references.
 */
SerialisationUtils.convertStringArrayToAdaptorObject = function(array)
{
    var newObject = new Array(); // Array type used for consistency with old code.
    var m_adaptors = FormController.getInstance().m_adaptors;
    for (var i=0,l=array.length; i<l;i++)
    {
        newObject[array[i]] = m_adaptors[array[i]];     
    }
    return newObject;
}




