/**
 * Note that this method should not be used. Equivalent functionality
 * is available using the fwFileDataLoader class.
 *
*/

XML.loadStatic = function(url)
{
    // Set up request information object. In this instance
    // store both request object and reference to dom in
    // request information object
    var index;
    var requestInfo = new Object();
    
    index = xmlHttpServiceRequestQueue.length;
    xmlHttpServiceRequestQueue.push(requestInfo);
    
    requestInfo.server = new XMLHttpServiceRequest();
    
    var dom = XML.createDocument();
    requestInfo.dom = dom;
    
    // Set up and invoke get request
    var async = false;
    
    requestInfo.server.initialise(null, url, async, null, handleLoadStaticReadyStateChange);
    
    var handlerArgs = new Array();
    handlerArgs[0] = index;
    
    requestInfo.server.sendGET("loadStaticFile", handlerArgs);
    
    // Return XML document
    return dom;
}

function handleLoadStaticReadyStateChange(handlerArgs)
{
    var index = handlerArgs[0];
    
    var requestInfo = xmlHttpServiceRequestQueue[index];
    
    if(null != requestInfo)
    {
        var request = requestInfo.server.getRequest();
        
        if(request.readyState == 4)
        {
            if(request.status == 200)
            {
                var theXML = request.responseText;
                requestInfo.dom.loadXML(theXML);
            }
            
            // Clean up request object
            requestInfo.server.dispose();
            requestInfo.server = null;
            
            // Dom referred to by reference in calling function
            requestInfo.dom = null;
            
            delete xmlHttpServiceRequestQueue[index];
        }
        
        requestInfo = null;
    }
    
}

/**
 * Get the text content of a node in a browser independant manner
 *
 * @param n the node who's text content to get
 * @result the text content of the node or null if there is none
 */
XML.getNodeTextContent = function(n)
{
  // fc_assert(null != n, "XML.getNodeTextContent(): node is null");
	var t = null;
	var f = false;

	// Locate the children to remove
	var cn = n.childNodes;
	for(var i = 0, l = cn.length; i < l; i++)
	{
		var c = cn[i];
		if(XML.TEXT_NODE == c.nodeType)
		{
			t = (null == t) ? c.nodeValue : t + c.nodeValue;
		}
	}
	
	return t;
}

/**
 * Get the text content of the node selected in the relative XPath
 *
 * @param node the node to select relative to
 * @param xpath the xpath to select the target node
 * @param the text content of the specified node or null if the no text content was
 *        found or the xpath does not resolve a node
 */
XML.getPathTextContent = function(node, xpath)
{
	var n = node.selectSingleNode(xpath);
	
	return null == n ? null : XML.getNodeTextContent(n);
}


/** 
 * Method to produce an HTML representation of a XMLDocument
 *
 * @param dom the XMLDocument to render
 * @return a string containing the HTML representation of the XMLDocument
 */
XML.showDom = function(dom)
{
		var msg = "DOM";
		if (dom.childNodes)
		{
   	msg += "<ul>";
   	msg += XML.showChildren(dom.childNodes);
    msg += "</ul>";
		}
		else
		{
				msg += " has no childNodes";
		}
		return msg;
}


/**
 * Method to produce an HTML representation of a set of nodes
 *
 * @param nodelist the list nodes to render
 * @return a string containing an HTML representation of the nodes
 */
XML.showChildren = function(nodelist, indent)
{
	var iindent = (null!=indent) ? indent++ : 1;
//	if (iindent == 1) alert("!!!!!1")
	var indentString = "";
	for (var i=0; i < iindent; i++)
	{
		indentString += "\t";	
	} 
	
   var msg = '';
   if (nodelist && nodelist.length)
   {
	   for(var i = 0; i < nodelist.length; i++)
	   {
	      var node = nodelist[i];
	      msg += "\n" + indentString +"<li>Node: type=" + XML.NODE_TYPES[node.nodeType - 1] + ", name=" + node.nodeName + ", value=" + node.nodeValue;
	      if(node.hasChildNodes())
	      {
	         msg += "<ul>";
	         msg += XML.showChildren(node.childNodes, iindent);
	         msg += "</ul>";
	      }
	      msg += "</li>";
	   }
   }
   return msg;
}


/**
 * Convenience method to get the text content of a node to be found
 * with an xpath (second argument) in a node (first argument).
 * Returns null or the text found.
 */
XML.selectNodeGetTextContent = function(node, xp)
{
	var text = null;
	var foundNode = node.selectSingleNode(xp)
	if (null != foundNode)
	{
		text = XML.getNodeTextContent(foundNode);
	}
	return text;
}


/**
 * Convenience method to set an element's text content
 *
 * @param node Root to search from
 * @param xp XPath to the node to set
 * @param value of the text to set in the node
 * @throws XMLException if the node is not found
 */
XML.setElementTextContent = function(node, xp, value)
{
	var text = null;
	var foundNode = node.selectSingleNode(xp);

	if(null != foundNode)
	{
		XML.replaceNodeTextContent(foundNode, value);
	}
	else
	{
		throw new XMLException("Unable to location child node at path: " + xp);
	}
}


/**
 * Set the specified node's text the value specified
 *
 * @param n the node whose text content to set
 * @param v the value to set the node text content to
 */
XML.replaceNodeTextContent = function(n, v)
{
	var r = new Array();  // Array containing child nodes to remove
	
	// Locate the children to remove
	var cn = n.childNodes;
	for(var i = 0, l = cn.length; i < l; i++)
	{
		var c = cn[i];
		if(XML.TEXT_NODE == c.nodeType)
		{
			r.push(c);
		}
	}
	
	// Remove children after search 
	for(var i = 0, l = r.length; i < l; i++)
	{
		n.removeChild(r[i]);
	}
	
	if(null != v)
	{
		// Set the text content of the node
		var t = XML.createTextNode(n.ownerDocument, v);
		n.appendChild(t);
	}
}


/**
 * Exception thrown for XML errors
 *
 * @param message the message to report in the exception
 */
function XMLException(message)
{
   this.message = message;
}


/**
 * AppConfigError is a sub class of Error
 */
XMLException.prototype = new Error();
XMLException.prototype.constructor = XMLException;


/**
 * Array containing nodetype values to human readable strings
 * refactor the offset in index!! use the true nodeType value as index in the array.
 */
XML.NODE_TYPES = new Array();
XML.NODE_TYPES[0] = 'Element';
XML.NODE_TYPES[1] = 'Attribute';
XML.NODE_TYPES[2] = 'Text';
XML.NODE_TYPES[3] = 'CData Section';
XML.NODE_TYPES[4] = 'Entity Reference';
XML.NODE_TYPES[5] = 'Entity';
XML.NODE_TYPES[6] = 'Processing Instruction';
XML.NODE_TYPES[7] = 'Comment';
XML.NODE_TYPES[8] = 'Document';
XML.NODE_TYPES[9] = 'Document Type';
XML.NODE_TYPES[10] = 'Document Fragment';
XML.NODE_TYPES[11] = 'Notation';

XML.ELEMENT_NODE = 1;
XML.ATTRIBUTE_NODE = 2;
XML.TEXT_NODE = 3;
XML.CDATA_SECTION = 4;
XML.ENTITY_REFERENCE = 5;
XML.ENTITY = 6;
XML.PROCESSING_INSTRUCTION = 7;
XML.COMMENT = 8;
XML.DOCUMENT = 9;
XML.DOCUMENT_TYPE = 10;
XML.DOCUMENT_FRAGMENT = 11;
XML.NOTATION = 12;

//===========================================================================
//
// CallbackList class for registering and invoking callbacks
//
//===========================================================================


/**
 * Simple callback list
 *
 * @constructor
 * @private
 */
function CallbackList()
{
	this.m_callbacks = new Array();
}


/**
 * Add a callback function to the list of callbacks
 *
 * @param callback the callback function to register
 * @private
 */
CallbackList.prototype.addCallback = function(callback)
{
	fc_assert(typeof callback == "function", "CallbackList.addCallback(): callback must be function");
	
	this.m_callbacks[this.m_callbacks.length] = callback;
}

/**
 * Remove a callback function from the list of callbacks
 *
 * @param callback the callback function to be removed.
 *
 */
 
CallbackList.prototype.removeCallback = function(callback)
{
    var position = -1;
    
    for( var i = 0, len=this.m_callbacks.length; i < len; i++ )
    {
    
        if( callback == this.m_callbacks[i] )
        {
            position = i;
            break;
        }
        
    }
        
    if( position != -1 )
    {
    
        // Remove function from array
        
        this.m_callbacks.splice( position, 1 );
    }
    
}

/**
 * Invoke the list of callback functions, passing an optional
 * set of arguments to each callback. Any arguments passed to
 * this function are forwarded to the callback function.
 *
 * @private
 */
CallbackList.prototype.invoke = function()
{
	for(var i = 0, l = this.m_callbacks.length; i < l ; i++)
	{
		if(arguments.length == 0)
		{
			this.m_callbacks[i].apply(null);
		}
		else
		{
			this.m_callbacks[i].apply(null, arguments);
		}
	}
}

/**
 * Invoke selected callback. First argument in argument list
 * should specify position of function in callback list.
 * Method returns any value returned by the callback method.
 *
*/

CallbackList.prototype.invokeSelectedCallbackMethod = function()
{
    var returnValue = null;
    
    var length = arguments.length;
    
    if( length == 1 )
    {
        returnValue = this.m_callbacks[arguments[0]].apply(null);
    }
    else if( length > 1 )
    {
        var methodIndex = arguments[0];
        
        var newArguments = new Array();
        
        for(var i = 1; i < length; i++)
        {
            newArguments[i-1] = arguments[i];
        }
        
        returnValue = this.m_callbacks[methodIndex].apply(null, newArguments);
        
    }
    
    return returnValue;
    
}
            


/**
 * Perform any cleanup required before the object is destroyed
 */
CallbackList.prototype.dispose = function()
{
	for(var i = this.m_callbacks.length; i >= 0 ; i--)
	{
		delete this.m_callbacks[this.m_callbacks.length];
	}
}
//==================================================================
// XPathParser
//  Exception class thrown by XPathParser
//==================================================================


/**
 * Exception thrown when an error occurs while parsing an XPath
 *
 * @param message the message to report in the exception
 * @param ex a chained exception
 * @constructor
 * @private
 */
function XPathParseError(message, ex)
{
   this.message = message;
   this.exception = ex;
}


// XPathParseError is a sub class of Error
XPathParseError.prototype = new Error();
XPathParseError.prototype.constructor = XPathParseError;
//==================================================================
// XPathParser
//  Class for parsing XPaths
//==================================================================

//@import XPathParserError
//@import XPathListener

/**
 * Class which implements a simple xpath parser XPathParser
 *
 * @constructor
 * @private
 */
function XPathParser()
{
	this.m_xp = null;
	this.m_listener = null;
}


/**
 * Get the xpath currently being parsed
 *
 * @return the xpath currently being parsed, or null if no xpath is being parsed.
 * @type String
 * @private
 */
XPathParser.prototype.getXPath = function()
{
	return this.m_xp;
}


/**
 * Parse an xpath
 *
 * @param xp the xpath string to parse
 * @param listener the object which will listen to the parse events as
 *        they occur.
 * @throws XPathParseException if an error occured during parsing
 * @private
 */
XPathParser.prototype.parse = function(xp, listener)
{
	fc_assert(xp != null, "XPathParser.parse(): XPath must not be a null string");
	fc_assert(listener != null, "XPathParser.parse(): listener must not be null");
	
	// Initialise internal variables
	this.m_xp = xp;
	this.m_listener = listener;
	
	var p = 0;
	
	if(p < xp.length)
	{
		switch (xp.charAt(p))
		{
			case '/':
				this._startNode(++p);
				break;
				
			default:
				this._exception(p, "XPath must start at root - first character must be /");
		}
	}
	else
	{
		this._exception(p, "XPath was empty");
	}
	
	// Reset internal state.
	this.m_xp = null;
	this.m_listener = null;
}


/**
 * Start parsing a node
 *
 * @param p position in xpath to start parsing
 * @throws XPathParseException if an error occured during parsing
 * @private
 */
XPathParser.prototype._startNode = function(p)
{
	var xp = this.m_xp;
	if(p < xp.length)
	{
		switch(xp.charAt(p))
		{
			case '/':
				// Match recursive element i.e. //
				this.m_listener.node('/');
				this._decendantNode(++p);
				break;
				
			case "'":
			case '"':
			case '[':
			case ']':
				this._exception(p, "Illegal character '" + xp.charAt(p) + "' in startNode");
				break;
				
			default:
				this._parseNode(p);
				break;
		}
	}
}


/**
 * Start parsing a node after a decendant node match
 *
 * @param p position in xpath to start parsing
 * @throws XPathParseException if an error occured during parsing
 * @private
 */
XPathParser.prototype._decendantNode = function(p)
{
	var xp = this.m_xp;
	if(p < xp.length)
	{
		switch(xp.charAt(p))
		{
			case '/':
			case "'":
			case '"':
			case '[':
			case ']':
				this._exception(p, "Illegal character '" + xp.charAt(p) + "' in decendantNode");
				break;
				
			default:
				this._parseNode(p);
		}
	}
	else
	{
		this._exception(p, "Recursive match must be followed by a node match");
	}
}


/**
 * Start parsing a node name
 *
 * @param p position in xpath to start parsing
 * @throws XPathParseException if an error occured during parsing
 * @private
 */
XPathParser.prototype._parseNode = function(p)
{
	var s = p;
	var xp = this.m_xp;
	var le = xp.length;
	
	while(p < le && s != -1)
	{
		switch(xp.charAt(p))
		{
			case '/':
				// TODO add element
				this.m_listener.node(xp.substring(s, p));
				this._startNode(++p);
				s = -1;
				break;
				
			case '[':
				// TODO add element
				this.m_listener.node(xp.substring(s, p));
				this._startPredicate(++p);
				s = -1;
				break;
				
			case "'":
			case '"':
			case ']':
				this._exception(p, "Illegal character '" + xp.charAt(p) + "' in parseNode");
				break;
			
			default:
				p++;
		}
	}
	
	// Run out of chars, so if we haven't previously reported element name and this
	// wasn't simply a trailing / then report the element name.
	if(s != -1 && s != p)
	{
		this.m_listener.node(xp.substring(s, p));
	}
}


/**
 * Start parsing a predicate
 *
 * @param p position in xpath to start parsing
 * @throws XPathParseException if an error occured during parsing
 * @private
 */
XPathParser.prototype._startPredicate = function(p)
{
	var s = p;
	var xp = this.m_xp;
	var le = xp.length;
	
	// Keeps a count of how many '[' characters have been parsed so far
	// in this predicate.
	var nestedPredicateCount = 1;  // First '[' has already been identified

	while(p < le && s != -1)
	{
		switch(xp.charAt(p))
		{
			case '"':
			case "'":
				p++;
				var e = xp.indexOf(xp.charAt(p - 1), p);    // Also returns -1 if p >= length of string
				if(-1 == e)
				{
					this._exception(p, "Unterminated quoted string");
				}
				else
				{
					p = e + 1;
				}
				break;
				
			case '[':
			  p++;
				nestedPredicateCount++;
				break;				
				
			case ']':
			  nestedPredicateCount--;
			  if (nestedPredicateCount == 0) // All '[' characters matched.
			  {
			    this.m_listener.predicate(xp.substring(s,p));
				  this._endPredicate(++p);
				  s = -1;
				  break;
			  }	
			default:
				p++;
		}
	}


	// Run out of chars, so if we haven't previously reported element name and this
	// wasn't simply a trailing / then report the element name.
	if(s != -1 && s != p)
	{
		this._exception(p, "Unclosed predicate");
	}
}


/**
 * End parsing a predicate
 *
 * @param p position in xpath to start parsing
 * @throws XPathParseException if an error occured during parsing
 * @private
 */
XPathParser.prototype._endPredicate = function(p)
{
	var xp = this.m_xp;
	if(p < xp.length)
	{
		switch(xp.charAt(p))
		{
			case '/':
				this._startNode(++p);
				break;
			
			case '[':
			  this._startPredicate(++p);
			  break;
				
			default:
				this._exception(p, "Illegal character after predicate '" + xp.charAt(p) + "' in endPredicate");
				break;
		}
	}
}


/**
 * Utility function to throw useful parsing exception
 *
 * @param position the character position within the xpath which caused the parsing exception
 * @param message the message for the exception
 * @throws XPathParseError always
 * @private
 */
XPathParser.prototype._exception = function(position, message)
{
	throw new XPathParseError(message + " at char: " + position + " in xpath: " + this.m_xp);
}
//==================================================================
// XPathParser
//  Exception class thrown by XPathParser
//==================================================================


/**
 * Exception thrown when an error occurs while parsing an XPath
 *
 * @param message the message to report in the exception
 * @param ex a chained exception
 * @constructor
 * @private
 */
function XPathParserListenerError(message, ex)
{
   this.message = message;
   this.exception = ex;
}


// XPathParseError is a sub class of Error
XPathParserListenerError.prototype = new Error();
XPathParserListenerError.prototype.constructor = XPathParserListenerError;
//==================================================================
// XPathParserListener
//  Class definining the interface that needs to be implemented to
//  listen to events fired by the XPathParser.
//               
//==================================================================

/**
 * Interface definition for Listener used by the XPathParser
 * @constructor
 * @private
 */
function XPathParserListener()
{
}


/**
 * Called when the XPathParser encounters a complete
 * node definition when parsing an xpath
 *
 * @param name the name of the node excluding any
 *        leading or trailing / or any predicate. Node
 *        name may be * to indicate any element or /
 *        to indicate a recursive match.
 * @private
 */
XPathParserListener.prototype.node = undefined;


/**
 * Called when the XPathParser encounters a complete
 * predicate definition.
 *
 * @param pred the string representation of the predicate
 *        excluding the surrounding [ ] characters
 * @private
 */
XPathParserListener.prototype.predicate = undefined;
