/**
 * Class which contains the parameters for a service request. Contains a number
 * of factory methods which add parameters to the set of parameters.
 */
function ServiceParams()
{
	// Create dom to carry parameters
	this.m_dom = XML.createDOM(null, null, null);

	// Create the root node for the parameters DOM	
	this.m_paramsNode = XML.createElement(this.m_dom, 'params');
  	this.m_dom.appendChild(this.m_paramsNode);
}


/**
 * Return the XML DOM containing the parameters
 *
 * @return the XML DOM containing the parameters
 */
ServiceParams.prototype.getDOM = function()
{
	return this.m_dom;
}


/**
 * Add a simple parameter to the set of parameters
 *
 * @param paramName the name of the parameter
 * @param value the item to add as the value of the parameters (must support toString()).
 */
ServiceParams.prototype.addSimpleParameter = function(paramName, value)
{
	var paramNode = this._createBaseParameterNode(paramName);
	if(value != null)
	{
		var valueNode = XML.createTextNode(this.m_dom, value.toString());
		paramNode.appendChild(valueNode);	
	}
}


/**
 * Add the contents of a DOM as a parameter
 *
 * @param paramName the name of the parameter
 * @param dom the XML DOM who's contents to add as the parameter
 */
ServiceParams.prototype.addDOMParameter = function(paramName, dom)
{
	var paramNode = this._createBaseParameterNode(paramName);
	
	// Copy DOM nodes to be children on the paramNode
	var copy = dom.documentElement.cloneNode(true);
	
	paramNode.appendChild(copy);
}


/**
 * Add the content of the node as a parameter
 *
 * @param paramName the name of the parameter
 * @param node The XML node to add
 */
ServiceParams.prototype.addNodeParameter = function(paramName, node)
{
	var paramNode = this._createBaseParameterNode(paramName);
	
	// Copy DOM node to be a child on the paramNode
	var copy = node.cloneNode(true);
	
	paramNode.appendChild(copy);
}


/**
 * Method to create a basic param node and add it to the ServiceParameter
 * DOM.
 *
 * @param paramName the name of the parameter to add.
 * @private
 */
ServiceParams.prototype._createBaseParameterNode = function(paramName)
{
	// Create a node for the parameter
	var paramNode = XML.createElement(this.m_dom, 'param');
	
	// Create a name attribute node and add it to the param element
	var nameNode = XML.createAttribute(this.m_dom, 'name');
	nameNode.value = paramName;
	paramNode.attributes.setNamedItem(nameNode);
	
	// Add the parameter to the list of parameters
	this.m_paramsNode.appendChild(paramNode);
	
	return paramNode;
}

ServiceParams.PAYLOAD_XML_HEADER = "<?xml version=\"1.0\" encoding=\"UTF-8\"?>";
ServiceParams.prototype.getPayload = function() 
{
	
    var xmlString = this.m_dom.xml;
	if(xmlString.indexOf(ServiceParams.PAYLOAD_XML_HEADER) == -1)
	{
		xmlString = ServiceParams.PAYLOAD_XML_HEADER + xmlString;
	}
    return xmlString;
}

function fwDataService()
{
}

/**
 * Logging category for fwDataService
 *
 * @private
 */
fwDataService.m_logger = new Category("fwDataService");


/**
 * Data Service Configuration object
 *
 * @type Object
 * @protected
 */
fwDataService.prototype.m_config = null;


/**
 * Fuction that handles the result of call to load()
 *
 * @type Function
 * @private
 */
fwDataService.prototype.m_resultHandler = null;


/**
 * Reference to DOM created during load().<b> 
 *
 * @type DOM
 * @private
 */
fwDataService.prototype.m_dom = null;


/**
 * Load the data
 *
 * @protected
 */
fwDataService.prototype.load = function()
{
	fc_assertAlways("fwDataService.load() base class method must be overridden");
}


/**
 * Handles an apparently successful XML Document creation
 * by checking the result DOM for parseErrors. If no
 * parseErrors exist, then the dom is passed to handleValidDom
 * as a successful Document creation, otherwise a suitable
 * fwDataServiceException is created and is passed to 
 * handleException as a Document creation exception
 *
 * @param dom the apparently successfully loaded DOM
 * @protected
 */
fwDataService.prototype._handleResultDOM = function(dom)
{
	var error = dom.parseError;
	
	if(error.errorCode != 0)
	{
		// Invoke handleException with a suitable exception
		this.handleException(
			new fwDataServiceException(
				"Loaded Document contained parsing error." +
				"\nReason for failure: " + error.reason
			)
		);
	}
	else
	{
		// Invoke handleValidDom without exception - onSuccess should be invoked.
		this.handleValidDom(dom);
	}
}

/*
 * Handle a successfully parsed dom
 */
fwDataService.prototype.handleValidDom = function(dom)
{
	try
	{
		if(null != dom)
		{
			if(null != this.m_resultHandler.onSuccess)
			{
                // Process the document - may have an exception thrown from the serverside,
                // in which case a handler should be invoked
                // If either the dom is ok or a handler is successfully found and processed then the
                // processing is considered to be successful.
                // If unsuccessful onError should be invoked.
                this._processSuccessfulDOMCreation(dom);
			}
			else
			{
				// No onSuccess handler defined - throw exception which is caught
				// in the outer catch block
				throw new ConfigurationException("No onSuccess method defined on handler.");
			}
		}
		else
		{
			this.handleException(new fwDataServiceException("Empty DOM returned from server."));
		}
	}
	catch(exception) 
	{
        this.handleException(exception)
	}
}



/*
 * Find the most specific exception handler available and invoke it. Note that,
 * some data services like the reference data and model initialisation services
 * require some additional work to be done, deregistering the
 * services from the FormController services running list, before the
 * exception can be handled.
 *
 */
fwDataService.prototype.handleException = function(ex)
{
    try
    {
        // First apply any specified pre-exception handling processing
        var handler = this.m_resultHandler;
        this._executeExceptionHandlingPreprocessing(handler);
        
        // Handle exception
		var exceptionHandled = false;
    	if(ex instanceof fwException)
    	{
		    var exceptionArray = ex.exceptionHierarchy;
	        
			for(var i = exceptionArray.length - 1; i > -1; i--)
			{
		        if (handler["on" + exceptionArray[i]] != null)
		        {
		            // Invoke the appropriate handler and
		            // create the parent exception containing the message.
		            handler["on" + exceptionArray[i]](ex, this.m_serviceMethodName);
		            exceptionHandled = true;
	                break;
		        }
		    }
		}
		else
		{
			// This is not an fwException, so wrap it up in one and pass it
			// to onError
			ex = new fwException("Runtime exception throw", ex);
		}
	    
	    if (!exceptionHandled)
	    {
            this.invokeOnError(ex);
		}
	}
	catch(exception)
	{
        var newException = new fwException("Exception thrown handling result of document creation - " 
                                           + fwException.getErrorMessage(exception), ex);
        FormController.handleFatalException(newException); 
	}
}


/*
 * Invoke the onError method in the result handler.
 *
 * throws fwException
 */                
fwDataService.prototype.invokeOnError = function(ex, name)
{
	if(null != this.m_resultHandler.onError)
	{
		this.m_resultHandler.onError(ex, this.m_serviceMethodName);
	}
	else
	{
        this.m_resultHandler.defaultErrorHandler(ex, this.m_serviceMethodName);
	}
}


/*
 * Handle a successful dom creation (may be overriden by sublclasses 
 * (for example a successful dom creation may still not be a successful call)
 */                
fwDataService.prototype._processSuccessfulDOMCreation = function(dom)
{
    // Success loading the data - invoke the onSuccess method
	this.m_resultHandler.onSuccess(dom, this.m_serviceMethodName);
}

/*
 * Factory method to create the appropriate DataService subclass
 *
 * @param config.serviceName - this and the following 4 options are mutually 
                               exclusive and determing the type of DataService
                               to be created.
 * @param config.fileName;
 * @param config.srcXPath;
 * @param config.computed;
 * @param config.xml;
 *
 * @param resultHandler - handler containing methods onSuccess, onError and onXXXX(?)
 * @param async - boolean flag that indicates whether or not data service is asyncronous
 *
 */
fwDataService.create = function(config, resultHandler, async)
{
	if(null == config)
	{
		throw new ConfigurationException("No configuration provided");
	}

	// Check that only a single method of retrieving the data has been specified
	if (!(fwDataService.isDataServiceConfigured(config)))
	{
		throw new ConfigurationException("Form fwDataService configuration must specify one and only of serviceName, fileName, srcXPath, xml or computed properties");
	}
	
	// Create the appropriate type of fwDataService
	var dS = null;
	if(config.serviceName != null)
	{
		dS = new fwServiceCallDataService();
	}
	else if(config.fileName != null)
	{
		dS = new fwFileDataService();
	}
	else if(config.computed != null)
	{
		dS = new fwComputedDataService();
	}
	else if(config.srcXPath != null)
	{
		dS = new fwSrcXPathDataService();
	}
	else if(config.xml != null)
	{
		dS = new fwXMLStringDataService();
	}
	
	dS._initialise(config, async, resultHandler);
	
	return dS;
}


fwDataService.isDataServiceConfigured = function(config)
{
	// Determine what sort of fwDataService has been configured.
	var serviceName = config.serviceName;
	var fileName = config.fileName;
	var srcXPath = config.srcXPath;
	var computed = config.computed;
	var xml = config.xml;
	
	// Check that only a single method of retrieving the data has been specified
	return (
		(null != serviceName && null == fileName && null == srcXPath && null == computed && null == xml) ||
		(null == serviceName && null != fileName && null == srcXPath && null == computed && null == xml) ||
		(null == serviceName && null == fileName && null != srcXPath && null == computed && null == xml) ||
		(null == serviceName && null == fileName && null == srcXPath && null != computed && null == xml) ||
		(null == serviceName && null == fileName && null == srcXPath && null == computed && null != xml)
	);
}


fwDataService.prototype._setResultDOM = function(dom)
{
	this.m_dom = dom;
}


fwDataService.prototype._initialise = function(config, async, resultHandler)
{
	this.m_config = config;
	this.m_resultHandler = resultHandler;
	this.m_async = async;
    this.m_serviceMethodName = config.method; // Unfortunate backwards compatibility requirement.
}


/**
 * Get a name associated with the service based on its configuration
 *
 * @return the default name for the fwDataService
 * @type String
 */
fwDataService.prototype.getDefaultName = function()
{
	// Derived fwDataServices should replace this with a more meaningful identification string
	return "Unknown";
}

/**
 * Method runs any pre-exception handling processing specified in the service call
 * result handler object. At present, such functions will only be present for form
 * reference and model initialisation data services.
 *
*/
fwDataService.prototype._executeExceptionHandlingPreprocessing = function(resultHandler)
{
    var preProcessingFunc = resultHandler[ fwDataLoader.EXCEPTION_HANDLER_PREPROCESSING ];
    
    if(null != preProcessingFunc)
    {
        preProcessingFunc.call(this);
    }
}

/**
 * Method checks whether service handler contains a handler for Http
 * connection exceptions.
 *
 * @return Returns "true" if result handler has the property onHttpConnectionException
 *         defined, otherwise returns "false".
 *
*/
fwDataService.prototype.httpConnectionExceptionHandlerExists = function()
{
    return null != this.m_resultHandler.onHttpConnectionException;
}

/**
 * Method invokes Http connection exception handler on result handler passing
 * exception in as an argument.
 *
*/
fwDataService.prototype.invokeOnHttpConnectionExceptionHandler = function(ex)
{
    this.m_resultHandler.onHttpConnectionException(ex, this.m_serviceMethodName);
}

/**
 * Superclass providing common functions for service
 * classes which contact the application server
 *
*/

// Define global variable used to store queue of
// service call requests
var xmlHttpServiceRequestQueue = new Array();

function fwServerCallDataService()
{
}

fwServerCallDataService.prototype = new fwDataService();
fwServerCallDataService.prototype.constructor = fwServerCallDataService;

fwServerCallDataService.m_logger = new Category("fwServerCallDataService");

/**
 * The default maximum number of times to retry server call
 */
fwServerCallDataService.MAX_RETRIES = 3;

/**
 * Server call HTTP error constants
 *
*/
fwServerCallDataService.HTTP_Error_Constants = { 400   : "Erroneous request made to the server.",
                                                 401   : "Not authorized to access this resource.",
                                                 403   : "Forbidden to access this resource.",
                                                 404   : "Service not found on server.",
                                                 500   : "An internal error has occurred at the server.",
                                                 501   : "Service not implemented.",
                                                 502   : "Service call timed out.",
                                                 12002 : "The request has timed out.",
                                                 12029 : "The attempt to connect to the server failed.",
                                                 12030 : "The connection with the server has been terminated.",
                                                 12031 : "The connection with the server has been reset.",
                                                 12152 : "The server response could not be parsed.",
                                                 13030 : "Request/response status not available."
};

/**
 * Define default Http connection error retry responses.
 *
 * Defect 1046. These default values enable the default retry actions of
 * framework release 9.0.29 to be identical to those of previous releases
 * of the framework.
 *
*/
fwServerCallDataService.DEFAULT_HTTP_CONNECTION_ERROR_RETRY_RESPONSES = { "12030": true,
                                                                          "12152": true };

/**
 * Constant denoting XMLHttpRequest request status unavailable.
 *
*/
fwServerCallDataService.HTTP_REQUEST_STATUS_UNAVAILABLE = 13030;
                                         

fwServerCallDataService.prototype._initialise = function( config, async, resultHandler )
{
    // Initialise retry count
    this.m_retryCount = 0;
    
    // Invoke _initialise on super class
    fwDataService.prototype._initialise.call( this, config, async, resultHandler );
}

/**
 * Core method for listening to the request and calling onSuccess or
 * onError/onXXX as required.
 *
 * @param request - the request object form the server.
 * @param handler - the handler on which to call onSucess etc.
 */
fwServerCallDataService.prototype.handleReadyStateChange = function(index)
{
    var requestInfo = xmlHttpServiceRequestQueue[index];
    
    if(null != requestInfo)
    {
        var request = requestInfo.server.getRequest();
        
        if(request.readyState == 4)
        {
            if (this.m_config.showProgress)
            {
                // Defect 1059. Define reference to FormController
                // and pass to method hideProgress to allow
                // method to reassert focus.
                var fc = FormController.getInstance();
                
	            this.m_appC.m_serviceRequestCount--;
	            this.m_appC._hideProgress(fc);
            }
            
            // Determine status of request
            var requestStatus = this._getRequestStatus(request);

            // Defect 1060. Successful service returns will be marked with
            // status 200. However, returns following system and business
            // exceptions will be marked with a new user specified code
            // of 999.
            //
            // In practice, both request types are handled in the same way. The
            // new error code simply prevents the results of service calls
            // which raise exceptions from being cached.
            if(requestStatus == 200 || requestStatus == 999)
            {
	            this.resetRetryCount();
                if(fwServerCallDataService.m_logger.isDebug()) fwServerCallDataService.m_logger.debug("Response text: " + request.responseText);
                if(fwServerCallDataService.m_logger.isDebug()) fwServerCallDataService.m_logger.debug("Status text: " + request.statusText);
            
                var dom = XML.createDOM(null, null, null);
		        dom.loadXML(request.responseText);
           	    this._handleResultDOM(dom);
           	    
           	    // Clean up references to objects used to call service
           	    requestInfo.server.dispose();
           	    requestInfo.server = null;
           	    
           	    delete xmlHttpServiceRequestQueue[index];
           	    requestInfo = null;
            }
            else
            {
                // Handle error status code.
                
                // First retrieve information required to handle error correctly.
                var errorRetryResponses = this._getHttpConnectionErrorRetryResponses();
                
                var retryStatus = this._isRetryStatus(requestStatus, errorRetryResponses);
                
                var httpConnectionExceptionHandlerExists = this.httpConnectionExceptionHandlerExists();
                
                // Handle special cases first.
                if(retryStatus && httpConnectionExceptionHandlerExists)
                {
                    // Pass HttpConnectionException to handler on service handler.
                    // Effectively let application determine whether or not to retry.
                    
                    // Reset count as application may respond to retry codes in
                    // different ways for different services.
                    this.resetRetryCount();
                    
                    var errorMessage = fwServerCallDataService.HTTP_Error_Constants[ requestStatus ];
                    
                    var exception;
                    
                    if(null != errorMessage)
                    {
                        exception = new HttpConnectionException( "Http connection error - " + errorMessage );
                    }
                    else
                    {
                        exception = new HttpConnectionException( "Request/response status defined in configured Http connection error retry responses detected. Request status : " +
                                                                 requestStatus );
                    }
                    
                    // Set status on exception
                    exception.setResponseStatus(requestStatus);
                    
                    // Clean up references to objects used to call service
           	        requestInfo.server.dispose();
           	        requestInfo.server = null;
           	    
           	        delete xmlHttpServiceRequestQueue[index];
           	        requestInfo = null;
           	        
           	        // Pass control to exception handler
           	        this.invokeOnHttpConnectionExceptionHandler(exception);
           	        
           	    }
                else if (retryStatus &&
                         (!httpConnectionExceptionHandlerExists) && 
                         this.getRetryCount() < this._getHttpConnectionErrorRetryLimit())
                {
                    // In this case default to framework retry mechanism.
        	        this.incrementRetryCount();
        	    
        	        // Clean up references to objects used to call service
           	        requestInfo.server.dispose();
           	        requestInfo.server = null;
           	    
           	        delete xmlHttpServiceRequestQueue[index];
           	        requestInfo = null;
           	    
           	        // Re-submit service call
                    this.load();
                }
                else // A HTTP level error 
                {
	                this.resetRetryCount();
                    if(fwServerCallDataService.m_logger.isDebug()) fwServerCallDataService.m_logger.debug("requestStatus: " + requestStatus);

                    var errorMessage = fwServerCallDataService.HTTP_Error_Constants[requestStatus];
                    var exception;
                    if (errorMessage != null)
                    {
                        exception = new SystemException("Network or System error - " + requestStatus + " : " + errorMessage);
                    }
                    else
                    {
                        exception = new SystemException("Erroneous or unexpected server response code: " + requestStatus);
                    }
                
                    // Clean up references to objects used to call service
           	        requestInfo.server.dispose();
           	        requestInfo.server = null;
           	    
           	        delete xmlHttpServiceRequestQueue[index];
           	        requestInfo = null;
           	    
           	        // Display error message
                    this.invokeOnError(exception);
                }
                
                // Reset local variables
                errorRetryResponses = null;
                retryStatus = null;
                httpConnectionExceptionHandlerExists = null;
                
            } // End of if(requestStatus == 200 || requestStatus == 999) logic
            
        } // End of if(request.readyState == 4)

    } // End of if(null != requestInfo)
    
}

/*
 * Increments the internal retry counter.
 */
fwServerCallDataService.prototype.incrementRetryCount = function() {
	this.m_retryCount++;
}

/*
 * Gets the internal retry counter.
 */
fwServerCallDataService.prototype.getRetryCount = function() {
	return this.m_retryCount;
}

/*
 * Sets the retry count back to 0.
 */
fwServerCallDataService.prototype.resetRetryCount = function() {
	this.m_retryCount = 0;
}

/**
 * Method returns request status of Http request.
 *
 * @param request An instance of the appropriate XMLHttpRequest object.
 *
 * @return Returns status of request following return from server. If no
 *         value available returns Mozilla default of 13030.
 *
*/
fwServerCallDataService.prototype._getRequestStatus = function( request )
{
    var requestStatus;
    
    try
    {
        if(request.status !== undefined && request.status != 0)
        {
            requestStatus = request.status;
        }
        else
        {
            requestStatus = fwServerCallDataService.HTTP_REQUEST_STATUS_UNAVAILABLE;
        }
        
    } 
    catch(ex)
    {
        requestStatus = fwServerCallDataService.HTTP_REQUEST_STATUS_UNAVAILABLE;
    }
    
    return requestStatus;
}

/**
 * Method determines maximum number of retries to be attempted if Http
 * connection occurs and retries are allowed.
 *
 * @return Returns maximum allowed number of retries.
 *
*/
fwServerCallDataService.prototype._getHttpConnectionErrorRetryLimit = function()
{
    var retryLimit = null;
    
    if(null != this.m_appC)
    {
        // For calls when the application loads the AppController may not exist.
        // In this case use default value defined for this class, otherwise
        // attempt to retrieve value from application configuration file.
        retryLimit = this.m_appC.getHttpConnectionErrorRetryLimit();
    }
    
    if(null == retryLimit)
    {
        // AppController does not exist or retry limit
        // not defined in configuration.
        retryLimit = fwServerCallDataService.MAX_RETRIES;
    }
    
    return retryLimit;
}

/**
 * Method returns details of error retry response for various request
 * status codes.
 *
 * @return Object with set of properties corresponding to request codes.
 *         The value of each property will be either "true" or "false".
 *
*/
fwServerCallDataService.prototype._getHttpConnectionErrorRetryResponses = function()
{
    var errorRetryResponses = null;
    
    if(null != this.m_appC)
    {
        // Retrieve responses defined in configuration file
        errorRetryResponses = this.m_appC.getHttpConnectionErrorRetryResponses();
    }
    
    if(null == errorRetryResponses)
    {
        // Application controller does not exist or error retry responses
        // not defined in configuration file.
        errorRetryResponses = fwServerCallDataService.DEFAULT_HTTP_CONNECTION_ERROR_RETRY_RESPONSES;
    }
    
    return errorRetryResponses;
}

/**
 * Method determines whether, or not, the framework should attempt a retry
 * following a Http connection error. The method looks up the requested retry
 * response for the request status in the error retry response details provided.
 *
 * @param requestStatus       The status code for the Http request/response
 * @param errorRetryResponses Object detailing retry response for various
 *                            status codes.
 *
 * @return Returns "true" or "false" depending on configuation. The default is "false".
 *
*/
fwServerCallDataService.prototype._isRetryStatus = function( requestStatus, errorRetryResponses )
{
    var isRetryStatus = errorRetryResponses[ requestStatus.toString() ];
    
    if(null == isRetryStatus)
    {
        isRetryStatus = false;
    }
    
    return isRetryStatus;
}//==================================================================
