/**
 * Class which handles loading Data into the form's DataModel
 * during form initialisation
 */
function RecordsProtocolLazyLoadingDataLoader()
{
}


// Derived off fwDataLoader
RecordsProtocolLazyLoadingDataLoader.prototype = new fwDataLoader();
RecordsProtocolLazyLoadingDataLoader.prototype.constructor = RecordsProtocolLazyLoadingDataLoader;

/**
 * Logging category for RecordsProtocolLazyLoadingDataLoader
 *
 * @type Category
 * @private
 */
RecordsProtocolLazyLoadingDataLoader.m_logger = new Category("RecordsProtocolLazyLoadingDataLoader");


/**
 * Reference to recordProtocol which created this DataLoader
 *
 * @type RecordsProtocol
 * @private
 */
RecordsProtocolLazyLoadingDataLoader.prototype.m_recordsProtocol = null;


/**
 * XPath to the data which is being lazy loaded
 *
 * @type String
 * @private
 */
RecordsProtocolLazyLoadingDataLoader.prototype.m_rowXPath;



RecordsProtocolLazyLoadingDataLoader.prototype._successHandler = function(dom, name)
{
	// Delegate success back up to RecordsProtocol that created this DataLoader...
	this.m_recordsProtocol.onLazyFetchingServerSuccess(dom, this.m_rowXPath, this.m_resultTargetXPath);
}


RecordsProtocolLazyLoadingDataLoader.prototype._abort = function()
{
	// Don't do anything if the user aborts a retry attempt - data is simply not loaded
}


RecordsProtocolLazyLoadingDataLoader.create = function(config, recordsProtocol, rowXPath, resultTargetXPath)
{
	var dl = new RecordsProtocolLazyLoadingDataLoader();
	
	// Hang onto records protocol, rowXPath and resultTargetXPath as we need them during in _successHandler
	dl.m_recordsProtocol = recordsProtocol;
	dl.m_rowXPath = rowXPath;
	dl.m_resultTargetXPath = resultTargetXPath;
	
	dl._initialise(config);
	
	return dl;
}


/**
 * Get a name associated with this type of service
 *
 * @return a string containing the name of this type of service
 * @type String
 * @protected
 */
RecordsProtocolLazyLoadingDataLoader.prototype._getServiceTypeName = function()
{
	return "Lazy loading data service";
}


/**
 * Get the message that should be displayed when the Cancel button is presed
 * on the Retry/Cancel dialog
 *
 * @return the message detailing the action that will be taken if the cancel
 *   button is pressed.
 * @type String
 */
RecordsProtocolLazyLoadingDataLoader.prototype._getAbortMessage = function()
{
	return "abort the data retrieval (data will not be available for viewing or editing)";
}
//==================================================================
//
// RecordsProtocol.js
//
// Class which provides the members required by a GUIAdaptor to support
// definitions of records in the DOM. This allows the form to only
// submit dirty records for performance improvements.
//
//==================================================================


/*
 * RecordsProtocol constructor
 *
 * @constructor
 */
function RecordsProtocol()
{
}

RecordsProtocol.m_logger = new Category("RecordsProtocol");

/**
 * Current enablement state of the adaptor - defaults to enabled.
 */
RecordsProtocol.prototype.m_records = null;
RecordsProtocol.prototype.m_isRecord = false;
RecordsProtocol.prototype.m_recordName = null;

RecordsProtocol.RECORD_DIRTY_ELEMENT = "RecordDirty";

/**
 * Initialise the protocol
 *
 * @param e the DataModelEvent for initialisation
 */
RecordsProtocol.prototype.initialiseRecordsProtocol = function(e)
{
}

RecordsProtocol.prototype.getMarkDirtyRecordOn = function()
{
	return this.m_markDirtyRecordOn;
}

RecordsProtocol.prototype.getLazyFetchRecordOn = function()
{
	return this.m_lazyFetchRecordOn;
}

RecordsProtocol.prototype.hasRecordsForStripping = function()
{
	if(this.m_hasRecordsForStripping == null)
	{
		this.m_hasRecordsForStripping = false;
		for(var i=0, l=this.m_records.length; i<l; i++)
		{
			if(this.m_records[i].getStripCleanRecords() == true)
			{
				this.m_hasRecordsForStripping = true;
				break;
			}
		}
	}
	return this.m_hasRecordsForStripping;
}

RecordsProtocol.prototype.hasRecords = function()
{
	return (this.m_records.length > 0);
}

/**
 * form.records = [
 * 		{ 	xpath: "/ds/model/records/record",
 			keyXPath: "id",				// only required for lazy fetching, defaults for grids etc.
 *			stripCleanRecords: false	// defaults to true, unless only specify lazy fetching config???
 *			displayName: ""				// optional, used when displaying any error messages
 *			lazyFetchXPath: "/ds/var/page/selectedRecord"	// defaults to the adaptors dataBinding for grids etc.
 *			lazyFetchs {
 *				[
 *					{	
 *						nodeXPath: "address",
 *						resultTargetXPath: "/Cases/Case/Addresses/Address",
 *						service: {...}
 *						displayName: ""				// optional, used when displaying any error messages when fetching the data
 *					},
 *					...
 *				]
 * 			}
 *		}
 * ]
 *
 *	example for a grid lazy fetching config without clean record stripping. Note that the changeRecordXPath is not required
 * as it defaults to the grid's dataBinding. Note that you do not require the myGrid.isRecord = true config if you declare 
 * a lazyFetch config, and the record xpath defaults to the grid's rowXPath as for normal dirty record behaviour.
 *
 *	myGrid.lazyFetchs = {
 *		[ { nodeXPath: "address", resultTargetXPath: "/Cases/Case/Addresses/Address", service: {...} }
 *		]
 *	}
 *	myGrid.isRecord = true;
 */

/**
 * This is used when configuring an adaptor that supports the ListSrcDataProtocol without bothering
 * to configure the isRecord for clean record stripping
 */
RecordsProtocol.prototype.configLazyFetchs = function(c)
{
    if(c.lazyFetchs && this.getSrcData && this.getSrcData() != null)
    {
    	c.isRecord = true;
    	c.stripCleanRecords = false;
    	
    	this.configIsRecord(c);
	}
}

RecordsProtocol.prototype.configIsRecord = function(c)
{
    // We have a special quick-config for adaptors that support the ListSrcDataProtocol
    // that allows the row configuration to be applied as a record if applicable
	if(c.isRecord && c.isRecord == true && this.getSrcData && this.getSrcData() != null)
	{
		this.m_isRecord = true;
		var xpath = this._getRowXPath();
		var keyXPath = (c.keyXPath == null) ? this.keyXPath : c.keyXPath;
		var displayName = (c.displayName == null) ? this.getDisplayName() : c.displayName;
		var stripCleanRecords = (c.stripCleanRecords == null) ? true : c.stripCleanRecords;
		var lazyFetchXPath = (c.lazyFetchXPath == null) ? this.dataBinding : c.lazyFetchXPath;
		var lazyFetchs = c.lazyFetchs;

		this.m_records[this.m_records.length] = this.createRecord(xpath, keyXPath, stripCleanRecords, lazyFetchXPath, lazyFetchs, displayName);
	}
} 
 
RecordsProtocol.prototype.configRecords = function(c)
{
	if(c.records)
	{
		this.m_isRecord = false;
		for(var i=0, l=c.records.length; i<l; i++)
		{
			var record = c.records[i];
			record.displayName = (record.displayName == null) ? this.getDisplayName() : record.displayName;
			record.stripCleanRecords = (record.stripCleanRecords == null) ? true : record.stripCleanRecords;
			this.m_records[this.m_records.length] = this.createRecord(record.xpath, record.keyXPath, record.stripCleanRecords, record.lazyFetchXPath, record.lazyFetchs, record.displayName);
		}
	}
} 
 
/**
 * Configure the Protocol
 *
 * @param cs the configuration objects to inspect for protocol configuration properties
 * @type void
 */
RecordsProtocol.prototype.configRecordsProtocol = function(cs)
{
	if(RecordsProtocol.m_logger.isTrace()) RecordsProtocol.m_logger.trace(this.getDisplayName() + ": configRecordsProtocol()");
	// Need to determine how to merge enableOn xpaths. At
	// the moment just use the first array found.
	var cs = this.getConfigs();

	if(this.m_records == null)
	{
		this.m_records = new Array();
	}
	if(this.m_markDirtyRecordOn == null)
	{
		this.m_markDirtyRecordOn = new Array();
	}
	if(this.m_lazyFetchRecordOn == null)
	{
		this.m_lazyFetchRecordOn = new Array();
	}

	for(var i = 0, l = cs.length; i < l; i++)
	{
		var c = cs[i];
	    if(c.records)
	    {
	    	this.configRecords(c);
	    }
	    else if(c.isRecord)
	    {
	    	this.configIsRecord(c);
	    }
	    else if(c.lazyFetches)
	    {
	    	this.configLazyFetchs(c);
	    }
	}
	// if this not a form adaptor then register the records with the form adaptor
	// because it needs to know about all records for cleaning up the data before
	// calling a service
	var formAdaptor = FormController.getInstance().getFormAdaptor();
	if(this.getId() != formAdaptor.getId() && this.m_records.length>0)
	{
		formAdaptor.addRecords(this.m_records);
	}
}

RecordsProtocol.prototype.addRecords = function(recordOn)
{
	if(RecordsProtocol.m_logger.isTrace()) RecordsProtocol.m_logger.trace(this.getDisplayName() + ": addRecords() this.m_records length = " + this.m_records.length + ", adding " + recordOn.length + " records");
	this.m_records = this.m_records.concat(recordOn);
}

/**
 * Perform cleanup required by the protocol before it is destroyed
 */
RecordsProtocol.prototype.disposeRecordsProtocol = function()
{
}

RecordsProtocol.stripCleanRecords = function(stripNode, recordOffset, targetXPath)
{
	var formAdaptor = FormController.getInstance().getFormAdaptor();
	if(formAdaptor.hasRecordsForStripping())
	{
		stripNode = formAdaptor.stripCleanRecords(stripNode, recordOffset, targetXPath);
	}
	return stripNode;
}

RecordsProtocol.prototype.stripCleanRecords = function(stripNode, recordOffset, targetXPath)
{
	if(RecordsProtocol.m_logger.isDebug()) RecordsProtocol.m_logger.debug(this.getDisplayName() + ": stripCleanRecords() recordOffset = " + recordOffset + ", targetXPath = " + targetXPath);

	// ToDo: complete
	// search for nodes containing the dirty flag, if there is none then return an empty node
	// but if there are then remove all clean records - find dirty elements, navigate up a node
	// then remove all other child nodes that don't contain a dirty flag. But also need to look
	// for records that have no dirty flags set at all by comparing against this.m_records.
	for(var i=0, rl=this.m_records.length; i<rl; i++)
	{
		// If we have a recordOffset then remove this from the beginning of the record xpaths - this
		// is used when people are adding a subNode from the main node and we need to alter the record
		// xpath to be able to determine xpaths
		var record = this.m_records[i];
		var recordXPath = record.getXPath();
		if(RecordsProtocol.m_logger.isDebug()) RecordsProtocol.m_logger.debug(this.getDisplayName() + ": stripCleanRecords() recordXPath = " + recordXPath);
		if(recordOffset != null && recordOffset != "")
		{
			var index = recordXPath.indexOf(recordOffset);
			// If the recordOffset does not equal the beginning of the string then the record in not
			// contained in the xml fragment
			if(index != 0)
			{
				recordXPath = null;
			}
			else
			{
				recordXPath = recordXPath.substring(recordOffset.length);
			}
			if(RecordsProtocol.m_logger.isDebug()) RecordsProtocol.m_logger.debug(this.getDisplayName() + ": stripCleanRecords() recordXPath after taking into account recordOffset = " + recordXPath);
		}
		// This is only used from the form lifecycle code as you can construct a node, and then construct a new
		// xml structure to put the node into
		if(targetXPath != null && targetXPath != "")
		{
			recordXPath = XPathUtils.concatXPaths(targetXPath, recordXPath);
			if(RecordsProtocol.m_logger.isDebug()) RecordsProtocol.m_logger.debug(this.getDisplayName() + ": stripCleanRecords() added targetXPath, recordXPath = " + recordXPath);
		}
		if(recordXPath != null)
		{
			var nodes = stripNode.selectNodes(recordXPath);
			for(var j=0, nl=nodes.length; j<nl; j++)
			{
				var node = nodes[j];
				var dirtyNode = node.selectSingleNode("./" + RecordsProtocol.RECORD_DIRTY_ELEMENT);
				if(dirtyNode == null || XML.getNodeTextContent(dirtyNode) != "true")
				{
					// remove this child from the parent because the record is clean
					var parent = node.parentNode;
					parent.removeChild(node) ;	
				}
				else
				{
					// strip out the dirty flag so as not to affect server-side schema validation
					var parent = dirtyNode.parentNode;
					parent.removeChild(dirtyNode) ;	
				}
			}
		}
	}
	
	return stripNode;
}

/**
 * Invoke the isEnabled method(s) of the GUI Element
 *
 * @param event the DataModelEvent that triggered this call
 * @return the name of the GUI Element.
 * @type String
 */
RecordsProtocol.prototype.invokeMarkRecordDirty = function(event)
{
	if(RecordsProtocol.m_logger.isDebug()) RecordsProtocol.m_logger.debug(this.getDisplayName() + ": invokeMarkRecordDirty() data model event = " + event.toString());
	
	if(event.getType() != DataModelEvent.REMOVE)
	{
	    // Defect 912.
	    // No need to process delete operations because the node will
	    // be removed from the DOM. Therefore, setting the record
	    // dirty node is pointless.
	    
	    var dirtyRecordXPath = "/" + RecordsProtocol.RECORD_DIRTY_ELEMENT;
	
	    var dm = FormController.getInstance().getDataModel();
	    var eventXPath = event.getXPath();
	    
	    // Ignore changing of dirty record nodes for marking records as dirty, otherwise
	    // we can't clean a record by removing the dirty record node
	    if(eventXPath.lastIndexOf("/RecordDirty") != (eventXPath.length - dirtyRecordXPath.length))
	    {
		    for(var i=0, rl=this.m_records.length; i<rl; i++)
		    {
			    var recordXPath = this.m_records[i].getXPath();
			    
			    // Defect 934. The xpath below does not always
			    // work correctly.
			    //var xpath = recordXPath + "[descendant-or-self::node() = " + eventXPath + "]";
			    
			    // Use this definition instead. Defect 977. Use method getNameOfLastNode
			    // rather than getLastNodeName.
			    var finalNode = XPathUtils.getNameOfLastNode(eventXPath);
			    var xpath = recordXPath + "[descendant-or-self::" + finalNode + " = " + eventXPath + "]";
			    
			    var nodes = dm.getNodes(xpath);
			    
			    if(nodes.length > 0)
			    {
				    var rowToMarkDirtyXPath = RecordsProtocol.getRowXPathFromEventXPath(eventXPath, recordXPath);
				    
				    // D1017 - It is possible to have retrieved nodes using the combination of the event XPath
				    // and the current record XPath but there is not a match with the current record XPath.
				    // For example:
				    //   eventXPath: "/ds/Case/Prosecutor[position()=1]/PrivateRepresentation/CPFId"
				    //   recordXPath: "/ds/Case/Defendants/Defendant"
				    // The following DOM fragment has the same Private Representation set up for both
				    // Defendant and Prosecutor. This will retrieve the Defendant node but the event
				    // XPath will not match the record XPath.
				    //   <Case>
					//	   <Defendants>
					//	     <Defendant>
					//		   <PrivateRepresentation>
					//		     <CPFId>123456</CPFId>
					//		   </PrivateRepresentation>
					//		 </Defendant>
					//	   </Defendants>
					//	   <Prosecutor>
					//	     <PrivateRepresentation>
					//		   <CPFId>123456</CPFId>
					//	     </PrivateRepresentation>
					//	   </Prosecutor>
					//   </Case>
				    if(rowToMarkDirtyXPath != null)
				    {
				    	dm.setValue(rowToMarkDirtyXPath + dirtyRecordXPath, "true");
				    }
			    }
		    }
	    }
	}
	
	// Marking records dirty does not require a repaint of the adaptor
	return false;
}

// eventXPath =  "/ds/Cases/Case[id = 1]/Addresses/Address[id = 1]/AddressLine1"
// recordXPath = "/ds/Cases/Case/Addresses/Address"

RecordsProtocol.getRowXPathFromEventXPath = function(eventXPath, recordXPath)
{
	var originalXPath = eventXPath;
	var eventIndex = 0;
	var slashIndex = 0;

	while(slashIndex != -1)
	{
		recordXPath = recordXPath.substring(slashIndex + 1);
		slashIndex = recordXPath.indexOf("/");
		
		if(slashIndex != -1)
		{
			// Multiple nodes in record XPath
			var nextElement = recordXPath.substring(0, slashIndex);
			var index = eventXPath.indexOf(nextElement);
			
			if(index != -1)
			{
				// Matched node of record XPath in event XPath
				eventIndex = eventIndex + index + nextElement.length;
				eventXPath = eventXPath.substring(index + nextElement.length);
				
				// Iterate to the end of the predicate(s) for the matched
				// node in the event XPath
				while(eventXPath.charAt(0) == "[")
				{
					index = eventXPath.indexOf("]");
					eventIndex = eventIndex + index + 1;
					eventXPath = eventXPath.substring(index + 1);
				}
			}
			else
			{
				// No match for record XPath node in event XPath
				return null;
			}
		}
		else
		{
			// Only one node in record XPath
			var nextElement = recordXPath;
			var index = eventXPath.indexOf(nextElement);

			if(index != -1)
			{
				// Matched node of record XPath in event XPath
				eventIndex = eventIndex + index + nextElement.length;
				eventXPath = eventXPath.substring(index + nextElement.length);

				// Iterate to the end of the predicate(s) for the matched
				// node in the event XPath				
				while(eventXPath.charAt(0) == "[")
				{
					index = eventXPath.indexOf("]");
					eventIndex = eventIndex + index + 1;
					eventXPath = eventXPath.substring(index + 1);
				}
			}
			else
			{
				// No match for record XPath node in event XPath
				return null;
			}
		}
	}
	
	// Event XPath up to last record XPath node plus any predicates
	return originalXPath.substring(0, eventIndex);
}

/**
 * Invoke the isEnabled method(s) of the GUI Element
 *
 * @param event the DataModelEvent that triggered this call
 * @return the name of the GUI Element.
 * @type String
 */
RecordsProtocol.prototype.invokeLazyFetchRecord = function(event)
{
	if(RecordsProtocol.m_logger.isDebug()) RecordsProtocol.m_logger.debug(this.getDisplayName() + ": invokeLazyFetchRecord() data model event = " + event.toString());

	var dm = FormController.getInstance().getDataModel() ;
	var eventXPath = event.getXPath();
	for(var i=0, rl=this.m_records.length; i<rl; i++)
	{
		var record = this.m_records[i];
		var lazyFetchXPath = record.getLazyFetchXPath();
		if(lazyFetchXPath == eventXPath)
		{
			var lazyFetchs = record.getLazyFetchs();
			var key = Services.getValue(lazyFetchXPath);
			if(key == null || key == "")
			{
				// don't bother to lazily fetch if there is no row
			}
			else
			{
				var rowXPath = record.getXPath();
				rowXPath = rowXPath + "[" + record.getKeyXPath() + " = \'" + key + "\']";
				for(var i=0, l=lazyFetchs.length; i<l; i++)
				{
					var lazyFetch = lazyFetchs[i];
					var nodeExistsCheckXPath = rowXPath + "/" + lazyFetch.getNodeXPath();
					if(!Services.exists(nodeExistsCheckXPath))
					{
						this.invokeLazyFetchingService(rowXPath, lazyFetch);
					}
				}
			}
		}
	}
	// lazy fetching of records does not require a repaint of the adaptor
	return false;
}

RecordsProtocol.prototype.invokeLazyFetchingService = function(rowXPath, lazyFetch)
{
	var serviceConfig = lazyFetch.getService();
	var resultTargetXPath = lazyFetch.getResultTargetXPath();
	var dL = RecordsProtocolLazyLoadingDataLoader.create(serviceConfig, this, rowXPath, resultTargetXPath);
	dL.load();
}

// The success function calls a static method on a timeout because for synchronous computed service calls
// the call to this happens inside of a processEvents() loop which invalidates the suspension of dirty record events.
// By putting this on a timeout then we are guaranteed that it will not happen inside a processEvents loop.
RecordsProtocol.prototype.onLazyFetchingServerSuccess = function(dom, rowXPath, resultTargetXPath)
{
	var fc = FormController.getInstance();
//	var dm = fc.getDataModel();
	//alert("it worked, received dom = " + dom.xml);

	var formAdaptor = fc.getFormAdaptor();
	
	// If adaptor supports FormDirtyProtocol and dirty event monitoring is not suspended,
	// then suspend dirty event monitoring. This way a form's dirty state won't be
	// affected by data being lazy loaded into the model.
	var restartDirtyEventChecking = false
	if(formAdaptor.supportsProtocol("FormDirtyProtocol") && !formAdaptor.dirtyEventsSuspended())
	{
		restartDirtyEventChecking = true;
		formAdaptor.suspendDirtyEvents(true);
	}
		
	try
	{
	if(resultTargetXPath != null)
	{
		var nodesToAdd = dom.selectNodes(resultTargetXPath);
		for(var i=0, l=nodesToAdd.length; i<l; i++)
		{
			Services.addNode(nodesToAdd[i], rowXPath);
		}
	}
	else
	{
		Services.addNode(dom, rowXPath);
	}
	}
	catch(e)
	{
		if(RecordsProtocol.m_logger.isError()) RecordsProtocol.m_logger.error(this.getDisplayName() + ": RecordsProtocol.onLazyFetchingServerSuccess() caught exception attempting to add the lazy fetch data to the record, e = " + e);
	}
	
	// If FormDirtyProtocol dirty event monitoring was suspended, then restart it now
	if(restartDirtyEventChecking)
	{
		formAdaptor.suspendDirtyEvents(false);
    }
}

/**
 *  Returns all of the listeners for this adaptor for this protocol 
 *
 */
RecordsProtocol.prototype.getListenersForRecordsProtocol = function()
{
    var listenerArray = new Array();
    var dirtyRecordListener = FormControllerListener.create(this, FormController.DIRTY_RECORD);
    var lazyFetchListener = FormControllerListener.create(this, FormController.LAZY_FETCH_RECORD);
    
	var on = this.getMarkDirtyRecordOn();
	if(null != on)
	{
		for(var i = on.length-1; i>=0; i--)
		{
            listenerArray.push({xpath: on[i] + "//*", listener: dirtyRecordListener});
		}
	}

	var on = this.getLazyFetchRecordOn();
	if(null != on)
	{
		for(var i = on.length-1; i>=0; i--)
		{
            listenerArray.push({xpath: on[i], listener: lazyFetchListener});
		}
	}
    
    return listenerArray;
}

RecordsProtocol.prototype.createRecord = function(xpath, keyXPath, stripCleanRecords, lazyFetchXPath, lazyFetchs, displayName)
{
	var record = Record._create(xpath, keyXPath, stripCleanRecords, lazyFetchXPath, lazyFetchs, displayName);
	if(stripCleanRecords == true)
	{
		this.m_markDirtyRecordOn[this.m_markDirtyRecordOn.length] = xpath;
	}
	if(lazyFetchs != null && lazyFetchs.length > 0)
	{
		this.m_lazyFetchRecordOn[this.m_lazyFetchRecordOn.length] = lazyFetchXPath;
	}
	return record;
}

function Record()
{
	this.m_xpath = null;
	this.m_stripCleanRecords = null;
	this.m_lazyFetchXPath = null;
	this.m_lazyFetchs = null;
	this.m_displayName = null;
}

Record._create = function(xpath, keyXPath, stripCleanRecords, lazyFetchXPath, lazyFetchs, displayName)
{
	var record = new Record();
	record.m_xpath = xpath;
	record.m_keyXPath = keyXPath;
	record.m_stripCleanRecords = stripCleanRecords;
	record.m_lazyFetchXPath = lazyFetchXPath;
	record.m_lazyFetchs = new Array();
	if(lazyFetchs != null)
	{
		for(var i=0, l=lazyFetchs.length; i<l; i++)
		{
			var lazyFetchConfig = lazyFetchs[i];
			record.m_lazyFetchs[record.m_lazyFetchs.length] = new LazyFetch(lazyFetchConfig);
		}
	}
	// optional, only used for displaying logging and error messages
	record.m_displayName = displayName;
	
	return record;
}

Record.prototype.getXPath = function()
{
	return this.m_xpath;
}

Record.prototype.getKeyXPath = function()
{
	return this.m_keyXPath;
}

Record.prototype.getLazyFetchXPath = function()
{
	return this.m_lazyFetchXPath;
}

Record.prototype.getStripCleanRecords = function()
{
	return this.m_stripCleanRecords;
}

Record.prototype.getLazyFetchs = function()
{
	return this.m_lazyFetchs;
}

Record.prototype.getDisplayName = function()
{
	return this.m_displayName;
}

function LazyFetch(lazyFetchConfig)
{
	this.m_nodeXPath = lazyFetchConfig.nodeXPath;
	this.m_resultTargetXPath = lazyFetchConfig.resultTargetXPath;
	this.m_service = lazyFetchConfig.service;
	this.m_displayName = (lazyFetchConfig.displayName == null) ? XPathUtils.getLastNodeName(this.m_nodeXPath) : lazyFetchConfig.displayName;
}

LazyFetch.prototype.getNodeXPath = function()
{
	return this.m_nodeXPath;
}

LazyFetch.prototype.getResultTargetXPath = function()
{
	return this.m_resultTargetXPath;
}

LazyFetch.prototype.getService = function()
{
	return this.m_service;
}

LazyFetch.prototype.getDisplayName = function()
{
	return this.m_displayName;
}
//==================================================================
//
// EnablementProtocol.js
//
// Class which provides the members required by a GUIAdaptor for it
// to support enablement and disablement. When a GUIAdaptor is set
// to disabled it should stop responding to user input of any kind
// and render itself in suitable manner to indicate that it is 
// disabled (typically some form of greying out).
//
// If the Enablement protocol is added to a GUIAdaptor, then the
// FormController will call the Adaptor's invokeIsEnabled() method 
// to call any configured isEnabled methods when any of the xpaths
// in the enableOn array are modified.
// The FormController will then notify the adaptor of it's new
// enablement state by calling the setEnabled() method supplied by
// this protocol. This sets the internal m_enabled flag.
//
// It is the responsability of the adaptor itself to interpret the
// meaning of m_enabled and render itself appropriately and disable
// any approriate event handling in its renderState() method.
//
//==================================================================


/*
 * EnablementProtocol constructor
 *
 * @constructor
 */
function EnablementProtocol()
{
}


/**
 * Current enablement state of the adaptor - defaults to enabled.
 */
EnablementProtocol.prototype.m_enabled = true;

EnablementProtocol.prototype.m_originalEnabled = true;
EnablementProtocol.prototype.m_containerEnabled = true;

/**
 * Keep track of previous enablement state
 */
EnablementProtocol.prototype.m_enabledChanged = false;


/**
 * Array of XPaths which determine when the enablement state of 
 * the GUI Adaptor is re-evaluated.
 *
 * @configuration
 * @merge-rule
 */
EnablementProtocol.prototype.enableOn = null;


/**
 * Configuration function for object which determines whether
 * or not the field is enabled or not.
 *
 * @return true if the field is enabled or false otherwise.
 * @type boolean
 * @configuration
 * @merge-rule Least specific rule processed first - if parent
 *   component isn't enabled, then there is no point evaluating
 *   child enablement.
 */
EnablementProtocol.prototype.isEnabled = null;


/**
 * Initialise the protocol
 *
 * @param e the DataModelEvent for initialisation
 */
EnablementProtocol.prototype.initialiseEnablementProtocol = function(e)
{
	this.setEnabled(this.invokeIsEnabled(e));	
}


/**
 * Configure the Protocol
 *
 * @param cs the configuration objects to inspect for protocol configuration properties
 * @type void
 */
EnablementProtocol.prototype.configEnablementProtocol = function(cs)
{
	// Need to determine how to merge enableOn xpaths. At
	// the moment just use the first array found.
	var cs = this.getConfigs();

	for(var i = 0, l = cs.length; i < l; i++)
	{
		if(null != cs[i].enableOn)
		{
			this.enableOn = cs[i].enableOn;
			break;
		}
	}
}


/**
 * Perform cleanup required by the protocol before it is destroyed
 */
EnablementProtocol.prototype.disposeEnablementProtocol = function()
{
}


/**
 * Get additional databindings that trigger a refresh of the
 * field's enablement state.
 */
EnablementProtocol.prototype.getEnableOn = function()
{
	return this.enableOn;
}


EnablementProtocol.prototype.hasIsEnabled = function()
{
	return this.hasConfiguredProperty("isEnabled");
}


/**
 * Invoke the isEnabled method(s) of the GUI Element
 *
 * @param event the DataModelEvent that triggered this call
 * @return the name of the GUI Element.
 * @type String
 */
EnablementProtocol.prototype.invokeIsEnabled = function(event)
{
	// Invoke all configurations, if any isEnabled returns
	// false then the adapter is disabled.
	var cs = this.getConfigs();

	var enabled = true;	
	for(var i = 0, l = cs.length; i < l && enabled; i++)
	{
		if(null != cs[i].isEnabled && !cs[i].isEnabled.call(this, event))
		{
			enabled = false;
			break;
		}
	}
	
	return enabled;
}

EnablementProtocol.prototype.setContainerEnabled = function(e)
{
	var r = false;
	this.m_containerEnabled = e;
	if(e == true)
	{
		if(this.m_enabled != this.m_originalEnabled)
		{
			this.m_enabled = this.m_originalEnabled;

			// Toggle mandatory change flag
			this.m_enabledChanged = !this.m_enabledChanged;

			r = true;
			
			// Trigger a StateChangeEvent if the value has changed
			var e = StateChangeEvent.create(StateChangeEvent.ENABLED_TYPE, this.m_enabled, this);
			this.changeAdaptorState(e);
		}
	}
	else
	{
		this.m_originalEnabled = this.m_enabled;
		if(e != this.m_enabled)
		{
			this.m_enabled = e;
			
			// Toggle mandatory change flag
			this.m_enabledChanged = !this.m_enabledChanged;

			r = true;
			
			// Trigger a StateChangeEvent if the value has changed
			var e = StateChangeEvent.create(StateChangeEvent.ENABLED_TYPE, this.m_enabled, this);
			this.changeAdaptorState(e);
		}
	}
	return r;
}

/**
 * Set whether or not the GUI Element should be rendered in the
 * enabled state or not.
 *
 * @param e boolean that determines whether or not the field
 *   is rendered in the enabled state or not
 * @param detail is an object providing additional information
 *               Ignored in the default implementation.
 * @return true if the state of adaptor changed
 * @type boolean
 */
EnablementProtocol.prototype.setEnabled = function(e, detail)
{
	var r = false;
	if(this.m_containerEnabled == false)
	{
		this.m_originalEnabled = e;
	}
	if(this.m_containerEnabled == true && e != this.m_enabled)
	{
		this.m_enabled = e;
		
		this.m_enabledChanged = !this.m_enabledChanged;
		
		r = true;

		// Trigger a StateChangeEvent if the value has changed
		var e = StateChangeEvent.create(StateChangeEvent.ENABLED_TYPE, this.m_enabled, this);
		this.changeAdaptorState(e);
	}
	return r;
}


/**
 * Get whether the GUI Element is rendered as enabled or not
 *
 * @return true if the Element is rendered as enabled or false if
 *    it isn't
 * @type boolean
 */
EnablementProtocol.prototype.getEnabled = function()
{
	return this.m_enabled;
}


/**
 *  Returns all of the listeners for this adaptor for this protocol 
 *
 */
EnablementProtocol.prototype.getListenersForEnablementProtocol = function()
{
	// Note enablement do not depend on the fields own values -
	// this would mean that they could become none editable depending
	// on what was entered, which does not make sense.
	
	//@todo This is hack to get initialisation of fields with static 
	// enablement rules to work correctly
    
    var listenerArray = new Array();
    
    if (!this.hasIsEnabled())
    {
        return listenerArray; 
    } 
    
    var listener = FormControllerListener.create(this, FormController.ENABLEMENT);
    
    var db = this.dataBinding;
        
	if(null != db) 
    {
        listenerArray.push({xpath: db, listener: listener});
    }
	var on = this.getEnableOn();
	if(null != on)
	{
		for(var i = on.length-1; i>=0; i--)
		{
            listenerArray.push({xpath: on[i], listener: listener});
		}
	}
    
    return listenerArray;
}
//==================================================================
//
// FocusProtocol.js
//
// Class which provides the members required by a GUIAdaptor for it
// to support focussing. When an adaptor has the focus it needs to
// render itself approriately and also accept keyboard events (if
// appropriate).
//
// This protocol will have considerable interaction with the
// TabManager when it is implemented and the more details on the
// precise useage of this protocol will be provided then.
//
//==================================================================


/*
 * FocusProtocol constructor
 *
 * @constructor
 */
function FocusProtocol()
{
}

FocusProtocol.m_logger = new Category("FocusProtocol");

/**
 * Configuration property that determines the position of the
 * GUI Element within the form's tabbing order
 *
 * @type Integer
 * @configuration
 */
FocusProtocol.prototype.tabIndex = null;


/**
 * Property to keep track of whether we have focus or not.
 */
FocusProtocol.prototype.m_focus = false;


/**
 * Property to keep track of whether or not focus has changed since last
 * refresh
 */
FocusProtocol.prototype.m_focusChanged = false;


/**
 * Configuration function that allows the application to override
 * the default tabbing order by returning the id of the field to
 * move to next. The function accepts a single boolwean parameter
 * which indicates whether the user is tabbing forward (true) or
 * backwards (false) and should return the id of the next field to
 * move to, or null if the default tabbing order should be used.
 *
 * @type Function(boolean): String
 * @configuration
 */
FocusProtocol.prototype.moveFocus = null;


/**
 * Initialisation method for Focus protocol
 *
 * @param cs the configuration objects to apply to the GUIAdaptor
 * @type void
 */
FocusProtocol.prototype.configFocusProtocol = function(cs)
{
	// Look for first tabIndex configuration
	for(var i = 0, l = cs.length; i < l ; i++)
	{
		if(null != cs[i].tabIndex)
		{
			// If there is tabIndex then just set this Adaptor's
			// tabIndex configuration to it - there is no chaining
			if(this.tabIndex == null) this.tabIndex = cs[i].tabIndex;
		}

		if(null != cs[i].moveFocus)
		{
			// If there is moveFocus then just set this Adaptor's
			// moveFocus configuration to it - there is no chaining
			if(this.moveFocus == null) this.moveFocus = cs[i].moveFocus;
		}
	}
}


/**
 * Perform cleanup required by the FocusProtocol before
 * it is destroyed
 */
FocusProtocol.prototype.disposeFocusProtocol = function()
{
}


/**
 * Get the tabIndex for this adaptor
 *
 * @return the tabIndex for this adaptor
 * @type Integer
 */
FocusProtocol.prototype.getTabIndex = function()
{
	// Default to unordered
	var index = 0;
	
	if(this.tabIndex != null)
	{
		var indexPosition = parseInt(this.tabIndex);
		if(indexPosition > 0 || indexPosition < 0)
		{
			// indexPosition is positive - in the sorted list
			// or indexPosition is negative - excluded from tabbing order
			index = indexPosition;
		}
		else
		{
			// Anything else return 0 - not in ordered tabIndex
		}
	}

	return index;
}


FocusProtocol.prototype.invokeMoveFocus = function(forwards)
{
	// If there is no moveFocus configuration, simply return null so the default
	// tabbing order is used instead, otherwise invoke the configured moveFocus
	// method.
	var targetAdaptorId = null;
	if(null != this.moveFocus)
	{
		targetAdaptorId = this.moveFocus.call(this, forwards);
	}
	return targetAdaptorId;
}


/**
 * Change the elements focus state
 *
 * @param f if true render the component as focussed, if false render the
 *   component as unfocussed.
 * @param wasClick Specifies whether focus was achieved by user clicking 
 *        on component (true) or moving onto component using tab key (false).
 *        To many components this value will not be of importance. However,
 *        in certain cases the TabSelectorGUIAdaptor has to implement
 *        different behaviours depending on how focus was achieved. This
 *        value is used only when focus is set not lost.
 * @return true if the GUI component's focus changed, or false otherwise
 * @type boolean
 */
FocusProtocol.prototype.setFocus = function(f,wasClick)
{
	if(FocusProtocol.m_logger.isDebug()) FocusProtocol.m_logger.debug("FocusProtocol.setFocus() adaptor " + this.getId() + ", focus = " + f);
	var r = false;
	if(f != this.m_focus)
	{
		this.m_focus = f;
		
		// Toggle focus change flag
		//this.m_focusChanged = !this.m_focusChanged;
		this.m_focusChanged = true;
		
		r = true;
	}
	else
	{
		this.m_focusChanged = false;
	}
	return r;
}


/**
 * Get whether the GUI Element is rendered as focussed or not
 *
 * @return true if the Element is rendered as focussed or false if
 *    it isn't
 * @type boolean
 */
FocusProtocol.prototype.hasFocus = function()
{
	return this.m_focus;
}


/**
 * Method which can be overridden by a component to which allows it to
 * reject accepting the focus. By default always returns true.
 *
 * @return true if the component can accept the focus or false to refuse it
 * @type boolean 
 */
FocusProtocol.prototype.acceptFocus = function()
{
	return true;
}

FocusProtocol.prototype.onFocus = null;

FocusProtocol.prototype.onBlur = null;//==================================================================
//
// FormDirtyProtocol.js
//
// Protocol implemented on Forms which allows them to detect when
// they are dirty.
//
//==================================================================


/*
 * FormDirtyProtocol constructor
 *
 * @constructor
 */
function FormDirtyProtocol()
{
}

FormDirtyProtocol.m_logger = new Category("FormDirtyProtocol");


FormDirtyProtocol.DEFAULT_MODEL_XPATH = DataModel.DEFAULT_ROOT;


/**
 * Property to keep track of the dirty state of the form
 *
 * @type boolean
 * @private
 */
FormDirtyProtocol.prototype.m_dirty = false;


/**
 * Flag to indicate whether or not the protocol is currently
 * accepting dirty events or not
 *
 * @type boolean
 * @private
 */
FormDirtyProtocol.prototype.m_suspend = false;


/**
 * Initialisation method for FormDirty protocol
 *
 * @param cs the configuration objects to apply to the GUIAdaptor
 * @type void
 * @private
 */
FormDirtyProtocol.prototype.configFormDirtyProtocol = function(cs)
{
}


/**
 * Dispose of the FormDirty Protocol
 *
 * @private
 */
FormDirtyProtocol.prototype.disposeFormDirtyProtocol = function()
{
}


/**
 * Get the XPath of the node that contains the model
 *
 * @return a string containing the XPath of the node that contains the model
 * @type String
 */
FormDirtyProtocol.prototype.getModelXPath = function()
{
	fc_assertAlways("FormDirtyProtocol.getModelXPath(): must be overridden in implmeneting adaptor");
}


FormDirtyProtocol.prototype.formDirtyUpdate = function(e)
{
	if (this._getState() != FormElementGUIAdaptor.FORM_BLANK)
	{
		// If we are using the default databinding of /ds then we need to ignore updates to /ds/var
		if (!((this.getModelXPath() == FormDirtyProtocol.DEFAULT_MODEL_XPATH && (e.getXPath().indexOf(DataModel.VARIABLES_ROOT) == 0)) || e.getXPath() == "/"))
		{
			if(FormDirtyProtocol.m_logger.isDebug()) FormDirtyProtocol.m_logger.debug("set form to dirty - change to xpath: " + e.getXPath());
	
			// Set this form to dirty
			this._setDirty(true);
	
			// Update the data model
			this.update();
		}
		else
		{
			if(FormDirtyProtocol.m_logger.isDebug()) FormDirtyProtocol.m_logger.debug("Not setting form dirty because xpath is outside Form Model Xpath. Change to xpath: " + e.getXPath());
		}
	}
	else
	{
		if(FormDirtyProtocol.m_logger.isDebug()) FormDirtyProtocol.m_logger.debug("Not setting form dirty because form is in blank state. Change to xpath: " + e.getXPath());
	}
}


/**
 *  Returns all of the listeners for this adaptor for this protocol 
 */
FormDirtyProtocol.prototype.getListenersForFormDirtyProtocol = function()
{
    var listenerArray = new Array();
    var listener = FormControllerListener.create(this, FormController.FORMDIRTY);
    
    listenerArray.push({xpath: this.getModelXPath() + "//*", listener: listener});
    
    return listenerArray;
}


/**
 * Should dirty events from the DataModel be ignored?
 *
 * @return true if dirty events should be ignore or false otherwise
 */
FormDirtyProtocol.prototype.dirtyEventsSuspended = function()
{
	return this.m_suspend;
}


/**
 * Suspend or re-instate dirty event propogation from the DataModel
 * 
 * @param suspend true to suspend dirty event propogation or false to
 *   allow dirty event propogation.
 */
FormDirtyProtocol.prototype.suspendDirtyEvents = function(suspend)
{
	this.m_suspend = suspend;
}
//==================================================================
//
// HelpProtocol.js
//
// Class which provides the members required by a GUIAdaptor for it
// to support help. It is up to the framework how this help is
// rendered. A default implementation of this protocol for HTML is
// provided (see HelpProtocolHTMLImpl.js) which by shows the help
// as popup help. Additionally the FormController displays the
// help text in the status bar when the field has focus.
//
//==================================================================


/*
 * HelpProtocol constructor
 *
 * @constructor
 */
function HelpProtocol()
{
}


/**
 * Configuration property that contains the help text for the
 * GUI Element.
 *
 * @type String
 * @configuration
 */
HelpProtocol.prototype.helpText = null; 


HelpProtocol.prototype.getHelpText = function()
{
	return this.helpText;
}


/**
 * Initialisation method for Help protocol
 *
 * @param cs the configuration objects to apply to the GUIAdaptor
 * @type void
 */
HelpProtocol.prototype.configHelpProtocol = function(cs)
{
	for(var i = 0, l = cs.length; i < l ; i++)
	{
		if(null != cs[i].helpText)
		{
			// If there is specific help text then just set this
			// Adaptors helpText configuration to it - there is no
			// chaining
			this.helpText = cs[i].helpText;
			this.bindHelp();
			break;
		}
	}
}


HelpProtocol.prototype.disposeHelpProtocol = function()
{
    if(this.helpText != null)
    {
        if(this.unbindHelp != null)
        {
            // Remove help
            this.unbindHelp();
        }
    }
}

/**
 * Setup help on the adaptor. This must be implemented
 * by the adaptor, which knows how to add help to itself.
 *
 * @return void
 * @type void
 */
HelpProtocol.prototype.bindHelp = undefined;

/**
 * Remove help on the adaptor. This must be implemented by the
 * adaptor, which knows how to remove help itself.
 *
 * @return void
 * @type void
*/

HelpProtocol.prototype.unbindHelp = undefined;
//==================================================================
//
// InitialiseProtocol.js
//
// Class which provides the members required by a GUIAdaptor for it
// to support an configurable initialisation method.
//
// The FormController calls invokeInitialise after it has performed
// all initialisation activities that it needs to do (including
// creation, configuration and initialisation of all the adaptors
// on the form), but before the user can interact with the form.
//
//==================================================================


/*
 * InitialiseProtocol constructor
 *
 * @constructor
 */
function InitialiseProtocol()
{
}


/**
 * Configuration function which allows the GUI Element to perform
 * some custom initialisation.
 *
 * @type Function(): void
 * @configuration
 */
InitialiseProtocol.prototype.initialise = null;


/**
 * The default value for the GUI Element
 */
InitialiseProtocol.prototype.m_defaultValue = null;


InitialiseProtocol.prototype.hasInitialise = function()
{
	return this.hasConfiguredProperty("initialise");
}


/**
 * Invoke the initialise method(s) of the GUI Element
 *
 * @return the name of the GUI Element.
 * @type String
 */
InitialiseProtocol.prototype.invokeInitialise = function()
{
	// Invoke all configurations, with least specific first
	var cs = this.getConfigs();
	
	for(var i = cs.length - 1; i >= 0; i--)
	{
		if(null != cs[i].initialise) 
		{
			var dV = cs[i].initialise.call(this);
			if(null != dV)
			{
				this.m_defaultValue = dV;
			}
		}
	}
}


/**
 * Initialisation method for Initialise protocol
 *
 * @param cs the configuration objects to apply to the GUIAdaptor
 * @type void
 */
InitialiseProtocol.prototype.configInitialiseProtocol = function(cs)
{
}


InitialiseProtocol.prototype.disposeInitialiseProtocol = function()
{
}
//==================================================================
//
// KeybindingProtocol.js
//
// Class which provides the members required by a GUIAdaptor for it
// to support keybindings.
//
//==================================================================


/*
 * KeybindingProtocol constructor
 *
 * @constructor
 */
function KeybindingProtocol()
{
}


/**
 * The key bindings for this GUIAdaptor
 */
KeybindingProtocol.prototype.m_keys = null;


/**
 * Configuration property for GUI Element for it to support key
 * bindings. The property is an array of objects containing the
 * properties key of type Key and callback of type Function.
 *
 * e.g.
 *  [
 *    {key: Key.F5, callback: function() { alert("F5"); }},
 *    {key: Key.F6, callback: my_function}
 *  ];
 *
 * @type Array[Object{key, callback}]
 * @configuration
 */
KeybindingProtocol.prototype.keyBindings = null;


/**
 * Initialisation method for Keybinding protocol
 *
 * @param cs the configuration objects to apply to the GUIAdaptor
 * @type void
 */
KeybindingProtocol.prototype.configKeybindingProtocol = function(cs)
{
	// Array containing combined key bindings
	var kbs = [];
	for(var i = 0, l = cs.length; i < l ; i++)
	{
		var c = cs[i];		     // Current configuration object
		var ckbs = c.keyBindings; // Current configuration key bindings
		
		if(null != ckbs)
		{
			// Join the keybinding arrays
			kbs = kbs.concat(ckbs);
		}
	}
	
	// Configure specified keys
	
	// Enhancement 366. Allow key binding protocol to
	// support key qualifiers (i.e. Ctrl, Alt and Shift).
	
	var kb = null;
	var qualifiers = null;
	var propagate;
	
	for(var i = 0, l = kbs.length; i < l; i++)
	{
		kb = kbs[i];
		
		if(kb.ctrl == true ||
		   kb.alt == true ||
		   kb.shift == true)
		{
		    // Key binding includes qualifier
		    qualifiers = new Object();
		    
		    qualifiers.ctrl = kb.ctrl;
		    qualifiers.alt = kb.alt;
		    qualifiers.shift = kb.shift;
		}
		
		propagate = (kb.propagate == true) ? true : false;
		
		this.bindKey(kb.key, kb.action, qualifiers, propagate);
		
		if(null != qualifiers)
		{
		    qualifiers = null;
		}
		
	} // End of loop
}


KeybindingProtocol.prototype.disposeKeybindingProtocol = function()
{
	if(null != this.m_keys) this.m_keys.dispose();
}


/**
 * Bind the key to the form element.
 *
 * @param k the key to be bound
 * @param a the action to called when the key is pressed.
 * @param q the key binding qualifiers (Ctrl, Alt and Shift).
 * @param p the flag that determines whether or not to propagate the event
 * @return void
 * @type void
 */
KeybindingProtocol.prototype.bindKey = function(k, a, q, p)
{
	var keys = this.getKeyBindings();
	
	keys.bindKey(k, a, q, p);
}


/**
 * Get the key bindings object. This is really a bit of a hack - key event
 * binding should really take place in the view object which doesn't currently
 * exist. The method is used internally by the EventBinding object which 
 * also binds to key events.
 *
 * @return the ElementKeyBindings object which binds keys to HTML Elements
 * @type ElementKeyBindings
 * @private
 * @todo This binding really needs to be abstracted out into the view
 */
KeybindingProtocol.prototype.getKeyBindings = function()
{
	if(null == this.m_keys) this.m_keys = new ElementKeyBindings(this);
	return this.m_keys;
}
