/**
 * This is a utility class for which contains utility methods which
 * relate to HTML documents.
 *
 * @constructor
 * @private
 */
function HTMLView()
{
}


/**
 * Logging category for HTMLView
 * 
 * @private
 */
HTMLView.m_logger = new Category("HTMLView");


/**
 * Public variable that identifies if this is Internet Explorer or not
 */
HTMLView.isIE = (document.attachEvent != null);


HTMLView.preventBubblingHandler = function()
{
	return false;
}


/**
 * Add event handlers that prevent context menu, help and default
 * key bindings on the supplied document.
 *
 * @param d the HTML document to add the event handlers to
 */
HTMLView.blockEventsForDocument = function(d)
{
	d.onhelp = HTMLView.preventBubblingHandler;
	d.oncontextmenu = HTMLView.preventBubblingHandler;
	
	if (HTMLView.isIE)
	{
		d.onkeydown = HTMLView._blockEvents;
	}
	else
	{
		// Mozilla - onkeydown doesn't prevent default for all keys
		d.onkeypress = HTMLView._blockEvents;
	}
}


/**
 * Remove event handlers from the supplied document that prevent
 * context menu, help and default key bindings
 *
 * @param d the HTML document to remove the event handlers from
 */
HTMLView.unblockEventsForDocument = function(d)
{
	d.onhelp = null;
	d.oncontextmenu = null;

	if (HTMLView.isIE)
	{
		d.onkeydown = null;
	}
	else
	{
		d.onkeypress = null;
	}
}


/**
 * Add event handlers that prevent default actions for the progress bar
 *
 * @param e the HTML element to add the event handlers to
 */
HTMLView.blockEventsForProgress = function(e)
{
	e.onhelp = HTMLView.preventBubblingHandler;
	e.oncontextmenu = HTMLView.preventBubblingHandler;
	e.onclick = HTMLView.preventBubblingHandler;
	
	if (HTMLView.isIE)
	{
		e.onkeydown = HTMLView._blockProgressEvents;
	}
	else
	{
		// Mozilla - onkeydown doesn't prevent default for all keys
		e.onkeypress = HTMLView._blockProgressEvents;
	}
}


/**
 * Remove event handlers that prevent default actions for the progress bar
 *
 * @param e the HTML element to remove the event handlers from
 */
HTMLView.unblockEventsForProgress = function(e)
{
	e.onclick = null;

	HTMLView.unblockEventsForDocument(e);
}


HTMLView._blockProgressEvents = function(evt)
{
	if (null == evt) {evt = window.event; } 

	if (null != evt)
	{
		SUPSEvent.stopPropagation(evt);
		SUPSEvent.preventDefault(evt);

		if (HTMLView.isIE && !evt.altKey) {
			// If IE and not Alt-key combination, reset key code otherwise
			// default action is not cancelled by IE
			try
			{
				evt.keyCode = 0;
			}
			catch(e)
			{
			}
		}
	}

	return false;
}


/**
 * Check for unfreed event handlers in the view which can cause memory leaks.
 * Should only be used while debugging/testing. 
 */
HTMLView.checkForEventHandlers = function()
{
	var events = [
		"onabort",
		"onblur",
		"onchange",
		"oncontextmenu",
		"onclick",
		"ondblclick",
		"onerror",
		"onfocus",
		"onkeydown",
		"onkeyup",
		"onkeypress",
		"onload",
		"onmousedown",
		"onmousemove",
		"onmouseout",
		"onmouseover",
		"onmouseenter",
		"onmouseleave",
		"onreset",
		"onresize",
		"onselect",
		"onselectstart",
		"onselectend",
		"onscroll",
		"onsubmit",
		"onunload"
	];

	var unfreedHandlers = new Array();	
	
	HTMLView._checkElementsForEventHandlers(document.documentElement, events, unfreedHandlers);
	
	
	if(unfreedHandlers.length > 0)
	{
		var msg = "Unfreed event handlers detected:\n";
	
		for(var i = 0, l = unfreedHandlers.length; i < l ; i++)
		{
			var unfreedHandler = unfreedHandlers[i];
			var element = unfreedHandler.element;
			var event = unfreedHandler.event;
			msg +=
				"Unfreed handler: '" + event +
				"' on element (nodeName: '" + element.nodeName + "' id: '" + element.id + "' class: '" + element.className + "')\n";
		}
		
		alert(msg);
	}
}


/**
 * Check an HTML element and its children for unfreed model 0 event handlers.
 *
 * @param e the element to check
 * @param events array containing the events to check for
 * @param array of objects which will be populated with the 
 */
HTMLView._checkElementsForEventHandlers = function(e, events, unfreedHandlers)
{
	// Check element e for unfreed event handlers
	HTMLView._checkElementForEventHandlers(e, events, unfreedHandlers);
	
	// Check all elements e's children for unfreed event handlers.
	for(var i = 0, l = e.childNodes.length; i < l; i++)
	{
		HTMLView._checkElementsForEventHandlers(e.childNodes[i], events, unfreedHandlers);
	}
}


HTMLView._checkElementForEventHandlers = function(e, events, unfreedHandlers)
{
	for(var i = 0, l = events.length; i < l; i++)
	{
		var event = events[i];
		if(HTMLView.m_logger.isDebug()) HTMLView.m_logger.debug("Checking for event handler: " + event + " value is: " +e[event]);
		if(e[event] != null)
		{
			if(HTMLView.m_logger.isWarn()) HTMLView.m_logger.warn("Unfreed " + event + " event handler detected");
			unfreedHandlers.push({element: e, event: event});
		}
	}
}


HTMLView._blockEvents = function(evt)
{   
	if (null == evt) { evt = window.event; } 

	if (null != evt)
	{
	    // Defect 1000.
	    // First determine whether, or not, application progress bar is visible.
	    // Even though the progress bar is visible if an HTML component on the underlying
	    // document has focus key press events will be routed to this handler method.
	    // In such cases the the key press default action must be stopped.
	    
	    // Defect 1059. As Familyman use the tab key to initiate service calls
	    // we need to be more careful. If a key handler fires with the propagate
	    // property set to "true" the key handler will check the visibility state
	    // of the progress bar and set an expando property on the document. If
	    // this property exists and is set to "false" the key press should not be
	    // blocked.
	    var cancelKeyPress = false;
	    
	    var doc = window.document;
	    
	    if(null == doc.framework_expando_progressBarVisible)
	    {
	        // Key action cancellation depends on current state of progress bar
	    
	        var ac = Services.getAppController();
	    
	        if(null != ac)
	        {
	            if(ac.isProgressBarVisible())
	            {
	                cancelKeyPress = true;
	            }
	        }
	        
	    }
	    else
	    {
	        // Key action cancellation depends on state of progress bar
	        // before key binding function executed
	        if(doc.framework_expando_progressBarVisible != false)
	        {
	            cancelKeyPress = true;
	        }
	        
	        // Clean up expando property
	        doc.framework_expando_progressBarVisible = null;
	    }
	    
	    if(cancelKeyPress)
	    {
	        // Cancel key press
	        return HTMLView._cancelKeyPress(evt);
	    }
	    else
	    {
		    // If Alt key is pressed in W3C use 'keyCode' property otherwise 'which'
		    var keyCode = (HTMLView.isIE || evt.altKey) ? evt.keyCode : evt.which;
		
		    if (HTMLView.m_logger.isDebug()) HTMLView.m_logger.debug("Key pressed: " + String.fromCharCode(keyCode) + " Key code: " + keyCode + " Ctrl key: " + evt.ctrlKey + " Alt key: " + evt.altKey + " Shift key: " + evt.shiftKey);

		    var target = SUPSEvent.getTargetElement(evt);

		    if (
			    // Prevent backspace key performing the browser "back" functionality if the target element does not absorb the backspace key
			    (keyCode == Key.Backspace.m_keyCode && !HTMLView._canAcceptBackspaceKeyEvents(target)) ||
			    // Prevent actions bound to function keys from propagating (NB: 'keyCode' property used for function keys in Mozilla)
			    HTMLView._isFunctionKey(evt.keyCode) ||
			    // Prevent Escape key presses
			    Key.ESC.m_keyCode == keyCode ||
			    // Only allow a subset of Ctrl key combinations to perform the default browser functionality
			    evt.ctrlKey && !(Key.CHAR_X.m_keyCode == keyCode || Key.CHAR_x.m_keyCode == keyCode ||
				  			     Key.CHAR_C.m_keyCode == keyCode || Key.CHAR_c.m_keyCode == keyCode ||
							     Key.CHAR_V.m_keyCode == keyCode || Key.CHAR_v.m_keyCode == keyCode ||
							     Key.CHAR_A.m_keyCode == keyCode || Key.CHAR_a.m_keyCode == keyCode ||
							     Key.CHAR_Z.m_keyCode == keyCode || Key.CHAR_z.m_keyCode == keyCode ||
							     Key.CHAR_Y.m_keyCode == keyCode || Key.CHAR_y.m_keyCode == keyCode ||							 
							     Key.Home.m_keyCode == keyCode ||
							     Key.End.m_keyCode == keyCode) ||
			    // Prevent actions bound to Alt key (if possible, Alt+Home for example still works in IE)
			    evt.altKey)
		    {
			    if (HTMLView.m_logger.isDebug()) HTMLView.m_logger.debug("Cancelling key: " + keyCode + " Ctrl key: " + evt.ctrlKey + " Alt key: " + evt.altKey + " Shift key: " + evt.shiftKey);

			    return HTMLView._cancelKeyPress(evt);
		    }
		    
	    } // End of (cancelKeyPress) if block
	    
	} // End of (null != evt) if block

	return true;
}




/**
 * Returns true if the supplied element should allow the backspace key. 
 * Elements that can accept backspace keys are textareas that are not
 * readonly and text/password fields that are not readonly.
 *
 * @param e the element to test
 * @return true if the element should allow the backspace key, or false
 *   otherwise
 * @type boolean
 */
HTMLView._canAcceptBackspaceKeyEvents = function(e)
{
	return ((e.nodeName == "TEXTAREA" && !e.readOnly) || (e.nodeName == "INPUT" && (e.type=="text" || e.type=="password") && !e.readOnly));
}


/**
 * Returns true if the supplied keyCode is a function key or false
 * otherwise.
 *
 * @param keyCode the keyCode to check
 * @return true if the keycode represents a function key or false otherwise
 */
HTMLView._isFunctionKey = function(keyCode)
{
	return (keyCode >= Key.F1.m_keyCode && keyCode <= Key.F12.m_keyCode) ? true: false;
}

/**
 * Method performs actions to cancel a key press.
 *
 * @param evt The event associated with a key press.
 *
*/
HTMLView._cancelKeyPress = function(evt)
{
    SUPSEvent.stopPropagation(evt);
	SUPSEvent.preventDefault(evt);

	if (HTMLView.isIE && !evt.altKey)
	{
	    // If IE and not Alt-key combination, reset key code otherwise
	    // default action is not cancelled by IE
		try
		{
		    evt.keyCode = 0;
		}
		catch(e)
		{
		}
	}

	return false;
}
//==================================================================
//
// EventBinding.js
//
//
//==================================================================


/**
 * EventBinding constructor
 *
 * @constructor
 */
function EventBinding(id) 
{
    this.m_id = id;
};

EventBinding.m_logger = new Category("EventBinding");

/**
 * Create array to store list of associated prototocols.
 * In this case this should contain the enablement
 * prototocol only.
 *
*/
EventBinding.prototype.m_protocols = new Array();

// Set up enablement protocol
GUIAdaptor._setUpProtocols('EventBinding');
GUIAdaptor._addProtocol('EventBinding', 'EnablementProtocol');


/**
 * List of ids of adaptors that have key bindings to trigger this event
 *
 * @type Array[String]
 */
EventBinding.prototype.m_keyAdaptors = null;


/**
 * List of ids of adaptors that have single click bindings to trigger this event
 *
 * @type Array[String]
 */
EventBinding.prototype.m_singleClickAdaptors = null;


/**
 * List of ids of adaptors that have double click bindings to trigger this event
 *
 * @type Array[String]
 */
EventBinding.prototype.m_doubleClickAdaptors = null;


/**
 * Flag to indicate whether event bindings have been started or not
 *
 * @type Boolean
 */
EventBinding.prototype.m_started = false;


/**
 * Configuration for the EventBinding. This is an Object with properties as
 * described by EventConfiguration.js
 *
 * @type Object(EventConfiguration)
 */
EventBinding.prototype.m_config = null;

/**
 * Reference to inner function that invokes method _handleEvent.
 * The inner function may be passed to a grid for callback following
 * double clicks.
 *
 * @type Function
 *
*/
EventBinding.prototype.m_eventHandler = null;

/**
 * Method returns identifier for event binding
 *
*/
EventBinding.prototype.getId = function()
{
    return this.m_id;
}

/**
 * Method getConfigs returns the event binding
 * configuration object as the first element
 * in an array.
 *
*/
EventBinding.prototype.getConfigs = function()
{
    var cs = new Array();
    
    if(null != this.m_config)
    {
        cs[cs.length] = this.m_config;
    }
    
    return cs;
}

/**
 * Method configures EventBinding instance setting up
 * any required adaptors.
 *
 * @param config The object describing the bindings
*/
EventBinding.prototype.configure = function(config)
{
    this.m_config = config;
    
    // Configure associated protocols
    var protocolName;
    
    var cs = this.getConfigs();
    
    for( var i = 0, l = this.m_protocols.length; i < l; i++ )
    {
        protocolName = this.m_protocols[i];
        
        if(EventBinding.m_logger.isTrace())
        {
            EventBinding.m_logger.trace( "Configuring protocol " +
                                         i +
                                         ": " +
                                         protocolName +
                                         " for event binding." );
        }
        
        this[ 'config' + protocolName ].call(this, cs);
    }
}

/**
 * Bind events as described by an object which has properties as
 * defined by an EventConfiguration object
 *
 * @param callback the client function to invoke when the event
 *    is triggered
 */
EventBinding.prototype.bind = function(callback)
{
    var config = this.m_config;
    
	this.m_keyAdaptors = this._locateAdaptors(config.keys);
	this.m_singleClickAdaptors = this._locateAdaptors(config.singleClicks);
	this.m_doubleClickAdaptors = this._locateAdaptors(config.doubleClicks);
	
	this.m_callback = callback;
	this.m_started = false;
}



EventBinding.prototype.dispose = function()
{
    // Remove event binding event handlers
	this.stop();
	
	// Dispose of any associated protocols
	var protocolName;
	
	var cs = this.getConfigs();
	
	for( var i = 0, l = this.m_protocols.length; i < l; i++ )
	{
	    protocolName = this.m_protocols[i];
	    
	    if(EventBinding.m_logger.isTrace())
        {
            EventBinding.m_logger.trace( "Disposing protocol " +
                                         i +
                                         ": " +
                                         protocolName +
                                         " for event binding." );
        }
        
        this[ 'dispose' + protocolName ].call(this, cs);
    }
	
}


EventBinding.prototype.start = function()
{
	fc_assert(this.m_callback, "Must bind EventBinding");

	var fc = FormController.getInstance();

	// Make start() idempotent
	if(false == this.m_started)
	{
		this.m_started = true;
		
		var thisObj = this;
		this.m_eventHandler = function() { return thisObj._handleEvent() };
		
		// Start all the key listeners		
		var iBindingPos = 0;
		this.m_keyBindings = new Array();
		var keys = this.m_config.keys;
		if(null != keys)
		{
			var qualifiers = null;
			var propagate;
			for(var i = 0, l = keys.length ; i <  l ; i++)
			{
				var key = keys[i];
				var adaptor = fc.getAdaptorById(key.element);
				if(adaptor.supportsProtocol("KeybindingProtocol"))
				{
					this.m_keyBindings[i] = new ElementKeyBindings(this.m_keyAdaptors[i]);
					
					if(key.ctrl == true || key.alt == true || key.shift == true)
					{
						qualifiers = new Object();
						qualifiers.ctrl = key.ctrl;
						qualifiers.alt = key.alt;
						qualifiers.shift = key.shift;
					}

					propagate = (key.propagate == true) ? true : false;
							
					this.m_keyBindings[i].bindKey(keys[i].key, this.m_eventHandler, qualifiers, propagate);
					
					// Copy the key binding object to the adaptor that handles the key press
					// This enables the adaptor to detect that a key has been bound via event binding
					if(adaptor.m_keys != null)
					{
						// Keys already bound to adaptor
						var keyCodeString = '' + keys[i].key.m_keyCode;
						keyCodeString += ElementKeyBindings.getQualifiersSuffix(key);
						
						if(null == adaptor.m_keys.m_keys[keyCodeString])
						{
							// Only bind key if not already bound					
							adaptor.bindKey(keys[i].key, this.m_eventHandler, qualifiers, propagate);
						}
					}
					else
					{
						// No keys bound, so we can just copy the object
						adaptor.m_keys = this.m_keyBindings[i];
					}
					
					if(null != qualifiers) qualifiers = null;
				}
				else
				{
					if(EventBinding.m_logger.isError()) EventBinding.m_logger.error("Adaptor does not support keybinding: " + adaptor.getId());
				}
			}
		}
	
		// Start all the single click listeners
		this.m_SClickBindings = new Array();
		for(var i = 0 ; i < this.m_singleClickAdaptors.length ; i++)
		{
			this.m_SClickBindings[i] = SUPSEvent.addEventHandler(this.m_singleClickAdaptors[i].getElement(), 'click', this.m_eventHandler);
		}
	
		// Start all the double click listeners
		this.m_DClickBindings = new Array();
		for(var i = 0; i < this.m_doubleClickAdaptors.length ; i++)
		{
		    if(!GridGUIAdaptor.isGridAdaptor(this.m_doubleClickAdaptors[i]))
		    {
			    this.m_DClickBindings[iBindingPos] = SUPSEvent.addEventHandler(this.m_doubleClickAdaptors[i].getElement(), 'dblclick', this.m_eventHandler);
			    
			    iBindingPos++;
			}
			else
			{
			    // Instance of grid adaptor
			    this.m_doubleClickAdaptors[i].addDblclickListener(this.m_eventHandler);
			}
		}	
	}
}


EventBinding.prototype.stop = function()
{
	// Make stop() idempotent
	if(true == this.m_started)
	{
		this.m_started = false;
		var iBindingPos = 0;
		
		// Stop all the key listeners
		for(var i = 0, l = this.m_keyBindings.length; i < l; i++)
		{
			this.m_keyBindings[i].dispose();		
		}
	
		// Stop all the single click listeners
		for(var i = 0, l = this.m_SClickBindings.length; i < l; i++)
		{
			SUPSEvent.removeEventHandlerKey(this.m_SClickBindings[i]);
			this.m_SClickBindings[i] = null;
		}
	
		for(var i = 0, l = this.m_doubleClickAdaptors.length; i < l; i++)
		{
		    if(!GridGUIAdaptor.isGridAdaptor(this.m_doubleClickAdaptors[i]))
		    {
			    SUPSEvent.removeEventHandlerKey(this.m_DClickBindings[iBindingPos]);
			    this.m_DClickBindings[iBindingPos] = null;
			    
			    iBindingPos++;
			}
			else
			{
			    // Instance of grid adaptor
			    this.m_doubleClickAdaptors[i].removeDblclickListener(this.m_eventHandler);
			}
		}
		
		// Clear reference to inner function
		this.m_eventHandler = null;
	}
}


EventBinding.prototype._locateAdaptors = function(bindings)
{
	var fc = FormController.getInstance();
	var targetAdaptors = new Array();
	if(bindings != null) 
	{
		// The following line does not work across frames probably because it compares
		// the reference to the constructor function
		//if(bindings.constructor != Array)
		if(bindings.length == null)
		{	
			throw new ConfigurationException("EventBinding properties must be arrays");
		}
	
		for(var i = 0, l = bindings.length ; i < l ; i++)
		{
			// TODO: May be able to replace this with associate array lookup
			targetAdaptors[i] = fc.getAdaptorById(bindings[i].element);
			if(null == targetAdaptors[i])
			{	
				throw new ConfigurationException("Invalid element ID in EventBinding binding: " + bindings[i].element);
			}
		}
	}
	return targetAdaptors;
}


EventBinding.prototype.getSources = function()
{
	fc_assert(this.m_callback, "Must bind EventBinding");
	// Concatenate the event generatation arrays
	if(null == this.m_sources)
	{
		this.m_sources = new Array();
		var all = this.m_keyAdaptors.concat(this.m_singleClickAdaptors.concat(this.m_doubleClickAdaptors));
	 	
	 	// Remove duplicates
	 	all.sort(function(a, b) { return String.strcmp(a.m_element.id, b.m_element.id); });

	 	var last = null;
	 	while(all.length > 0)
	 	{
	 		var candidate = all.pop();
	 		if(last != candidate.m_element.id)
	 		{
	 			last = candidate.m_element.id;
	 			this.m_sources.push(candidate);	
	 		}
	 	}
	 }

	// Return array
	return this.m_sources;
}

/**
 * Method handles event generated for event binding
 *
*/
EventBinding.prototype._handleEvent = function()
{
    if(this.getEnabled() == true)
    {
        this.m_callback.call();
    }
}

/**
 * Method returns listeners associated with event binding.
 *
*/
EventBinding.prototype.getListeners = function()
{
    var listenersForProtocol;
    
    var index = 0;
    var allListeners = new Array();
    
    for( var i = 0, l1 = this.m_listeningProtocols.length; i < l1; i++ )
    {
        listenersForProtocol = this[ 'getListenersFor' + this.m_listeningProtocols[i] ].call(this);
        
        for( var j = 0, l2 = listenersForProtocol.length; j < l2; j++)
        {
            allListeners[index] = listenersForProtocol[j];
            index++;
        }
        
        listenersForProtocol = null;
        
    }
    
    return allListeners;
}

/**
 * Method initialises prototcols implemented by EventBinding.
 *
*/
EventBinding.prototype.initialiseStates = function(e)
{
    Services.startTransaction();
    
    for( var i = 0, l = this.m_initialiseList.length; i < l; i++ )
    {
        this[ this.m_initialiseList[i] ].call( this, e );
    }
    
    Services.endTransaction();
}

EventBinding.prototype.hasConfiguredProperty = function(propName)
{
	var ret = false;
	var cs = this.getConfigs();
	for(var i = 0, l = cs.length; i < l ; i++)
	{
		if(null != cs[i][propName])
		{
			ret = true;
			break;
		}
	}
	
	return ret;

}

/**
 * This method is a dummy stub for the state change protocol method
 * "changeAdaptorState". The event binding class does not implement
 * the state change protocol although methods of this prototcol
 * are invoked by the enablement protocol. As the event binding
 * will never be submitted it does not need the submissibility
 * functionality.
 *
*/
EventBinding.prototype.changeAdaptorState = function(event)
{
    // Do nothing
}

/**
 * This method is a dummy stub for the "renderState" method implemented
 * by all adaptors. The event binding class is not a true adaptor
 * and does not need to be redrawn when the enablement state changes.
 *
*/
EventBinding.prototype.renderState = function()
{
    // Do nothing
}
//==================================================================
//
// HTMLElement.js
//
// Implement some of the IE HTMLElement APIs on other browsers
//
//==================================================================


// If this browser isn't IE then implement IE's proprietry contains()
// method as it's rather useful.
if(window.addEventListener != null)
{
	HTMLElement.prototype.contains = function (oEl)
	{
		if (oEl == this) return true;
		if (oEl == null) return false;
		return this.contains(oEl.parentNode);
	};
	
	HTMLElement.prototype.__defineGetter__(
		"innerText",
		function()
		{
			HTMLElement.getInnerText(this);
		}
	);

	HTMLElement.prototype.__defineSetter__(
		"innerText",
		function (sText)
		{
   			this.innerHTML = sText.replace(/\&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
		}
	);
	
	
	HTMLElement.getInnerText = function(e)
	{
		var result = "";
		var kids = e.childNodes;
		for(var i = 0, l = kids.length; i < l; i++)
		{
			var kid = kids[i];
			
			switch (kid.nodeType)
			{
				case 1:		// Element
				{
					// Replace <br> elements with \n
					if("BR" == kid.nodeName)
					{
						result += "\n";
					}
					break;
				}
				
				case 3:		// TextNode
				{
					// Append text content to result
					result += kid.nodeValue;
				}
			}
		}
		
		return result;
	}
}//==================================================================
//
// StyleManager.js
//
// Class which manages stylesheets in documents controlled by the
// Framework
//
//==================================================================


/**
 * StyleManager constructor
 *
 * @constructor
 */
function StyleManager()
{
}

StyleManager.m_logger = new Category("StyleManager");
StyleManager.FRAMEWORK_STYLESHEET_TITLE = "Default";
StyleManager.FRAMEWORK_STYLESHEET_ID = "FW_StyleSheet";


StyleManager.prototype.m_config = null;

StyleManager.prototype.m_currentStyle = "default";

StyleManager.prototype.m_documents = null;


/**
 * For IE scrollbars must register functions with style manager
 * that are invoked once the associated stylesheet has loaded.
*/
StyleManager.prototype.m_onLoadCallbackLists = null;


StyleManager.prototype.setConfiguration = function(config)
{
	this.m_config = config;
	
	this.m_currentStyle = config.getDefaultStyleSheetName();
	
	this.m_documents = new Array();
	
	this.m_onLoadCallbackLists = [];
}


StyleManager.prototype.dispose = function()
{
	// Dispose of all the callback lists.
	for(var i = 0; i < this.m_onLoadCallbackLists.length; i++)
	{
		var callBackListEntry = this.m_onLoadCallbackLists[i];
		callBackListEntry.document = null;
		callBackListEntry.callbackList.dispose();
		callBackListEntry.callbackList = null;
	}
    this.m_onLoadCallbackLists = null;


	// Dispose of all documents
	for(var i = 0; i < this.m_documents.length; i++)
	{
		this.m_documents[i].dispose();
	}
    this.m_documents = null;
}


StyleManager.prototype.registerOnLoadHandler = function(callbackListMethod, doc)
{
	// Check to see if there is a callback for the supplied document already
	var cbListEntry = null;
	for(var i = 0, l = this.m_onLoadCallbackLists.length; i < l; i++)
	{
		var cble = this.m_onLoadCallbackLists[i];
		
		if(cble.document == doc)
		{
			cbListEntry = cble;
			break;
		}
	}
	
	// If not then create a new entry for the document in the list of callbacks
	if(null == cbListEntry)
	{
		var cbListEntry = {
			document: doc,
			callbackList: new CallbackList()
		};
		
		this.m_onLoadCallbackLists.push(cbListEntry);
	}

	// Add a callback to list for the specified document
    cbListEntry.callbackList.addCallback(callbackListMethod);
}


StyleManager.prototype.unregisterOnLoadHandler = function(callbackListMethod, doc)
{
	// Check to see if there is a callback for the supplied document already
	var cbListEntry = null;
	for(var i = 0, l = this.m_onLoadCallbackLists.length; i < l; i++)
	{
		var cble = this.m_onLoadCallbackLists[i];
		
		if(cble.document == doc)
		{
			cbListEntry = cble;
			break;
		}
	}

	// If entry found for the specified document then remove the callback from the list	
	if(null != cbListEntry)
	{
		cbListEntry.callbackList.removeCallback(callbackListMethod);
	}
}


StyleManager.prototype._handleCSSLoaded = function(docEntry)
{
	var doc = docEntry.m_document;

	// Check to see if there is a callback for the supplied document
	for(var i = 0, l = this.m_onLoadCallbackLists.length; i < l; i++)
	{
		var cble = this.m_onLoadCallbackLists[i];
		
		if(cble.document == doc)
		{
			// Document found, so notify listeners interested in
			// hearing about stylesheet changes to this document.
			cble.callbackList.invoke();
			break;
		}
	}
}

	
StyleManager.prototype.setStyle = function(name)
{
	// If no name specified use "default"
	if(name == null)
	{
		name = "default";
	}
	
	var found = true;
	if(this.m_currentStyle != name)
	{
		this.m_currentStyle = name;
		
		found = false;
		var availableStyles = this.getAvailableStyles();
		for(var i = 0, l = availableStyles.length; i < l; i++)
		{
			if(availableStyles[i].getName() == name)
			{
				found = true;
				break;
			}
		}
		
		if(found)
		{
			for(var i = 0, l = this.m_documents.length; i < l; i++)
			{
				this.m_documents[i].applyStyleSheets(this.m_currentStyle);
			}
		}
	}
	
	return found;
}


StyleManager.prototype.getCurrentStyle = function()
{
	return this.m_currentStyle;
}


StyleManager.prototype.getAvailableStyles = function()
{
	return this.m_config.getAvailableStyleSheets();
}


StyleManager.prototype.registerDocument = function(doc, styleSheets)
{
	var docEntry = this.getDocumentEntry(doc);
	
	if(null != docEntry)
	{
		// Already in list
		if(StyleManager.m_logger.isWarn()) StyleManager.m_logger.warn("StyleManager.registerDocument(): Adding duplicate document with url: " + doc.URL);
	}
	else
	{
		if(StyleManager.m_logger.isDebug()) StyleManager.m_logger.debug("StyleManager.registerDocument(): Adding document with url: " + doc.URL);
		
		// Create a new StyleManagerDocEntry to maintain information about the document
		// and the stylesheets loaded on it.
		
		// Add the framework stylesheet to the list of stylesheets applied to a document
		var ac = Services.getAppController();
		var rootURL = ac.m_config.m_appBaseURL;
		
		var ss = [AppCSS.create(rootURL + "/fw_", true, true)];
		if(null != styleSheets)
		{
			ss = ss.concat(styleSheets);
		}
		var docEntry = new StyleManagerDocEntry(this, doc, ss);

		// Add document to list.
		this.m_documents.push(docEntry);
	
		// Set the current sheet on the newly registered document
		docEntry.applyStyleSheets(this.m_currentStyle);
	}

	if(StyleManager.m_logger.isDebug())
	{
		this._logRegisteredDocuments();
	}
}


StyleManager.prototype.unregisterDocument = function(doc)
{   
    var isIE = (navigator.appName == "Microsoft Internet Explorer");
    
	var newArray = new Array();
	var count = 0;

	// Can't simply delete an item from an array to remove it,
	// as this leaves the array length unchanged (!). Instead
	// we need to create a new array, and copy all elements from
	// the old array to the new one, ignoring the entry to be
	// ignored.
	for(var i = 0, l = this.m_documents.length; i < l; i++)
	{
		if(this.m_documents[i].m_document != doc)
		{
			newArray[count++] = this.m_documents[i];
		}
		else
		{
			// Dispose of the document when we find it in the list
			this.m_documents[i].dispose();
		}
	}
	
	// Copy the new array over the old one.
	this.m_documents = newArray;

	if(StyleManager.m_logger.isDebug())
	{
		this._logRegisteredDocuments();
	}
}


StyleManager.prototype._logRegisteredDocuments = function()
{
	for(var i = 0, l = this.m_documents.length; i < l; i++)
	{
		var d = this.m_documents[i].m_document;
		StyleManager.m_logger.debug("StyleManager._logRegisteredDocuments(): Have document: " + (i + 1) + " of " + l);
		StyleManager.m_logger.debug("StyleManager._logRegisteredDocuments(): Have registered document with URL: " + null == d.URL ? "null" : d.URL);
	}
}


StyleManager.prototype.getDocumentEntry = function(document)
{
    var docEntry = null;
    
    for(var i = 0, l = this.m_documents.length; i < l; i++)
    {
        if(this.m_documents[i].m_document == document)
        {
            docEntry = this.m_documents[i];
            break;
        }
    }
    
    return docEntry;
}   




/**
 * Class StyleManagerDocEntry enables style sheet on load handlers
 * to be associated with documents managed by the StyleManager.
 *
 * @param manager reference to the StyleManager which created this
 *   StyleManagerDocEntry
 * @param doc the HTMLDocument registered with the StyleManager
 * @param styleSheets array of base URLs to additional stylesheets to be
 *    managed by the StyleManager (those which are colourscheme sensative)
 * @constructor
 */
function StyleManagerDocEntry(manager, doc, cssDefs)
{
	this.m_manager = manager;
	
    this.m_document = doc;
    
    this.m_styleSheets = new Array(cssDefs.length);

	for(var i = 0; i < cssDefs.length; i++)
	{
		var cssDef = cssDefs[i];
		this.m_styleSheets[i] = StyleManagerCSSEntry.create(
			this,
			cssDef.getBaseURL(),
			cssDef.getBrowserDependant(),
			cssDef.getColourSchemeDependant()
		);
	}
}


StyleManagerDocEntry.prototype.dispose = function()
{
	for(var i = 0, l = this.m_styleSheets.length; i < l; i++)
	{
		this.m_styleSheets[i].dispose();
	}
}


StyleManagerDocEntry.prototype.handleStyleSheetLoaded = function(cssEntry)
{
	var allLoaded = true;
	
	// Expect at most 2 or 3 stylesheets so this loop
	// isn't too expensive.
	for(var i = 0, l = this.m_styleSheets.length; i < l; i++)
	{
		var ss = this.m_styleSheets[i];
		if(ss == cssEntry)
		{
			ss.loaded = true;
		}
		
		if(true !== ss.loaded)
		{
			allLoaded = false;
		}	
	}
	
	if(allLoaded)
	{
		this.m_manager._handleCSSLoaded(this);
	}
}


StyleManagerDocEntry.prototype.applyStyleSheets = function(colourScheme)
{
	// Reset flag on stylesheet entries to indicate that they
	// are not loaded.
	for(var i = 0, l = this.m_styleSheets.length; i < l; i++)
	{
		var ss = this.m_styleSheets[i];
		ss.loaded = false;
	}
	
	// Start loading each stylesheet in turn
	for(var i = 0, l = this.m_styleSheets.length; i < l; i++)
	{
		var ss = this.m_styleSheets[i];
		ss.applyStyleSheet(colourScheme);
	}
}










function StyleManagerCSSEntry()
{
}


StyleManagerCSSEntry.m_logger = new Category("StyleManagerCSSEntry");

StyleManagerCSSEntry.prototype.m_baseURL = null;

StyleManagerCSSEntry.prototype.m_browserDependant = false;

StyleManagerCSSEntry.prototype.m_colourSchemeDependant = true;

StyleManagerCSSEntry.prototype.m_linkElement = null;

StyleManagerCSSEntry.prototype.m_onLoadHandlerKey = null;


StyleManagerCSSEntry.create = function(docEntry, baseURL, browserDependant, colourSchemeDependant)
{
	var css = new StyleManagerCSSEntry();
	
	css.m_docEntry = docEntry;
	css.m_baseURL = baseURL;
	css.m_browserDependant = browserDependant;
	css.m_colourSchemeDependant = colourSchemeDependant;
	
	return css;
}


StyleManagerCSSEntry.prototype.dispose = function()
{
	if(null != this.m_onLoadHandlerKey)
	{
		SUPSEvent.removeEventHandlerKey(this.m_onLoadHandlerKey);
		this.m_onLoadHandlerKey = null;
	}
}


StyleManagerCSSEntry.prototype._getURL = function(colourScheme)
{
	var styleSheetURL = this.m_baseURL;
	
	if(this.m_browserDependant)
	{
		var isIE = (navigator.appName == "Microsoft Internet Explorer");
		var styleSheetURL = styleSheetURL + (isIE ? "IE" : "Moz");
	}
	
	if(this.m_colourSchemeDependant && colourScheme != null)
	{
		// If no stylesheet name supplied, then default to old stylesheet name for backwards compatibility
		styleSheetURL += ("_" + colourScheme);
	}

	// Complete the stylesheet url
	styleSheetURL += ".css";
	
	return styleSheetURL;
}


StyleManagerCSSEntry.prototype.isColourSchemeDependant = function()
{
	return this.m_colourSchemeDependant;
}


StyleManagerCSSEntry.prototype.applyStyleSheet = function(colourScheme)
{
	var d = this.m_docEntry.m_document;

	var headElement = GUIUtils.getDocumentHeadElement(d);

	var url = this._getURL(colourScheme);

	if(null == this.m_linkElement)
	{
		// Document doesn't contain stylesheet so create the link element to include it
		if(StyleManagerCSSEntry.m_logger.isDebug()) StyleManagerCSSEntry.m_logger.debug("StyleManager.applyStyleSheet(): Creating new stylesheet link for document with URL: '" + d.URL + "' with href: '"  + url + "'");

		this.m_linkElement = GUIUtils.createStyleLinkElement(headElement, url, null);

		// If we are running in IE, then add an onload handler to the link element,
		// so we can notify the StyleManagerDocEntry when all the stylesheet has loaded.
		// On other browsers that don't support onload handlers on link elements,
		// the _handleOnLoadEvent is simply invoked as soon as the link element's
		// src attribute has been set.
		if(HTMLView.isIE)
		{
		    // Add event hanlder to link element
		    var thisObj = this;
		    this.m_onLoadHandlerKey = SUPSEvent.addEventHandler(this.m_linkElement, "load", function() {thisObj._handleOnLoadEvent();} );
		}
	}
	else
	{
		if(StyleManagerCSSEntry.m_logger.isDebug()) StyleManagerCSSEntry.m_logger.debug("StyleManagerCSSEntry.applyStyleSheet(): Updating stylesheet link for document with URL: '" + d.URL + "' with href: '" + url + "'");
		// Document already contains the LINK element to the framework stylesheet, so just update
		// href attribute of the LINK element to load the new stylesheet.
		this.m_linkElement.setAttribute("href", url);
	}

	// Invoke handleOnLoadEvent immediately on none IE browsers,
	// as only IE supports onload handlers 
	if(!HTMLView.isIE)
	{
		this._handleOnLoadEvent();
	}
}


StyleManagerCSSEntry.prototype._handleOnLoadEvent = function()
{
	// Notify the parent StyleManagerDocEntry that loading of the stylesheet has completed.
	this.m_docEntry.handleStyleSheetLoaded(this);
}
/**
 * Exception thrown when a StyleManager error occurs
 *
 * @param message the message to report in the exception
 * @param ex a chained exception
 * @constructor
 */
function StyleManagerError(message, rootCause)
{
	this.message = message;
	this.m_rootCause = rootCause;
	this.exceptionHierarchy = new Array('Error','SystemException','StyleManagerError');
	this.name = 'StyleManagerError';
}


/**
 * StyleManagerError is a sub class of Error
 */
StyleManagerError.prototype = new Error();
StyleManagerError.prototype.constructor = StyleManagerError;


/**
 * Class to handle key events on an HTML Element
 *
 * @param a the GUIAdaptor to add key bindings to
 */
function ElementKeyBindings(a)
{
	// Hang on to the element we are bound too.
	this.m_adaptor = a;
	
	// Map that maps keycodes to action to be called when a key is pressed
	this.m_keys = new Array();

	// Qualifier keys map for keycodes
	this.m_qualifiers = new Array();

	// Stop propagation flag map for keycodes
	this.m_stopPropagation = new Array();
	
	// Add an event handler to the element
	var thisObj = this;
	var evtToHdle = ElementKeyBindings.isIE ? "keydown" : "keypress";
	// Binding element for form is 'BODY' not 'FORM'
	var bindingElement = this.getKeyBindingElement(this.m_adaptor);
	
	this.evtHdle = SUPSEvent.addEventHandler(bindingElement, evtToHdle, function(evt) { thisObj.handleKeyEvent(evt); });
}

ElementKeyBindings.m_logger = new Category("ElementKeyBindings");

// Qualifier keys bit masks
ElementKeyBindings.CTRL_KEY_MASK = 1;
ElementKeyBindings.ALT_KEY_MASK = 2;
ElementKeyBindings.SHIFT_KEY_MASK = 4;

// Qualifier keys string suffixes. Allows the same key to be bound to the same
// adaptor with no/different qualifiers. E.g. F1, Ctrl+F1, Alt+F1 and Shift+F1
ElementKeyBindings.CTRL_KEY_SUFFIX = "_ctrl";
ElementKeyBindings.ALT_KEY_SUFFIX = "_alt";
ElementKeyBindings.SHIFT_KEY_SUFFIX = "_shift";

ElementKeyBindings.prototype.dispose = function() 
{
	if(this.evtHdle != null)
	{
		SUPSEvent.removeEventHandlerKey(this.evtHdle);
		this.evtHdle = null;
	}
	this.m_adaptor = null;
	this.m_keys = null;
	this.m_qualifiers = null;
	this.m_stopPropagation = null;
}

ElementKeyBindings.prototype.handleKeyEvent = function(evt)
{ 
  // If IE then use the global event object.
  if(null == evt) evt = window.event;
  
  // Set return value
  var ret = true;
  
  // Before handling event check that the progress bar is not currently raised.
  var progressBarVisible = false;
  
  var ac = Services.getAppController();
          
  if(null != ac)
  {
      progressBarVisible = ac.isProgressBarVisible();
  }
  
  if(!progressBarVisible)
  {

      // Get the keycode from the event (If function key is pressed in W3C use 'keyCode' property otherwise 'which')
      var kc = (ElementKeyBindings.isIE || Key.isFunctionKey(evt.keyCode)) ? evt.keyCode : evt.which;
      var keyCodeString = '' + kc;
    
      if(ElementKeyBindings.m_logger.isDebug()) ElementKeyBindings.m_logger.debug('Handling key event. Adaptor ID: ' + this.m_adaptor.getId() + ' KeyCode: ' + kc);
 
      // Get the qualifier keys from the event
      var qualifiers = 0;
      if(evt.ctrlKey)
      {
  	      qualifiers |= ElementKeyBindings.CTRL_KEY_MASK;
  	      keyCodeString += ElementKeyBindings.CTRL_KEY_SUFFIX;
      }
      if(evt.altKey)
      {
  	      qualifiers |= ElementKeyBindings.ALT_KEY_MASK;
  	      keyCodeString += ElementKeyBindings.ALT_KEY_SUFFIX;
      }
      if(evt.shiftKey)
      {
  	      qualifiers |= ElementKeyBindings.SHIFT_KEY_MASK;
  	      keyCodeString += ElementKeyBindings.SHIFT_KEY_SUFFIX;
      }

      if(ElementKeyBindings.m_logger.isDebug()) ElementKeyBindings.m_logger.debug("Qualifiers - Ctrl: " + (qualifiers & ElementKeyBindings.CTRL_KEY_MASK) + " Alt: " + (qualifiers & ElementKeyBindings.ALT_KEY_MASK) + " Shift: " + (qualifiers & ElementKeyBindings.SHIFT_KEY_MASK));

      var handled = this._handleKey(kc, qualifiers);
 
      if(handled)
      {
          if(this.m_stopPropagation[keyCodeString])
          {
              // If the event was handled and 'propgate' configuration is false,
              // then stop the event propagating up to its parent elements
              ret = ElementKeyBindings.cancelKeyEvent(evt);
          
          }
          else
          {   
              if(null == window.document.framework_expando_progressBarVisible)
              {
                  window.document.framework_expando_progressBarVisible = progressBarVisible;
              }
          }
          
      }
      else
      {
          if(null == window.document.framework_expando_progressBarVisible)
          {
              window.document.framework_expando_progressBarVisible = progressBarVisible;
          }
      }
  
  }
  else
  {
      // Progress bar visible. Check for document expando property as
      // this may have been set by an event lower down in the event bubbling
      var docExpando = window.document.framework_expando_progressBarVisible;
      
      if(docExpando != false)
      {
          ret = ElementKeyBindings.cancelKeyEvent(evt);
      }
      
  }

  return ret;
}

ElementKeyBindings.determineBrowser = function()
{
    switch(navigator.appName)
    {
	    case "Netscape":
	    {
		    ElementKeyBindings.isIE = false;
		    ElementKeyBindings.isMoz = true;
		    break;
	    }
	    case "Microsoft Internet Explorer":
	    {
		    ElementKeyBindings.isIE = true;
		    ElementKeyBindings.isMoz = false;
		    break;
	    }
	    default:
	    {
		    alert("Unknown browser type");
		    break;
	    }
    }
    return null;
}

ElementKeyBindings.forceDetermineBrowser = ElementKeyBindings.determineBrowser();

/**
 * Bind a key to this html element
 *
 * @param key the key to bind to this element
 * @param action the function to call when the key is pressed on this element
 * @param qualifiers key qualifiers pressed
 * @param propagate the flag that determines whether or not to propagate the event
 */
ElementKeyBindings.prototype.bindKey = function(key, action, qualifiers, propagate)
{
  var keyCodeString = '' + key.m_keyCode;

  // If required add the qualifiers suffix to the key code string
  if(qualifiers != null)
  {
	keyCodeString += ElementKeyBindings.getQualifiersSuffix(qualifiers);
  }
  
  if(this.m_keys[keyCodeString] != null)
  {
   	// Key already bound so log a warning
   	if(ElementKeyBindings.m_logger.isWarn()) ElementKeyBindings.m_logger.warn('Key with keyCode "' + keyCodeString + '" already bound to HTML element with id: ' + this.m_adaptor.getId());
  }
  
  // Bind the key
  this.m_keys[keyCodeString] = action;

  // Bind any key qualifiers
  this.m_qualifiers[keyCodeString] = 0;
  if (qualifiers != null)
  {
	if (qualifiers.ctrl) this.m_qualifiers[keyCodeString] |= ElementKeyBindings.CTRL_KEY_MASK;
	if (qualifiers.alt) this.m_qualifiers[keyCodeString] |= ElementKeyBindings.ALT_KEY_MASK;
	if (qualifiers.shift) this.m_qualifiers[keyCodeString] |= ElementKeyBindings.SHIFT_KEY_MASK;
  }
  
  // Bind the stop event propagation flag
  this.m_stopPropagation[keyCodeString] = !propagate;
}


/**
 * Handle a key event on this element, calling the appropriate action function
 * for a key if it is bound to this element.
 *
 * @param keyCode the key code of the key pressed
 * @param qualifiers key qualifiers pressed bit pattern
 * @private
 */
ElementKeyBindings.prototype._handleKey = function(keyCode, qualifiers)
{
	var keyCodeString = '' + keyCode;

	// If required add the qualifiers suffix to the key code string
	if(qualifiers != 0)
	{
		if (qualifiers & ElementKeyBindings.CTRL_KEY_MASK) keyCodeString += ElementKeyBindings.CTRL_KEY_SUFFIX;
		if (qualifiers & ElementKeyBindings.ALT_KEY_MASK) keyCodeString += ElementKeyBindings.ALT_KEY_SUFFIX;
		if (qualifiers & ElementKeyBindings.SHIFT_KEY_MASK) keyCodeString += ElementKeyBindings.SHIFT_KEY_SUFFIX;
	}
	
	// Lookup the action using the keycode
	var action = this.m_keys[keyCodeString];

	// If we have an action for this key (and if any required qualifier key is pressed) then call it.
	if(action != null && this._canAdaptorAcceptKey(this.m_adaptor) && this.m_qualifiers[keyCodeString] == qualifiers)
	{
		if(ElementKeyBindings.m_logger.isDebug()) ElementKeyBindings.m_logger.debug("Calling action for key: " + keyCode);

		// Force an update because otherwise when hitting a keybinding on an adaptor
		// the latest data will not be in the DOM
		
		// Update the adaptor that the key is bound to
		if(this.m_adaptor.update)
		{
			this.m_adaptor.update();
		}
		
		// We may have to update the currently focussed adaptor if it is not the adaptor that the key is
		// bound to
		var currentFocussedAdaptor = FormController.getInstance().getTabbingManager().m_currentFocussedAdaptor;
		if(currentFocussedAdaptor != null && currentFocussedAdaptor.update)
		{
			if(currentFocussedAdaptor.getId() != this.m_adaptor.getId())
				currentFocussedAdaptor.update();
		}

		action.call(this.m_adaptor);
		return true;
	}
	else
	{
		return false;
	}
}


/**
 * Determine whether or not an adaptor is able to accept the key
 * and thus call the action for the key binding.
 *
 * @param a an adaptor
 * @returns true if adaptor is enabled and active. Otherwise false.
 * @private
 */
ElementKeyBindings.prototype._canAdaptorAcceptKey = function(a)
{
	// If enabled protocol is not supported then adaptor is enabled
	var enabled = true;
	// If active protocol is not supported then adaptor is active
	var active = true;

	if(a.supportsProtocol("EnablementProtocol"))
	{
		enabled = a.getEnabled();
	}

	if(a.supportsProtocol("ActiveProtocol"))
	{
		active = a.isActive();
	}

	return (enabled && active);
}

/**
 * Method getKeyBindingElement. In most cases an adaptor's key
 * binding element is the element referenced to by the adaptor's
 * instance variable m_element. However, the behaviour of form
 * level key bindings is a little flakey when keys are bound to
 * the form element. This is because in some cases the source
 * element for key presses appears to be the document body rather
 * than the form. Therefore, in the case of form adaptors we will
 * bind the key handler to the document's body instead of the form.
 *
 * @param adaptor The adaptor for which a binding element must be defined
*/
ElementKeyBindings.prototype.getKeyBindingElement = function(adaptor)
{
    var bindingElement = adaptor.getElement();
    
    if(bindingElement.tagName == 'FORM')
    {
        // Replace form element with parent body if possible
        var parent = bindingElement.parentNode;
        
        while(null != parent)
        {
            if(parent.tagName == 'BODY')
            {
                bindingElement = parent;
                break;
            }
            
            parent = parent.parentNode;
        }
        
    }
    
    return bindingElement;
}

/**
 * Builds a string dependendent on the which qualifier key(s) - Ctrl, Alt and
 * Shift - is set.
 *
 * @param qualifiers object
 * @returns a string
 */
ElementKeyBindings.getQualifiersSuffix = function(qualifiers)
{
	var suffix = "";
	
	if(qualifiers.ctrl == true) suffix += ElementKeyBindings.CTRL_KEY_SUFFIX;
	if(qualifiers.alt == true) suffix += ElementKeyBindings.ALT_KEY_SUFFIX;
	if(qualifiers.shift == true) suffix += ElementKeyBindings.SHIFT_KEY_SUFFIX;
	
	return suffix;
}

/**
 * Method cancelKeyEvent stops a key event from propagating and prevents
 * the default event action occurring.
 *
 * @param evt The event to be cancelled
 * @return    Returns "false", the value to be returned by the event handler
 *
*/
ElementKeyBindings.cancelKeyEvent = function(evt)
{
    SUPSEvent.stopPropagation(evt);
    SUPSEvent.preventDefault(evt);

	// More stuff to prevent default actions in IE...
	// Wrapped in try/catch block as this causes exceptions in other browsers
    try
    {
          if(ElementKeyBindings.isMoz != true)
      	  {
              evt.keyCode = 0;
          }
      }
      catch(e)
      {
      }
          
      return false;
}


/**
 * Abstraction of keys and their codes
 *
 * @param keyCode the key code of the key.
 */
function Key(keyCode)
{
  this.m_keyCode = keyCode;
}

