/**
 * Renderer constructor - never used. Use factory methods of
 * derived classes to create instances of component views
 * 
 * @private
 * @constructor
 */
function Renderer()
{
}

/**
 * Define class constants
 *
 * Constants used to define relationship of div to be created
*/
Renderer.CHILD_ELEMENT  = 0;
Renderer.BEFORE_ELEMENT = 1;
Renderer.AFTER_ELEMENT  = 2;


/**
 * Reference to the main (outermost) div element contains the component
 * and defines its type by virtue of its CSS class name
 *
 * @private
 */
Renderer.prototype.m_element = null;


/**
 * Create the outer div of a component as a child of another element. Note this
 * method does not append the element to any parent element - this is the
 * responsiblity of the caller.
 *
 * @param id the id of the component being created must not be null or empty string
 * @return the newly created div element
 * @type HTMLDivElement
 * @throws ConfigurationException if id is null on empty string
 */
Renderer.createAsChild = function(id)
{
	if(null == id || "" == id)
	{
		throw new ConfigurationException("Must supply id to Renderer.createAsChild");
	}
	
	// All framework components which are not standard HTML controls
	// must be surrounded by an outer div and must have a unique id
	var e = window.document.createElement("div");
	e.id = id;
	
	return e;
}


/**
 * Render the outer div of a component at the current end of the document. If invoked
 * as an inline JavaScript function in an HTML document, the div will be written immediately
 * after the script tag which contained the call to createInline method.
 *
 * @param id the id of the component being created must not be null or empty string
 * @return the newly created div element
 * @type HTMLDivElement
 * @throws ConfigurationException if id is null on empty string
 */
Renderer.createInline = function(id, focusable)
{
	if(null == id || "" == id)
	{
		throw new ConfigurationException("Must supply id to Renderer.createInline");
	}
	
	var divHTML = "<div id='" + id + "'";
	if(true == focusable)
	{
		divHTML += " tabindex='1' hideFocus='true'";
	}
	divHTML += "></div>";
	
	var d = window.document;
	
	// Write the outer element to the document
	d.write(divHTML);

	// Get the element using its id
	var e = d.getElementById(id);
	
	return e;
}

/*

Renderer.createAsInnerHTML = function(afterElement, id, focussable)
{
	if(null == id || "" == id)
	{
		throw new ConfigurationException("Must supply id to Renderer.createInline");
	}

	// Create a wrapper div to temporarily contain the rendered element
	var wrapper = window.document.createElement("div");
                       
	wrapper.innerHTML = ("<div id='" + id + "' tabIndex='1' hideFocus='true'></div>");

	// Get the inner \<div\> element and remove it from the temporary wrapper
	var innerDiv = wrapper.childNodes[0];
	wrapper.removeChild(innerDiv);
  
	var nodeAfterElement = afterElement.nextSibling;

	// Insert innerDiv into  document immediately after the script tag to simulate what happens
	// when a normal renderer.createInline() is executed
	if (null == nodeAfterElement)
	{
		afterElement.parentNode.appendChild(innerDiv);
	}
	else
	{
		afterElement.parentNode.insertBefore(innerDiv, nodeAfterElement)
	}
	
	// Return the inner div which will contain the rest of the component
	return innerDiv;
}

*/

/**
 * Method creates the outer div for a component positioned relative to a
 * specified HTML element using the "innerHTML" method.
 *
 * @param refElement  The HTML element relative to which the new div will
 *                    be positioned
 * @param relativePos An integer value specifying the relationship between
 *                    the new div and the element "refElement". Valid values
 *                    are:
 *
 *                    Renderer.CHILD_ELEMENT    Create div as child of "refElement"
 *                    Renderer.BEFORE_ELEMENT   Div is created as preceeding sibling of "refElement"
 *                    Renderer.AFTER_ELEMENT    Div is created as following sibling of "refElement"
 * @param id     The identifier for the new element
 * @param focusable If "true" use framework focussing mechanism
 *
 * @return Returns the new element
 *
*/
Renderer.createAsInnerHTML = function(refElement, relativePos, id, focussable)
{
	if(null == id || "" == id)
	{
		throw new ConfigurationException("Must supply id to Renderer.createInline");
	}

	// Create a wrapper div to temporarily contain the rendered element
	var wrapper = window.document.createElement("div");
	
	var divHTML = "<div id='" + id + "'";
	
	if(focussable == true)
	{
	    divHTML += " tabindex='1'  hideFocus='true'";
	}
	
	divHTML += "></div>";
                       
	wrapper.innerHTML = (divHTML);

	// Get the inner \<div\> element and remove it from the temporary wrapper
	var innerDiv = wrapper.childNodes[0];
	wrapper.removeChild(innerDiv);
	
	// Add innerDiv to document with appropriate relationship
	// to refElement
	
	switch (relativePos)
	{
	
	    case Renderer.CHILD_ELEMENT:
	    
	        refElement.appendChild( innerDiv );
	        break;
	        
	    case Renderer.BEFORE_ELEMENT:
	    
	        refElement.parentNode.insertBefore( innerDiv, refElement );
	        break;
	        
	    case Renderer.AFTER_ELEMENT:
	    
	        var nodeAfterElement = refElement.nextSibling;
	        if(null == nodeAfterElement)
	        {
	            refElement.parentNode.appendChild(innerDiv);
	        }
	        else
	        {
	            refElement.parentNode.insertBefore( innerDiv, nodeAfterElement );
	        }
	        break;
	        
	    default:
	        break;
	            
	}
	
	// Return the inner div which will contain the rest of the component
	return innerDiv;
}


/**
 * Create a new element in the current document and append it to the supplied parent
 * element.
 *
 * @param p the parent HTMLElement
 * @param nodeName the type of element to create supplied a string. e.g. "div"
 * @return the newly created HTMLElement
 * @type HTMLElement
 */
Renderer.createElementAsChild = function(p, nodeName)
{
	var n = window.document.createElement(nodeName);
	p.appendChild(n);
	
	return n;
}

/**
 * Method creates a new div element as a child of the specified
 * parent element. This method is rather unusual, but it allows
 * the creation of divs after a page has loaded.
 *
 * @param parent The parent element
 * @param id     The identifier for the new element
 * @param focusable If "true" use framework focusiing mechanism
 *
 * @return Returns the new element
 *
*/

Renderer.createAsInnerHtml = function(parent, id, focusable)
{
    // Append script tag to parent
    var scriptTag = document.createElement( "script" );
    parent.appendChild(scriptTag);
      
    // Produce an anonymous function that as a wrapper around the script tag
                     
    var scriptText = "Renderer.createDivisionUsingInnerHTML('" +
                     id +
                     "',this.arguments[0],this.arguments[1]);";
                     
    var fn = new Function(scriptText);

    // Invoke the renderer function
    fn.call(fn, scriptTag, focusable);
    
    // Locate reference to new node
    var nodeChild = null;
    var e = null;
    
    var nodeChildren = parent.childNodes;
    
    for(var i = 0, l = nodeChildren.length; i < l; i++)
    {
    	nodeChild = nodeChildren[i];
    	
    	if(nodeChild.id == id)
    	{
            e = nodeChild;
            break;
        }
    }
    	
    return e;

}

/**
 * Create new element as sibling of script element. This method is
 * invoked by the method createAsInnerHtml in order to create
 * a element using the innerHTML property.
 *
 * @param id The identifier to be assigned to the new element
 * @param scriptTag The script tag to be associated with the new element
 *
*/

Renderer.createDivisionUsingInnerHTML = function(id, scriptTag, focusable)
{
    
    // Create a wrapper div to temporarily contain the rendered element
    var wrapper = document.createElement("div");
    
    var divHTML = "<div id='" + id + "'";
    
	if(true == focusable)
	{
		divHTML += " tabindex='1' hideFocus='true'";
		//divHTML += " tabindex='1'";
	}
	divHTML += "></div>";
                           
    wrapper.innerHTML = (divHTML);

    // Get the inner \<div\> element and remove it from the temporary wrapper
    var innerDiv = wrapper.childNodes[0];
    wrapper.removeChild(innerDiv);
      
    var nodeAfterScriptTag = scriptTag.nextSibling;

    // Insert innerDiv into  document immediately after the script tag to simulate what happens
    // when a normal renderer.createInline() is executed
    if (null == nodeAfterScriptTag)
    {
        scriptTag.parentNode.appendChild(innerDiv);
    }
    else
    {
        scriptTag.parentNode.insertBefore(innerDiv, nodeAfterScriptTag)
    }
          
}


/**
 * Get the main (outermost) div element of the component.
 *
 * @return the main (outermost) div element of the component
 * @type HTMLDivElement
 */
Renderer.prototype.getElement = function()
{
	return this.m_element;
}


/**
 * Set the main (outermost) div element of the component.
 *
 * @private
 * @param e the main (outermost) div element of the component
 */
Renderer.prototype._setElement = function(e)
{
	this.m_element = e;
}


/**
 * Set the main (outermost) div element of the component and
 * also write __renderer reference back to this renderer, so
 * that GUIAdaptors can locate this Renderer.
 */
Renderer.prototype._initRenderer = function(e)
{
	this.m_element = e;
	e.__renderer = this;
}
//==================================================================
//
// fwFrameManager.js
//
// Class for managing HTML Frames in the framework
//
//==================================================================



/**
 * fwFrameManager Constructor
 *
 * @constructor
 */
function fwFrameManager()
{
}

fwFrameManager.m_logger = new Category("fwFrameManager");


/**
 * The frame which is being managed by the fwFrameManager
 *
 * @type HTMLFrameElement
 * @private
 */
fwFrameManager.prototype.m_frame = null;


/**
 * The url that the frame is attempting to load
 *
 * @type String
 * @private
 */
fwFrameManager.prototype.m_url = null;


/**
 * The onload handler registered on the frame
 *
 * @type SUPSEventKey
 * @private
 */
fwFrameManager.prototype.m_loadHandler = null;


/**
 * The number of attempts made to access the frame's
 * document after the onload handler is called. This
 * is required as IE occasionally calls the onload
 * before the document is ready, leading to an 
 * permission denied exception being thrown.
 *
 * @type int
 * @private
 */
fwFrameManager.prototype.m_retries;


/**
 * The maximum number of attempts to access the frame's
 * document after the onLoadHandler has been fired that
 * the fwFrameManager will make before giving up
 *
 * @type int
 * @private
 */
fwFrameManager.MAX_NUMBER_OF_RETRIES = 20;

/**
 * Listeners who are interested in hearing about when
 * the frame's content is loaded. By this we mean loaded,
 * and the document can be accessed without the permission
 * denied exception being thrown.
 *
 * @type CallbackList
 * @private
 */
fwFrameManager.prototype.m_loadCompleteListeners = null;


/**
 * Create the fwFrameManager
 *
 * @param frame the HTMLFrameElement to manage
 */
fwFrameManager.create = function(frame)
{
	var fm = new fwFrameManager();
	fm.m_frame = frame;
	
	fm.m_loadHandler = SUPSEvent.addEventHandler(frame, 'load', function() {fm._loadComplete();});
	fm.m_loadCompleteListeners = new CallbackList();
	
	return fm;
}


/**
 * Dispose of the fwFrameManager. The HTMLFrameElement being managed is not disposed!
 */
fwFrameManager.prototype.dispose = function()
{
	if(null != this.m_loadHandler)
	{
		SUPSEvent.removeEventHandlerKey(this.m_loadHandler);
		this.m_loadHandler = null;
	}
	
	// Set reference to iframe to null
	this.m_frame = null;
	
}


/**
 * Add a listener to fwFrameManager that is invoked when a load
 * completes. The listener should expect a single String argument. 
 * If the value of the argument is null then the page loaded 
 * successfully. If it is not null then the page failed
 * to load and the String contains a description of the error.
 *
 * @param cb the listener function to add
 */
fwFrameManager.prototype.addLoadCompleteListener = function(cb)
{
	this.m_loadCompleteListeners.addCallback(cb);
}


/**
 * Remove a previously added listener from fwFrameManager.
 *
 * @param cb the listener function to remove
 */
fwFrameManager.prototype.removeLoadCompleteListener = function(cb)
{
	this.m_loadCompleteListeners.removeCallback(cb);
}


/**
 * Get a reference to the frame being managed
 *
 * @return a reference to the frame being managed
 * @type HTMLFrameElement
 */
fwFrameManager.prototype.getFrame = function()
{
	return this.m_frame;
}


/**
 * Attempt to load a specified url into the managed frame.
 * The client of this class can register listeners using
 * addLoadCompleteListener to hear about the success or
 * failure of the load attempt
 *
 * @param url the URL to load into the managed frame
 */
fwFrameManager.prototype.load = function(url)
{
	if(fwFrameManager.m_logger.isDebug()) fwFrameManager.m_logger.debug("Starting load of url: '" + url + "'");
	this.m_retries = 0;
	this.m_url = url;
	this.m_frame.src = url;
}


/**
 * onLoad event handler method which is informed of 
 * the completion of loading of the frames content
 *
 * @private
 */
fwFrameManager.prototype._loadComplete = function()
{
	var doc = null;
	
	if(fwFrameManager.m_logger.isDebug()) fwFrameManager.m_logger.debug("Checking ready state of document: '" + this.m_url + "'");

	try
	{
		// Try to access the frame's content document
		doc = this.m_frame.contentWindow.document;
		
		// @todo. Ideally we would check that the document loaded
		// successfully - i.e. There was no error condition such
		// as a 404 or 500 etc. Unforunately this is simply not
		// possible, although one solution might be to require the
		// web server to generate a special custom error page
		// that we can detect by inspecting the document.

		if(fwFrameManager.m_logger.isDebug()) fwFrameManager.m_logger.debug("Notifying listeners of successful load of url: '" + this.m_url + "'");

		// If we got here no permission denied exception was thrown
		// so notify any listeners of success.
		try
		{
		    // Defect 1034. In the case of dynamic pages the callback function may
		    // raise an exception when the page's adaptors are initialised. This will
		    // not happen for forms as the adaptors are initialised after a timeout.
		    this.m_loadCompleteListeners.invoke(null);
		}
		catch(innerEx)
		{
		    // Pass error message to listener function.
		    this.m_loadCompleteListeners.invoke(innerEx.message);
		}
	}
	catch (ex)
	{
		if(this.m_retries < fwFrameManager.MAX_NUMBER_OF_RETRIES)
		{
			if(fwFrameManager.m_logger.isDebug()) fwFrameManager.m_logger.debug("Access denied to frames document - will retry: '" + this.m_url + "'");

			this.m_retries++;
			var thisObj = this;
			// Try again in a little while
			setTimeout(function() {thisObj._loadComplete(); }, 100);
		}
		else
		{
			if(fwFrameManager.m_logger.isDebug()) fwFrameManager.m_logger.debug("Notifying listeners of failure to load url: '" + this.m_url + "'");

			// Give up - notify any listeners of failure.
			this.m_loadCompleteListeners.invoke(ex.message);
		}
	}
}
