/**
 * Class provides form navigate event processing. This includes both
 * the configuration to handle form navigate events and the subsequent
 * data processing tasks associated with navigating away from a form.
 *
 * @constructor
 *
*/
function NavigateFormBusinessLifeCycle()
{
}

/**
 * NavigateFormBusinessLifeCycle is a sub class of BusinessLifeCycle
 *
*/
NavigateFormBusinessLifeCycle.prototype = new BusinessLifeCycle();


/**
 *  Set the constructor property such that we can identify the type
 *  of the class
 *
*/
NavigateFormBusinessLifeCycle.prototype.constructor = NavigateFormBusinessLifeCycle;

/**
 * Define static class constants
 *
 * Used to indicate nature of navigate operation
 *
*/
NavigateFormBusinessLifeCycle.FORM = "form";
NavigateFormBusinessLifeCycle.LOGOUT = "logout";
NavigateFormBusinessLifeCycle.EXIT = "exit";


/**
 * Create a new instance of the NavigateFormBusinessLifeCycle class
 *
 * @return Returns a new instance of the class NavigateFormBusinessLifeCycle
 *
*/
NavigateFormBusinessLifeCycle.create = function()
{
    var navigateFormBusinessLifeCycle = new NavigateFormBusinessLifeCycle();
    
    return navigateFormBusinessLifeCycle;
}

/**
 * Get the name of the business life cycle
 *
 * @return String the name of the business life cycle
 *
*/
NavigateFormBusinessLifeCycle.prototype.getName = function()
{
    return BusinessLifeCycleEvents.EVENT_NAVIGATE;
}

/**
 * Invoke the business logic associated with the navigate form business
 * life cycle
 *
 * @param e The business life cycle event
 *
*/
NavigateFormBusinessLifeCycle.prototype.invokeBusinessLifeCycle = function(e)
{
	// Retrieve current state of form
	var state = this.m_adaptor._getState();
	var navigate = false;
	
	// Retrieve event details
	var details = e.getDetail();

	switch (state) {
		case FormElementGUIAdaptor.FORM_BLANK:
		    Services.getAppController().navigate(details[ "formName" ], details[ "mode" ]);
			break;
		case FormElementGUIAdaptor.FORM_CREATE:
		case FormElementGUIAdaptor.FORM_MODIFY:
		default:
		    if(details[ "raiseWarningIfDOMDirty" ])
		    {
		        var thisObj = this;
	            
	            FormBusinessLifeCycleDelegate.promptUserWhenDataModelDirty( thisObj,
	                                                                        BusinessLifeCycle.UNSAVED_DATA_DIALOG_MSG,
	                                                                        null,
	                                                                        e,
	                                                                        function(){Services.getAppController().navigate(details[ "formName" ], details[ "mode" ]);} );
	                                                                        
	        }
	        else
	        {
	            Services.getAppController().navigate(details[ "formName" ], details[ "mode" ]);
	        }
			break;
	}
}


//==================================================================
//
// FormElementGUIAdaptor.js
//
// Base class for adapting input elements for use in the framework
//
//==================================================================


/**
 * Base class for adapting html input elements for use in the
 * framework.
 *
 * @constructor
 */
function FormElementGUIAdaptor()
{
}


FormElementGUIAdaptor.m_logger = new Category("FormElementGUIAdaptor");


/**
 * FormElementGUIAdaptor is a sub class of HTMLElementGUIAdaptor
 */
FormElementGUIAdaptor.prototype = new HTMLElementGUIAdaptor();


/**
 * Make sure that the parent class' protocols are set up correctly for this GUIAdaptor
 */
GUIAdaptor._setUpProtocols("FormElementGUIAdaptor");


/**
 * Add the required protocols to the FormElementGUIAdaptor
 */
GUIAdaptor._setUpProtocols('FormElementGUIAdaptor');
GUIAdaptor._addProtocol('FormElementGUIAdaptor', 'ComponentContainerProtocol');				// 
GUIAdaptor._addProtocol('FormElementGUIAdaptor', 'KeybindingProtocol');            // Supports keybinding
GUIAdaptor._addProtocol('FormElementGUIAdaptor', 'InitialiseProtocol');            // Supports custom initialisation
GUIAdaptor._addProtocol('FormElementGUIAdaptor', 'DataBindingProtocol');
GUIAdaptor._addProtocol('FormElementGUIAdaptor', 'BusinessLifeCycleProtocol');
GUIAdaptor._addProtocol('FormElementGUIAdaptor', 'EnablementProtocol');            // Supports enablemen
GUIAdaptor._addProtocol('FormElementGUIAdaptor', 'ReadOnlyProtocol');			// Supports enablement/disablement
GUIAdaptor._addProtocol('FormElementGUIAdaptor', 'FormDirtyProtocol');				// Supports form dirty
GUIAdaptor._addProtocol('FormElementGUIAdaptor', 'RecordsProtocol');				// Supports form dirty

/**
 * Set the constructor property so we can identify the type
 */
FormElementGUIAdaptor.prototype.constructor = FormElementGUIAdaptor;


/**
 * CSS class set on the form to indicate that it is not submissable
 */
FormElementGUIAdaptor.NOT_SUBMISSIBLE_CSS_CLASS = "form_notsubmissable";


/**
 * Default location of the form's model data in the DataModel
 *
 * @type String
 */
FormElementGUIAdaptor.DEFAULT_MODEL_XPATH = DataModel.DEFAULT_ROOT;

/**
 * ID for the form's status line. Defaults to "status_line".
 *
 * @type String
 * @configuration
 */
FormElementGUIAdaptor.prototype.statusLine = "status_line";


/**
 * Reference to the status bar HTML element
 */
FormElementGUIAdaptor.prototype.m_statusLine = undefined;


/**
 * Define class members used to represent state of form
 *
 */
FormElementGUIAdaptor.FORM_BLANK = FormLifeCycleStates.FORM_BLANK;
FormElementGUIAdaptor.FORM_CREATE = FormLifeCycleStates.FORM_CREATE;
FormElementGUIAdaptor.FORM_MODIFY = FormLifeCycleStates.FORM_MODIFY;


/**
 * Names of the Nodes that are maintained by the form under its dataBinding
 */
FormElementGUIAdaptor.FORM_STATE_XPATH = "/state";
FormElementGUIAdaptor.FORM_DIRTY_XPATH = "/dirty";


/**
 * Variable to store a reference when the transient message on
 * the statusbar was set.
 */
FormElementGUIAdaptor.prototype.m_transientMessageTimeout = null;


/**
 * Amount of time (in milliseconds) after which a transient message
 * may be overwritten by an tabbing event. 
 */
FormElementGUIAdaptor.STATUSBAR_TIMEOUT = 1000;


/**
 * Stores an array of nodes (relative to /ds/var) which will 
 * not be cleared when clearDataModel is invoked.
 * Defaults to form parameters.
 */
FormElementGUIAdaptor.prototype.m_dmClearExclusionNodes = new Array("app","form");


/*
 * Defines the mandatory location for the form databinding.
 */
FormElementGUIAdaptor.prototype.FORM_REQUIRED_DATABINDING_ROOT = FormDatabindings.DEFAULT_FORM_DATABINDING_ROOT;


/**
 * Stores an array of XPaths which will be cleared when
 * the application navigates away from the form represented
 * by this adaptor.
 *
*/
FormElementGUIAdaptor.prototype.m_removeXPaths = null;


/**
 * Reference Data to be loaded on form initialisation
 *
 * @configuration
 * @type Array[Object]
 */
FormElementGUIAdaptor.prototype.refDataServices = [];


/**
 * Submit Lifecycle configuration
 *
 * @configuration
 * @type Object
 */
FormElementGUIAdaptor.prototype.submitLifeCycle = null;


/**
 * Clear Lifecycle configuration
 *
 * @configuration
 * @type Object
 */
FormElementGUIAdaptor.prototype.clearLifeCycle = null;


/**
 * Create Lifecycle configuration
 *
 * @configuration
 * @type Object
 */
FormElementGUIAdaptor.prototype.createLifeCycle = null;


/**
 * Modify Lifecycle configuration
 *
 * @configuration
 * @type Object
 */
FormElementGUIAdaptor.prototype.modifyLifeCycle = null;


/**
 * Navigate Lifecycle configuration
 *
 * @configuration
 * @type Object
 */
FormElementGUIAdaptor.prototype.navigation = null;


/**
 * startupState configuration for the form
 *
 * @configuration
 * @type varies 
 */
FormElementGUIAdaptor.prototype.startupState = null;


/**
 * The XPath of the node which contains the forms model data.
 */
FormElementGUIAdaptor.prototype.modelXPath = null;


/**
 * Data to load at form initialisation
 *
 * @deprecated
 */
FormElementGUIAdaptor.prototype.loadModelDataService = null;



/**
 * Override includeInValidation property from StateChangeProtocol
 * - forms are not included in validation message
 *
 * @type boolean
 */
FormElementGUIAdaptor.prototype.includeInValidation = false;


/**
 * The initial state of the form. Will be one of the Form
 * LifeCycle State constants.
 *
 * @type String
 * @private
 */ 
FormElementGUIAdaptor.prototype.m_initialFormState = null;


/**
 * Whether or not the form should be marked as dirty on initialisation
 *
 * @type boolean
 * @private
 */
FormElementGUIAdaptor.prototype.m_markAsDirtyOnInitialise = false;


/**
 * Initialise the FormElementGUIAdaptor
 *
 * @param e the input element to manage
 */
FormElementGUIAdaptor.create = function(e)
{
	var a = new FormElementGUIAdaptor();

	a._initialiseAdaptor(e);
	
	return a;
}


/**
 * Initialise the FormElementGUIAdaptor
 *
 * @param e the HTMLElement for the select element to be managed
 * @private
 */
FormElementGUIAdaptor.prototype._initialiseAdaptor = function(e)
{
	// Call parent class initialisation
	HTMLElementGUIAdaptor.prototype._initialiseAdaptor.call(this, e);

	// Create default data binding for backwards compatibility
	// with forms that do not use the form life cycle
	this.dataBinding = this.FORM_REQUIRED_DATABINDING_ROOT + "/" + this.getId();
	
	// Default the Form's DataBindingProtocol m_value to the correct initial state.
	this._setInitialValue();	

	// Add handlers to block form events
	var thisObj = this;
	
	// If one and only one text box is on a form, pressing the return key fires the
	// onsubmit event. (Could also be any adaptor which contains an input box, e.g.
	// date picker.) We need to block the submit because when the browser refreshes
	// the page after the submit completes adaptors are not rendered correctly.
	this.m_submitHandler = SUPSEvent.addEventHandler(this.m_element, "submit", function(evt) { thisObj._blockEventsForForm(evt); }, null);	

	// Disable drag and drop functionality in the Framework
	this.m_dragStartHandler = SUPSEvent.addEventHandler(this.m_element, "dragstart", function(evt) { thisObj._disableDragAndDrop(evt); }, null);

	// Hide the focus border on the BODY tag otherwise it may flash when the browser
	// momentarily focuses on it when tabbing
	//Change to fix firefox problem where this.m_element.document does not exist
	this.m_element.ownerDocument.body.setAttribute("hideFocus", "true");
}


FormElementGUIAdaptor.prototype.reinitialise = function()
{
	// Reset the data model as follows:
	//  - re-run reference data loading (so that it generates DataModel events)
	//  - re-run initial form model loading (so that it generates DataModel events)
	this._reinitialiseDataModel();
}


FormElementGUIAdaptor.prototype._reinitialiseDataModel = function()
{
	// Clear form model data from DataModel
    this.clearFormDataModel();

	// Default the Form's DataBindingProtocol m_value to the correct initial state.
	this._setInitialValue();

	// Re-run reference data loading - generating DataModel events
	this._loadReferenceData(true);
	
	// Load the initial model data - generating DataModel events
	this._loadInitialModelData(true);
	
	// Write form's current state to the DataModel.
	this.update();
}


FormElementGUIAdaptor.prototype._setInitialValue = function()
{
	// Default the Form's DataBindingProtocol m_value to the correct initial state.
	this.m_value = {
		state:	FormElementGUIAdaptor.FORM_BLANK,
		dirty:	false
	}
}


FormElementGUIAdaptor.prototype._dispose = function()
{
    if(this.m_submitHandler != null)
    {
        SUPSEvent.removeEventHandlerKey(this.m_submitHandler);
        this.m_submitHandler = null;
    }

    if(this.m_dragStartHandler != null)
    {
        SUPSEvent.removeEventHandlerKey(this.m_dragStartHandler);
        this.m_dragStartHandler = null;
    }
}


FormElementGUIAdaptor.prototype.renderState = function()
{
	this._renderForm("");
}


FormElementGUIAdaptor.prototype._renderForm = function(className)
{
	if(!this.getAggregateState().isSubmissible())
	{
		className += " " + FormElementGUIAdaptor.NOT_SUBMISSIBLE_CSS_CLASS;
	}
	
	this.m_element.className = className;
}


/**
 * Configure the GUIAdaptor
 *
 * @param cs an Array of configuration objects ordered with
 *   most specific items first.
 */
FormElementGUIAdaptor.prototype._configure = function(cs)
{
	// Locate life cycle and form navigation configuration objects within form configuration
	var c;
	
	var refDataServices = [];
	
	for(var i = 0, l = cs.length; i < l; i++)
	{
	    c = cs[i];
	    
	    if(c.submitLifeCycle && this.submitLifeCycle == null)
	    {
	        this.submitLifeCycle = c.submitLifeCycle;
	    }
	    
	    if(c.clearLifeCycle && this.clearLifeCycle == null)
	    {
	        this.clearLifeCycle = c.clearLifeCycle;
	    }
	    
	    if(c.createLifeCycle && this.createLifeCycle == null)
	    {
	        this.createLifeCycle = c.createLifeCycle;
	    }
	    
	    if(c.modifyLifeCycle && this.modifyLifeCycle == null)
	    {
	        this.modifyLifeCycle = c.modifyLifeCycle;
	    }
	    
	    if(c.startupState && this.startupState == null)
	    {
	    	this.startupState = c.startupState;
	    }
	    
	    // Retrieve navigation configuration
	    if(c.navigation && this.navigation == null)
	    {
	        this.navigation = c.navigation;
	    }
	    
	    if(c.loadModelDataService && this.loadModelDataService == null)
	    {
	    	this.loadModelDataService = c.loadModelDataService;
	    }
	    
	    // Most specific configuration is used.
	   	if(c.statusLine != null)
	   	{
	   		this.statusLine = c.statusLine;
	   	}

	   	if(c.prepareModelData)
	   	{
			this.prepareModelData = c.prepareModelData;	   	
	   	}
	   	
	   	// Concatanate reference data services
	   	if(c.refDataServices && c.refDataServices.length && c.refDataServices.length > 0)
	   	{
	   		refDataServices = refDataServices.concat(c.refDataServices);
	   	}
	   	
	   	if(c.modelXPath && this.modelXPath == null)
	   	{
	   		this.modelXPath = c.modelXPath;
	   	}
	}
	
	// Set final set of configured reference data services
	this.refDataServices = refDataServices;
	
	// If model XPath is not set then set it to the default
	if(null == this.modelXPath)
	{
		this.modelXPath = FormElementGUIAdaptor.DEFAULT_MODEL_XPATH;
	}
	else
	{
		// Check that model is not under /ds/var which is an invalid model xpath
		if(0 == this.modelXPath.indexOf(DataModel.VARIABLES_ROOT))
		{
			throw new ConfigurationException("Form " + this.getId() + " modelXPath cannot be inside " + DataModel.VARIABLES_ROOT + ". modelXPath is: " + this.modelXPath);
		}
	}
	
	// Determine if the form's dataBinding is located in a valid location
	if(this.dataBinding.indexOf(this.FORM_REQUIRED_DATABINDING_ROOT) != 0) 
	{
		throw new ConfigurationException("Form dataBinding must be under " 
										 + this.FORM_REQUIRED_DATABINDING_ROOT 
										 + ". Actual location: " + this.dataBinding);
	}


	// Create form submit lifecycle (may already have been added by subclass)
	if (this.m_lifeCycles[BusinessLifeCycleEvents.EVENT_SUBMIT] == null) 
	{
		var submitFormBusinessLifeCycle = SubmitFormBusinessLifeCycle.create();
		submitFormBusinessLifeCycle.initialise(this);
		this.addBusinessLifeCycle(submitFormBusinessLifeCycle);
		if(null != this.submitLifeCycle)submitFormBusinessLifeCycle.configure(this.submitLifeCycle);
		submitFormBusinessLifeCycle.start();
	}
	
	// Create form clear lifecycle
	var clearFormBusinessLifeCycle = ClearFormBusinessLifeCycle.create();
	clearFormBusinessLifeCycle.initialise(this);
	this.addBusinessLifeCycle(clearFormBusinessLifeCycle);
	
	// Create form create lifecycle
	var createFormBusinessLifeCycle = CreateFormBusinessLifeCycle.create();
	createFormBusinessLifeCycle.initialise(this);
	this.addBusinessLifeCycle(createFormBusinessLifeCycle);
	
	// Create form modify lifecycle
	var modifyFormBusinessLifeCycle = ModifyFormBusinessLifeCycle.create();
	modifyFormBusinessLifeCycle.initialise(this);
	this.addBusinessLifeCycle(modifyFormBusinessLifeCycle);

	// Create form navigate lifecycle
	var navigateFormBusinessLifeCycle = NavigateFormBusinessLifeCycle.create();
	navigateFormBusinessLifeCycle.initialise(this);
	this.addBusinessLifeCycle(navigateFormBusinessLifeCycle);
	
	// Configure life cycles
	if(null != this.clearLifeCycle)clearFormBusinessLifeCycle.configure(this.clearLifeCycle);
	if(null != this.createLifeCycle)createFormBusinessLifeCycle.configure(this.createLifeCycle);
	if(null != this.modifyLifeCycle)modifyFormBusinessLifeCycle.configure(this.modifyLifeCycle);
	
	// Start form life cycle event handlers - Is this the right place for this?
	clearFormBusinessLifeCycle.start();
	createFormBusinessLifeCycle.start();
	modifyFormBusinessLifeCycle.start();
	
	// Store XPaths to be removed on navigation to another form
	if(null != this.navigation)
	{
	    this.m_removeXPaths = this.navigation[ "removeXPaths" ];
	}
	
	// Load reference data
	this._loadReferenceData(false);
	
	// Load the initial model data
	this._loadInitialModelData(false);	
}


/**
 * Load reference data
 */
FormElementGUIAdaptor.prototype._loadReferenceData = function(withEvents)
{
	var rd = this.refDataServices;
	var l = rd.length;
	if(l > 0)
	{
		for(var i = 0; i < l; i++)
		{
			if(FormElementGUIAdaptor.m_logger.isTrace()) FormElementGUIAdaptor.m_logger.trace("About to create ref data service number " + i);
			var refDataLoader = fwFormRefDataLoader.create(rd[i], this, withEvents);
			refDataLoader.load();
		}
	}
	else
	{
		if(FormElementGUIAdaptor.m_logger.isInfo()) FormElementGUIAdaptor.m_logger.info("No ref data services configured for form " + this.getId());
	}
}



/**
 * Load data into form, both ref data and model data
 *
 * @private
 */
FormElementGUIAdaptor.prototype._loadInitialModelData = function(withEvents)
{
	// Data Loader used to load form data
	var modelDataLoader = null;

	// Configuration used during initialisation
	var initialConfig = null;

	// Determine initial state of the form
	this.m_value.state = this._determineInitialState();
	
	switch(this.m_value.state)
	{
		case FormElementGUIAdaptor.FORM_CREATE:
		{
			if(null == this.createLifeCycle)
			{
				throw new ConfigurationException("Form " + this.getId() + " configured to initially enter CREATE state but no createLifeCycle configuration specified");
			}

			// Create a DataService object which will load the model data using the createLifeCycle configuration
			modelDataLoader = fwFormInitModelDataLoader.create(this.createLifeCycle, this, withEvents);
			
			// Use the create config as the initial config
			initialConfig = this.createLifeCycle;

			break;
		}
		
		case FormElementGUIAdaptor.FORM_MODIFY:
		{
			if(null == this.modifyLifeCycle)
			{
				throw new ConfigurationException("Form " + this.getId() + " configured to initially enter MODIFY state but no modifyLifeCycle configuration specified");
			}

			// Create a DataService object which will load the model data using the createLifeCycle configuration
			modelDataLoader = fwFormInitModelDataLoader.create(this.modifyLifeCycle, this, withEvents);
			
			// Use the create config as the initial config
			initialConfig = this.modifyLifeCycle;

			break;
		}
		
		case FormElementGUIAdaptor.FORM_BLANK:
		{
			break;
		}
		
		default:
		{
			// No state specified and no update or modify lifecycles configured, so we assume that
			// we are running in backwards compatability (i.e. no form life cycles) mode.
			// Form stays in the BLANK state but may load data using the loadModelDataService
			this.m_value.state = FormElementGUIAdaptor.FORM_BLANK;
			
			if(null != this.loadModelDataService)
			{
			    modelDataLoader = fwFormInitModelDataLoader.create(this.loadModelDataService, this, withEvents);
			    if(FormElementGUIAdaptor.m_logger.isError()) FormElementGUIAdaptor.m_logger.error("Form with id: '" + this.getId() + "' uses obsolete loadModelDataService");
			}
			break;
		}
	}

	// If the form is entering CREATE or MODIFY lifecycle on initialisation,
	// then check if the form should be marked as dirty after initialisation
	if(null != initialConfig && null != initialConfig.initialise && null != initialConfig.initialise.markAsDirty)
	{
		// Hang on to mark as dirty config
		this.m_markAsDirtyOnInitialise = initialConfig.initialise.markAsDirty;
	}

	// If there is some model data to be loaded, then load it now...
	if(null != modelDataLoader)
	{
		modelDataLoader.load();
	}
}


/**
 * Determine the initial lifecycle state of the form.
 *
 * @return the initial state of the form, or if no FormLifeCycles configuration
 * is available, null.
 */
FormElementGUIAdaptor.prototype._determineInitialState = function()
{
	var s = null;
	if(this.startupState != null)
	{
        // Determine desired state for form. Note, if form state is
        // "Blank" neither service is invoked.
        s = this._invokeStartupState();
    }

    // State not explicitly determined by config, so we'll try to derive it from available config
    if(null == s)
    {		
		// Local references to create and modify lifecycle configurations
		var createConfig = this.createLifeCycle;
		var modifyConfig = this.modifyLifeCycle;

		if(null != createConfig && null == modifyConfig)
		{
			// Configure data service to load blank XML template
			if(FormElementGUIAdaptor.m_logger.isDebug()) FormElementGUIAdaptor.m_logger.debug("About to create model data service for new data");
			s = FormElementGUIAdaptor.FORM_CREATE;
		}
		else if(null == createConfig && null != modifyConfig)
		{
		    //Configure data service to load existing data
		    if(FormElementGUIAdaptor.m_logger.isDebug()) FormElementGUIAdaptor.m_logger.debug("About to create model data service for update data");
		    s = FormElementGUIAdaptor.FORM_MODIFY;
		}
		else if(null != createConfig && null != modifyConfig)
		{
			// Error. StartUpState must be defined if both initial services defined.
			throw new ConfigurationException( "Incorrect configuration for form " + this.getId() + ". startupState must be defined if both create and update lifecycles configured." );
		}
		else
		{
			// No create or update lifecycles declared and no initial form state
			// specified, so we assume we are running a form which does not have
			// form lifecycles configured.
		}
	}
	
	return s;
}


/**
 * Determine the value of the startupState configuration, which may be
 * a simple string of a function which returns a string. The value of
 * the string must be one of the Form Lifecycle state constants:
 *
 *   FormElementGUIAdaptor.FORM_BLANK
 *   FormElementGUIAdaptor.FORM_CREATE
 *   FormElementGUIAdaptor.FORM_MODIFY
 *
 * @return the value of the startupState configuration
 * @type String
 * @private
 */
FormElementGUIAdaptor.prototype._invokeStartupState = function()
{
	var state = null;

	// Retrieve mode property off start up state object
	var mode = this.startupState.mode;
	    
	if(null != mode)
	{
		// Determine nature of mode property
		switch(typeof mode)
		{
			case "string":
			{
				state = mode;

				if(!this.isValidState(state))
				{
					throw new ConfigurationException("Initial state for form " + this.getId() + " is invalid" );
				}
				break;
			}

			case "function":
			{
				state = mode.call(this);
				    
				if(!this.isValidState(state))
				{
					throw new ConfigurationException( "Initial state of form " + this.getId() + " provided by custom function is invalid" );
				}
				break;
			}

			default:
			{
				throw new ConfigurationException( "Invalid configuration for form " + this.getId() + ". Mode parameter of startUpState must be a string or a custom function" );
			}
		}
	}
	else
	{
		throw new ConfigurationException( "Invalid configuration for form " + this.getId() + ". Parameter mode of startUpState must be defined." );
	}
	
	return state;
}


/**
 * Method determines whether or not the supplied parameter is
 * a valid form state or not.
 *
 * @param s String identifying state of form
 * @return boolean Returns "true" if argument "s" is a valid state otherwise "false"
 *
*/
FormElementGUIAdaptor.prototype.isValidState = function(s)
{
	return (s == FormElementGUIAdaptor.FORM_BLANK || s == FormElementGUIAdaptor.FORM_MODIFY || s == FormElementGUIAdaptor.FORM_CREATE);
}


/**
 * Should the form be dirty on initialisation
 *
 * @return true if the form should be marked dirty on initialisation or
 *   false if it should be marked clean on initialisation.
 * @type boolean
 */
FormElementGUIAdaptor.prototype.isDirtyOnInit = function()
{
	// Form is not dirty by default
	var isDirty = false;
	
	if(null != this.m_markAsDirtyOnInitialise)
	{
		// If markAsDirty is a function invoke it and keep the result
		if(typeof this.m_markAsDirtyOnInitialise == "function")
		{
			isDirty = this.m_markAsDirtyOnInitialise();
		}
		else
		{
			isDirty = this.m_markAsDirtyOnInitialise;
		}
		
		if(typeof isDirty != "boolean")
		{
			throw new ConfigurationException("markAsDirty configuration must be of type boolean or a function that returns a boolean");
		}
	}
	
	return isDirty;
}


/**
 * FormElementGUIAdaptor has a custom update function that writes both the 
 * Form lifecycle state and the dirty state of the form to the databinding
 */
FormElementGUIAdaptor.prototype.update = function()
{
	if(FormElementGUIAdaptor.m_logger.isDebug()) FormElementGUIAdaptor.m_logger.debug("FormElementGUIAdaptor.update(): " + this.getId());

	var db = this.dataBinding;
	if(null != db)
	{
		var fc = FormController.getInstance();
		var dm = fc.getDataModel();
		
		fc.startDataTransaction(this);


		// Determine whether or not the form state has changed or not and update it in the model if necessary		
		var state = this.m_value.state;
		var stateXPath = db + FormElementGUIAdaptor.FORM_STATE_XPATH;
		var origState = dm.getValue(stateXPath);
		var stateChanged = Services.compareStringValues(state, origState);
		
		var stateUpdated = false;
		if(!stateChanged)
		{
			stateUpdated = dm.setValue(stateXPath, state);
		}
		
		
		// Determine whether or not the form dirty state has changed or not and update it in the model if necessary		
		var dirty = this.m_value.dirty.toString();
		var dirtyXPath = db + FormElementGUIAdaptor.FORM_DIRTY_XPATH;
		var origDirty = dm.getValue(dirtyXPath);
		var dirtyChanged = Services.compareStringValues(state, origState);
		
		var dirtyUpdated = false;
		if(!dirtyUpdated)
		{
			dirtyUpdated = dm.setValue(dirtyXPath, dirty);
		}


		fc.endDataTransaction(this);
		return stateUpdated || dirtyUpdated;
	}
	else
	{
		throw new DataBindingError("DataBindingProtocol.update(), no dataBinding specified for adaptor id = " + this.getId());
	}
}


FormElementGUIAdaptor.prototype._setState = function(state)
{
	this.m_value.state = state;
}


FormElementGUIAdaptor.prototype._getState = function()
{
	return this.m_value.state;
}


FormElementGUIAdaptor.prototype._setDirty = function(dirty)
{
	this.m_value.dirty = dirty;
}


FormElementGUIAdaptor.prototype._isDirty = function()
{
	return this.m_value.dirty;
}


/**
 * Method _getValueFromView is implemented to enable the FormElementGUIAdaptor
 * to update an associated data value in the client side DOM. Although, a form
 * has no associated display value the form life cycle requires the maintenance
 * of form state. The adaptor stores this state on the client side DOM. The adaptor
 * stores the state in the field m_value. This value is returned by the method
 * _getValueFromView to enable the DataBinding protocol method update to set
 * the state value on the client side DOM.
 *
 * @return String the state of the form as stored in the instance variable m_value
 *
 */
FormElementGUIAdaptor.prototype._getValueFromView = function()
{
    return this.m_value;
}

/**
 * Method retrieve is a dummy method. In the case of the form adaptor there
 * is no display value to update.
 *
 */
FormElementGUIAdaptor.prototype.retrieve = function()
{
}

/**
 * Method initialise sets the state of the form adaptor on the client side DOM.
 *
*/

FormElementGUIAdaptor.prototype.initialise = function()
{
    // Transfer form state to client side DOM.
    this.update();
}



/**
 * Handler function called when a Field takes focus
 *
 * @private
 */
FormElementGUIAdaptor.prototype._setCurrentFocusedField = function(a)
{
	var message = null;
	if(null != a)
	{
		if(a.supportsProtocol('ValidationProtocol'))
		{
			var lastError = a.getLastError();
	
			if(null != lastError)
			{
				message = lastError.getMessage();
			}
		}
	
		if(null == message && a.supportsProtocol('HelpProtocol'))
		{
			message = a.getHelpText();
		}
	}
					
	if(null == message)
	{
		message = "OK";
	}
	
    // Get current time and compare to timeout.
    // If not expired then don't set the statusBarMessage.	
    
    var date = new Date();
    var current_time = date.valueOf();
    if (this.m_transientMessageTimeout == null 
        || current_time - this.m_transientMessageTimeout > FormElementGUIAdaptor.STATUSBAR_TIMEOUT)
    {
      this.setStatusBarMessage(message);
    }
}


/**
 * Display a message on the status bar
 *
 * @param message the message to display
 * @private
 */
FormElementGUIAdaptor.prototype.setStatusBarMessage = function(message)
{
	if(this.m_statusLine === undefined)
	{
		this.m_statusLine = document.getElementById(this.statusLine);
	}
	
	if(this.m_statusLine) this.m_statusLine.innerHTML = message;
}


/**
 * Set a message which will override all setStatusBarMessage calls
 * made by the tabbing manager for a period of time (defined by
 * STATUSBAR_TIMEOUT).
 */
FormElementGUIAdaptor.prototype.setTransientMessage = function(message)
{
  // Update the status bar.
  this.setStatusBarMessage(message);
  
  // Record the system time for use as a timeout.
  var date = new Date();
  this.m_transientMessageTimeout = date.valueOf();
}


FormElementGUIAdaptor.prototype.getModelXPath = function()
{
	return this.modelXPath;
}


FormElementGUIAdaptor.prototype.getModelParentXPath = function()
{
	// Get the form's model xpath
	var parentXPath = this.getModelXPath();
	
	// Default is /ds so we just bind the loaded document into /ds
	// If modelXPath is not /ds (say /ds/formModel), then we need
	// to strip the trailing /formModel, as the loaded document will
	// contain the formModel node as it's root node.
	// Ideally all forms would specify modelXPath, but historically
	// this hasn't been the case - all of /ds was used as the model
	// with the exception of /ds/var. Backwards compatability is the
	// reason behind this slightly weird behaviour.
	if(FormElementGUIAdaptor.DEFAULT_MODEL_XPATH != parentXPath)
	{
		parentXPath = XPathUtils.removeTrailingNode(parentXPath);
	}
	
	return parentXPath;
}


/*
 * Function to remove the entire datamodel except those nodes in
 * /ds/var defined in m_dmClearExclusionNodes
 *
 */
FormElementGUIAdaptor.prototype.clearFormDataModel = function()
{
    var i, j, il, jl, tmpXPath;
    var removeXPaths = new Array();
    var dm = FormController.getInstance().getDataModel();
    
    var rootNode = dm._getRootNode(dm.m_dom);
    
    var rootNodeName = rootNode.nodeName;
    
    // Loop through children of root node removing all except "/ds/var/app"
    // and "/ds/var/form (actually, whatever is defined in  this.m_dmClearExclusionNodes.
    
    dm._startTransaction(); 
    
    var rootNodeChildren = rootNode.childNodes;
    
    for(i = 0, il = rootNodeChildren.length; i < il; i++)
    {
        if( rootNodeChildren[i].nodeType == XML.ELEMENT_NODE)
        {
            var rootChildNodeName = rootNodeChildren[i].nodeName;
        
            if( rootChildNodeName != "var" )
            {
                tmpXPath = "/" + rootNodeName + "/" + rootChildNodeName;
                removeXPaths[removeXPaths.length] = tmpXPath;
            }
            else
            {
                // Delete all nodes under var except those defined in this.m_dmClearExclusionNodes
                var varNodeChildren = rootNodeChildren[i].childNodes;
            
                for(j = 0, jl = varNodeChildren.length; j < jl; j++)
                {
                    if(varNodeChildren[j].nodeType == XML.ELEMENT_NODE)
                    {
                        var varChildNodeName = varNodeChildren[j].nodeName;
                
                        if(!ArrayUtils.contains(this.m_dmClearExclusionNodes, varChildNodeName))
                        {
                            tmpXPath = "/" + rootNodeName + "/var/" + varChildNodeName;
                    
                            removeXPaths[removeXPaths.length] = tmpXPath;
                        }
                    }
                }
            }
        }
    }
    
    
    // Remove nodes from data model
    for(i=0, il = removeXPaths.length; i < il; i++)
    {
        dm.removeNode( removeXPaths[i] );
    }
    
    // Set form to clean
   	this._setDirty(false);
    
    dm._endTransaction();
}

/**
 * Method removes selected XPaths from data model. Note this method is
 * intended for use cleaning unwanted data from the node "/ds/var/app"
 * either when navigating to a new form or following a clear event.
 *
*/

FormElementGUIAdaptor.prototype.removeSelectedXPaths = function( xPaths )
{

    if(null != xPaths)
    {
        var length = xPaths.length;
        
        if(length > 0)
        {
            // Remove XPaths from data model
            var dm = FormController.getInstance().getDataModel();
            
            dm._startTransaction();
            
            for(var i = 0; i < length; i++)
            {
                dm.removeNode( xPaths[i] );
            }
            
            dm._endTransaction();
            
        }
        
    }
    
}

/*
 * Function to block form events
 */
FormElementGUIAdaptor.prototype._blockEventsForForm = function(evt)
{
	if (null == evt) { evt = window.event; }
	SUPSEvent.preventDefault(evt);
	return false;
}

/**
 * Method disables drag and drop functionality
 * on form.
 *
 * @param evt Instance of onDragStart event.
 *
*/
FormElementGUIAdaptor.prototype._disableDragAndDrop = function(evt)
{
    if(null == evt) { evt = window.event; }
    
    var formElement = this.getElement();
    
    if(formElement.attachEvent)
    {
        // IE browser - do not prevent default action, rather set data
        // transfer effect allowed option to none to disable data transfer       
		try
		{
	        // D1118 - The data transfer object can sometimes be empty.
	        // Accessing it when it is results in an unspecified error
        	evt.dataTransfer.effectAllowed = "none";
        }
        catch(e)
        {
        	// Error occurred, so just prevent default browser action
        	SUPSEvent.preventDefault(evt);
        }
    }
    else if(formElement.addEventListener)
    {
        // W3C or Mozilla
        SUPSEvent.preventDefault(evt);
    }
    
    return false;
}


/**
 * GUIAdaptor which creates a second "form within a form" - containing
 * a full FormController, DataModel etc (but no AppController)
 */
function SubformElementGUIAdaptor() {};


/**
 * Subforms derived from FormElementGUIAdaptor
 */ 
SubformElementGUIAdaptor.prototype = new FormElementGUIAdaptor();


/**
 * Set the constructor property so we can identify the type
 */
SubformElementGUIAdaptor.prototype.constructor = SubformElementGUIAdaptor;


SubformElementGUIAdaptor.CSS_CLASS = "subform";


/**
 * Subform required databinding is different to forms
 */
SubformElementGUIAdaptor.prototype.FORM_REQUIRED_DATABINDING_ROOT = FormDatabindings.DEFAULT_SUBFORM_DATABINDING_ROOT;

/**
 * Initialise the FormElementGUIAdaptor
 *
 * @param e the input element to manage
 */
SubformElementGUIAdaptor.create = function(e)
{
	var a = new SubformElementGUIAdaptor();
	
	a._initialiseAdaptor(e);	
	
	return a;
}

/*
 * Configures cancel and submit business lifecycles 
 * before invoking the parent and passing up the remaining configurations.
 */
SubformElementGUIAdaptor.prototype._configure = function(cs)
{
	this.includeInValidation = false;
	
	var cancelBusinessLifeCycle = new CancelSubformBusinessLifeCycle();
	cancelBusinessLifeCycle.initialise(this);
	this.addBusinessLifeCycle(cancelBusinessLifeCycle);
	
	var submitSubformBusinessLifeCycle = new SubmitSubformBusinessLifeCycle();
	submitSubformBusinessLifeCycle.initialise(this);
	this.addBusinessLifeCycle(submitSubformBusinessLifeCycle);
	
	var cancel = null;
	var submit = null;
	
	var newCs = new Array();

	// Run through configuration specific to this element
	for(var i = 0, l = cs.length; i < l; i++)
	{
		var c = cs[i];
		
		// Get the event configuration objects for CANCEL
		if(c.cancelLifeCycle && cancel == null)
		{
			cancelBusinessLifeCycle.configure(c.cancelLifeCycle);
			cs[i].cancelLifeCycle = null;
		}
		
		// Get the event configuration objects for SUBMIT
		if(c.submitLifeCycle && submit == null)
		{
			submitSubformBusinessLifeCycle.configure(c.submitLifeCycle);
			cs[i].submitLifeCycle = null;
		}
	}

	
	// Start form life cycle event handlers 
	cancelBusinessLifeCycle.start();
	submitSubformBusinessLifeCycle.start();

	// Call parent and process remaining configuration items. 
    FormElementGUIAdaptor.prototype._configure.call(this,cs);
    
}


SubformElementGUIAdaptor.prototype.renderState = function()
{
	this._renderForm(SubformElementGUIAdaptor.CSS_CLASS);
}


/**
 * Stores an array of nodes (relative to /ds/var) which will 
 * not be cleared when clearDataModel is invoked.
 */
SubformElementGUIAdaptor.prototype.m_dmClearExclusionNodes = new Array("app","form","subform");



// Just to help define what we are expecting for tab selector initialisation
function TabDef(tabLabel, pageId)
{
	this.tabLabel = tabLabel;
	this.pageId = pageId;
}


function _fwTab(selector, tdElement, label, pageId)
{
	this.m_tabSelector = selector;
	this.m_tdElement = tdElement;
	this.m_label = label;
	this.m_pageId = pageId;
}


_fwTab.prototype.m_tabSelector = null;

_fwTab.prototype.m_enabled = true;

_fwTab.prototype.m_label = null;

_fwTab.prototype.m_tdElement = null;

_fwTab.prototype.m_pageId = null;

_fwTab.prototype.m_clickHandler = null;

_fwTab.prototype.m_selected = false;

_fwTab.prototype.m_submissable = true;



_fwTab.prototype.setEnabled = function(enabled)
{
	if(this.m_enabled != enabled)
	{
		this.m_enabled = enabled;
		return true;
	}
	else
	{
		return false;
	}
}


_fwTab.prototype.isEnabled = function()
{
	return this.m_enabled;
}


_fwTab.prototype.setLabel = function(label)
{
	if(this.m_label != label)
	{
		this.m_label = label;
		return true;
	}
	else
	{
		return false;
	}
}


_fwTab.prototype.setSelected = function(selected)
{
	if(this.m_selected != selected)
	{
		this.m_selected = selected;
		return true;
	}
	else
	{
		return false;
	}
}

_fwTab.prototype.isSelected = function(selected)
{
	return this.m_selected;
}

_fwTab.prototype.setSubmissible = function(submissible)
{
	this.m_submissable = submissible;
}

_fwTab.prototype.getPageId = function()
{
	return this.m_pageId;
}


_fwTab.prototype.renderState = function()
{
	var cellElement = this.m_tdElement;
	var tdClassName = TabSelector.TAB_CELL_CSS_CLASS;
	var divClassName = TabSelector.TAB_CELL_DIV_CSS_CLASS;
	
	if(this.m_enabled && this.m_tabSelector.isEnabled())
	{
		if(null == this.m_clickHandler)
		{
			var thisObj = this;
			this.m_clickHandler = SUPSEvent.addEventHandler(cellElement, "mousedown", function(evt) { thisObj.m_tabSelector._onCellClick(thisObj); }, false);
		}
		
		if(this.m_selected)
		{
			tdClassName += " " + TabSelector.TAB_CELL_SELECTED_CSS_CLASS;

			if(this.m_tabSelector.m_focussed)
			{
				tdClassName += " " + TabSelector.TAB_CELL_FOCUSSED_CSS_CLASS;
				divClassName += " " + TabSelector.TAB_CELL_DIV_FOCUSSED_CSS_CLASS;
                
                if(cellElement.focus)
                {
	                // We need to focus the div to make sure that the 
	                // key events (ie arrow keys) are applied to the
	                // correct element.
	                cellElement.focus();
	            }
			}
		}
        		
		if(!this.m_submissable)
		{
			tdClassName += " " + TabSelector.TAB_CELL_NOT_SUBMISSIBLE_CSS_CLASS;
		}
		
	}
	else
	{
		tdClassName += " " + TabSelector.TAB_CELL_DISABLED_CSS_CLASS;
	
		this._removeClickHandler();
	}
	
	cellElement.className = tdClassName;
	cellElement.firstChild.className = divClassName;
	cellElement.firstChild.innerHTML = this.m_label;	
}


_fwTab.prototype._removeClickHandler = function()
{
	if(null != this.m_clickHandler)
	{
		SUPSEvent.removeEventHandlerKey(this.m_clickHandler);
		this.m_clickHandler = null;
	}
}


_fwTab.prototype.dispose = function()
{
	this._removeClickHandler();
}


function TabSelector(){};

/**
 * TabSelector is a sub class of Renderer
 */
TabSelector.prototype = new Renderer();
TabSelector.prototype.constructor = TabSelector;

TabSelector.prototype.m_cellClickHandlers = null;

/*
 * CSS Class name defintions
 */
TabSelector.TABSEL_WRAPPER_CSS_CLASS_NAME = "tabselectorwrapper";
TabSelector.TAB_SELECTOR_CSS_CLASS = "tabselector";
TabSelector.TAB_CELL_CSS_CLASS = "tabCell";
TabSelector.TAB_CELL_UNSELECTED_CSS_CLASS = "tabCellUnselected";
TabSelector.TAB_CELL_SELECTED_CSS_CLASS = "tabCellSelected";
TabSelector.TAB_CELL_DISABLED_CSS_CLASS = "tabCellDisabled";
TabSelector.TAB_CELL_FOCUSSED_CSS_CLASS = "tabCellFocus";
TabSelector.TAB_CELL_NOT_SUBMISSIBLE_CSS_CLASS = "tabCellNotSubmissible";
TabSelector.TAB_CELL_DIV_CSS_CLASS = "tabCellDiv";
TabSelector.TAB_CELL_DIV_FOCUSSED_CSS_CLASS = "tabCellDivFocus";
TabSelector.SPACER_CSS_CLASS = "tabSpacer";
TabSelector.VISIBILITY_HIDDEN = "hidden";
TabSelector.VISIBILITY_INHERIT = "inherit";
TabSelector.VISIBILITY_VISIBLE = "visible";
TabSelector.TABBED_AREA_CSS_CLASS_NAME = "tabbedArea";


/**
 * Enablement state of the tab selector. Defaults to enabled when initially rendered
 *
 * @type boolean
 * @private
 */
TabSelector.prototype.m_enabled = true;


/**
 * Flag to indicate overall TabSelector enablement state has changed since last render
 *
 * @type boolean
 * @private
 */
TabSelector.prototype.m_enabledChanged = false;


/**
 * Flag to indicate whether or not the tab selector has focus or not
 *
 * @type boolean
 * @private
 */
TabSelector.prototype.m_focussed = false;


/**
 * Create a tab selector at the current location in the document while document
 * is parsing.
 *
 * The tabDefs parameter is an array of objects which define the tabs
 * to create in the selector. Each object must have pageId and tabLabel
 * properties. tabLabel is the text to display in the tab. pageId is the 
 * ID of the HTML page element associated with this tab.
 *
 * @param id the id of the tab selector being created
 * @param tabDefs an array which defines the tabs to create in the tab selector
 */
TabSelector.createInline = function(id, tabDefs)
{
	// Create the outer div by writing to the document.
	var e = Renderer.createInline(
		id,			// The id of the tab selector being created
		true		// The tab selector doesn't have any internal input element which can accept focus, so the div should accept focus
	);

	return TabSelector._create(e, tabDefs);
}

/**
 * Create a tab selector in the document relative to the supplied element
 *
 * The tabDefs parameter is an array of objects which define the tabs
 * to create in the selector. Each object must have pageId and tabLabel
 * properties. tabLabel is the text to display in the tab. pageId is the 
 * ID of the HTML page element associated with this tab.
 *
 * @param refElement the element relative to which the tab selector should be rendered
 * @param relativePos the relative position of the tab selector to "refElement".
 * Valid values are:
 *     Renderer.CHILD_ELEMENT    Created as a child of "refElement"
 *     Renderer.BEFORE_ELEMENT   Created as preceeding sibling of "refElement"
 *     Renderer.AFTER_ELEMENT    Created as following sibling of "refElement"

 * @param id the id of the tab selector being created
 * @param tabDefs an array which defines the tabs to create in the tab selector
 */
TabSelector.createAsInnerHTML = function(refElement, relativePos, id, tabDefs)
{
	var e = Renderer.createAsInnerHTML(
		refElement,		// The element relative to which to create the outer div in the document
		relativePos,	// Relative position of the outer div to the reference element
		id,				// The id of the tab selector being created
		true			// The tab selector doesn't have any internal input element which can accept focus, so the div should accept focus
	);

	return TabSelector._create(e, tabDefs);
}

/**
 * Create a tab selector as a child of another element
 *
 * The tabDefs parameter is an array of objects which define the tabs
 * to create in the selector. Each object must have pageId and tabLabel
 * properties. tabLabel is the text to display in the tab. pageId is the 
 * ID of the HTML page element associated with this tab.
 *
 * @param p the parent element to which the tab selector should be added
 * @param id the id of the tab selector being created
 * @param tabDefs an array which defines the tabs to create in the tab selector
 */
TabSelector.createAsChild = function(p, id, tabDefs)
{
	var e = Renderer.createAsChild(id);

	// Append the tab selector's outer div to it's parent element
	p.appendChild(e);	

	return TabSelector._create(e, tabDefs);
}

TabSelector._create = function(e, tabDefs)
{
	// Set the class of the element wrapping this selector
	e.className = TabSelector.TABSEL_WRAPPER_CSS_CLASS_NAME;

	var r = new TabSelector();
	
	// Initialise sets main element and the reference to the renderer in the dom
	r._initRenderer(e);
	
	r.m_cellClickHandlers = new Array();

	// Prevent the selection of text content in the tab selector
	preventSelection(e);
	
	// Create the table element and set its class
	r.m_tabsTable = Renderer.createElementAsChild(e, "table");
	r.m_tabsTable.className = TabSelector.TAB_SELECTOR_CSS_CLASS;
	
	// Ideally this attribute could be specified in the stylesheet,
	// but CSS support in this area is too flaky.
	r.m_tabsTable.setAttribute("cellspacing", "0px");
	r.m_tabsTable.setAttribute("cellpadding", "0px");

	var tbody = Renderer.createElementAsChild(r.m_tabsTable, "tbody");
	var row = Renderer.createElementAsChild(tbody, "tr");
	
	r.m_tabs = new Array(tabDefs.length);
	
	var cellIdBase = e.id + "_id";
	
	for(var i = 0 ; i < tabDefs.length ; i++)
	{
		var tabDef = tabDefs[i];
		var pageId = tabDef.pageId;
		var label = tabDef.tabLabel;
		if(null == pageId || "" == pageId || null == label || "" == label)
		{
			throw new ConfigurationException("tabDefs parameter must contain objects with a pageId and tabLabel properties");
		}

	    // Create cell element
		var cellId = cellIdBase + i.toString();
		var cell = Renderer.createElementAsChild(row, "td")
		cell.id = cellId;
		cell.className = TabSelector.TAB_CELL_CSS_CLASS;
				
		// Create inner division to store text
		var cellInnerDiv = Renderer.createElementAsChild( cell, "div" );
		cellInnerDiv.innerHTML = label;
		cellInnerDiv.className = TabSelector.TAB_CELL_DIV_CSS_CLASS;

		r.m_tabs[i] = new _fwTab(r, cell, label, pageId);
		r.m_tabs[i].renderState();
	}
	
	var spacer = Renderer.createElementAsChild(row, "td");
	spacer.className = TabSelector.SPACER_CSS_CLASS;
	// Need to have something in the cell otherwise the border is not rendered
	spacer.innerHTML = "&nbsp;";

	r.setTabClickHandler(function(clickedTab) {r._unmanagedClickHandler(clickedTab);});
	
	return r;
}


/**
 * Called by tabselector GUI adaptor to dispose of 
 * this object
 * @private
 */
TabSelector.prototype.dispose = function()
{
	// Remove selection prevention event handler from drop down
	unPreventSelection(this.m_element);

	for(var i = 0, l = this.m_tabs.length ; i < l ; i++) 
	{
		this.m_tabs[i].dispose();
	}
}


/**
 * onClick event handler which is used only when the TabbedDialogue 
 * is used outside of the framework (i.e. when the HTML screen painter
 * is developing the screens).
 *
 * @param tab The _fwTab which was clicked on
 * @private
 */
TabSelector.prototype._onCellClick = function(clickedTab)
{
	// If there has been a change in the currently selected tab
	if(this.m_currentTab != clickedTab)
	{
		// Call the function which is currently handling tab clicks
		this.m_tabClickHandler.call(null, clickedTab);
	}
}


/**
 * Set the handler function which deals with clicks on tabs in the tabselector
 *
 * @param handler the function to invoke when a tab is clicked on in the tabselector
 */
TabSelector.prototype.setTabClickHandler = function(handler)
{
	this.m_tabClickHandler = handler;
}


/**
 * Default tab click handler - allows the tab selector to display
 * pages in a paged area without involvement of GUIAdaptors. Useful
 * during page development.
 *
 * @param clickedTab the _fwTab that was clicked on
 */
TabSelector.prototype._unmanagedClickHandler = function(clickedTab)
{
	// Check for initialisation condition
	if(null != this.m_currentTab)
	{
		this.m_currentTab.setSelected(false);
		this.m_currentTab.renderState();
	}
	
	this.m_currentTab = clickedTab;
	this.m_currentTab.setSelected(true);
	this.m_currentTab.renderState();
	
	// Check for initialisation condition
	if(null != this.m_currentPageElement)
	{
		this.m_currentPageElement.style.visibility = TabSelector.VISIBILITY_HIDDEN;
	}
	
	// Find the page element
	this.m_currentPageElement = document.getElementById(this.m_currentTab.getPageId());
	
	// It's possible that page is a dynamic page and has therefore not yet been created yet.
	// Alternatively it could just be a bad id, but we can only determine this once the
	// GUIAdaptors have been created.
	if(null != this.m_currentPageElement)
	{
		this.m_currentPageElement.style.visibility = TabSelector.VISIBILITY_INHERIT;			
	}
}


/**
 * Get the tab which correspondes to a give page id
 *
 * @param pageId the id of the page for which to get the corresponding tab
 * @return the tab which corresponds to the given pageId or null if no 
 *    corresponding tab was found
 */
TabSelector.prototype._getTabForPageId = function(pageId)
{
	var t = this.m_tabs;

	for(var i = 0, l = t.length; i < l; i++)
	{
		if(pageId == t[i].getPageId())
		{
			return t[i];
		}
	}
	
	return null;
}


/**
 * Get the Paged Area associated with this tab selector
 *
 * @return the div which represents the paged area
 * @throws ConfigurationException if a paged area was not found
 * @private
 */
TabSelector.prototype._getAssociatedPagedArea = function()
{
	if(null == this.m_associatedPagedArea)
	{
		// TabSelector and PagedArea should be siblings
		var kids = this.m_element.parentNode.childNodes;
		
		for(var i = 0, l = kids.length; i < l; i++)
		{
			var kid = kids[i];
			
			// Only care about elements of type div with className that corresponds to the paged area
			if(1 == kid.nodeType && "DIV" == kid.nodeName && PagedAreaGUIAdaptor.CSS_CLASS_NAME == kid.className)
			{
				this.m_associatedPagedArea = kid;
				break;
			}
		}
		
		if (null == this.m_associatedPagedArea) throw new ConfigurationException("Could not find pagedArea associated with TabSelector: " + this.m_element.id);
	}
	
	return this.m_associatedPagedArea;
}


/**
 * Enable or disable the tabselector
 *
 * @param enabled true to enable, false to disable
 * @return true if the enablement state of the TabSelector changed
 * @type boolean
 */
TabSelector.prototype.setEnabled = function(enabled)
{
	if(this.m_enabled != enabled)
	{
		this.m_enabled = enabled;
		
		// Toggle m_enabledChanged flags
		this.m_enabledChanged = !this.m_enabledChanged;
		return true;
	}
	else
	{
		return false;
	}
}


TabSelector.prototype.isEnabled = function()
{
	return this.m_enabled;
}


TabSelector.prototype.renderState = function()
{
	if(this.m_enabledChanged)
	{
		// If enablement state of the TabSelector has changed, need
		// to re-render all of the tabs on the TabSelector
		var t = this.m_tabs;

		for(var i = 0, l = t.length; i < l; i++)
		{
			t[i].renderState();
		}
		this.m_enabledChanged = false
	}
}


/**
 * Checks whether all tabs on the tabselector are disabled or not
 *
 * @return true if all tabs on the tab selector are disabled, false otherwise
 * @type boolean
 * @private
 */
TabSelector.prototype.getAllTabsDisabled = function()
{
	var t = this.m_tabs;
	
	for(var i = 0, l = t.length; i < l; i++)
	{
		if(t[i].isEnabled()) return false;
	}
	
	return true;
}


TabSelector.prototype.getCurrentlySelectedTab = function()
{
	// Get the position of the currently selected tab
	var pos = this._getPositionOfCurrentlySelectedTab();
	
	// Return the currently selected tab, if there is one
	return (null == pos ? null : this.m_tabs[pos]);
}


TabSelector.prototype.setFocus = function(focussed)
{
	this.m_focussed = focussed;
	var tab = this.getCurrentlySelectedTab();
	if(null != tab)
	{
		tab.renderState();
	}
}


TabSelector.prototype.setTabSelectionState = function(tab, selected)
{
	if(tab.setSelected(selected))
	{
		tab.renderState();
	}
}


TabSelector.prototype.setTabLabel = function(tab, label)
{
	if(tab.setLabel(label))
	{
		tab.renderState();
	}
}


TabSelector.prototype.setTabEnablementState = function(tab, enabled)
{	
	if(tab.setEnabled(enabled))
	{
		// Ought to track which tabs have changed and then render them all at the end.
		tab.renderState();
	}
}


TabSelector.prototype.selectPreviousTab = function()
{
	// Get the position of the currently selected tab if there is one
	var initialPos = this._getPositionOfCurrentlySelectedTab();
	
	// If no currently selected tab, then wrap round the rightmost tab (actually start at beginning of tab order and work backwards)
	if(null == initialPos) initialPos = 0;
	
	var pos = initialPos;
	
	// loop round through the array, wrapping round, until we reach our starting position again.
	do
	{
		// Move to previous tab
		pos--;
		
		// If we've gone past the beginning of the array, wrap round to the end
		if(pos < 0) pos = this.m_tabs.length - 1;
		
		// When we find a tab that can accept the focus, break out of the loop
		if(this.m_tabs[pos].isEnabled()) break;
	} while (pos != initialPos);
	
	// If position is not the same position as we started on then select the new tab 
	// (and corresponding page). This is treated as a click on the tab
	if(pos != initialPos)
	{
		// Found another tab that could accept the focus
		this._onCellClick(this.m_tabs[pos]);
	}
}


TabSelector.prototype.selectNextTab = function()
{
	// Get the position of the currently selected tab if there is one
	var initialPos = this._getPositionOfCurrentlySelectedTab();
	
	// If no currently selected tab, then wrap round the leftmost tab (actually start at end of tab order and work forwards)
	if(null == initialPos) initialPos = this.m_tabs.length - 1;
	
	var pos = initialPos;
	
	// loop round through the array, wrapping round, until we reach our starting position again.
	do
	{
		// Move to previous tab
		pos++;
		
		// If we've gone past the end of the array, wrap round to the beginning
		if(pos >= this.m_tabs.length) pos = 0;
		
		// When we find a tab that can accept the focus, break out of the loop
		if(this.m_tabs[pos].isEnabled()) break;
	} while (pos != initialPos);
	
	// If position is not the same position as we started on then select the new tab 
	// (and corresponding page). This is treated as a click on the tab
	if(pos != initialPos)
	{
		// Found another tab that could accept the focus
		this._onCellClick(this.m_tabs[pos]);
	}
}


TabSelector.prototype._getPositionOfCurrentlySelectedTab = function()
{
	var t = this.m_tabs;

	for(var i = 0, l = t.length; i < l; i++)
	{
		if(t[i].isSelected()) return i;
	}
	
	return null;
}


/**
 * Style sheet puts a -2px margin on the table containing the tab selector.
 * This adjusts the overall width of the outer div to ensure that the bottom
 * border of the spacer cell extends to the right border of the paged area.
 *
 * @private
 */
TabSelector.prototype._setTabSelectorWidth = function()
{
	var pagedArea = this._getAssociatedPagedArea();

	var style = getCalculatedStyle(pagedArea);
	var borderWidth = style.borderRightWidth.slice(0, -2);

	// If stylesheet has not loaded then this will be "medium", if so default to 1px
	borderWidth = isNaN(borderWidth) ? 1 : Number(borderWidth);

	style = getCalculatedStyle(this.m_tabsTable);
	var marginWidth = style.marginRight.slice(0, -2);

	// If stylesheet has not loaded then this will be "auto", if so default to 2px
	marginWidth = isNaN(marginWidth) ? 2 : Math.abs(Number(marginWidth));

	// Adjust width for the table right margin plus the paged area right border
	this.m_element.style.width = pagedArea.offsetWidth + marginWidth + borderWidth + "px";
}

//==================================================================
//
// Button.js
//
// Implementation of a Button GUI object using html div tags.
//
//==================================================================


/**
 * GUI Button object which is implemented using html div tags.
 *
 * To create an object, use one of the factory methods:
 *   Button.createInline()
 *   Button.createAsChild()
 *
 * @constructor
 * @private
 */
function Button()
{
}


/**
 * The main element of the button
 *
 * @type HTMLElement
 * @private
 */
Button.prototype.m_element = null;


/**
 * The inner element of the button
 *
 * @type HTMLElement
 * @private
 */
Button.prototype.m_inner = null;


/**
 * The enablement state of the button
 *
 * @type boolean
 * @private
 */
Button.prototype.m_disabled = false;


/**
 * The repeat interval for the button. When this
 * is none zero and the button is clicked and held,
 * the clickListeners will notified of a click at
 * this interval.
 *
 * @type Integer
 * @private
 */
Button.prototype.m_repeatInterval = 0;


Button.m_clickedButton = null;

Button.m_timeoutID = null;


/**
 * The pressed state of the button
 *
 * @type boolean
 * @private
 */
Button.prototype.m_pressed = false;


/**
 * Additional CSS classes for the button
 *
 * @type String
 * @private
 */
Button.prototype.m_addClasses = null;


/**
 * Button released flag
 *
 * @type boolean
 * @private
 */
Button.prototype.m_buttonReleased = true;


/**
 * Listeners which receive click events
 *
 * @type CallbackList
 * @private
 */
Button.prototype.m_clickListeners = null;


/**
 * Key to the event handler for mousedown events
 *
 * @type EventHandlerKey
 * @private
 */
Button.prototype.m_mousedownHandler = null;


/**
 * Key to the event handler for mousedown events
 *
 * @type EventHandlerKey
 * @private
 */
Button.prototype.m_mouseupHandler = null;


/**
 * Key to the event handler for mousedown events
 *
 * @type EventHandlerKey
 * @private
 */
Button.prototype.m_mouseoutHandler = null;


/**
 * Key to the event handler for mousedown events
 *
 * @type EventHandlerKey
 * @private
 */
Button.prototype.m_mouseoverHandler = null;


/**
 * Create a button at the current position in the HTML document
 *
 * @param id the id to give the newly created button
 * @return the newly created Button
 * @type Button
 */
Button.createInline = function(id)
{
  // Write the outer button element to the document
  document.write("<div id='" + id + "'></div>");

  // Get the element using its id
  var e = document.getElementById(id);

  // Create the rest of the button
  return Button._createButton(e, null);
}


/**
 * Create a button as a child of another html element
 *
 * @param p the parent element to add the Button to.
 * @param id the id to give the newly created button
 * @param ac additional css classes to add to the button
 * @return the newly created Button
 * @type Button
 */
Button.createAsChild = function(p, id, ac)
{
  // Create the outer button element
  var b = document.createElement("div");
  
  if(null != id) b.id = id;

  // Append the button to it's parent element
  p.appendChild(b);

  // Create the rest of the button
  return Button._createButton(b, ac);
}


/**
 * Common button creation code shared by factory methods.
 *
 * @param be the main button element
 * @param ac additional css classes to add to the button
 * @return the new Button object
 * @type Button
 * @private
 */
Button._createButton = function(be, ac)
{
  var b = new Button();
  b.m_element = be;
  b.m_inner = document.createElement("div");
  be.appendChild(b.m_inner);

  // Prevent selection of the button label
  preventSelection(be);

  b.m_disabled = false;
  b.m_addClasses = ac;
  b.m_buttonReleased = true;
  b.m_clickListeners = new CallbackList();
  b._render();

  this.m_mousedownHandler = null;
  this.m_mouseupHandler = null;
  this.m_mouseoutHandler = null;
  this.m_mouseoverHandler = null;

  // Set a property on the main div element so that the Adapter can have
  // rapid access to this class.
  be.__renderer = b;

  return b;
}


/**
 * Clean up after the component
 */
Button.prototype.dispose = function()
{
	// Break circular reference in HTML
	this.m_element.__renderer = null;

	this.stopEventHandlers();  

	unPreventSelection(this.m_element);

	// Get rid of listeners	
	this.m_clickListeners.dispose();
	this.m_clickListeners = null;
	this.m_element = null;
}


Button.prototype.startEventHandlers = function()
{
	if(null == this.m_mousedownHandler)
	{
		var b = this;
		b.m_mousedownHandler = SUPSEvent.addEventHandler(b.m_element, "mousedown", function() { b._handleMouseDown(); });
	}
}


Button.prototype.stopEventHandlers = function()
{
  	// Release event handlers
	if(null != this.m_mousedownHandler)
	{
		SUPSEvent.removeEventHandlerKey(this.m_mousedownHandler);
		this.m_mousedownHandler = null;
	}
	
  	// Release event handlers
	if(null != this.m_mouseupHandler)
	{
		SUPSEvent.removeEventHandlerKey(this.m_mouseupHandler);
		this.m_mouseupHandler = null;
	}
	
  	// Release event handlers
	if(null != this.m_mouseoutHandler)
	{
		SUPSEvent.removeEventHandlerKey(this.m_mouseoutHandler);
		this.m_mouseoutHandler = null;
	}
	
  	// Release event handlers
	if(null != this.m_mouseoverHandler)
	{
		SUPSEvent.removeEventHandlerKey(this.m_mouseoverHandler);
		this.m_mouseoverHandler = null;
	}
}


/**
 * Set the disablement state of the button
 *
 * @param disable boolean to indicate whether the button is disabled or not.
 */
Button.prototype.setDisable = function(disable)
{
  if(this.m_disabled != disable)
    {
      this.m_disabled = disable;
      this._render();
    }
}


/**
 * Register a callback to be notified when the button is clicked.
 *
 * @param cb the function called when the button is clicked.
 */
Button.prototype.addClickListener = function(cb)
{
  this.m_clickListeners.addCallback(cb);
}


/**
 * Set the time interval in milliseconds between click notification
 * if the button is clicked and held.
 *
 * @param initialDelay the delay after the initial click before
 *   the button starts sending repeated click events.
 * @param repeatInterval the interval between click events when
 *   repeating
 */
Button.prototype.setRepeatInterval = function(initialDelay, repeatInterval)
{
	this.m_initialDelay = initialDelay;
	this.m_repeatInterval = repeatInterval;
}


/**
 * Event handler that is called when the mouse button is pressed
 *
 * @private
 */
Button.prototype._handleMouseDown = function()
{
	this.m_pressed = true;
	this.m_buttonReleased = false;
	b = this;

	// Add event handlers needed while button is pressed.
	if(null == this.m_mouseupHandler)
	{
		this.m_mouseupHandler = SUPSEvent.addEventHandler(document, "mouseup", function() { b._handleMouseUp(); }, null);
	}

	if(null == this.m_mouseoutHandler)
	{
		this.m_mouseoutHandler = SUPSEvent.addEventHandler(this.m_element, "mouseout", function() { b._handleMouseOut(); }, null);
	}

	if(null == this.m_mouseoverHandler)
	{
		this.m_mouseoverHandler = SUPSEvent.addEventHandler(this.m_element, "mouseover", function() { b._handleMouseOver(); }, null);
	}

	this._render();
	
	if(0 != this.m_repeatInterval)
	{
		Button.m_clickedButton = this;
		this._startRepeat(this.m_initialDelay);
	}
}


Button._clickRepeat = function()
{
	var b = Button.m_clickedButton;
	if(b != null)
	{
		b._startRepeat(b.m_repeatInterval);
	}
}


Button.prototype._startRepeat = function(timeout)
{
	// Listeners invoked immediately
	this.m_clickListeners.invoke();
	
	Button.m_timeoutID = setTimeout("Button._clickRepeat()", timeout);	
}


/**
 * Event handler called when the mouse button is released
 *
 * @private
 */
Button.prototype._handleMouseUp = function()
{
	this.m_pressed = false;
	this.m_buttonReleased = true;
	this._render();

	// Remove event handlers needed while button is pressed.
	SUPSEvent.removeEventHandlerKey(this.m_mouseupHandler);
	SUPSEvent.removeEventHandlerKey(this.m_mouseoutHandler);
	SUPSEvent.removeEventHandlerKey(this.m_mouseoverHandler);
	this.m_mouseupHandler = null;
	this.m_mouseoutHandler = null;
	this.m_mouseoverHandler = null;

	// If this is none repeating button, invoke the listeners when
	// it is released.
	if(0 == this.m_repeatInterval)
	{
		this.m_clickListeners.invoke();
	}
	else
	{
		if(null != Button.m_timeoutID)
		{
			clearTimeout(Button.m_timeoutID);
			Button.m_timeoutID = null;
		}
	}
	Button.m_clickedButton = null;
}


/**
 * Event handler called when the mouse pointer leaves the button
 *
 * @private
 */
Button.prototype._handleMouseOut = function()
{
  this.m_pressed = false;
  this._render();
}


/**
 * Event handler called when the mouse pointer enters the button
 *
 * @private
 */
Button.prototype._handleMouseOver = function()
{
  this.m_pressed = !this.m_buttonReleased;
  this._render();
}


/**
 * Method which renders the button according to its state
 *
 * @private
 */
Button.prototype._render = function()
{
  var oc = "button";
  var ic = "button_inner";
  var ac = "";
  if(this.m_disabled)
  {
    ac += " disabled";
  }
  else
  {
    if(this.m_pressed)
    {
      ac += " pressed";
    }
  }
  
  // Set class of inner div without additional classnames specified in the constructor
  this.m_inner.className = ic + ac;

  // Add any additional external style classes
  if(null != this.m_addClasses)
  {
    ac += " " + this.m_addClasses;
  }
  this.m_element.className = oc + ac;
}

//==================================================================
//
// Scrollbar.js
//
// Implementation of a Scrollbar GUI object using html div tags.
//
//==================================================================


var isIE = !(document.implementation && document.implementation.createDocument);


function Scrollbar()
{
}

Scrollbar.m_logger = new Category("Scrollbar");

// Define class variable for minimum scroll bar size

Scrollbar.MINIMUM_HEIGHT = 40;

// Define instance variables

Scrollbar.prototype.m_element = null;

Scrollbar.prototype.m_vertical = true;

Scrollbar.prototype.m_decButton = null;

Scrollbar.prototype.m_container = null;

Scrollbar.prototype.m_slider = null;

Scrollbar.prototype.m_sliderInner = null;

Scrollbar.prototype.m_incButton = null;

Scrollbar.prototype.m_min = 0;

Scrollbar.prototype.m_max = 100;

Scrollbar.prototype.m_proportion = 100;

Scrollbar.prototype.m_position = 0;

Scrollbar.prototype.m_increment = 100;

Scrollbar.prototype.m_dragStartX = null;

Scrollbar.prototype.m_dragStartY = null;

Scrollbar.prototype.m_changeListeners = null;

Scrollbar.prototype.m_mousedownHandler = null;

Scrollbar.prototype.m_mouseupHandler = null;

Scrollbar.prototype.m_mousemoveHandler = null;

Scrollbar.prototype.m_registerWithStyleManager = null;

Scrollbar.prototype.m_resetVScrollbarHeight = null;

Scrollbar.REPEAT_INITIAL_DELAY = 250;

Scrollbar.REPEAT_INTERVAL = 100;

/**
 * Create a scrollbar at the current position in the HTML document
 *
 * @param id the id to give the newly created Scrollbar
 * @param vertical true if this a vertical scrollbar, false if it is horizontal
 * @param registerWithStyleManager In most cases scroll bars are rendered before
 *                                 a form's style sheets are loaded. When this occurs a
 *                                 small correction to the height of the scroll bar may
 *                                 be required. This is achieved by the scrollbar registering a 
 *                                 callback function with the style manager. In the case of
 *                                 the framework select component the scroll bar will be rendered
 *                                 after the form's style sheet has loaded. Therefore, a callback
 *                                 function is not required. This flag is used to indicate,
 *                                 whether or not, the callback function should be registered
 *                                 with the style manager. The default value is "true".
 * @return the newly created Button
 * @type Button
 */
Scrollbar.createInline = function(id, vertical, registerWithStyleManager)
{
  // Write the outer button element to the document
  document.write("<div id='" + id + "'></div>");

  // Get the element using its id
  var e = document.getElementById(id);

  // Create the rest of the button
  return Scrollbar._create(e, vertical, null, registerWithStyleManager);
}


/**
 * Create a scrollbar as a child of another html element
 *
 * @param p the parent element to add the Scrollbar to.
 * @param id the id to give the newly created Scrollbar - may be null
 * @param vertical true if this a vertical scrollbar, false if it is horizontal
 * @param ac additional css classes to add to the Scrollbar
 * @param registerWithStyleManager Boolean flag indicating whether, or not,
 *                                 the scroll bar should register a callback
 *                                 function with the style manager.
 * @return the newly created Button
 * @type Button
 */
Scrollbar.createAsChild = function(p, id, vertical, ac, registerWithStyleManager)
{
  // Create the outer button element
  var e = document.createElement("div");
  
  if(null != id) e.id = id;

  // Append the button to it's parent element
  p.appendChild(e);

  // Create the rest of the button
  return Scrollbar._create(e, vertical, ac, registerWithStyleManager);
}



Scrollbar._create = function(sbe, vertical, ac, registerWithStyleManager)
{
	var sb = new Scrollbar();
	
	sb.m_element = sbe;
	sb.m_element.className = "scrollbar scrollbar_" + (vertical ? "vertical" : "horizontal");
	
	if(registerWithStyleManager == false)
	{
	    sb.m_registerWithStyleManager = false;
	}
	else
	{
	    sb.m_registerWithStyleManager = true;
	}
	
	if(isIE)
	{
		// Normal stylesheets get this right in mozilla, however
		// on IE we need an expression to
		// calculate the height.
		sbe.style.height = Scrollbar._calculateHeight(sbe) + "px";
		
		if(vertical && sb.m_registerWithStyleManager)
		{
		    // Register function used to resize vertical scrollbar
		    // after CSS load
		    sb._registerResetVScrollBarHeight();
		}
	}

	sb.m_vertical = vertical;

	sb.m_decButton = Button.createAsChild(sb.m_element, null, "dec");
	sb.m_decButton.setRepeatInterval(Scrollbar.REPEAT_INITIAL_DELAY, Scrollbar.REPEAT_INTERVAL);
	sb.m_decButton.addClickListener(function() { sb._handleDecrementClick(); });
  
	sb.m_container = document.createElement("div");
	sb.m_container.className = "scrollbar_container";
	sb.m_element.appendChild(sb.m_container);

	sb.m_slider = document.createElement("div");
	sb.m_slider.className = "scrollbar_slider button";
	sb.m_container.appendChild(sb.m_slider);
	var sliderInner = document.createElement("div");
	sliderInner.className = "button_inner";
	sb.m_slider.appendChild(sliderInner);

	sb.m_incButton = Button.createAsChild(sb.m_element, null, "inc");
	sb.m_incButton.setRepeatInterval(Scrollbar.REPEAT_INITIAL_DELAY, Scrollbar.REPEAT_INTERVAL);
	sb.m_incButton.addClickListener(function() { sb._handleIncrementClick(); });

	sb.m_min = 0;
	sb.m_max = 100;
	sb.m_proportion = 100;
	sb.m_position = 0;
	sb.m_increment = 100;

	sb.m_dragStartX = null;
	sb.m_dragStartY = null;

	sb.m_dragStartSliderX = null;
	sb.m_dragStartSliderY = null;

	sb.m_changeListeners = new CallbackList();

	sb.m_mousedownHandler = null;
	sb.m_mouseupHandler = null;
	sb.m_mousemoveHandler = null;

	sb._render();
	
	// Set a property on the main div element so that the Adapter can have
	// rapid access to this class.
	sbe.__renderer = sb;
	
	return sb;
}


/**
 * Clean up after the component
 */
Scrollbar.prototype.dispose = function()
{
	// Get rid of event handlers
	this.stopEventHandlers();  

	// Get rid of child buttons
	this.m_incButton.dispose();
	this.m_decButton.dispose();

	// Break circular reference in HTML
	this.m_element.__renderer = null;

	// Get rid of listeners	
	this.m_changeListeners.dispose();
	this.m_changeListeners = null;
	
	if(isIE && this.m_vertical && this.m_registerWithStyleManager)
	{
	    // Unregister function which resets scrolbar height
	    // after CSS load
	    this._unregisterResetVScrollBarHeight();
	}
}


Scrollbar.prototype.startEventHandlers = function()
{
	var sb = this;
	sb.m_mousedownHandler = SUPSEvent.addEventHandler(sb.m_slider, "mousedown", function(e) { sb._handleDragMouseDown(e); }, null);

	// event handlers to handle scrolling the scrollbar by pressing the mouse down and holding it above or below the slider
	sb.m_containerMouseDownHandler = SUPSEvent.addEventHandler(sb.m_container, "mousedown", function(e) { sb._handleMouseDownContainer(e); }, null);
	sb.m_containerMouseUpHandler = SUPSEvent.addEventHandler(sb.m_container, "mouseup", function(e) { sb._handleMouseUpContainer(e); }, null);

	this.m_incButton.startEventHandlers();
	this.m_decButton.startEventHandlers();
}


Scrollbar.prototype.stopEventHandlers = function()
{
	this.m_incButton.stopEventHandlers();
	this.m_decButton.stopEventHandlers();

  	// Release event handlers
	if(null != this.m_mousedownHandler)
	{
		SUPSEvent.removeEventHandlerKey(this.m_mousedownHandler);
		this.m_mousedownHandler = null;
	}
	
  	// Release event handlers
	if(null != this.m_mouseupHandler)
	{
		SUPSEvent.removeEventHandlerKey(this.m_mouseupHandler);
		this.m_mouseupHandler = null;
	}
	
  	// Release event handlers
	if(null != this.m_mousemoveHandler)
	{
		SUPSEvent.removeEventHandlerKey(this.m_mouseoutHandler);
		this.m_mouseoutHandler = null;
	}

	if(null != this.m_containerMouseDownHandler)
	{
		SUPSEvent.removeEventHandlerKey(this.m_containerMouseDownHandler);
		this.m_containerMouseDownHandler = null;
	}

	if(null != this.m_containerMouseUpHandler)
	{
		SUPSEvent.removeEventHandlerKey(this.m_containerMouseUpHandler);
		this.m_containerMouseUpHandler = null;
	}
}


Scrollbar.prototype.addPositionChangeListener = function(cb)
{
	this.m_changeListeners.addCallback(cb);
}


/**
 * Function call by proprietry Internet Explorer CSS
 * expression, which lays out the scrollbar correctly
 */
function ScrollbarCalculateHeightId(id)
{
	var sb = document.getElementById(id);
	return sb == null ? Scrollbar.MINIMUM_HEIGHT : Scrollbar._calculateHeight(sb);
}

Scrollbar._calculateHeight = function(scrollbar)
{
	var parent = scrollbar.parentElement;
	var height = parent.offsetHeight;
	
	return height < Scrollbar.MINIMUM_HEIGHT ? Scrollbar.MINIMUM_HEIGHT : parent.offsetHeight;
}


Scrollbar.prototype.setScaling = function(min, max, proportion, increment)
{
	this.m_min = min;
	this.m_max = max;
	this.m_proportion = proportion;
	
	this.m_increment = null == increment ? proportion : increment;
	
	this._render();
}


Scrollbar.prototype.setPosition = function(position)
{
	this.m_position = position;
}

Scrollbar.prototype.getPosition = function()
{
    return this.m_position;
}


Scrollbar.prototype._render = function()
{
	if(Scrollbar.m_logger.isTrace()) Scrollbar.m_logger.trace("SCROLLBAR: Scrollbar.prototype._render");
	var range = this.m_max - this.m_min;

	var scale;
	var start;
	if(0 == range)
	{
		scale = 1;
		start = 0;
	}
	else
	{
		scale = range/this.m_proportion;
		start = this.m_position;
	}
	
	if(Scrollbar.m_logger.isTrace()) Scrollbar.m_logger.trace("SCROLLBAR: Range: " + range + "\nScale: "+ scale + "\nStart: " + start);
	
	if(this.m_vertical)
	{
		// Need to calculate height of container - stylesheets don't work in this instance
		if(isIE)
		{
			this.m_element.style.height = Scrollbar._calculateHeight(this.m_element);
			// Stylesheets get this right in mozilla...
		}
		this.m_container.style.top = this.m_incButton.m_element.offsetHeight + "px";
		if(Scrollbar.m_logger.isTrace()) Scrollbar.m_logger.trace("SCROLLBAR: this.m_container.style.top: " + this.m_container.style.top + "\nthis.m_incButton.m_element.offsetHeight: "+ this.m_incButton.m_element.offsetHeight);
		this.m_container.style.height = (this.m_element.offsetHeight - (this.m_incButton.m_element.offsetHeight + this.m_decButton.m_element.offsetHeight)) + "px";
	
		// Calculate the size of the button but make sure it doesn't get too small.
		var buttonSize = Math.floor(this.m_container.offsetHeight * scale);
		if(buttonSize < 10) buttonSize = 10;
	
		// Calculate the top of the slider
		var a = this.m_proportion -(this.m_max - this.m_min);
	 	var top = a == 0 ? 0 : (start * (this.m_container.offsetHeight - this.m_slider.offsetHeight)) / a;
	 	top = Math.floor(top);
		if(top > (this.m_container.offsetHeight - buttonSize))
		{
			top =  (this.m_container.offsetHeight - buttonSize);
		}
		
		this.m_slider.style.height = buttonSize + "px";
		this.m_slider.style.top = top + "px";
		// store the top and height so we can determine if we have clicked above or below the slider
		this.m_sliderTop = top;
		this.m_sliderHeight = buttonSize;
		
		if (isIE)
		{
			// Set size for "button_inner" if slider size has been initialized.
			var sliderHeight = this.m_slider.offsetHeight-4;
			var sliderWidth = this.m_slider.offsetWidth-4;
			
			if (sliderHeight > 0) { // Can't set height if sliderHeight is negative/undefined
			  this.m_slider.firstChild.style.height = sliderHeight + "px";
			}
			
			if (sliderWidth > 0) {
			  this.m_slider.firstChild.style.width = sliderWidth + "px";
			}
		}
		
		
		if(Scrollbar.m_logger.isTrace()) Scrollbar.m_logger.trace("SCROLLBAR: top: " + top + "\nthis.m_slider.style.top: "+ this.m_slider.style.top);
		

		if(Scrollbar.m_logger.isTrace()) Scrollbar.m_logger.trace("SCROLLBAR: Vertical\nButtonSize: " + buttonSize + "\nTop Pos: " + top + "\nContainer height: " + this.m_container.offsetHeight);
	}
	else
	{
		var buttonSize = Math.floor(this.m_container.offsetWidth * scale);
		if(buttonSize < 10) buttonSize = 10;
		
		//var top = (this.m_position / range) * (this.m_container.offsetWidth - buttonSize);
		var a = this.m_proportion -(this.m_max - this.m_min);
	 	var top = a == 0 ? 0 : (start * (this.m_container.offsetWidth - this.m_slider.offsetWidth)) / a;
	 	top = Math.floor(top);
		if(top > (this.m_container.offsetWidth - buttonSize))
		{
			top =  (this.m_container.offsetWidth - buttonSize);
		}		
		this.m_slider.style.width = buttonSize + "px";
		this.m_slider.style.left = top + "px";

		//alert("Horizontal\nButtonSize: " + buttonSize + "\nLeft Pos: " + top + "\nContainer width: " + this.m_container.offsetWidth);
	}
}


Scrollbar.prototype._handleDragMouseDown = function(e)
{
	if(null == e) e = window.event;
	
	this.m_dragStartX = e.screenX;
	this.m_dragStartY = e.screenY;
	
	this.m_dragStartSliderX = this.m_slider.offsetLeft;
	this.m_dragStartSliderY = this.m_slider.offsetTop;
	
	var s = this;
	if(null == this.m_mouseupHandler)
	{
		this.m_mouseupHandler = SUPSEvent.addEventHandler(document, "mouseup", function() { s._handleDragMouseUp(); }, null);
	}
  
	if(null == this.m_mousemoveHandler)
	{
		this.m_mousemoveHandler = SUPSEvent.addEventHandler(document, "mousemove", function() { s._handleDragMouseMove(e); }, null);
	}
}


Scrollbar.prototype._handleDragMouseUp = function()
{
	SUPSEvent.removeEventHandlerKey(this.m_mouseupHandler);
	SUPSEvent.removeEventHandlerKey(this.m_mousemoveHandler);
	
	this.m_mouseupHandler = null;
	this.m_mousemoveHandler = null;
}


Scrollbar.prototype._handleDragMouseMove = function(e)
{
	if(null == e) e = window.event;
	
	var pos;
	var range;
	var size;
	var delta;
	
	if(this.m_vertical)
	{
		delta = e.screenY - this.m_dragStartY;
		pos = this.m_dragStartSliderY + delta;
		range = this.m_container.offsetHeight;
		size = this.m_slider.offsetHeight;
	}
	else
	{
		delta = e.screenX - this.m_dragStartX;
		pos = this.m_dragStartSliderX + delta;
		range = this.m_container.offsetWidth;
		size = this.m_slider.offsetWidth;
	}
	
	// Test whether the mouse drag changhed position in the axis we are intested in
	if(delta > 0)
	{
		// If the mouse was dragged far enough to pull the slider out of the container
		// put the slider at the end of the container
		if(pos + size > range) pos = range - size;
	}
	else
	{
		// If the mouse was dragged past the start of the container set the
		// slidebar to the start 
		if(pos < 0) pos = 0;
	}
	
	// Calculate container size - slider size
	var scrollEmptySize = range - size;
	
	// Calculate total number of rows being represented - number of rows that can be displayed at one time
	var logicalRange = this.m_proportion - (this.m_max - this.m_min);
	var scaledPosition = this.m_min + ((pos * logicalRange) / scrollEmptySize);
	this.m_position = parseInt(scaledPosition.toFixed(0));
	
	if(this.m_vertical)
	{
		this.m_slider.style.top = pos + "px";
	}
	else
	{
		this.m_slider.style.left = pos + "px";
	}
	
	this.m_changeListeners.invoke(pos, range, size);
}

Scrollbar.prototype._setScrollbarTimeout = function()
{
	// vary the speed depending upon the amount of paging required to scroll the entire scrollbar
	var numPages = this.m_proportion / (this.m_max - this.m_min);
	if(numPages < 5) numPages = 5;
	var timer = 20 + Math.round(600 / numPages);
	Scrollbar.scrollTimeout = timer;
}

Scrollbar.prototype._handleMouseDownContainer = function(evt)
{
	var target = SUPSEvent.getTargetElement(evt);
	
	// If the target is the slider then ignore
	if(target.className == "scrollbar_container")
	{
		// D892 - Respond to mouse clicks using a constant timeout
		// rather than varying the timeout with the amount of data
		//this._setScrollbarTimeout();
		Scrollbar.scrollTimeout = 35;
		
		// Mozilla and IE use different coordinate systems - great!		
		if(evt.layerY != null)
		{
			Scrollbar.clickY = evt.layerY;
		}
		else
		{
			Scrollbar.clickY = evt.offsetY;
		}
		if(Scrollbar.clickY < this.m_sliderTop)
		{
			Scrollbar.direction = "UP";
		}
		else
		{
			Scrollbar.direction = "DOWN";
		}
		Scrollbar.currentScrollbar = this;
		Scrollbar.mouseDownTimeout = setTimeout("Scrollbar._handleContainerScroll()", Scrollbar.scrollTimeout);
	}
}

Scrollbar.prototype._handleMouseUpContainer = function(evt)
{
	if(null == evt) evt = window.event;
	if(Scrollbar.m_logger.isTrace()) Scrollbar.m_logger.trace("SCROLLBAR: Scrollbar._handleMouseUpContainer()");

	Scrollbar.currentScrollbar = null;
	clearTimeout(Scrollbar.mouseDownTimeout);
	Scrollbar.mouseDownTimeout = null;
}

Scrollbar._handleContainerScroll = function()
{
	if(Scrollbar.currentScrollbar != null)
	{
		var scrollbar = Scrollbar.currentScrollbar;
		// position = number of rows in data
		// min and max define the number of rows in the view
		var numberOfRows = scrollbar.m_max - scrollbar.m_min;

		var scrolled = false;	
		if(Scrollbar.direction == "UP")
		{
			if(Scrollbar.clickY < scrollbar.m_sliderTop)
			{
				if(Scrollbar.m_logger.isTrace()) Scrollbar.m_logger.trace("SCROLLBAR: Scrollbar._handleClickContainer() clicked above slider so page up");
				// page up
				scrollbar.m_position = scrollbar.m_position - numberOfRows;
				if(scrollbar.m_position < scrollbar.m_min)
				{
					scrollbar.m_position = scrollbar.m_min;
				}
				scrolled = true;
			}
		}
		else
		{
			if(Scrollbar.clickY > scrollbar.m_sliderTop + scrollbar.m_sliderHeight)
			{
				if(Scrollbar.m_logger.isTrace()) Scrollbar.m_logger.trace("SCROLLBAR: Scrollbar._handleClickContainer() clicked below slider so page down");
				// page down
				scrollbar.m_position = scrollbar.m_position + numberOfRows;
				if(scrollbar.m_position >= scrollbar.m_proportion - numberOfRows)
				{
					scrollbar.m_position = scrollbar.m_proportion - numberOfRows;
				}
				scrolled = true;
			}
		}
		if(scrolled == true)
		{
			scrollbar.m_changeListeners.invoke();
			Scrollbar.mouseDownTimeout = setTimeout("Scrollbar._handleContainerScroll()", Scrollbar.scrollTimeout);
		}
	}
}

Scrollbar.prototype._handleIncrementClick = function()
{
	if(Scrollbar.m_logger.isTrace()) Scrollbar.m_logger.trace("SCROLLBAR: Scrollbar.prototype._handleIncrementClick");
	if(Scrollbar.m_logger.isTrace()) Scrollbar.m_logger.trace("SCROLLBAR: this.m_position == " + this.m_position + " this.m_proportion ==  " + this.m_proportion + " this.m_max == " + this.m_max + " this.m_min == " + this.m_min);
	
	// Is the first visible row less than the last row minus the number of visible rows
	// (i.e. First row visible plus the number of visible rows = the end of the list (i.e. no scroll possible)
	// firstVisibleRow = this.m_position;
	// totalVisibleRows = (this.m_max - this.m_min);
	// lastRowInData = this.m_proportion
	// firstVisibleRow + totalVisibleRows < lastRowInData then scroll down
	if(this.m_position < (this.m_proportion - (this.m_max - this.m_min)))
	{
		this.m_position++;
		
		this._render();
		
		this.m_changeListeners.invoke();
	}
}


Scrollbar.prototype._handleDecrementClick = function()
{
	if(Scrollbar.m_logger.isTrace()) Scrollbar.m_logger.trace("SCROLLBAR: Scrollbar.prototype._handleDecrementClick");
	if(Scrollbar.m_logger.isTrace()) Scrollbar.m_logger.trace("SCROLLBAR: this.m_position == " + this.m_position + " this.m_min == " + this.m_min);
	if(this.m_position > this.m_min)
	{
		this.m_position--;
		
		this._render();
		
		this.m_changeListeners.invoke();
	}
}

Scrollbar.prototype._registerResetVScrollBarHeight = function()
{
    // Have to retrieve reference to AppController using complex method
    // because FormController created after scroll bar
    var ac = Services.getAppController();
    
    if(null != ac)
    {
        var sm = ac.getStyleManager();
        
        if(null != sm)
        {
            var thisObj = this;
            this.m_resetVScrollbarHeight = function(){return thisObj._resetVScrollbarHeight();};
            
            sm.registerOnLoadHandler(this.m_resetVScrollbarHeight, document);
        }
    }
    
}

Scrollbar.prototype._unregisterResetVScrollBarHeight = function()
{
    var ac = Services.getAppController();
    
    var sm = ac.getStyleManager();
    
    sm.unregisterOnLoadHandler(this.m_resetVScrollbarHeight, document);
    this.m_resetVScrollbarHeight = null;
    
}

/**
 * This method resizes a vertical scrollbar. If a form's stylesheet is
 * loaded lated in IE the scrollbar may be too large. Setting the
 * style height to "auto" causes the scroll bar to correctly size itself.
*/
Scrollbar.prototype._resetVScrollbarHeight = function()
{
    // Set scrollbar style height to be "auto" causing scrollbar
    // to readjust height
    this.m_element.style.height = "auto";
    
    // Redraw scrollbar
    this._render();
}
