/**
 * AutoCompletion field renderer
 *
 * @constructor
 */
function AutoCompletionRenderer()
{
}


/**
 * AutoCompletionRenderer is a sub class of Renderer
 */
AutoCompletionRenderer.prototype = new Renderer();
AutoCompletionRenderer.prototype.constructor = AutoCompletionRenderer;


AutoCompletionRenderer.m_logger = new Category("AutoCompletionRenderer");
AutoCompletionRenderer.prototype.m_handlersStarted = false;


/**
 * Array containing the divs representing the rows in the dropdown
 *
 * @type Array[HTMLDivElement]
 * @private
 */
AutoCompletionRenderer.prototype.m_rows = null;


/**
 * The row currently highlighted (but not selected!) by the user.
 * 
 *
 * @type Integer
 * @private
 */
AutoCompletionRenderer.prototype.m_highlightedRow = null;


/**
 * Maximum allowed number of rows in autocomplete.
 *
 * @type Integer
 * @private
*/
AutoCompletionRenderer.prototype.m_maxNumberOfRows = null;

/**
 * Number of visible rows.
 *
 * @type Integer
 * @private
 */
AutoCompletionRenderer.prototype.m_visibleRows = null;

/**
 * The top visibile row
 *
 * @type Integer
 * @private
 */
AutoCompletionRenderer.prototype.m_topRow = null;

/**
 * The top visibile row
 *
 * @type Integer
 * @private
 */
AutoCompletionRenderer.prototype.m_selectionMode = null;

/**
 * The row that the user has selected. May be null if the user
 * hasn't selected a row. To select a row the user must either
 * double click on a row or press return while it is highlighted.
 */
AutoCompletionRenderer.prototype.m_selectedRow = null;

/**
 * Listeners to be notified when the value of the component changes
 */
AutoCompletionRenderer.prototype.m_valueChangeListeners = null;

/**
 * Key binding flag - static required to prevent keys after submit/cancel key(s)
 * raising the drop down
 */
AutoCompletionRenderer.showDropDown = true;

/**
 * Reference to main table row in autocompletion dropdown component
 *
*/
AutoCompletionRenderer.prototype.m_tableRow = null;

/**
 * Reference to table row cell used to store matches in divs.
 *
*/
AutoCompletionRenderer.prototype.m_rowsCell = null;

/**
 * Reference to table row cell used to store scrollbar when present
 *
*/
AutoCompletionRenderer.prototype.m_scrollbarCell = null;

/**
 * Reference to vertical scrollbar component when present
 *
*/
AutoCompletionRenderer.prototype.m_verticalScrollbar = null;

/**
 * Reference to array of all the selects in the document visibility and disabled state
 *
*/
AutoCompletionRenderer.prototype.m_selectsState = new Array(PopupLayer.m_allSelects.length);

/**
 * Reference to popup layer that this renderer's dropdown will be shown in
 *
*/
AutoCompletionRenderer.prototype.m_popupLayerCount = null;

AutoCompletionRenderer.CSS_CLASS_NAME = "autocomplete";
AutoCompletionRenderer.TABLE_CSS_CLASS_NAME = "autocomplete_table";
AutoCompletionRenderer.TABLEROW_CSS_CLASS_NAME = "autocomplete_tablerow";
AutoCompletionRenderer.ROWCELL_CSS_CLASS_NAME = "autocomplete_rowscell";
AutoCompletionRenderer.SCROLLCELL_CSS_CLASS_NAME = "autocomplete_scrollcell";
AutoCompletionRenderer.ROW_CSS_CLASS_NAME = "autocomplete_row";
AutoCompletionRenderer.ROW_HIDDEN_CSS_CLASS_NAME = AutoCompletionRenderer.ROW_CSS_CLASS_NAME + " autocomplete_rowhidden";
AutoCompletionRenderer.ROW_SELECTED_CSS_CLASS_NAME = AutoCompletionRenderer.ROW_CSS_CLASS_NAME + " autocomplete_rowselected";
AutoCompletionRenderer.ROW_SELECTED_AND_NOT_SUBMISSIBLE_CSS_CLASS_NAME = AutoCompletionRenderer.ROW_CSS_CLASS_NAME + " autocomplete_rowSelectedNotSubmissible";
AutoCompletionRenderer.ROW_NOT_SUBMISSIBLE_CSS_CLASS_NAME = AutoCompletionRenderer.ROW_CSS_CLASS_NAME + " autocomplete_rowNotSubmissible";
AutoCompletionRenderer.DEFAULT_NUMBER_OF_ROWS = 8;

// Settings for button
AutoCompletionRenderer.REPEAT_INITIAL_DELAY = 1000;
AutoCompletionRenderer.REPEAT_INTERVAL = 200;

// Single matching states
AutoCompletionRenderer.DONT_MATCH = 2;
AutoCompletionRenderer.MATCH = 3;
AutoCompletionRenderer.FOUND_MATCH = 4;

// Drop down changing rows states
AutoCompletionRenderer.NO_CHANGE = 5;
AutoCompletionRenderer.ADDING_ROWS = 6;
AutoCompletionRenderer.REMOVING_ROWS = 7;

/**
 * Create an autocomplete at the current location in the document while document
 * is parsing.
 *
 * @param id the id of the autocomplete being created
 * @param maxRows the maximum number of rows in the drop down menu
 */
AutoCompletionRenderer.createInline = function(id, maxRows)
{
	// Create the outer div by writing to the document.
	var e = Renderer.createInline(
		id,			// The id of the autocomplete being created
		false		// The autocomplete has an internal input element which can accept focus, so the div should not accept focus
	);

	return AutoCompletionRenderer._create(e, maxRows);
}


/**
 * Create an autocomplete in the document relative to the supplied element
 *
 * @param refElement the element relative to which the autocomplete should be rendered
 * @param relativePos the relative position of the autocomplete to "refElement".
 * Valid values are:
 *     Renderer.CHILD_ELEMENT    Created as a child of "refElement"
 *     Renderer.BEFORE_ELEMENT   Created as preceeding sibling of "refElement"
 *     Renderer.AFTER_ELEMENT    Created as following sibling of "refElement"
 * @param id the id of the autocomplete being created
 * @param maxRows the maximum number of rows in the drop down menu
 */
AutoCompletionRenderer.createAsInnerHTML = function(refElement, relativePos, id, maxRows)
{
	var e = Renderer.createAsInnerHTML(
		refElement,		// The element relative to which to create the outer div in the document
		relativePos,	// Relative position of the outer div to the reference element
		id,				// The id of the autocomplete being created
		false			// The autocomplete has an internal input element which can accept focus, so the div should not accept focus
	);

	return AutoCompletionRenderer._create(e, maxRows);
}


/**
 * Create an autocomplete as a child of another element
 *
 * @param p the parent element to which the autocomplete should be added
 * @param id the id of the autocomplete being created
 * @param maxRows the maximum number of rows in the drop down menu
 */
AutoCompletionRenderer.createAsChild = function(p, id, maxRows)
{
	var e = Renderer.createAsChild(id);

	// Append the autocomplete's outer div to it's parent element
	p.appendChild(e);	
	
	return AutoCompletionRenderer._create(e, maxRows);
}


AutoCompletionRenderer._create = function(e, maxRows)
{
	e.className = AutoCompletionRenderer.CSS_CLASS_NAME;
	
	var ac = new AutoCompletionRenderer();
	
	// Initialise sets main element and the reference to the renderer in the dom
	ac._initRenderer(e);	
	
	// Default the number of rows to 8 if not specified
	if(null == maxRows)
	{
		ac.m_maxNumberOfRows = AutoCompletionRenderer.DEFAULT_NUMBER_OF_ROWS;
	}
	else
	{
		ac.m_maxNumberOfRows = maxRows;
	}
	
	// Initialise the DropDownField part of the renderer
	ac.m_dropDownField = DropDownFieldRenderer.createAsChild(e);
	
	// Listen for show hide events
	ac.m_dropDownField.addShowHideListener(function(show) {ac._handleDropDownShowHide(show);});
	
	// Get the dropdown container
	var dropdown = ac.m_dropDownField._getDropDownElement();
	
	// Prevent selection of content in the dropdown
	preventSelection(dropdown);

	// Local reference to the document that we are adding elements to
	var d = window.document;

	// Create table to hold rows and scrollbar
	var table = d.createElement("table");
	table.className = AutoCompletionRenderer.TABLE_CSS_CLASS_NAME;
	
	// Ideally these attributes could be specified in the stylesheet,
	// but CSS support in this area is too flaky.
	table.setAttribute("cellspacing", "0px");
	table.setAttribute("cellpadding", "0px");

	// Require a tbody element
	var tableBody = d.createElement("tbody");

	// D643 - Override any centre/right alignment that may be set on a containing
	// table, otherwise the scrollbar gets moved to the right
	tableBody.setAttribute("align", "left");

	// Row to hold two cells.
	var tableRow = d.createElement("tr");
	ac.m_tableRow = tableRow;
	
	tableRow.className = AutoCompletionRenderer.TABLEROW_CSS_CLASS_NAME;

	var rowsCell = d.createElement("td");
	ac.m_rowsCell = rowsCell;
	rowsCell.className = AutoCompletionRenderer.ROWCELL_CSS_CLASS_NAME;

	tableRow.appendChild(rowsCell);
	tableBody.appendChild(tableRow);
	table.appendChild(tableBody);
	
	dropdown.appendChild(table);

	// Create new callback list for value change listeners
	ac.m_valueChangeListeners = new CallbackList();
	
	// No model yet
	ac.m_model = null;

	// Started in render() method
	//ac.startEventHandlers();
	
	return ac.m_dropDownField.m_element;
}


AutoCompletionRenderer.prototype.startEventHandlers = function()
{
	// Makes this call idempotent
	if(!this.m_handlersStarted)
	{	
		this.m_handlersStarted = true;
		
		if(this.m_verticalScrollbar != null)
		{
			this.m_verticalScrollbar.startEventHandlers();
		}

		var ac = this;
		this.m_keyupHndlr = SUPSEvent.addEventHandler(this.m_element, 'keyup', function(evt) { return ac._handleKeyUpEvent(evt); });
		this.m_keydownHndlr = SUPSEvent.addEventHandler(this.m_element, 'keydown', function(evt) { return ac._handleKeyDownEvent(evt); });

		// Started in DropDownFieldRenderer render() method
		//this.m_dropDownField.startDropDownEventHandlers();
		
		this.m_rowsCell.onclick = function(evt) { ac._handleClick(evt); };
		this.m_rowsCell.ondblclick = function(evt) { ac._handleDoubleClick(evt); };
		this.m_rowsCell.onmouseover = function(evt) { ac._handleMouseOver(evt); };
	}
}


AutoCompletionRenderer.prototype.stopEventHandlers = function()
{
	// Makes this call idempotent
	if(this.m_handlersStarted)
	{
		this.m_handlersStarted = false;

		if(this.m_verticalScrollbar != null)
		{
			this.m_verticalScrollbar.stopEventHandlers();
		}

		SUPSEvent.removeEventHandlerKey(this.m_keyupHndlr);
		this.m_keyupHndlr = null;

		SUPSEvent.removeEventHandlerKey(this.m_keydownHndlr);		
		this.m_keydownHndlr = null;

		// Stopped in DropDownFieldRenderer render() method
		//this.m_dropDownField.stopDropDownEventHandlers();
		
		this.m_rowsCell.onclick = null;
		this.m_rowsCell.ondblclick = null;
		this.m_rowsCell.onmouseover = null;
	}
}


AutoCompletionRenderer.prototype.dispose = function()
{
	this.stopEventHandlers();
	
	// Remove selection prevention event handler from drop down
	unPreventSelection(this.m_dropDownField._getDropDownElement());
	
	this.m_model = null;
	
	if(this.m_verticalScrollbar != null)
	{	
		this.m_verticalScrollbar.dispose();
	    this.m_verticalScrollbar = null;
	}

	// Dispose of HTML references
	if(this.m_rows != null)
	{
	    for(var i = 0, l = this.m_rows.length; i < l; i++)
	    {
	        this.m_rows[i] = null;
	    }
	    
	    this.m_rows = null;
	}
	
	this.m_tableRow = null;
	this.m_rowsCell = null;
	
	if(this.m_scrollbarCell != null)
	{
	    this.m_scrollbarCell = null;
	}
		
	this.m_dropDownField.dispose();
	
	this.m_valueChangeListeners.dispose();
	delete this.m_valueChangeListeners;
}



/*
 * Add a listener which will be called if the display value of the 
 * field changes.
 *
 * @param callback the function invoked when the value changes
 */
AutoCompletionRenderer.prototype.addValueChangeListener = function(callback)
{
	this.m_valueChangeListeners.addCallback(callback);
} 

AutoCompletionRenderer.prototype.setSelectionMode = function(mode)
{
	this.m_selectionMode = mode;
}

AutoCompletionRenderer.prototype.setModel = function(model)
{
	this.m_model = model;
}


/**
 * Handle changes in the postion of the vertical scrollbar
 *
 * @private
 */
AutoCompletionRenderer.prototype._handleVerticalScroll = function()
{
	if(this.m_topRow != this.m_verticalScrollbar.m_position)
	{
		this.m_topRow = this.m_verticalScrollbar.m_position;
	
		this._renderRows();
	}
}


/**
 * Handle changes in the dropdown's visibility state
 *
 * @param show true if the dropdown has been shown or false if it has been hidden
 * @private
 */
AutoCompletionRenderer.prototype._handleDropDownShowHide = function(show)
{
	if(show)
	{
		if(null == this.m_model)
		{
			// Set the scaling of the scrollbar to a sensible default
			this.m_verticalScrollbar.setScaling(0, 100, 100);
		}
		else
		{
			if(null == this.m_popupLayerCount)
			{
				// First time that dropdown has been shown, so store the
				// popup layer that this dropdown popup is shown in
				this.m_popupLayerCount = PopupLayer.m_popupCount - 1;
			}
			
		    // Update contents of dropdown component
			this._createDynamicDropDownContent();
			
			// Drop down may have been shown with more rows than required. In this case the popup layer
			// may have hidden selects that are visible when the drop down content is updated. Find all
			// the hidden selects and check that they are still overlapped. If they are not then restore
			// them to their previous visibility and disabled state.
			var hiddenSelects = this.m_dropDownField.m_popupLayer.m_hiddenSelects[this.m_popupLayerCount];
			
			if(hiddenSelects != null)
			{
				var container = this.m_rowsCell;

				// Currently popup layer puts all selects in the document in the hidden selects array,
				// even if they aren't hidden. This enables us to keep a simple 1 to 1 mapping between
				// the popup layer arrays and our select state array
				for(var i = hiddenSelects.length - 1; i >= 0; i--)
				{
					var s = hiddenSelects[i];
					var element = s.element;
					
					if(element.style.visibility == "hidden")
					{
	        			// Store the previous state of the hidden select
	        			var selectState = new Object();
						selectState.visibility = s.prevState;
						selectState.disabled = s.prevDisabled;
						
						this.m_selectsState[i] = selectState;
						
			    		// Check if select control is still overlapped by the drop down			
						if(!isContained(element, container))
						{
							// Not overlapped, so restore it's previous visibility and enabled state
							element.style.visibility = s.prevState;
							element.disabled = s.prevDisabled;
						}
						
						selectState = null;
    				}
				}
			}
			
			this._showMatches();
		}
	}
}


/**
 * Handle a click event on one of the rows in the drop down
 *
 * @param evt the click event - null on IE
 */
AutoCompletionRenderer.prototype._handleClick = function(evt)
{
	if (null == evt) evt = window.event;
	
	var target = SUPSEvent.getTargetElement(evt);

	// If this is IE evt.detail will not be defined, however IE does not call
	// click handler twice on a double click. In Mozilla click handler is called
	// for each click and evt.detail contains the number of sucessive clicks, so
	// for a double click evt.detail will be two - we only want to handle single
	// clicks here so ignore clicks with evt.detail != 1. All double clicks are
	// handled in _handleDoubleClick below.
    if(evt.detail == undefined || evt.detail == 1)
	{
		/*
		 * D434 - Highlighting of rows is now in _handleMouseOver() method
		 *
		for(var i = 0, l = this.m_rows.length; i < l ; i++)
		{
			if(target == this.m_rows[i])
			{
				break;
			}
		}
		
		if(i < l)
		{
			this.m_highlightedRow = i + this.m_topRow;
			this._renderRows();
			
			// If we are in click update mode then we set the value in the data model at this point
			if(this.m_updateMode == AutocompletionGUIAdaptor.CLICK_MODE)
			{
				this._useCurrentMatch();
			}
		}
		*/

		// If we are in click update mode then we set the value in the data model at this point
		if(this.m_selectionMode == AutocompletionGUIAdaptor.CLICK_MODE)
		{
			this._useCurrentMatch();
		}		
	}
}


/**
 * Handle a double click on one of the rows in the drop down
 *
 * @param evt the double click event - null on IE
 * @private
 */
AutoCompletionRenderer.prototype._handleDoubleClick = function(evt)
{
	// A row will have been selected in _handleMouseOver - we 
	// just need to use it.
	this._useCurrentMatch();
}


/**
 * Mouseover handler. Highlights the row as the mouse is moved into it.
 *
 * @param evt the event structure.
 * @private
 */
AutoCompletionRenderer.prototype._handleMouseOver = function(evt)
{
	if (null == evt) evt = window.event;
	
	var target = SUPSEvent.getTargetElement(evt);
	
	for(var i = 0, l = this.m_rows.length; i < l ; i++)
	{
		if(target == this.m_rows[i])
		{
			break;
		}
	}
	
	if(i < l)
	{
		this.m_highlightedRow = i + this.m_topRow;
		this._renderRows();
	}
}


/**
 * Key up handler for autocompletion field
 *
 * @param evt the event structure.
 * @return true to allow the event to propogate
 * @private
 */
AutoCompletionRenderer.prototype._handleKeyUpEvent = function(evt)
{
	// If IE the use the global event 
	evt = (null != evt) ? evt : window.event;
		
	// Get the keycode from the event - the same on IE and W3C compliant browsers
	var eventKeyCode = evt.keyCode;

	if(eventKeyCode == Key.ArrowUp.m_keyCode || eventKeyCode == Key.ArrowDown.m_keyCode) 
	{
		// Up/down arrow scrolling processed in key down handler, just show
		// drop down here
  		if(!this.m_dropDownField.isRaised())
		{
			// Update contents of dropdown component before showing it
			this._createDynamicDropDownContent();
			
			this.m_dropDownField.showDropDown();
		}
	}
	else if(eventKeyCode == Key.Return.m_keyCode)
	{
		this._useCurrentMatch();
	}
	else if(eventKeyCode == Key.Tab.m_keyCode ||
			eventKeyCode == Key.ESC.m_keyCode ||
			eventKeyCode == Key.PageUp.m_keyCode || eventKeyCode == Key.PageDown.m_keyCode ||
			eventKeyCode == Key.ScrollLock.m_keyCode ||
			eventKeyCode == Key.PrintScreen.m_keyCode ||
			eventKeyCode == Key.Insert.m_keyCode ||
			eventKeyCode == Key.NumLock.m_keyCode ||
			eventKeyCode == Key.Menu.m_keyCode ||
			eventKeyCode == Key.Home.m_keyCode || eventKeyCode == Key.End.m_keyCode ||
			eventKeyCode == Key.Windows.m_keyCode)
	{
		// Ignore tabs - handled by focus in/out anyway. This prevents the
		// drop down being raised when the user first tabs into the field
		
		// Ignore esc - handled by drop down field anyway. This prevents the
		// drop down hiding itself then immediately showing itself again
		
		// Ignore miscellaneous keys - prevents the drop down from showing
		// for these keys
	}
	else
	{
		if (AutoCompletionRenderer.m_logger.isDebug()) AutoCompletionRenderer.m_logger.debug("KeyHandler about to showMatches for key: " +  eventKeyCode);
		
		// If a key is bound via the Key Binding protocol or Event Binding then
		// we don't want to show the drop down.
		var keyBindings = new Array();
		keyBindings.push(this.m_guiAdaptor.getKeyBindings());

		// Submit/cancel lifecycles have a delay before a subform is closed. If a
		// key is bound to the submit/cancel lifecycle and it is pressed when in an
		// autocomplete then it's dropdown is raised before the subform is closed.
		// Don't show the drop down if the key press matches the bound key(s).
		var fa = FormController.getInstance().getFormAdaptor();

		if(fa instanceof SubformElementGUIAdaptor)
		{
			var cancelEventBinding = fa.m_lifeCycles.cancel.getEventBinding();
			var submitEventBinding = fa.m_lifeCycles.submit.getEventBinding();

			if(cancelEventBinding != null)
			{
				keyBindings = keyBindings.concat(cancelEventBinding.m_keyBindings);
			}

			if(submitEventBinding != null)
			{
				keyBindings = keyBindings.concat(submitEventBinding.m_keyBindings);
			}
		}

		var keyCodeString = '' + eventKeyCode;	
		var qualifiers = 0;

		// Get the qualifier keys from the event
		if(evt.ctrlKey) qualifiers |= ElementKeyBindings.CTRL_KEY_MASK;
		if(evt.altKey) qualifiers |= ElementKeyBindings.ALT_KEY_MASK;
		if(evt.shiftKey) qualifiers |= ElementKeyBindings.SHIFT_KEY_MASK;
		
		AutoCompletionRenderer.showDropDown = true;
		
		for(var i = 0, l = keyBindings.length; i < l; i++)
		{
			if(keyBindings[i].m_keys[keyCodeString] != null &&
				keyBindings[i].m_qualifiers[keyCodeString] == qualifiers)
			{
				AutoCompletionRenderer.showDropDown = false;
			}
		}
		
  		if(this.m_dropDownField.isRaised())
		{
			// Popup is visible	
			if(!AutoCompletionRenderer.showDropDown)
			{
				// Hide before matched key binding action occurs		
				this.m_dropDownField.hideDropDown();
			}
			else
			{
			    // Update contents of dropdown component
    			var change = this._createDynamicDropDownContent();
				
				if(change != AutoCompletionRenderer.NO_CHANGE)
				{
					// Adding or removing dropdown rows
					this._refreshSelectElements(change);
				}
				
				this._showMatches();
			}
		}
		else if(AutoCompletionRenderer.showDropDown)
		{
			// Popup is not visible and no matched key binding need to show it
			
			// Check for printable key
			if((Key.isPrintableKey(eventKeyCode) &&
					!evt.ctrlKey && !evt.altKey &&
						!Key.isFunctionKey(eventKeyCode)) ||
								(eventKeyCode == Key.Backspace.m_keyCode))
			{
				// Key is printable, so OK to show
				
				// Update contents of dropdown component before showing it
				this._createDynamicDropDownContent();
				
				this.m_dropDownField.showDropDown();
			}
		}
	}

	return true;
}


/**
 * Key down handler for autocompletion field. Move selection up/down drop down
 * if up/down arrows keys held down.
 *
 * @param evt the event structure.
 * @return true to allow the event to propogate
 *
 * @private
 */
AutoCompletionRenderer.prototype._handleKeyDownEvent = function(evt)
{
	// If IE the use the global event
	evt = (null != evt) ? evt : window.event;
	
	// Get the keycode from the event
	var eventKeyCode = evt.keyCode;
	var propagateEvent = true;
	
	// If the popup is not raised let the key up handler process the key
	if(this.m_dropDownField.isRaised())
	{
		switch(eventKeyCode)
		{
			case Key.ArrowUp.m_keyCode:
			{
				this._selectPreviousMatch();
				break;
			}
			case Key.ArrowDown.m_keyCode:
			{
				this._selectNextMatch();
				break;
			}
			case Key.PageUp.m_keyCode:
			{
				this._selectPreviousPageMatch();
				
				// Prevent cursor moving to the start of the text in the input field
	    		SUPSEvent.preventDefault(evt);
				propagateEvent = false;
				
				break;
			}
			case Key.PageDown.m_keyCode:
			{
				this._selectNextPageMatch();
				
				// Prevent cursor moving to the end of the text in the input field
	    		SUPSEvent.preventDefault(evt);
				propagateEvent = false;
				
				break;
			}
			case Key.Home.m_keyCode:
			{
				this._selectFirstMatch();
				
				// Prevent cursor moving to the start of the text in the input field
	    		SUPSEvent.preventDefault(evt);
				propagateEvent = false;
				
				break;
			}
			case Key.End.m_keyCode:
			{
				this._selectLastMatch();
				
				// Prevent cursor moving to the end of the text in the input field
	    		SUPSEvent.preventDefault(evt);
				propagateEvent = false;
				
				break;
			}
		}
	}

	// Only perform single match processing if adaptor is in strict validation mode
	if(this.m_guiAdaptor.strictValidation)
	{
		var currentSelection = document.selection.createRange();

		if(eventKeyCode == Key.Backspace.m_keyCode ||
		  (evt.ctrlKey && (eventKeyCode == Key.CHAR_X.m_keyCode || eventKeyCode == Key.CHAR_x.m_keyCode)))
		{
			// Delete or cut, so we don't want to autocomplete single matches
			this.m_matchSingle = AutoCompletionRenderer.DONT_MATCH;
		}
		else if(currentSelection.text.length != 0)
		{
			// Text is selected
			
			if(eventKeyCode == Key.Delete.m_keyCode)
			{
				// Deleting selection, so we don't want to autocomplete single matches
				this.m_matchSingle = AutoCompletionRenderer.DONT_MATCH;
			}
			else if(eventKeyCode != Key.Tab.m_keyCode &&
			   eventKeyCode != Key.Home.m_keyCode && eventKeyCode != Key.End.m_keyCode &&
			   eventKeyCode != Key.PageUp.m_keyCode && eventKeyCode != Key.PageDown.m_keyCode &&
			   eventKeyCode != Key.ArrowLeft.m_keyCode && eventKeyCode != Key.ArrowRight.m_keyCode)
			{
				// Tab key selects text when moving into field, navigation keys de-select text.
				// Any other key press will replace the text, so allow single matching
				this.m_matchSingle = AutoCompletionRenderer.MATCH;
			}
		}
		else
		{
			// No text is selected
			
			if(this.m_matchSingle == AutoCompletionRenderer.FOUND_MATCH)
			{
				// Already matched, so only allow navigation and edit keys. Any others are blocked
		
				if(eventKeyCode != Key.Home.m_keyCode && eventKeyCode != Key.End.m_keyCode &&
				   eventKeyCode != Key.PageUp.m_keyCode && eventKeyCode != Key.PageDown.m_keyCode &&
				   eventKeyCode != Key.ArrowLeft.m_keyCode && eventKeyCode != Key.ArrowRight.m_keyCode &&
				 !(evt.ctrlKey && (eventKeyCode == Key.CHAR_A.m_keyCode || eventKeyCode == Key.CHAR_a.m_keyCode ||
				 				   eventKeyCode == Key.CHAR_C.m_keyCode || eventKeyCode == Key.CHAR_c.m_keyCode ||
				                   eventKeyCode == Key.CHAR_Z.m_keyCode || eventKeyCode == Key.CHAR_z.m_keyCode ||
				                   eventKeyCode == Key.CHAR_Y.m_keyCode || eventKeyCode == Key.CHAR_y.m_keyCode)))							 
				{

					// Not navigation or edit keys, so block key press
	    			SUPSEvent.preventDefault(evt);
					propagateEvent = false;
				}
			}
			else if(Key.isPrintableKey(eventKeyCode) && !Key.isFunctionKey(eventKeyCode) &&
				   !evt.ctrlKey && !evt.altKey)
			{
				// Valid key press, so allow single matching
				this.m_matchSingle = AutoCompletionRenderer.MATCH;
			}
		}
	}
	
	return propagateEvent;
}


AutoCompletionRenderer.prototype._useCurrentMatch = function()
{
	if(this.m_highlightedRow != null)
	{
		this.m_dropDownField._getInputFieldElement().value = this.m_model.getMatch(this.m_highlightedRow);
		
		// The selected row is the currently highlighted row
		this.m_selectedRow = this.m_highlightedRow;
		
		if(this.m_guiAdaptor.strictValidation)
		{
			// Selecting via a row in the drop down, is the same as
			// single matching via the keyboard
			this.m_matchSingle = AutoCompletionRenderer.FOUND_MATCH;
		}
	}
	
	// Hide the drop down
	this.m_dropDownField.hideDropDown();
	
	// Notify listeners that the value has changed.
	this.m_valueChangeListeners.invoke();
}


AutoCompletionRenderer.prototype._showMatches = function()
{
	if(this.m_model != null)
	{
		this.m_numberOfMatches = this.m_model.setMatchString(this.getTextFieldValue());
				
		// Reset the current selection
		this.m_topRow = 0;
		this.m_highlightedRow = null;
		this.m_selectedRow = null;
		
		// Size the scrollbar appropriately & determine how many rows are visible
		var scale = null;
		
		if (this.m_rows.length > this.m_numberOfMatches)
		{
			scale = this.m_rows.length;
			this.m_visibleRows = this.m_numberOfMatches;
		}
		else
		{
			scale = this.m_numberOfMatches;
			this.m_visibleRows = this.m_rows.length;
		}

		if(this.m_verticalScrollbar != null)
		{	
			// Size the scrollbar correctly
			this.m_verticalScrollbar.setScaling(0, this.m_rows.length, scale);
		}
		
		this._renderRows();
		
		// Only autocomplete single matches if adaptor is in strict validation mode
		// and single matching enabled
		if(this.m_guiAdaptor.strictValidation && this.m_guiAdaptor.m_singleMatchingEnabled)
		{
			// Only autocomplete if one match and not already matched a single entry
			if (this.m_numberOfMatches == 1 && this.m_matchSingle == AutoCompletionRenderer.MATCH)
			{
				this.m_matchSingle = AutoCompletionRenderer.FOUND_MATCH;

				// Set match in input box
				this.m_dropDownField._getInputFieldElement().value = this.m_model.getMatch(0);
				
				// Notify listeners of a change in value
				this.m_valueChangeListeners.invoke();
			}
		}
	}
}


AutoCompletionRenderer.prototype._renderRows = function()
{
	// Render the visible rows.
	var i;
	var topRow = this.m_topRow;
	for(i = 0, l = this.m_visibleRows; i < l ; i++)
	{
		this._renderRow(i);
	}

	var hiddenRowClass = AutoCompletionRenderer.ROW_HIDDEN_CSS_CLASS_NAME;
	for(i = this.m_visibleRows, l = this.m_rows.length; i < l; i++)
	{
		this.m_rows[i].className = hiddenRowClass;
	}
	
	if(this.m_verticalScrollbar != null)
	{
		// Position the scrollbar appropriately
		this.m_verticalScrollbar.setPosition(this.m_topRow);
		this.m_verticalScrollbar._render();
	}
}

AutoCompletionRenderer.prototype._renderRow = function(rowNumber)
{
	var dataRow = rowNumber + this.m_topRow;
	var r = this.m_rows[rowNumber];
	var text = this.m_model.getMatch(dataRow);
	
	this._setRowContent(r, text);
	
	var cN = "";
	var isSubmissible = this.m_model.isKeyForMatchSubmissible(dataRow);
	var isSelected = this.m_highlightedRow == dataRow;
	
	if(isSubmissible == true)
	{
		cN = isSelected ? AutoCompletionRenderer.ROW_SELECTED_CSS_CLASS_NAME : AutoCompletionRenderer.ROW_CSS_CLASS_NAME;
	}
	else
	{
		cN = isSelected ? AutoCompletionRenderer.ROW_SELECTED_AND_NOT_SUBMISSIBLE_CSS_CLASS_NAME : AutoCompletionRenderer.ROW_NOT_SUBMISSIBLE_CSS_CLASS_NAME;
	}
	
	r.className = cN;
	
	/*r.className = (this.m_highlightedRow == dataRow)
		? AutoCompletionRenderer.ROW_SELECTED_CSS_CLASS_NAME
		: AutoCompletionRenderer.ROW_CSS_CLASS_NAME;*/
}


AutoCompletionRenderer.prototype._selectPreviousMatch = function()
{
	if(0 == this.m_numberOfMatches)
	{
		// No matches, so do nothing
		return;
	}
	if(null == this.m_highlightedRow)
	{
		// First press of up arrow in drop down, so select first row
		this._moveSelection(0);
	}
	else if(this.m_highlightedRow != 0)
	{
		// Not at first row in matches, so select previous row
		this._moveSelection(this.m_highlightedRow - 1);
	}
}


AutoCompletionRenderer.prototype._selectNextMatch = function()
{
	if(0 == this.m_numberOfMatches)
	{
		// No matches, so do nothing
		return;
	}
	if(null == this.m_highlightedRow)
	{
		// First press of down arrow in drop down, so select first row
		this._moveSelection(0);
	}
	else if(this.m_highlightedRow != (this.m_numberOfMatches - 1))
	{
		// Not at last row in matches, so select next row
		this._moveSelection(this.m_highlightedRow + 1);
	}
}


AutoCompletionRenderer.prototype._selectPreviousPageMatch = function()
{
	var numberOfMatches  = this.m_numberOfMatches;
	
	if(numberOfMatches != 0 && this.m_highlightedRow != 0)
	{
		// Has some data and not at first row, so move selection up from the
		// highlighted row by the number of matched rows in the drop down
		
		var rowsInDropDown = this.m_rows.length;
		var rowsToPage = (numberOfMatches < rowsInDropDown) ? numberOfMatches : rowsInDropDown;		
		var rowToSelect = this.m_highlightedRow - rowsToPage + 1;
		
		if(rowToSelect < 0)
		{
			// Past first row in matches, so select first row
			rowToSelect = 0;
		}
		
		this._moveSelection(rowToSelect);
	}
}


AutoCompletionRenderer.prototype._selectNextPageMatch = function()
{
	var numberOfMatches  = this.m_numberOfMatches;
	var lastRow = numberOfMatches - 1;
	
	if(numberOfMatches != 0 && this.m_highlightedRow != lastRow)
	{
		// Has some data and not at last row, so move selection down from the
		// highlighted row by the number of matched rows in the drop down
		
		var rowsInDropDown = this.m_rows.length;
		var rowsToPage = (numberOfMatches < rowsInDropDown) ? numberOfMatches : rowsInDropDown;
		var rowToSelect = this.m_highlightedRow + rowsToPage - 1;
				
		if(rowToSelect > lastRow)
		{
			// Past last row in matches, so select last row
			rowToSelect = lastRow;
		}
		
		this._moveSelection(rowToSelect);
	}
}


AutoCompletionRenderer.prototype._selectFirstMatch = function()
{
	if(this.m_numberOfMatches != 0 && this.m_highlightedRow != 0)
	{
		// Has some data and not at first row, so move selection to the
		// first row in the drop down
		
		this._moveSelection(0);
	}
}


AutoCompletionRenderer.prototype._selectLastMatch = function()
{
	var numberOfMatches  = this.m_numberOfMatches;
	var lastRow = numberOfMatches - 1;
	
	if(numberOfMatches != 0 && this.m_highlightedRow != lastRow)
	{
		// Has some data and not at last row, so move selection to the
		// last row in the drop down
				
		this._moveSelection(lastRow);
	}
}


AutoCompletionRenderer.prototype._moveSelection = function(newSelectedRow)
{
	// If newly selected row is not visible make it visible
	if(newSelectedRow < this.m_topRow)
	{
		// Selected row is "above" the topmost displayed rows, so scroll to make it visible

		// Make the selected row the top most visible row
		this.m_topRow = newSelectedRow;
		
		// Update the selected row
		this.m_highlightedRow = newSelectedRow;
		
		// All the rows will need re-rendering
		this._renderRows();
	}
	else if(newSelectedRow > (this.m_topRow + this.m_rows.length - 1))
	{
		// Selected row is "below" the bottommost displayed rows, so scroll to make it visible
		this.m_topRow = newSelectedRow - (this.m_rows.length - 1);
		
		// Update the selected row
		this.m_highlightedRow = newSelectedRow;
		
		// All the rows will need re-rendering
		this._renderRows();		
	}
	else
	{
		// Newly selected row is one of the currently displayed rows in the list, so just
		// highlight it

		var csr = this.m_highlightedRow;

		// If there is a selected row and it is currently one of the displayed
		// rows, then render it as unselected
		if(null != csr && csr >= this.m_topRow && csr < (this.m_topRow + this.m_rows.length))
		{
			this.m_highlightedRow = null;
			this._renderRow(csr - this.m_topRow);
		}
		
		// Render the newly selected row as rendered
		this.m_highlightedRow = newSelectedRow;
		this._renderRow(newSelectedRow - this.m_topRow);
	}
}


/**
 * Get the value of the text field of the dropdown
 */
AutoCompletionRenderer.prototype.getTextFieldValue = function()
{
	return this.m_dropDownField._getInputFieldElement().value;
}


AutoCompletionRenderer.prototype.resetSelectedMatch = function()
{
	this.m_selectedRow = null;
}

AutoCompletionRenderer.prototype.getSelectedMatch = function()
{
	return this.m_selectedRow;
}


AutoCompletionRenderer.prototype.setValue = function(value)
{
	// Don't want to display "null" in the field.
	if(value == null) value="";

	// Set the value of the field
	this.getInputElement().value = value;
}


AutoCompletionRenderer.prototype.dataUpdate = function()
{
    // Create or update contents of dropdown component
    var change = this._createDynamicDropDownContent();
	
	// If the dropdown is shown update it, otherwise wait until
	// dropdown is displayed
	if(this.m_dropDownField.isRaised())
	{
		if(change != AutoCompletionRenderer.NO_CHANGE)
		{
			// Adding or removing dropdown rows		
			this._refreshSelectElements(change);
		}
		
		this._showMatches();
	}
}


AutoCompletionRenderer.prototype.render = function(disabled, focussed, mandatory, invalid, serverInvalid, readonly, inactive, isSubmissible, isServerValidationActive)
{
	// D743 - Prevent key press showing drop down if not enabled
	if (disabled || readonly || inactive)
	{
		// Stop all input event handlers
		this.stopEventHandlers();
	}
	else
	{
		// Start all input event handlers
		this.startEventHandlers();		
	}

	this.m_dropDownField.render(disabled, focussed, mandatory, invalid, serverInvalid, readonly, inactive, isSubmissible, isServerValidationActive);
}


AutoCompletionRenderer.prototype.getInputElement = function()
{
	return this.m_dropDownField._getInputFieldElement();
}

/**
 * Set the width of the drop down rows, so that text that is too wide for the
 * row is clipped. (In IE, if the width is not set then the drop down outer
 * div changes to fit the width of the longest row in view as the rows are
 * scrolled up and down.)
 */
AutoCompletionRenderer.prototype._setRowWidth = function()
{
	// Use style rather than this.m_element.clientWidth because this can be zero
	// when display:none style is applied (As in the autocmpletion test page!).
	var style = getCalculatedStyle(this.m_guiAdaptor.getElement());
	
	var elementWidth = style.width.slice(0, -2);
	// If stylesheet hasn't loaded then this will be "auto", if so default to 180px
    elementWidth = isNaN(elementWidth) ? 180 : Number(elementWidth);
	
	style = getCalculatedStyle(this.m_dropDownField._getDropDownElement());
	
    var borderLeftWidth = style.borderLeftWidth.slice(0, -2);
    // If stylesheet hasn't loaded then this will be "medium", if so default to 1px
    borderLeftWidth = isNaN(borderLeftWidth) ? 1 : Number(borderLeftWidth);
	
    var borderRightWidth = style.borderRightWidth.slice(0, -2);
    // If stylesheet hasn't loaded then this will be "medium", if so default to 1px
    borderRightWidth = isNaN(borderRightWidth) ? 1 : Number(borderRightWidth);
	
	var borderWidth = borderLeftWidth + borderRightWidth;
	
	var scrollBarWidth = 0;
	if(this.m_verticalScrollbar != null)
	{
		scrollBarWidth = this.m_verticalScrollbar.m_element.clientWidth;
	}
	
	var rowWidth = elementWidth - scrollBarWidth - borderWidth;
	
	var rows = this.m_rows;

	for (var i = 0, l = rows.length; i < l; i++)
	{
		rows[i].style.width = rowWidth;
	}
	
	// Make the overall drop down width narrower by the border width
	var dropDown = this.m_dropDownField._getDropDownElement();
	dropDown.style.width = elementWidth - borderWidth;
}

/**
 * Method populates the autocompletion element dropdown component with match
 * rows.
 */
AutoCompletionRenderer.prototype._createDynamicDropDownContent = function()
{
	var change = AutoCompletionRenderer.NO_CHANGE;
            
    if(this.m_model != null)
    {
        var maxRows = this.m_maxNumberOfRows;
        var requiredRows = this.m_model.setMatchString(this.getTextFieldValue());
                
        if(0 == requiredRows)
        {
        	var srcDataRows = this.m_model.getSrcDataRowCount();
        	
        	// Set required rows in dropdown to lesser of source data and maximum rows
        	requiredRows = (srcDataRows != 0 && srcDataRows < maxRows) ? srcDataRows : maxRows;
        }
        
        if(null == this.m_rows)
        {
            // First time the dropdown has been displayed, so we need to create
            // the dropdown components
        
            // Stop event handlers if they have been started
            this.stopEventHandlers();
            
            if(requiredRows > maxRows)
            {
                // More rows required than rows in dropdown, so create rows
                // and vertical scrollbar in dropdown
                
                this._createDynamicDropDownRows(maxRows);
                this._createDynamicDropDownScrollbar();
            }
            else
            {
                // Less rows required than rows in dropdown, so just create
                // rows in dropdown
                
                this._createDynamicDropDownRows(requiredRows);
            }
            
            // Set the width of the drop down rows
            this._setRowWidth();
            
            // Restart event handlers
            this.startEventHandlers();
        }
        else
        {
          	// Dropdown has already been displayed, so we need to redraw
            // the dropdown components
            
            var currentDropdownRows = this.m_rows.length;
            
            // Stop events whilst performing redraw
            this.stopEventHandlers();
                       
        	if(requiredRows == currentDropdownRows)
        	{
        		// Same number of rows required as rows in dropdown, so just
        		// remove scrollbar if required. This happens if the dropdown
        		// currently has a scrollbar and if source data is loaded that
        		// has the same amount of rows as the dropdown. All data rows
        		// now fit in the dropdown, so scrollbar needs to be removed.
        		
                if(null != this.m_verticalScrollbar)
                {
                    this._removeDynamicDropDownScrollbar();
                }
        	}
        	else if(requiredRows < currentDropdownRows)
        	{        	            	
        		// Less rows required than rows in dropdown, so remove existing
        		// rows and scrollbar if required then create fewer new rows
        		
        		change = AutoCompletionRenderer.REMOVING_ROWS;
        		
	            this._removeDynamicDropDownRows();
	            
                if(null != this.m_verticalScrollbar)
                {
                    this._removeDynamicDropDownScrollbar();
                }
                
                this._createDynamicDropDownRows(requiredRows);
        	}
            else
            {
            	// More rows required than rows in dropdown, so remove existing
            	// rows and then determine how many new rows to create and whether
            	// or not a scrollbar is required
            	
            	change = AutoCompletionRenderer.ADDING_ROWS;
            	
	            if(requiredRows > maxRows)
	            {
	                // More rows required than maximum rows, so create maximum
	                // rows and vertical scrollbar in dropdown
		            
		            if(maxRows != currentDropdownRows)
		            {
		            	// Don't already have the maximum number of rows, so
		            	// remove existing rows and add maximum rows
		            	
	                	this._removeDynamicDropDownRows();
	                	this._createDynamicDropDownRows(maxRows);
	                }
	                
	                if(null == this.m_verticalScrollbar)
	                {
	                    this._createDynamicDropDownScrollbar();
	                }
	            }
	            else
	            {
	                // Less rows required than maximum rows, so just create
	                // required number of rows in dropdown
	             	
                	this._removeDynamicDropDownRows();
	                this._createDynamicDropDownRows(requiredRows);
	            }
			}
			
            // Set the width of the dropdown rows
            this._setRowWidth();
            
            // Restart event handlers
            this.startEventHandlers();
        }
    }
    
    return change;
}

/**
 * Method creates the rows within the autocompletion element dropdown. These
 * "rows" are actually individual divs which reside within a table cell.
 *
 * @param numberOfRows The number of rows to be created.
 */
AutoCompletionRenderer.prototype._createDynamicDropDownRows = function(numberOfRows)
{
    // Create new array to reference divs
    this.m_rows = new Array(numberOfRows);
    
    // Create div components
    var doc = window.document;
    
    for(var i = 0; i < numberOfRows; i++)
    {
		var r = doc.createElement("div");
		
		r.className = AutoCompletionRenderer.ROW_CSS_CLASS_NAME;
		
		// Give the row some initial text otherwise the dropdown
		// is sometimes rendered with zero height
		this._setRowContent(r, "row " + i);
		
		this.m_rowsCell.appendChild(r);
		
		this.m_rows[i] = r;
    }
}

/**
 * Method removes current rows in autocompletion element dropdown. These
 * "rows" are actually individual divs which reside within a table cell.
 */
AutoCompletionRenderer.prototype._removeDynamicDropDownRows = function()
{
    if(this.m_rows != null)
    {
        for(var i = 0, l = this.m_rows.length; i < l; i++)
        {
            var r = this.m_rows[i];
            
            // Clean up child nodes
            var childNodes = r.childNodes;
            
            for(var k = childNodes.length - 1; k >= 0; k--)
            {
                r.removeChild(childNodes[k]);
            }
            
            this.m_rowsCell.removeChild(r);
            this.m_rows[i] = null;
        }
        
        this.m_rows = null;
    }
}

/**
 * Method creates a vertical scrollbar for the autocompletion element dropdown
 * component.
 */
AutoCompletionRenderer.prototype._createDynamicDropDownScrollbar = function()
{
    var doc = window.document;
    
    // Create scrollbar cell
    this.m_scrollbarCell = doc.createElement("td");
    
    this.m_scrollbarCell.className = AutoCompletionRenderer.SCROLLCELL_CSS_CLASS_NAME;
    
    // Create scrollbar component
    this.m_verticalScrollbar = Scrollbar.createAsChild(this.m_scrollbarCell,
                                                       this.getElement().id + "VerticalScrollbar",
                                                       true,
                                                       null,
                                                       false);
    
    var thisObj = this;                    
    this.m_verticalScrollbar.addPositionChangeListener(function() { thisObj._handleVerticalScroll(); });
    
    // Append scroll bar cell to parent table row
    this.m_tableRow.appendChild(this.m_scrollbarCell);
}

/**
 *  Method removes a vertical scrollbar from the autocompletion element dropdown.
 */
AutoCompletionRenderer.prototype._removeDynamicDropDownScrollbar = function()
{
    // Dispose of scrollbar
    this.m_verticalScrollbar.dispose();
    this.m_verticalScrollbar = null;
    
    // Remove scrollbar HTML components
    this._removeChildNodes(this.m_scrollbarCell);
    
    // Remove table cell containing scrollbar
    this.m_tableRow.removeChild(this.m_scrollbarCell);
    
    this.m_scrollbarCell = null;
}

AutoCompletionRenderer.prototype._setRowContent = function(row, text)
{
    // Clean row content
    this._removeChildNodes(row);
    
    var textNodeContent = text;
    
    if(null == textNodeContent || "" == textNodeContent)
    {
        textNodeContent = "\u00a0";
    }
    
    var tn = window.document.createTextNode(textNodeContent);
    
    row.appendChild(tn);
}

AutoCompletionRenderer.prototype._removeChildNodes = function(element)
{
    var childNodes = element.childNodes;
    
    for(var k = childNodes.length - 1; k >= 0; k--)
    {
        element.removeChild( childNodes[k] );
    }
}

AutoCompletionRenderer.prototype._hideSelectElements = function()
{
	// Array of all the select elements in the document
	var selects = PopupLayer.m_allSelects;
	// Drop down container holds the table and it's rows
	var container = this.m_rowsCell;
	
	for(var i = selects.length - 1; i >= 0; i--)
	{
		var s = selects[i];
		
    	// Check if select control is overlapped by the drop down
    	if(isContained(s, container))
		{
		    // Is overlapped, so check if already hidden
			var visibility = s.style.visibility;
			
			if(visibility != "hidden")
			{
				// Not already hidden, so store it's visibility and disabled state			
				var selectState = new Object();
				selectState.visibility = visibility;
				selectState.disabled = s.disabled;
				
        		this.m_selectsState[i] = selectState;
        		
        		// Disable and hide the select
        		s.disabled = true;
        		s.style.visibility = "hidden";
        		
        		selectState = null;
        	}
		}
	}
}

AutoCompletionRenderer.prototype._showSelectElements = function()
{
	// Array of the select elements visibility states
	var selects = this.m_selectsState;
	// Drop down container holds the table and it's rows	
	var container = this.m_rowsCell;
	
	for(var i = selects.length - 1; i >= 0; i--)
	{
		var selectState = selects[i];
		
		if(selectState != null)
		{
			var element = PopupLayer.m_allSelects[i];
			
    		// Check if select control is still overlapped by the drop down			
			if(!isContained(element, container))
			{
				// Not overlapped, so restore it's previous visibility and disabled states
				element.style.visibility = selectState.visibility;
				element.disabled = selectState.disabled;
			}
		}
	}
}

AutoCompletionRenderer.prototype._refreshSelectElements = function(change)
{
	var dropDownField = this.m_dropDownField;
	var requiredPos = dropDownField._getDropDownPosition(this.m_rowsCell);
	
	// Number of rows in dropdown has changed, so determine whether the
	// dropdown being shown above or below the field will change
	
	if(requiredPos != dropDownField.m_dropDownPosition)
	{
		// Dropdown position will change
		
		// Hide dropdown in current position
		dropDownField.hideDropDown();
		
		// Restore any overlapped selects in the current position
		this._showSelectElements();
		
		// Show dropdown in new position
		dropDownField.showDropDown();
	}
	else
	{
		if(change == AutoCompletionRenderer.ADDING_ROWS)
		{
			// Adding rows, so hide any overlapped selects
			this._hideSelectElements();
		}
		else
		{
			// Removing rows, so restore any overlapped selects
			this._showSelectElements();
		}
	}
}

/*
 * Sets the single match flag. Called from _refreshDisplayedValue method on the adaptor.
 * @param matched - boolean flag that indicates whether or not a match was found
 */
AutoCompletionRenderer.prototype.setMatchSingle = function(matched)
{
	if(matched)
	{
		this.m_matchSingle = AutoCompletionRenderer.FOUND_MATCH;
	}
	else
	{
		this.m_matchSingle = AutoCompletionRenderer.MATCH;
	}
}
//==================================================================
//
// FwSelectElementRenderer.js
//
//==================================================================

/**
 * Framework select element renderer
 *
 * @constructor
 */
function FwSelectElementRenderer()
{
}


/**
 * FwSelectElementRenderer is a sub class of Renderer
 */
FwSelectElementRenderer.prototype = new Renderer();
FwSelectElementRenderer.prototype.constructor = FwSelectElementRenderer;


FwSelectElementRenderer.m_logger = new Category("FwSelectElementRenderer");

FwSelectElementRenderer.prototype.m_handlersStarted = false;


/**
 * Array containing the divs representing the rows in the dropdown
 *
 * @type Array[HTMLDivElement]
 * @private
 */
FwSelectElementRenderer.prototype.m_rows = null;

/**
 * Number of rows in source data for select
 *
 * @type Integer
 * @private
 *
*/
FwSelectElementRenderer.prototype.m_numberOfSelectDataRows = null;

/**
 * The row currently highlighted, but not necessarily selected, by the user.
 *
 * @type Integer
 * @private
 *
*/
FwSelectElementRenderer.prototype.m_highlightedRow = null;

/**
 * Maximum allowed number of rows in framework select.
 *
 * @type Integer
 * @private
*/
FwSelectElementRenderer.prototype.m_maxNumberOfRows = null;

/**
 * The top visible row
 *
 * @type Integer
 * @private
 */
FwSelectElementRenderer.prototype.m_topRow = null;

/**
 * The row that the user has selected. May be null if the user
 * hasn't selected a row. Rows may be selected in a number of
 * ways including moving the curosr over a row and clicking,
 * or double clicking, the mouse or pressing the return key. Rows
 * may be selected by navigating up and down the options using
 * the arrow keys etc. also.
 *
 * A row will also be selected if a user presses a printable key
 * whilst the select has focus and the key matches the first character
 * of one of the select's display options.
 */
FwSelectElementRenderer.prototype.m_selectedRow = null;

/**
 * Optional array of hardcoded select options defined in HTML page
 *
*/
FwSelectElementRenderer.prototype.m_hardcodedOptions = null;

/**
 * Listeners to be notified when the value of the component changes
 */
FwSelectElementRenderer.prototype.m_valueChangeListeners = null;

/**
 * Key binding flag - static required to prevent keys after submit/cancel key(s)
 * raising the drop down
 */
FwSelectElementRenderer.showDropDown = true;

/**
 * Boolean flag indicating whether, or not, the width of the select
 * should be assigned dynamically. The value of this flag will be
 * determined from the value of the input argument "dynamicRowWidth"
 * of the appropriate renderer creation method.
 *
*/
FwSelectElementRenderer.prototype.m_dynamicRowWidth = null;

/**
 * Integer variable used to store the required maximum row width when
 * the width of the select element is set dynamically. This value
 * must be recalculated each time the select component's source data
 * changes.
 *
*/
FwSelectElementRenderer.prototype.m_maxRowWidth = null;

/**
 * Reference to main table row in select dropdown component
 *
*/
FwSelectElementRenderer.prototype.m_tableRow = null;

/**
 * Reference to table row cell used to store select options in divs.
 *
*/
FwSelectElementRenderer.prototype.m_rowsCell = null;

/**
 * Reference to table row cell used to store scrollbar when present
 *
*/
FwSelectElementRenderer.prototype.m_scrollbarCell = null;

/**
 * Reference to vertical scrollbar component when present
 *
*/
FwSelectElementRenderer.prototype.m_verticalScrollbar = null;

FwSelectElementRenderer.CSS_CLASS_NAME = "fwselectelement";
FwSelectElementRenderer.TABLE_CSS_CLASS_NAME = "fwselectelement_table";
FwSelectElementRenderer.TEMP_TABLE_CSS_CLASS_NAME = "fwselectelement_temp_table";
FwSelectElementRenderer.TABLEROW_CSS_CLASS_NAME = "fwselectelement_tablerow";
FwSelectElementRenderer.ROWCELL_CSS_CLASS_NAME = "fwselectelement_rowscell";
FwSelectElementRenderer.SCROLLCELL_CSS_CLASS_NAME = "fwselectelement_scrollcell";
FwSelectElementRenderer.ROW_CSS_CLASS_NAME = "fwselectelement_row";
FwSelectElementRenderer.ROW_SELECTED_CSS_CLASS_NAME = FwSelectElementRenderer.ROW_CSS_CLASS_NAME + " fwselectelement_rowselected";
FwSelectElementRenderer.ROW_SELECTED_AND_NOT_SUBMISSIBLE_CSS_CLASS_NAME = FwSelectElementRenderer.ROW_CSS_CLASS_NAME + " fwselectelement_rowSelectedNotSubmissible";
FwSelectElementRenderer.ROW_NOT_SUBMISSIBLE_CSS_CLASS_NAME = FwSelectElementRenderer.ROW_CSS_CLASS_NAME + " fwselectelement_rowNotSubmissible";


FwSelectElementRenderer.DEFAULT_MAX_NUMBER_OF_ROWS = 8;
FwSelectElementRenderer.DEFAULT_INITIAL_WIDTH = "180px";

/**
 * Define width of drop down component's table cell containing
 * vertical scroll bar.
 *
*/
FwSelectElementRenderer.SCROLLCELL_CSS_WIDTH = 16;

// Settings for button
FwSelectElementRenderer.REPEAT_INITIAL_DELAY = 1000;
FwSelectElementRenderer.REPEAT_INTERVAL = 200;




/**
 * Create a framework select element at the current location in the document
 * while document is parsing.
 *
 * @param id               The id of the framework select element being created
 * @param maxRows          The maximum number of rows in the drop down menu
 * @param dynamicRowWidth  Boolean flag indicating whether, or not, the select
 *                         width is dynamic. The default value is "true".
 * @param initialWidth     Width used for dynamically szied select when first rendered.
 * @param hardcodedOptions Optional array of hard coded selection options
 */
FwSelectElementRenderer.createInline = function(id, 
                                                maxRows, 
                                                dynamicRowWidth,
                                                initialWidth,
                                                hardcodedOptions)
{
	// Create the outer div by writing to the document.
	var e = Renderer.createInline(
		id,			// The id of the framework select element being created
		false		// The framework select element has an internal input element which can accept focus, so the div should not accept focus
	);

	return FwSelectElementRenderer._create(e, 
	                                       maxRows, 
	                                       dynamicRowWidth, 
	                                       initialWidth, 
	                                       hardcodedOptions);
}


/**
 * Create a framework select element in the document relative to the supplied element
 *
 * @param refElement the element relative to which the framework select element should be rendered
 * @param relativePos the relative position of the framework select element to "refElement".
 * Valid values are:
 *     Renderer.CHILD_ELEMENT    Created as a child of "refElement"
 *     Renderer.BEFORE_ELEMENT   Created as preceeding sibling of "refElement"
 *     Renderer.AFTER_ELEMENT    Created as following sibling of "refElement"
 * @param id               The id of the framework select element being created
 * @param maxRows          The maximum number of rows in the drop down menu
 * @param dynamicRowWidth  Boolean flag indicating whether, or not, the select
 *                         width is dynamic. The default value is "true".
 * @param initialWidth     Width used for dynamically szied select when first rendered.
 * @param hardcodedOptions Optional array of hard coded selection options
 */
FwSelectElementRenderer.createAsInnerHTML = function(refElement, 
                                                     relativePos, 
                                                     id, 
                                                     maxRows, 
                                                     dynamicRowWidth,
                                                     initialWidth,
                                                     hardcodedOptions)
{
	var e = Renderer.createAsInnerHTML(
		refElement,		// The element relative to which to create the outer div in the document
		relativePos,	// Relative position of the outer div to the reference element
		id,				// The id of the framework select element being created
		false			// The framework select element has an internal input element which can accept focus, so the div should not accept focus
	);

	return FwSelectElementRenderer._create(e, 
	                                       maxRows, 
	                                       dynamicRowWidth,
	                                       initialWidth, 
	                                       hardcodedOptions);
}


/**
 * Create a framework select element as a child of another element
 *
 * @param p                The parent element to which the framework select element should be added
 * @param id               The id of the framework select element being created
 * @param maxRows          The number of rows in the drop down menu
 * @param dynamicRowWidth  Boolean flag indicating whether, or not, the select
 *                         width is dynamic. The default value is "true".
 * @param initialWidth     Width used for dynamically szied select when first rendered.
 * @param hardcodedOptions Optional array of hard coded selection options
 */
FwSelectElementRenderer.createAsChild = function(p, 
                                                 id, 
                                                 maxRows,
                                                 dynamicRowWidth,
                                                 initialWidth,
                                                 hardcodedOptions)
{
	var e = Renderer.createAsChild(id);

	// Append the framework select element's outer div to it's parent element
	p.appendChild(e);	
	
	return FwSelectElementRenderer._create(e, 
	                                       maxRows, 
	                                       dynamicRowWidth,
	                                       initialWidth,
	                                       hardcodedOptions);
}


FwSelectElementRenderer._create = function(e, 
                                           maxRows,
                                           dynamicRowWidth,
                                           initialWidth,
                                           hardcodedOptions)
{
	e.className = FwSelectElementRenderer.CSS_CLASS_NAME;
	
	var fse = new FwSelectElementRenderer();
	
	// Initialise sets main element and the reference to the renderer in the dom
	fse._initRenderer(e);
	
	// Default the maximum number of rows to 8 if not specified
	if(null == maxRows)
	{
	    fse.m_maxNumberOfRows = FwSelectElementRenderer.DEFAULT_MAX_NUMBER_OF_ROWS;
	}
	else
	{
	    fse.m_maxNumberOfRows = maxRows;
	}
	
	// Determine whether, or not, framework select should be sized dynamically
	if(null != dynamicRowWidth)
	{
	    if(dynamicRowWidth == true)
	    {
	        fse.m_dynamicRowWidth = true;
	    }
	    else
	    {
	        fse.m_dynamicRowWidth = false;
	    }
	}
	else
	{
	    fse.m_dynamicRowWidth = true;
	}
	
	if(fse.m_dynamicRowWidth)
	{
	    // If using dynamic width set initial width to a sensible value.
	    if(null != initialWidth)
	    {
	        fse.m_element.style.width = initialWidth;
	    }
	    else
	    {
	        fse.m_element.style.width = FwSelectElementRenderer.DEFAULT_INITIAL_WIDTH;
	    }
	}
	
	// Store array of hardcoded options if defined
	if(null != hardcodedOptions)
	{
	    fse.m_hardcodedOptions = hardcodedOptions;
	}
	
	// Initialise the DropDownField part of the renderer
	fse.m_dropDownField = DropDownFieldRenderer.createAsChild(e, true);
	
	// Listen for show hide events
	fse.m_dropDownField.addShowHideListener(function(show) {fse._handleDropDownShowHide(show);});
	
	// Get the dropdown container
	var dropdown = fse.m_dropDownField._getDropDownElement();
	
	// Prevent selection of content in the dropdown
	preventSelection(dropdown);

	// Local reference to the document that we are adding elements to
	var d = window.document;

	// Create table to hold rows and scrollbar
	var table = d.createElement("table");
	table.className = FwSelectElementRenderer.TABLE_CSS_CLASS_NAME;
	
	// Ideally these attributes could be specified in the stylesheet,
	// but CSS support in this area is too flaky.
	table.setAttribute("cellspacing", "0px");
	table.setAttribute("cellpadding", "0px");

	// Require a tbody element
	var tableBody = d.createElement("tbody");

	// D643 - Override any centre/right alignment that may be set on a containing
	// table, otherwise the scrollbar gets moved to the right
	tableBody.setAttribute("align", "left");

	// Row to hold two cells.
	var tableRow = d.createElement("tr");
	fse.m_tableRow = tableRow;

	tableRow.className = FwSelectElementRenderer.TABLEROW_CSS_CLASS_NAME;

	var rowsCell = d.createElement("td");
	fse.m_rowsCell = rowsCell;
	rowsCell.className = FwSelectElementRenderer.ROWCELL_CSS_CLASS_NAME;

	tableRow.appendChild(rowsCell);
	tableBody.appendChild(tableRow);
	table.appendChild(tableBody);
	
	dropdown.appendChild(table);

	// Create new callback list for value change listeners
	fse.m_valueChangeListeners = new CallbackList();

	
	// No model yet
	fse.m_model = null;
	
	return fse.m_dropDownField.m_element;
}


FwSelectElementRenderer.prototype.startEventHandlers = function()
{
	// Makes this call idempotent
	if(!this.m_handlersStarted)
	{	
		this.m_handlersStarted = true;
		
		if(null != this.m_verticalScrollbar)
		{
		    this.m_verticalScrollbar.startEventHandlers();
		}

		var fse = this;
		this.m_keyupHndlr = SUPSEvent.addEventHandler(this.m_element, 'keyup', function(evt) { return fse._handleKeyUpEvent(evt); });
		this.m_keydownHndlr = SUPSEvent.addEventHandler(this.m_element, 'keydown', function(evt) { return fse._handleKeyDownEvent(evt); });
		
		this.m_rowsCell.onclick = function(evt) { fse._handleClick(evt); };
		this.m_rowsCell.ondblclick = function(evt) { fse._handleDoubleClick(evt); };
		this.m_rowsCell.onmouseover = function(evt) { fse._handleMouseOver(evt); };
	}
}


FwSelectElementRenderer.prototype.stopEventHandlers = function()
{
	// Makes this call idempotent
	if(this.m_handlersStarted)
	{
		this.m_handlersStarted = false;

        if(null != this.m_verticalScrollbar)
        {
		    this.m_verticalScrollbar.stopEventHandlers();
		}

		SUPSEvent.removeEventHandlerKey(this.m_keyupHndlr);
		this.m_keyupHndlr = null;

		SUPSEvent.removeEventHandlerKey(this.m_keydownHndlr);		
		this.m_keydownHndlr = null;
		
		this.m_rowsCell.onclick = null;
		this.m_rowsCell.ondblclick = null;
		this.m_rowsCell.onmouseover = null;
	}
}


FwSelectElementRenderer.prototype.dispose = function()
{
	this.stopEventHandlers();
	
	// Remove selection prevention event handler from drop down
	unPreventSelection(this.m_dropDownField._getDropDownElement());
	
	this.m_model = null;
	
	// Clear array of hard coded options if defined
	if(null != this.m_hardcodedOptions)
	{
	    this.m_hardcodedOptions = null;
	}
	
	if(null != this.m_verticalScrollbar)
	{
	    this.m_verticalScrollbar.dispose();
	    this.m_verticalScrollbar = null;
	}
	
	// Dispose of HTML references
	if(null != this.m_rows)
	{
	    for(var i = 0, l = this.m_rows.length; i < l; i++)
	    {
	        this.m_rows[i] = null;
	    }
	    
	    this.m_rows = null;
	}
	
	this.m_rowsCell = null;
	
	if(null != this.m_scrollbarCell)
	{
	    this.m_scrollbarCell = null;
	}
	
	this.m_tableRow = null;
	
	this.m_dropDownField.dispose();
	
	this.m_valueChangeListeners.dispose();
	delete this.m_valueChangeListeners;
	
    this.m_element = null;
}


/*
 * Add a listener which will be called if the display value of the 
 * field changes.
 *
 * @param callback the function invoked when the value changes
 */
FwSelectElementRenderer.prototype.addValueChangeListener = function(callback)
{
	this.m_valueChangeListeners.addCallback(callback);
}

FwSelectElementRenderer.prototype.setModel = function(model)
{
	this.m_model = model;
	
	this.m_dropDownField.m_guiAdaptor = model;
}


/**
 * Handle changes in the postion of the vertical scrollbar
 *
 * @private
 */
FwSelectElementRenderer.prototype._handleVerticalScroll = function()
{
	if(this.m_topRow != this.m_verticalScrollbar.m_position)
	{
		this.m_topRow = this.m_verticalScrollbar.m_position;
	
		this._renderRows();
	}
}


/**
 * Handle changes in the dropdown's visibility state. Function registered
 * with drop down field which invokes function to display select options.
 *
 * @param show true if the dropdown is to be shown or false if it to be hidden
 * @private
 */
FwSelectElementRenderer.prototype._handleDropDownShowHide = function(show)
{
	if(show)
	{
		if(null == this.m_model)
		{
		    if(null != this.m_verticalScrollbar)
		    {
			    // Set the scaling of the scrollbar to a sensible default
			    this.m_verticalScrollbar.setScaling(0, 100, 100);
			}
		}
		else
		{
			// Populate with data
			this._renderDropDown();
		}
	}
}


/**
 * Handle a click event on one of the rows in the drop down
 *
 * @param evt the click event - null on IE
 */
FwSelectElementRenderer.prototype._handleClick = function(evt)
{
	if (null == evt) evt = window.event;

	// If this is IE evt.detail will not be defined, however IE does not call
	// click handler twice on a double click. In Mozilla click handler is called
	// for each click and evt.detail contains the number of sucessive clicks, so
	// for a double click evt.detail will be two - we only want to handle single
	// clicks here so ignore clicks with evt.detail != 1. All double clicks are
	// handled in _handleDoubleClick below.
    if(evt.detail == undefined || evt.detail == 1)
	{
		// Update current match.
		this._useCurrentMatch(true);
	}
}


/**
 * Handle a double click on one of the rows in the drop down
 *
 * @param evt the double click event - null on IE
 * @private
 */
FwSelectElementRenderer.prototype._handleDoubleClick = function(evt)
{
	// As with onClick handler update current match
	this._useCurrentMatch(true);
}


/**
 * Method handles mouse over event on select option. Note that mouse over
 * causes row to be highlighted.
 *
 * @param evt the event structure.
 * @private
 */
FwSelectElementRenderer.prototype._handleMouseOver = function(evt)
{
	if (null == evt) evt = window.event;
	
	var target = SUPSEvent.getTargetElement(evt);
	
	if(null != this.m_rows)
	{
	
	    for(var i = 0, l = this.m_rows.length; i < l ; i++)
	    {
		    if(target == this.m_rows[i])
		    {
			    break;
		    }
	    }
	
	    if(i < l)
	    {
	        // Select option highlighted
		    this.m_highlightedRow = i + this.m_topRow;
		    
		    // If mouse over event occurs drop down must be raised.
		    this._renderRows();
	    }
	    
	}
	
}


/**
 * Key up handler for framework select element
 *
 * @param evt the event structure.
 * @return true to allow the event to propogate
 * @todo need to check for non-printable characters - and determine behavior!
 * @private
 */
FwSelectElementRenderer.prototype._handleKeyUpEvent = function(evt)
{
	// If IE the use the global event 
	evt = (null != evt) ? evt : window.event;
		
	// Get the keycode from the event - the same on IE and W3C compliant browsers
	var eventKeyCode = evt.keyCode;

	if(eventKeyCode == Key.ArrowUp.m_keyCode || eventKeyCode == Key.ArrowDown.m_keyCode) 
	{
		// Defect 973. In previous versions of code up or down key events caused
		// drop down component to be displayed. Post defect 973 up and
		// down arrow keys handled by key down handler only.
	}
	else if(eventKeyCode == Key.Return.m_keyCode)
	{
	    // As with "onClick" and "onDblClick" update selection
	    this._useCurrentMatch(true);
	}
	else if(!this._isPrintableChar(eventKeyCode))
	{
		// Ignore tabs - handled by focus in/out anyway. This avoids the
		// drop down being raised when the user first tabs into the field
		
		// Ignore esc - handled by drop down field anyway. This avoids the
		// drop down hiding itself then immediately showing itself again.
		
		// Ignore miscellaneous keys - prevents drop down showing for
		// these keys
	}
	else
	{
		if (FwSelectElementRenderer.m_logger.isDebug()) FwSelectElementRenderer.m_logger.debug("KeyHandler about to showMatches for key: " +  eventKeyCode);
		
		// If a key is bound via the Key Binding protocol or Event Binding then
		// we don't want to show the drop down.
		var keyBindings = new Array();
		keyBindings.push(this.m_model.getKeyBindings());

		// Submit/cancel lifecycles have a delay before a subform is closed. If a
		// key is bound to the submit/cancel lifecycle and it is pressed when in an
		// autocomplete then it's dropdown is raised before the subform is closed.
		// Don't show the drop down if the key press matches the bound key(s).
		var fa = FormController.getInstance().getFormAdaptor();

		if(fa instanceof SubformElementGUIAdaptor)
		{
			var cancelEventBinding = fa.m_lifeCycles.cancel.getEventBinding();
			var submitEventBinding = fa.m_lifeCycles.submit.getEventBinding();

			if(cancelEventBinding != null)
			{
				keyBindings = keyBindings.concat(cancelEventBinding.m_keyBindings);
			}

			if(submitEventBinding != null)
			{
				keyBindings = keyBindings.concat(submitEventBinding.m_keyBindings);
			}
		}

		var keyCodeString = '' + eventKeyCode;	
		var qualifiers = 0;

		// Get the qualifier keys from the event
		if(evt.ctrlKey) qualifiers |= ElementKeyBindings.CTRL_KEY_MASK;
		if(evt.altKey) qualifiers |= ElementKeyBindings.ALT_KEY_MASK;
		if(evt.shiftKey) qualifiers |= ElementKeyBindings.SHIFT_KEY_MASK;
		
		FwSelectElementRenderer.showDropDown = true;
		
		for(var i = 0, l = keyBindings.length; i < l; i++)
		{
			if(keyBindings[i].m_keys[keyCodeString] != null &&
				keyBindings[i].m_qualifiers[keyCodeString] == qualifiers)
			{
				FwSelectElementRenderer.showDropDown = false;
			}
		}
			
  		if(this.m_dropDownField.isRaised())
		{
			if(!FwSelectElementRenderer.showDropDown)
			{
				// Hide select drop down before matched key binding action occurs		
				this.m_dropDownField.hideDropDown();
			}
			else
			{		
				// Attempt to match input character with display options
			    this._matchInputCharacter(eventKeyCode, evt);
			}
		}
		else if(FwSelectElementRenderer.showDropDown)
		{
		    // Attempt to match input character with display options
			this._matchInputCharacter(eventKeyCode, evt);
		}
	}

	return true;
}


/**
 * Key down handler for framework select element. Move selection up/down drop down
 * if up/down arrows keys held down.
 *
 * @param evt the event structure.
 * @return Return "true" to let event propagate upwards unless key is
 *         a scrollable key because this would cause a surrounding
 *         scrolling div to scroll.
 * @private
 */
FwSelectElementRenderer.prototype._handleKeyDownEvent = function(evt)
{
    // If IE the use the global event 
	evt = (null != evt) ? evt : window.event;

	// Get the keycode from the event
    var eventKeyCode = evt.keyCode;

	switch(eventKeyCode)
	{
	
		case Key.ArrowUp.m_keyCode:
		{
			this._selectPreviousOption();
			break;
		}
		case Key.ArrowDown.m_keyCode:
		{
			this._selectNextOption();
			break;
		}
		case Key.PageUp.m_keyCode:
		{
			this._selectPreviousPageOption();
			break;
		}
		case Key.PageDown.m_keyCode:
		{
			this._selectNextPageOption();
			break;
		}
		case Key.Home.m_keyCode:
		{
			this._selectFirstOption();
			break;
		}
		case Key.End.m_keyCode:
		{
			this._selectLastOption();
			break;
		}

	}
	
	var returnValue = true;
	
	if(Key.isScrollKey(eventKeyCode))
	{
	    // Prevent default action because select component may be located
	    // within scrollable div and we do not want key press to cause
	    // div to scroll.
	    SUPSEvent.preventDefault(evt);
	    
	    returnValue = false;
	}
	
	return returnValue;
}

/**
 * Method updates renderer with latest option selection.
 *
 * @param hideDropDown Boolean flag indicating, whether, or not,
 *                     select drop down component should be hidden.
 *
 */
FwSelectElementRenderer.prototype._useCurrentMatch = function(hideDropDown)
{
	if(this.m_highlightedRow != null)
	{
		this.getInputElement().value = this.m_model.getMatch(this.m_highlightedRow);
		
		this.m_selectedRow = this.m_highlightedRow;
	}
	
	if(hideDropDown)
	{
	    this.m_dropDownField.hideDropDown();
	}
	
	// Notify listeners that the value has changed.
	this.m_valueChangeListeners.invoke();
}

/**
 * Draw, or redraw, rows in drop down.
 *
 */
FwSelectElementRenderer.prototype._renderDropDown = function()
{
	if(this.m_model != null)
	{
		
		// Retrieve current row selection. Note, post defect 973 this may not
		// be necessary as the adaptor is much better at keeping "m_selectedRow"
		// up to date.
		var currentRow = this.m_model.getRowNoFromDisplayValue(this.getTextFieldValue());
		
		// Set highlighted row to current selection. Note current selection will be
		// used to render dropdown. Highlighted row may be updated by cursor movement.
		this.m_highlightedRow = currentRow;
        
	    var visibleRows = this.m_rows.length;
			
		// Render rows including selected option.
		if(null != currentRow)
		{
			if(currentRow < visibleRows)
			{
			    this.m_topRow = 0;
			}
			else
			{
			    this.m_topRow = currentRow;
			    
			    if(this.m_topRow + visibleRows > this.m_numberOfSelectDataRows)
			    {
			        this.m_topRow = this.m_numberOfSelectDataRows - visibleRows;
			    }
			}
	    }
		else
		{
			// Current row may be null if no data in select
			this.m_topRow = 0;
		}
	
	    if(null != this.m_verticalScrollbar)
	    {
		    // Size the scrollbar correctly
		    this.m_verticalScrollbar.setScaling(0, visibleRows, this.m_numberOfSelectDataRows);
		}

		this._renderRows();
		
	}
	
}

/**
 * Method controls refresh of select options.
 *
 */
FwSelectElementRenderer.prototype._renderRows = function()
{
	// Render the visible rows.
	var i;

	for(i = 0, l = this.m_rows.length; i < l ; i++)
	{
		this._renderRow(i);
	}
	
	if(null != this.m_verticalScrollbar)
	{
	    // Position the scrollbar appropriately
	    this.m_verticalScrollbar.setPosition(this.m_topRow);
	    this.m_verticalScrollbar._render();
	}
}

/**
 * Method refreshes content of a single select row.
 *
 * @param rowNumber The position of the row within the drop down component.
 *
 */
FwSelectElementRenderer.prototype._renderRow = function(rowNumber)
{
	var r = this.m_rows[rowNumber];
	var dataRow = rowNumber + this.m_topRow;
	var isSubmissible = this.m_model.isKeyForMatchSubmissible(dataRow);
	var isSelected = this.m_highlightedRow == dataRow;

	// Set row content
	this._setRowContent( r, this.m_model.getMatch(dataRow) );
	
	var cN = "";
	if(isSubmissible == true)
	{
		cN = isSelected ? FwSelectElementRenderer.ROW_SELECTED_CSS_CLASS_NAME : FwSelectElementRenderer.ROW_CSS_CLASS_NAME;
	}
	else
	{
		cN = isSelected ? FwSelectElementRenderer.ROW_SELECTED_AND_NOT_SUBMISSIBLE_CSS_CLASS_NAME : FwSelectElementRenderer.ROW_NOT_SUBMISSIBLE_CSS_CLASS_NAME;
	}
	
	r.className = cN;
	
}


FwSelectElementRenderer.prototype._selectPreviousOption = function()
{
	if(this.m_highlightedRow != null && this.m_highlightedRow != 0)
	{
		// Not at first row in options, so select previous row
		this._moveSelection(this.m_highlightedRow - 1);
	}
}


FwSelectElementRenderer.prototype._selectNextOption = function()
{
	if(0 == this.m_numberOfSelectDataRows)
	{
		// No options, so do nothing
		return;
	}
	if(null == this.m_highlightedRow)
	{
		// First press of down arrow in drop down, so select first row
		this._moveSelection(0);
	}
	else if(this.m_highlightedRow != (this.m_numberOfSelectDataRows - 1))
	{
		// Not at last row in options, so select next row
		this._moveSelection(this.m_highlightedRow + 1);
	}
}


FwSelectElementRenderer.prototype._selectPreviousPageOption = function()
{
	if(this.m_numberOfSelectDataRows != 0 && this.m_highlightedRow != 0)
	{
		// Has some data and not at first row, so move selection up from
		// the highlighted row by the number of rows in the drop down
		
		var rowToSelect = this.m_highlightedRow - this.m_rows.length + 1;
		
		if(rowToSelect < 0)
		{
			// Past first row in drop down, so select first row
			rowToSelect = 0;
		}
		
		this._moveSelection(rowToSelect);
	}
}


FwSelectElementRenderer.prototype._selectNextPageOption = function()
{
	var numberOfSelectDataRows  = this.m_numberOfSelectDataRows;
	var lastRow = numberOfSelectDataRows - 1;
		
	if(numberOfSelectDataRows != 0 && this.m_highlightedRow != lastRow)
	{
		// Has some data and not at last row, so move selection down from
		// the highlighted row by the number of rows in the drop down
			
		var rowToSelect = this.m_highlightedRow + this.m_rows.length - 1;
		
		if(rowToSelect > lastRow)
		{
			// Past last row in drop down, so select last row
			rowToSelect = lastRow;
		}
		
		this._moveSelection(rowToSelect);
	}
}


FwSelectElementRenderer.prototype._selectFirstOption = function()
{
	if(this.m_numberOfSelectDataRows != 0 && this.m_highlightedRow != 0)
	{
		// Has some data and not at first row, so move selection to the
		// first row in the drop down
		
		this._moveSelection(0);
	}
}


FwSelectElementRenderer.prototype._selectLastOption = function()
{
	var numberOfSelectDataRows  = this.m_numberOfSelectDataRows;
	var lastRow = numberOfSelectDataRows - 1;
	
	if(numberOfSelectDataRows != 0 && this.m_highlightedRow != lastRow)
	{
		// Has some data and not at last row, so move selection to the
		// last row in the drop down
				
		this._moveSelection(lastRow);
	}
}


FwSelectElementRenderer.prototype._moveSelection = function(newSelectedRow)
{
    if(this.m_dropDownField.isRaised())
    {
        // Drop down is raised so update current contents
	    if(newSelectedRow < this.m_topRow)
	    {
		    // Selected row is "above" the topmost displayed rows, so scroll to make it visible

		    // Make the selected row the top most visible row
		    this.m_topRow = newSelectedRow;
		
		    // Update the selected row
		    this.m_highlightedRow = newSelectedRow;
		
		    // All the rows will need re-rendering
		    this._renderRows();
	    }
	    else if(newSelectedRow > (this.m_topRow + this.m_rows.length - 1))
	    {
		    // Selected row is "below" the bottommost displayed rows, so scroll to make it visible
		    this.m_topRow = newSelectedRow - (this.m_rows.length - 1);
		
		    // Update the selected row
		    this.m_highlightedRow = newSelectedRow;
		
		    // All the rows will need re-rendering
		    this._renderRows();		
	    }
	    else
	    {
		    // Newly selected row is one of the currently displayed rows in the list, so just
		    // highlight it

		    var csr = this.m_highlightedRow;

		    // If there is a selected row and it is currently one of the displayed
		    // rows, then render it as unselected
		    if(null != csr && csr >= this.m_topRow && csr < (this.m_topRow + this.m_rows.length))
		    {
			    this.m_highlightedRow = null;
			    this._renderRow(csr - this.m_topRow);
		    }
		
		    // Render the newly selected row as rendered
		    this.m_highlightedRow = newSelectedRow;
		    this._renderRow(newSelectedRow - this.m_topRow);
	    }
	    
	}
	else
	{
	    // Drop down component is not raised so just update selected row
	    this.m_highlightedRow = newSelectedRow;
	}
	
	// Update display and, if necessary, persist change
	this._useCurrentMatch(false);
}


/**
 * Get the value of the text field of the dropdown
 */
FwSelectElementRenderer.prototype.getTextFieldValue = function()
{
	return this.m_dropDownField._getInputFieldElement().value;
}


FwSelectElementRenderer.prototype.resetSelectedMatch = function()
{
    this.m_selectedRow = null;
    
    // Also reset highlighted row as this should match selected row.
    this.m_highlightedRow = null;
}

FwSelectElementRenderer.prototype.getSelectedMatch = function()
{
	return this.m_selectedRow;
}

FwSelectElementRenderer.prototype.setSelectedRow = function( selectedRow )
{
    this.m_selectedRow = selectedRow;
    
    if(this.m_highlightedRow != this.m_selectedRow)
    {
        // Highlighted row should match selected row.
        this.m_highlightedRow = this.m_selectedRow;
    }
}

FwSelectElementRenderer.prototype.setValue = function(value)
{
	// Don't want to display "null" in the field.
	if(value == null) value="";

	// Set the value of the field
	this.getInputElement().value = value;
}


FwSelectElementRenderer.prototype.dataUpdate = function()
{
    var raised = false;
    
    var dropDownField = this.m_dropDownField;
    
    if(dropDownField.isRaised())
    {
        raised = true;
        
        // Hide drop down whilst updating contents
        dropDownField.hideDropDown();
    }
    
    // Update contents of dropdown component   
    this._createDynamicDropDownContent();
    
	if(raised)
	{   
		dropDownField.showDropDown();
	}
}


FwSelectElementRenderer.prototype.render = function(disabled, focussed, mandatory, invalid, serverInvalid, readonly, inactive, isSubmissible, isServerValidationActive)
{   
	// D743 - Prevent key press showing drop down if not enabled
	if (disabled || readonly || inactive)
	{
		// Stop all input event handlers
		this.stopEventHandlers();
	}
	else
	{
		// Start all input event handlers
		this.startEventHandlers();		
	}

	this.m_dropDownField.render(disabled, focussed, mandatory, invalid, serverInvalid, readonly, inactive, isSubmissible, isServerValidationActive);
}


FwSelectElementRenderer.prototype.getInputElement = function()
{
	return this.m_dropDownField._getInputFieldElement();
}

/**
 * Set the width of the drop down rows, so that text that is too wide for the
 * row is clipped. (In IE, if the width is not set then the drop down outer
 * div changes to fit the width of the longest row in view as the rows are
 * scrolled up and down.)
 */
FwSelectElementRenderer.prototype._setRowWidth = function()
{
	var elementWidth = this.m_element.clientWidth;
	
	var scrollBarWidth = 0;
	
	if(null != this.m_verticalScrollbar)
	{
	    scrollBarWidth = this.m_verticalScrollbar.m_element.clientWidth;
	}

    // Account for border on drop down component
    var dropDown = this.m_dropDownField._getDropDownElement();
	var borderWidth = this._getBorderWidth( dropDown );
	
	// Account for padding on select options
	var rowPaddingWidth = this._getDropDownRowPaddingWidth();

	var rowWidth = elementWidth - scrollBarWidth - borderWidth - rowPaddingWidth;

	var rows = this.m_rows;

	for (var i = 0, l = rows.length; i < l; i++)
	{
		rows[i].style.width = rowWidth;
	}

	// Make the overall drop down width narrower by the border width
	dropDown.style.width = elementWidth - borderWidth;
}

/**
 * Method sets width of select options based on previously
 * determined row widths.
 *
*/
FwSelectElementRenderer.prototype._setDynamicRowWidth = function()
{
    var maxRowWidth = this.m_maxRowWidth;
    
    if(null != maxRowWidth)
    {
    
        if(null == this.m_verticalScrollbar)
        {
            // If scrollbar not rendered row width must be increased
            maxRowWidth += FwSelectElementRenderer.SCROLLCELL_CSS_WIDTH;
        }
        
        var rows = this.m_rows;
        
        for(var i = 0, l = rows.length; i < l; i++)
        {
            rows[i].style.width = maxRowWidth + "px";
        }
    }
    
}  

FwSelectElementRenderer.prototype.getHardcodedOptions = function()
{
    return this.m_hardcodedOptions;
}

/**
 * Method helps to identify certain classes of keys handled by
 * key up handler.
 *
 * Makes key handling control structure easier to read.
 *
*/
FwSelectElementRenderer.prototype._isPrintableChar = function( keyCode )
{
    var printableCharacter;
    
    switch(keyCode)
    {
    
       case Key.Tab.m_keyCode:
	   case Key.ESC.m_keyCode:
	   case Key.PageUp.m_keyCode: 
	   case Key.PageDown.m_keyCode:
	   case Key.ScrollLock.m_keyCode:
	   case Key.PrintScreen.m_keyCode:
	   case Key.Insert.m_keyCode:
	   case Key.NumLock.m_keyCode:
	   case Key.Menu.m_keyCode:
	   case Key.Home.m_keyCode:
	   case Key.End.m_keyCode:
	   case Key.Windows.m_keyCode:
	   {
	       printableCharacter = false;
	       break;
	   }
	   
	   default:
	   {
	       printableCharacter = true;
	       break;
	   }
	   
    }
    
    return printableCharacter
}

/**
 * Method returns position of select entry which matches
 * input key.
 *
*/
FwSelectElementRenderer.prototype._matchInputCharacter = function(eventKeyCode, evt)
{
    if(Key.isPrintableKey(eventKeyCode) &&
	   !evt.ctrlKey && 
	   !evt.altKey &&
	   !Key.isFunctionKey(eventKeyCode))
	{
	    // Key is printable, so search for match
	    var matchedRow = this.m_model.matchFirstCharacter(String.fromCharCode(eventKeyCode));
				    
	    if(null != matchedRow)
	    {
	        this.getInputElement().value = this.m_model.getMatch(matchedRow);
				    
		    this.m_selectedRow = matchedRow;
		    
		    this.m_highlightedRow = this.m_selectedRow;
				    
		    if(this.m_dropDownField.isRaised())
		    {
		        this._renderDropDown();
		    }
				    
		    this.m_valueChangeListeners.invoke();
	    }
	}
}

/**
 * Method populates the framework select element dropdown component with select
 * option rows.
 *
 *
*/
FwSelectElementRenderer.prototype._createDynamicDropDownContent = function()
{
    if(null != this.m_model)
    {
        var maxRows = this.m_maxNumberOfRows;
        
        // Retrieve current number of data rows in select
        this.m_numberOfSelectDataRows = this.m_model.getNumberOfSelectRows();
        
        // Use local reference to number of rows
        var numberOfSelectDataRows = this.m_numberOfSelectDataRows;
    
        if(null == this.m_rows)
        {
            // If this condition occurs this is the first time the dropdown has been
            // displayed and we need to create the dropdown components.
            
            // Defect 1067. The use of ">=" may look a little strange. However,
            // the number of options in the client side DOM may drop to zero
            // (usually temporarily) and the component must handle this gracefully.
        
            if(numberOfSelectDataRows >= 0)
            {
                // Stop event handlers if they have been started. Might
                // be interesting aren't we in such a handler?
                this.stopEventHandlers();
                
                if(this.m_dynamicRowWidth)
                {
                    this._setSelectElementWidth(numberOfSelectDataRows);
                }
            
                if(numberOfSelectDataRows > maxRows)
                {
                    // Create select option rows
                    this._createDynamicDropDownRows(maxRows);
                
                    if(null == this.m_verticalScrollbar)
                    {
                        // Create vertical scrollbar
                        this._createDynamicDropDownScrollbar();
                    }
                }
                else
                {
                    this._createDynamicDropDownRows(numberOfSelectDataRows);
                }
            
                // If width of select component is fixed set row width appropriately
                if(!this.m_dynamicRowWidth)
                {
                    this._setRowWidth();
                }
                else
                {
                    this._setDynamicRowWidth();
                }
            
                // Restart event handlers
                this.startEventHandlers();
            
            }
        
        }
        else
        {
            // Redisplaying dropdown after original creation.
            if(!this.m_hardcodedOptions)
            {   
                // Stop events whilst performing redraw.
                this.stopEventHandlers();
                
                // Remove existing rows
                this._removeDynamicDropDownRows();
                
                if(numberOfSelectDataRows >= 0)
                {
                    var scrollbarChange = false;
                        
                    if(this.m_dynamicRowWidth)
                    {
                        this._setSelectElementWidth(numberOfSelectDataRows);
                    }
                    
                    if(numberOfSelectDataRows > maxRows)
                    {
                        this._createDynamicDropDownRows(maxRows);
                        
                        if(null == this.m_verticalScrollbar)
                        {
                            // Create scrollbar
                            this._createDynamicDropDownScrollbar();
                            
                            scrollbarChange = true;
                        }
                        
                    }
                    else
                    {
                        if(null != this.m_verticalScrollbar)
                        {
                            this._removeDynamicDropDownScrollbar();
                            
                            scrollbarChange = true;
                        }
                        
                        this._createDynamicDropDownRows(numberOfSelectDataRows);
                    }
                    
                    if(!this.m_dynamicRowWidth)
                    {
                        // Set row width appropriately
                        if(scrollbarChange)
                        {
                            this._setRowWidth();
                        }
                    }
                    else
                    {
                        this._setDynamicRowWidth();
                    }
                    
                }
                
                // Restart event handlers
                this.startEventHandlers();
            
            } // this.m_hardcodedOptions if block
        
        } // End of this.m_rows if block
        
    } // End of this.m_model if block
    
}

/**
 * Method creates the rows within the framework select dropdown. These "rows" are
 * actually individual divs which reside within a table cell.
 *
 * @param numberOfRows The number of rows to be created.
 *
*/
FwSelectElementRenderer.prototype._createDynamicDropDownRows = function(numberOfRows)
{
    // Create new array to reference divs
    if(numberOfRows > 0)
    {
        this.m_rows = new Array( numberOfRows );
    }
    else
    {
        this.m_rows = new Array();
    }
    
    // Create div components
    var doc = window.document;
    
    for(var i = 0; i < numberOfRows; i++)
    {
        var r = doc.createElement( "div" );
        
        r.className = FwSelectElementRenderer.ROW_CSS_CLASS_NAME;
        
        this.m_rowsCell.appendChild( r );
        
        this.m_rows[i] = r;
    }
    
}

/**
 * Method removes current rows in framework select dropdown. These "rows" are
 * actually individual divs which reside within a table cell.
 *
*/
FwSelectElementRenderer.prototype._removeDynamicDropDownRows = function()
{
    if(null != this.m_rows)
    {   
        for(var i = 0, l = this.m_rows.length; i < l; i++)
        {
            var r = this.m_rows[i];
            
            // Clean up child nodes
            var childNodes = r.childNodes;
            
            for(var k = childNodes.length - 1; k >= 0; k--)
            {
                r.removeChild( childNodes[k] );
            }
            
            this.m_rowsCell.removeChild( r );
            
            this.m_rows[i] = null;
        }
        
        this.m_rows = null;
    }
    
}

/**
 * Method creates a vertical scrollbar for the framework select element dropdown
 * component.
 *
*/
FwSelectElementRenderer.prototype._createDynamicDropDownScrollbar = function()
{
    var doc = window.document;
    
    // Create scrollbar cell
    this.m_scrollbarCell = doc.createElement( "td" );
    
    this.m_scrollbarCell.className = FwSelectElementRenderer.SCROLLCELL_CSS_CLASS_NAME;
    
    // Create scrollbar component
    this.m_verticalScrollbar = Scrollbar.createAsChild( this.m_scrollbarCell,
                                                        this.getElement().id + "VerticalScrollbar",
                                                        true,
                                                        null,
                                                        false );
                  
    var thisObj = this;                                      
    this.m_verticalScrollbar.addPositionChangeListener( function() { thisObj._handleVerticalScroll(); } );
    
    // Append scroll bar cell to parent table row.
    this.m_tableRow.appendChild(this.m_scrollbarCell);
    
}

/**
 *  Method removes a vertical scrollbar from the framework select element dropdown.
 *
*/
FwSelectElementRenderer.prototype._removeDynamicDropDownScrollbar = function()
{
    // Dispose of scrollbar
    this.m_verticalScrollbar.dispose();
    this.m_verticalScrollbar = null;
    
    // Remove scrollbar HTML components
    var childNodes = this.m_scrollbarCell.childNodes;
    
    for(var k = childNodes.length - 1; k >= 0; k--)
    {
        this.m_scrollbarCell.removeChild( childNodes[k] );
    }
    
    // Remove table cell containing scrollbar
    this.m_tableRow.removeChild( this.m_scrollbarCell );
    
    this.m_scrollbarCell = null;
    
}

/**
 * Method calculates the required width of the select component when
 * using dynamic widths.
 *
*/
FwSelectElementRenderer.prototype._setSelectElementWidth = function(numberOfSelectDataRows)
{
    // Determine properties of select options rows
    var rowProperties = this._determineRowProperties(numberOfSelectDataRows);
    
    this.m_maxRowWidth = rowProperties[ "maxWidth" ];
    
    var rowPaddingWidth = rowProperties[ "rowPaddingWidth" ];
    
    if(null != this.m_maxRowWidth && null != rowPaddingWidth)
    {
        var dropdownBorderWidth = this._getBorderWidth( this.m_dropDownField._getDropDownElement() );
        
        var totalSelectElementWidth = this.m_maxRowWidth +
                                      rowPaddingWidth +
                                      dropdownBorderWidth +
                                      FwSelectElementRenderer.SCROLLCELL_CSS_WIDTH;
                                      
        // Set element width
       this.getElement().style.width = totalSelectElementWidth + "px";
       
       // Explicitly set width of dropdown component such that it sizes correctly
       this.m_dropDownField._getDropDownElement().style.width = ( totalSelectElementWidth -
                                                                  dropdownBorderWidth ) +
                                                                  "px";
    }
    
}

/**
 * Method determines the maximum row width required to display the current
 * select options plus the current padding width.
 *
 * @param numberOfSelectDataRows The current number of select options.
 *
 * @return Returns an object containing the maximum row width and the total
 *         of the left and right padding values for the select rows.
 *
*/
FwSelectElementRenderer.prototype._determineRowProperties = function(numberOfSelectDataRows)
{
    var doc = window.document;
    
    // Create temporary table into which current select options can be loaded.
    var container = doc.createElement( "div" );
    doc.appendChild(container)
    
    var table = doc.createElement( "table" );
    table.className = FwSelectElementRenderer.TEMP_TABLE_CSS_CLASS_NAME;
    
    table.setAttribute( "cellspacing", "0px" );
    table.setAttribute( "cellpadding", "0px" );
    
    container.appendChild( table );
    
    var tableBody = doc.createElement( "tbody" );
    
    tableBody.setAttribute( "align", "left" );
    
    table.appendChild( tableBody );
    
    var tableRow = doc.createElement( "tr" );
    tableRow.className = FwSelectElementRenderer.TABLEROW_CSS_CLASS_NAME;
    
    tableBody.appendChild( tableRow );
    
    var rowsCell = doc.createElement( "td" );
    rowsCell.className = FwSelectElementRenderer.ROWCELL_CSS_CLASS_NAME;
    
    tableRow.appendChild( rowsCell );
    
    // Create row into which select options will be written
    var row = doc.createElement( "div" );
    row.className = FwSelectElementRenderer.ROW_CSS_CLASS_NAME;
    
    rowsCell.appendChild( row );
    
    // Determine maximum row width
    var rowWidth = 0;
    var maxRowWidth = 0;
    
    for(var i = 0; i < numberOfSelectDataRows; i++)
    {
        var text = this.m_model.getMatch( i );
        
        this._setRowContent( row, text );
        
        rowWidth = row.offsetWidth;
        
        if(null != rowWidth)
        {
            if(rowWidth > maxRowWidth)
            {
                maxRowWidth = rowWidth;
            }
        }
        
    }
    
    // Increase maximum row width to account for border around input field and button.
    maxRowWidth += this._getBorderWidth( this.m_dropDownField.m_borderDiv );
    
    // Determine width of row padding
    var rowPaddingWidth = this._getPaddingWidth( row );
    
    // Construct return object
    var rowProperties = new Object();
    
    rowProperties[ "maxWidth" ] = maxRowWidth;
    rowProperties[ "rowPaddingWidth" ] = rowPaddingWidth;
    
    // Delete temporary table and all contents
    this._removeChildNodes( row );
    
    rowsCell.removeChild( row );
    row = null;
    
    tableRow.removeChild( rowsCell )
    rowsCell = null;
    
    tableBody.removeChild( tableRow );
    tableRow = null;
    
    table.removeChild( tableBody );
    tableBody = null;
    
    container.removeChild( table );
    table = null;
    
    doc.removeChild(container);
    container = null;
    
    // Return row properties
    return rowProperties;
}

/**
 * Method sets text displayed in a select option "row".
 *
 * @param row  The "div" representing a row of the select
 * @param text The text to be displayed
 *
*/
FwSelectElementRenderer.prototype._setRowContent = function( row, text )
{
    // Clean row content
    this._removeChildNodes( row );
    
    var textNodeContent = text;
    
    if(null == textNodeContent || "" == textNodeContent)
    {
        textNodeContent = "\u00a0";
    }
    
    var tn = window.document.createTextNode(textNodeContent);
    
    row.appendChild(tn);
}

/**
 * Method removes an HTML element's child nodes.
 *
*/
FwSelectElementRenderer.prototype._removeChildNodes = function(element)
{
    var childNodes = element.childNodes;
    
    for(var k = childNodes.length - 1; k >= 0; k--)
    {
        element.removeChild( childNodes[k] );
    }
}

/**
 * Method determines the total of an element's left and right border
 * width values when these values are defined in pixels.
 *
 * @param element An HTML element.
 *
 * @return Integer value representing combined left and right border widths in pixels.
 *
*/
FwSelectElementRenderer.prototype._getBorderWidth = function( element )
{
    var borderWidth = 0;
    
    var pixels = "px";
    
    // Retrieve current style for element
    var elementStyle = getCalculatedStyle(element);
    
    var borderLeft = null;
    var borderLeftWidth = elementStyle.borderLeftWidth;
    
    if(borderLeftWidth.indexOf(pixels) != -1)
    {
        borderLeft = parseInt(borderLeftWidth);
    }
    
    var borderRight = null;
    var borderRightWidth = elementStyle.borderRightWidth;
    
    if(borderRightWidth.indexOf(pixels) != -1)
    {
        borderRight = parseInt(borderRightWidth);
    }
    
    if(null != borderLeft)
    {
        borderWidth += borderLeft;
    }
    
    if(null != borderRight)
    {
        borderWidth += borderRight;
    }
    
    return borderWidth;
}

/**
 * Method returns total of left and right padding valuess for the select component's
 * select rows in pixels.
 *
 * @return Sum of left and right padding values for "divs" representing select
 *         options.
 *
*/
FwSelectElementRenderer.prototype._getDropDownRowPaddingWidth = function()
{
    var paddingWidth = 0;
    
    if(null != this.m_rows && this.m_rows.length > 0)
    {
        // First locate row with correct class
        
        var rows = this.m_rows;
        var row = null;
        
        for(var i = 0, l = rows.length; i < l; i++)
        {
            var r = rows[i];
            
            if(r.className.indexOf( FwSelectElementRenderer.ROW_CSS_CLASS_NAME ) != -1)
            {
                row = r;
                break;
            }
        }
        
        if(null != row)
        {
            paddingWidth = this._getPaddingWidth( row );
        }
        
    }
    
    return paddingWidth;
}

/**
 * Method returns the sum of an HTML element's left and right padding values
 * in pixels.
 *
 * @param element An HTML element.
 *
 * @return Integer value representing combined left and right padding widths in pixels.
 *
*/
FwSelectElementRenderer.prototype._getPaddingWidth = function(element)
{
    var paddingWidth = 0;
    
    var pixels = "px";
    
    var elementStyle = getCalculatedStyle( element );
    
    var paddingLeft = elementStyle.paddingLeft;
    var paddingLeftWidth = null;
            
    if(paddingLeft.indexOf(pixels) != -1)
    {
        paddingLeftWidth = parseInt(paddingLeft);
    }
            
    var paddingRight = elementStyle.paddingRight;
    var paddingRightWidth = null;
            
    if(paddingRight.indexOf(pixels) != -1)
    {
        paddingRightWidth = parseInt(paddingRight);
    }
            
    if(null != paddingLeftWidth)
    {
        paddingWidth += paddingLeftWidth;
    }
            
    if(null != paddingRightWidth)
    {
        paddingWidth += paddingRightWidth;
    }
    
    return paddingWidth;
    
}
    
    

//==================================================================
//
// ActionBarRenderer.js
//
// Implementation of ActionBar rendering class. Creates a horizontal
// bar at the bottom of a form or popup, which can contain zero or
// more "action buttons" (these are simply normal HTML input buttons
// which can be configured in the framework in the normal way) and
// also an optional status bar area.
//
//==================================================================


/**
 * ActionBarRenderer constructor - never used. Use factory methods
 * below to either render an ActionBar into an HTML page, or create
 * an actionbar as a child of another element
 *
 * @private
 * @constructor
 */
function ActionBarRenderer() {}


/**
 * ActionBarRenderer is a sub class of Renderer
 */
ActionBarRenderer.prototype = new Renderer();
ActionBarRenderer.prototype.constructor = ActionBarRenderer;


/**
 * The CSS Classname of the outer element of an action bar
 *
 * @type String
 */
ActionBarRenderer.CSS_CLASS_NAME = "action_bar";


/**
 * An array which contains the buttons on the action bar
 *
 * @type Array[HTMLInputElement]
 * @private
 */
ActionBarRenderer.prototype.m_buttons = null;


/**
 * Render an action bar which includes a status message area at the current
 * location in the document while document is parsing. This is typically used
 * to create actionbars for a form.
 *
 * @param id the id of the action bar
 * @param buttons an array of objects containing the properties:
 *    id: the id of the button
 *    label: the label of the button
 *    className: CSS class to set on the button
 * @param statusBarId the id of the statusbar element. If not specified
 *  then this defaults to "status_line".
 */
ActionBarRenderer.createInline = function(id, buttons, statusBarId)
{
	ActionBarRenderer._createInline(id, buttons, null == statusBarId ? "status_line" : statusBarId);
}


/**
 * Render an action bar without a status line at the current location in the
 * document while document is parsing. This is typically used to create action
 * bars for popups.
 *
 * @param id the id of the action bar
 * @param buttons an array of objects containing the properties:
 *    id: the id of the button
 *    label: the label of the button
 *    className: CSS class to set on the button
 */ 
ActionBarRenderer.createInlineNoStatusBar = function(id, buttons)
{
	ActionBarRenderer._createInline(id, buttons, null);
}


/**
 * Render an action bar which includes a status message area in the document relative
 * to the supplied element. This is typically used to create actionbars for a form.
 *
 * @param refElement the element relative to which the action bar should be rendered
 * @param relativePos the relative position of the action bar to "refElement".
 * Valid values are:
 *     Renderer.CHILD_ELEMENT    Created as a child of "refElement"
 *     Renderer.BEFORE_ELEMENT   Created as preceeding sibling of "refElement"
 *     Renderer.AFTER_ELEMENT    Created as following sibling of "refElement"
 * @param id the id of the action bar
 * @param buttons an array of objects containing the properties:
 *    id: the id of the button
 *    label: the label of the button
 *    className: CSS class to set on the button
 * @param statusBarId the id of the statusbar element. If not specified
 *  then this defaults to "status_line".
 */
ActionBarRenderer.createAsInnerHTML = function(refElement, relativePos, id, buttons, statusBarId)
{
	ActionBarRenderer._createAsInnerHTML(refElement, relativePos, id, buttons, null == statusBarId ? "status_line" : statusBarId);
}


/**
 * Render an action bar without a status line in the document relative to the
 * supplied element. This is typically used to create action bars for popups.
 *
 * @param refElement the element relative to which the action bar should be rendered
 * @param relativePos the relative position of the action bar to "refElement".
 * Valid values are:
 *     Renderer.CHILD_ELEMENT    Created as a child of "refElement"
 *     Renderer.BEFORE_ELEMENT   Created as preceeding sibling of "refElement"
 *     Renderer.AFTER_ELEMENT    Created as following sibling of "refElement"
 * @param id the id of the action bar
 * @param buttons an array of objects containing the properties:
 *    id: the id of the button
 *    label: the label of the button
 *    className: CSS class to set on the button
 */ 
ActionBarRenderer.createAsInnerHTMLNoStatusBar = function(refElement, relativePos, id, buttons)
{
	ActionBarRenderer._createAsInnerHTML(refElement, relativePos, id, buttons, null);
}


/**
 * Create an actionbar at the current location in the document while document
 * is parsing.
 *
 * @param id the id of the action bar being created
 * @param buttons an array of objects containing the properties:
 *    id: the id of the button
 *    label: the label of the button
 *    className: CSS class to set on the button
 * @param statusBarId the id of the statusbar element.
 * @private
 */
ActionBarRenderer._createInline = function(id, buttons, statusBarId)
{
	// Create the outer div by writing to the document.
	var e = Renderer.createInline(
		id,			// The id of the actionbar being created
		false		// The actionbar has an internal input element which can accept focus, so the div should not accept focus
	);

	return ActionBarRenderer._create(e, buttons, statusBarId);
}


/**
 * Create an actionbar in the document immediately after the supplied element
 *
 * @param refElement the element relative to which the grid should be rendered
 * @param relativePos the relative position of the grid to "refElement".
 * Valid values are:
 *     Renderer.CHILD_ELEMENT    Created as a child of "refElement"
 *     Renderer.BEFORE_ELEMENT   Created as preceeding sibling of "refElement"
 *     Renderer.AFTER_ELEMENT    Created as following sibling of "refElement"
 * @param id the id of the actionbar being created
 * @param buttons an array of objects containing the properties:
 *    id: the id of the button
 *    label: the label of the button
 *    className: CSS class to set on the button
 * @param statusBarId the id of the statusbar element.
 * @private
 */
ActionBarRenderer._createAsInnerHTML = function(refElement, relativePos, id, buttons, statusBarId)
{
	var e = Renderer.createAsInnerHTML(
		refElement,		// The element relative to which to create the outer div in the document
		relativePos,	// Relative position of the outer div to the reference element
		id,				// The id of the actionbar being created
		false			// The actionbar has an internal input element which can accept focus, so the div should not accept focus
	);

	return ActionBarRenderer._create(e, buttons, statusBarId);
}


/**
 * Create an actionbar as a child of another element
 * 
 * @param p the parent element to which the actionbar should be added
 * @param id the id of the actionbar being created
 * @param buttons an array of objects containing the properties:
 *    id: the id of the button
 *    label: the label of the button
 *    className: CSS class to set on the button
 * @param statusBarId the id of the statusbar element
 */
ActionBarRenderer.createAsChild = function(p, id, buttons, statusBarId)
{
	var e = Renderer.createAsChild(id);

	// Append the actionbar's outer div to it's parent element
	p.appendChild(e);

	return ActionBarRenderer._create(e, buttons, statusBarId);
}


/**
 * Create the html elements that make up an actionbar
 *
 * @param e the outer element of the actionbar
 * @param buttons an array of objects containing the properties:
 *    id: the id of the button
 *    label: the label of the button
 *    className: CSS class to set on the button
 * @param statusBarId the id of the statusbar element. If null,
 *   then no statusbar will be created.
 * @private
 */
ActionBarRenderer._create = function(e, buttons, statusBarId)
{
	e.className = ActionBarRenderer.CSS_CLASS_NAME;

	var b = new ActionBarRenderer();

	// Initialise sets main element and the reference to the renderer in the dom
	//b._initRenderer(e);
	// Action bar renderer does not have an associated adaptor. Therefore,
	// we should not use _initRenderer method as it sets up a cyclic reference.
	b.m_element = e;	

	var d = document;

	// Create a table for the status label, status message and buttons
	var table = d.createElement("table");
	table.setAttribute("cellspacing", "0px");
	table.setAttribute("cellpadding", "0px");
	table.className = "action_bar_container";
	
	var tbody = d.createElement("tbody");
	table.appendChild(tbody);
	
	var tr = d.createElement("tr");
	tr.className = "action_bar_container_row";
	tbody.appendChild(tr);
	
	if(statusBarId != null)
	{
		// Create a table cell for the status label
		var statusLabelCell = d.createElement("td");
		statusLabelCell.className = "status_label";
		tr.appendChild(statusLabelCell);
	
		// Create a table cell for the status message
		var statusMessageCell = d.createElement("td");
		statusMessageCell.className = "status_message";
		tr.appendChild(statusMessageCell);

		// Set text in status label table cell
		statusLabelCell.innerHTML = "Status";
		
		// Create status message element
		var span = d.createElement("span");
		span.id = statusBarId;
		
		// Add status message element to table cell
		statusMessageCell.appendChild(span);
	}
	
	if(null != buttons && buttons.length > 0)
	{
		// Create a table cell for the buttons
		var buttonsCell = d.createElement("td");
		tr.appendChild(buttonsCell);

		b.m_buttons = new Array(buttons.length);

		// Create buttons container element
		var buttonContainer = d.createElement("div");
		buttonContainer.className = "button_container";

		// Create buttons
		for(var i = 0; i < buttons.length; i++)
		{
			var button = d.createElement("input");
			button.id = buttons[i].id;
			button.setAttribute("type", "button");
			button.setAttribute("value", buttons[i].label);
			button.className = buttons[i].className;
			buttonContainer.appendChild(button);
		
			b.m_buttons[i] = button;
		}
		
		// Add buttons container to table cell
		buttonsCell.appendChild(buttonContainer);
	}
	else
	{
		b.m_buttons = null;
	}

	e.appendChild(table);
	
	return b;
}

/**
 * Get set of buttons on the ActionBar
 *
 * @return an array containing references to the buttons on the ActionBar
 * @type Array[HTMLInputElements]
 */
ActionBarRenderer.prototype.getButtons = function()
{
	return this.m_buttons;
}//==================================================================
//
// PopupRenderer.js
//
// Class which renders outline for a popup
//
//==================================================================


/**
 * PopupRenderer constructor - never used. Use factory methods
 * below to either render a Popup into an HTML page, or create
 * a popup as a child of another element
 *
 * @private
 * @constructor
 */
function PopupRenderer()
{
}


/**
 * PopupRenderer is a sub class of Renderer
 */
PopupRenderer.prototype = new Renderer();
PopupRenderer.prototype.constructor = PopupRenderer;


/**
 * The CSS Classname of the outer div element of a popup
 *
 * @type String
 */
PopupRenderer.CSS_CLASS_NAME = "popup";
PopupRenderer.CSS_CLASS_NAME_FULLPAGE = "popup popup_fullscreen";



PopupRenderer.createAsChild = function(p, id, buttons, title)
{
	var popup = Renderer.createAsChild(id);
	
	var pr = PopupRenderer._create(popup, buttons, title);
	
	p.appendChild(popup);
	
	return pr;
}

PopupRenderer._create = function(p, buttons, title)
{
	var pr = new PopupRenderer();
	
	// Need to keep hold of reference to popup div so it can be raised and lowered.
	pr._setElement(p);
	
	p.className = PopupRenderer.CSS_CLASS_NAME;
	
	// Add a table, so that popup shrinkwraps around its content
	var table = Renderer.createElementAsChild(p, "table");
	table.setAttribute("cellspacing", "0px");
	table.setAttribute("cellpadding", "0px");
	table.className = "popup_layout";
	
	var tbody = Renderer.createElementAsChild(table, "tbody");	
	
	if(null != title)
	{
		var titleRow = Renderer.createElementAsChild(tbody, "tr");
		var titleCell = Renderer.createElementAsChild(titleRow, "td");
		pr.m_titleContainer = Renderer.createElementAsChild(titleCell, "div");
		pr.m_titleContainer.className = "popupTitle";
		pr.m_titleContainer.innerHTML = title;
	}
	
	var contentsRow = Renderer.createElementAsChild(tbody, "tr");
	
	// Create td element which contains the popup's contents
	pr.m_container = Renderer.createElementAsChild(contentsRow, "td");
	pr.m_container.className = "popup_contents";
	
	var actionBarRow = Renderer.createElementAsChild(tbody, "tr");
	var actionBarCell = Renderer.createElementAsChild(actionBarRow, "td");
	actionBarCell.className = "actionbar_container";
	
	// Create the actionbar
	pr.m_actionBar = ActionBarRenderer.createAsChild(
		actionBarCell,
		p.id + "_actionbar",
		buttons
	);
	
	return pr;
}


/**
 * Get the HTML element which contains the popup's contents
 *
 * @return the HTML element which contains the popup's contents.
 * @type HTMLTDElement
 */
PopupRenderer.prototype.getContentsContainerElement = function()
{
	return this.m_container;
}


/**
 * Get the ActionBarRenderer for the popup
 *
 * @return the ActionBarRenderer for the popup
 * @type ActionBarRenderer
 */
PopupRenderer.prototype.getActionBarRenderer = function()
{
	return this.m_actionBar;
}


/**
 * Get the HTML element which contains the popup's title bar contents
 *
 * @return the HTML element which contains the popup's title bar contents.
 * @type HTMLTDElement
 */
PopupRenderer.prototype.getTitleBarContainer = function()
{
	return this.m_titleContainer;
}//==================================================================
//
// PopupLowerBusinessLifeCycle.js
//
// Business Life Cycle class for lowering popups. This is along with
// PopupRaiseBusinessLifeCycle are essentially BusinessLifeCycle
// adaptors for the ComponentVisibilityProtocol, and therefore can
// generally be re-used for all components supporting the
// ComponentVisibilityProtocol.
//
//==================================================================


/**
 * BusinessLifeCycle to lower a popup
 */
function PopupLowerBusinessLifeCycle() {}

// PopupLowerBusinessLifeCycle is a sub class of BusinessLifeCycle
PopupLowerBusinessLifeCycle.prototype = new BusinessLifeCycle();
PopupLowerBusinessLifeCycle.prototype.constructor = PopupLowerBusinessLifeCycle;


/**
 * Get the name of the BusinessLifeCycle.
 *
 * @return the name of the BusinessLifeCycle
 * @type String
 */
PopupLowerBusinessLifeCycle.prototype.getName = function()
{
	return BusinessLifeCycleEvents.EVENT_LOWER;
}


/**
 * Invoke the business logic associated with this BusinessLifeCycle.
 * In this case this cause the requested popup to be hidden
 *
 * @param e the BusinessLifeCycleEvent
 */
PopupLowerBusinessLifeCycle.prototype.invokeBusinessLifeCycle = function(e)
{
	this.m_adaptor.show(false);
}
//==================================================================
//
// PopupRaiseBusinessLifeCycle.js
//
// Business Life Cycle class for raising popups. This is along with
// PopupLowerBusinessLifeCycle are essentially BusinessLifeCycle
// adaptors for the ComponentVisibilityProtocol, and therefore can
// generally be re-used for all components supporting the
// ComponentVisibilityProtocol.
//
//==================================================================


/**
 * BusinessLifeCycle to raise a popup
 */
function PopupRaiseBusinessLifeCycle() {}

// PopupRaiseBusinessLifeCycle is a sub class of BusinessLifeCycle
PopupRaiseBusinessLifeCycle.prototype = new BusinessLifeCycle();
PopupRaiseBusinessLifeCycle.prototype.constructor = PopupRaiseBusinessLifeCycle;


/**
 * Get the name of the BusinessLifeCycle.
 *
 * @return the name of the BusinessLifeCycle
 * @type String
 */
PopupRaiseBusinessLifeCycle.prototype.getName = function()
{
	return BusinessLifeCycleEvents.EVENT_RAISE;
}


/**
 * Invoke the business logic associated with this BusinessLifeCycle.
 * In this case this cause the requested popup to be shown
 *
 * @param e the BusinessLifeCycleEvent
 */
PopupRaiseBusinessLifeCycle.prototype.invokeBusinessLifeCycle = function(e)
{
    // Defect 1164. This life cycle action has become more complex owing
    // to problems with IE selects. If a popup is raised using a hot key
    // combination and the currently focussed adaptor on the background
    // form is an IE select the tabbing manager may not be able to focus
    // on the popup correctly. The problem is probably caused by the IE
    // select being disabled whilst it has focus.
    //
    // To prevent these problems the IE select must be unfocussed before
    // the popup is raised. In this case the identifier of the select
    // must be passed to the popup adaptor such that focus can be
    // returned to the select when the popup is closed.
    
    // Determine currently focussed adaptor
    var tm = FormController.getInstance().getTabbingManager();
    
    if(null != tm)
    {
        var currentFocussedAdaptor = tm.m_currentFocussedAdaptor;
        
        if(null != currentFocussedAdaptor &&
           (currentFocussedAdaptor instanceof SelectElementGUIAdaptor))
        {
            // Queue tabbing event corresponding to click on form background.
            // This will cause the select to lose focus.
            tm.queueTabbingEvent( new TabbingEvent( TabbingEvent.EVENTS.CLICK_FOCUS,
                                                    null ) );
                                                    
            // Tabbing events are processed after time out. Therefore, we must
            // delay invocation of popup show method.
            var adaptorId = this.m_adaptor.getId();
            var currentFocussedAdaptorId = currentFocussedAdaptor.getId();
            
            setTimeout( function(){ Services.getAdaptorById(adaptorId).show( true, currentFocussedAdaptorId ); }, 0 );
        }
        else
        {
            // Raise popup
            this.m_adaptor.show(true);
        }
    }
    else
    {
        // Raise popup
        this.m_adaptor.show(true);
    }
}


/**
 * Derived BusinessLifeCycle specific configuration.
 * For backwards compatability with existing code, the PopupRaiseBusinessLifeCycles
 * allows eventBindings to specified directly as the .raise configuration object,
 * rather than .raise.eventBindings. 
 *
 * @param config the BusinessLifeCycle configuration
 */ 
PopupRaiseBusinessLifeCycle.prototype._configure = function(config)
{
	// If eventBindings not configured already by base class, try to configure
	// then directly using the supplied config object here - for backwards 
	// compatability.
	if(null == this.m_eventBinding)
	{
	    var id = this.m_adaptor.getId() + 
	             "_" +
	             this.getName() +
	             "_eventBinding";
	             
		this.m_eventBinding = new EventBinding(id);
		
		this.m_eventBinding.configure(config);
		
		if(this.m_eventBinding.hasConfiguredProperty( "isEnabled" ) )
		{
		    FormController.getInstance().addEnablementEventBinding(this.m_eventBinding);
		}
		
		var thisObj = this;
		this.m_eventBinding.bind( function() { thisObj.dispatchEvent(); } );
	}
}
//==================================================================
//
// StandardDialogRenderer.js
//
// Renders HTML for Standard Prompt Dialogs that display a message and
// allow the user to select between available options by clicking
// on one of the buttons on the Popup's ActionBar.
//
//==================================================================


function StandardDialogRenderer()
{
}


/**
 * StandardDialogRenderer is a sub class of Renderer
 */
StandardDialogRenderer.prototype = new Renderer();
StandardDialogRenderer.prototype.constructor = StandardDialogRenderer;


/**
 * CSS Class name of the outermost div of the standard dialog
 */
StandardDialogRenderer.CSS_CLASS_NAME = "standard_dialog";

StandardDialogRenderer.DEFAULT_WIDTH = 500;
StandardDialogRenderer.FULLSCREEN_GAP = 10;

/**
 * Maximum number of buttons supported by a Standard Dialog
 *
 * @private
 * @type Integer
 */
StandardDialogRenderer.NUMBER_OF_BUTTONS = 3;


/**
 * Reference to the popup renderer used to create the standard dialog
 *
 * @private
 * @type PopupRenderer
 */
StandardDialogRenderer.prototype.m_popup = null;


/**
 * Reference to div element which contains the message
 * 
 * @private
 * type HTMLDivElement
 */
StandardDialogRenderer.prototype.m_messageContainer = null;


/**
 * Type of dialog which is currently renderered - see StandardDialogTypes
 * in ServicesConstants.js for actual values.
 *
 * @private
 * @type Integer
 */
StandardDialogRenderer.prototype.m_type = undefined;


/**
 * Create a standard dialog as a child of another element
 * (Which is usually the form element)
 *
 * @param id the id of the standard dialog being created
 */
StandardDialogRenderer.createAsChild = function(p, id)
{
	var e = Renderer.createAsChild(id);

	// Append the standard dialog's outer div to it's parent element
	p.appendChild(e);	
	
	return StandardDialogRenderer._create(e);
}


StandardDialogRenderer._create = function(e)
{
	e.className = StandardDialogRenderer.CSS_CLASS_NAME;

	var sdr = new StandardDialogRenderer();

	var id = e.id;

	// Generate array of buttons with generated ids and labels - labels
	// are updated later on.
	var buttons = new Array(StandardDialogRenderer.NUMBER_OF_BUTTONS);
	for(var i = 0, l = buttons.length; i < l; i++)
	{
		buttons[i] = {id: id + "_button_" + i, label: "button " + i};
	}

	sdr.m_popup = PopupRenderer.createAsChild(
		e,							// Parent of popup
		id + "_popup",				// Id of popup
		buttons,					// Generated array of buttons
		"standard_dialog_" + id		// Generated title
	);
	
	
	var contents = sdr.m_popup.getContentsContainerElement();
	var panel = Renderer.createElementAsChild(contents, "div");
	panel.className = "panel";
	
	sdr.m_messageContainer = Renderer.createElementAsChild(panel, "div");
	sdr.m_messageContainer.className = "message_container";

	// Initialise sets main element (which is the same as the popup's main element)
	// and the reference to the renderer in the dom
	sdr._initRenderer(sdr.m_popup.getElement());
	
	// RWW. Reference to renderer in DOM causes cyclic reference which must be broken
	sdr.m_popup.getElement().__renderer = null;

	return sdr;
}


StandardDialogRenderer.prototype.getButtons = function()
{
	return this.m_popup.getActionBarRenderer().getButtons();
}



StandardDialogRenderer.prototype.setTitle = function(title)
{
	this.m_popup.getTitleBarContainer().innerHTML = title;
}


StandardDialogRenderer.prototype.setMessage = function(message)
{
	this.m_messageContainer.innerHTML = message;
}


StandardDialogRenderer.prototype.setType = function(type)
{
	if(this.m_type != type)
	{
		// Array containing HTML input elements that implement the buttons
		var buttons = this.getButtons();

		// Get the types of buttons for this type of standard dialog
		var buttonTypes = StandardDialogRenderer.BUTTON_MAP[type];
		
		// Get the number of buttons needed for this type of standard dialog
		var buttonCount = buttonTypes.length;
		
		// Set up button labels	for the required buttons
		var i = 0;
		for(; i < buttonCount; i++)
		{
			buttons[i].value = StandardDialogRenderer.BUTTON_LABELS[buttonTypes[i]];
		}

		// Re-use counter
		i = 0;
		
		// Make required number of buttons visible
		for(; i < buttonCount; i++)
		{
			buttons[i].style.display = "";
		}
		// Hide the rest.
		for(l = buttons.length; i < l; i++)
		{
			buttons[i].style.display = "none";
		}
	
		// Remember the type
		this.m_type = type;
	}

}

/**
 * Set the width of the popup
 *
 * @param width the popup's required width
 * Optional, default width is 500px
 */
StandardDialogRenderer.prototype.setWidth = function(width)
{
	// Set default width if required
	width = Number(width);
	width =
		(isNaN(width) || 0 == width || width < 0)
		? StandardDialogRenderer.DEFAULT_WIDTH
		: width;

	// If wider than form's iframe set to iframe width
	var e = this.getElement();
	var docEl = e.ownerDocument.documentElement;
	var windowWidth =
		window.innerWidth != null
		? window.innerWidth				// W3C
		: docEl.clientWidth;			// IE

	// Leave a gap between dialog and screen left/right edges
	windowWidth -= (StandardDialogRenderer.FULLSCREEN_GAP * 2);

	if (width >= windowWidth) {
		width = windowWidth;
	}

	e.style.width = width  + "px";
}

/**
 * Position the popup in the centre of the form's iframe
 *
 * @param top the popup's top left y position.
 * Optional, default is to center in the forms's iframe
 * @param left the popup's top left x position.
 * Optional, default is to center in the forms's iframe
 */
StandardDialogRenderer.prototype.positionPopup = function(top, left)
{
	var e = this.getElement();
	var docEl = e.ownerDocument.documentElement;

	var windowHeight = 
		window.innerHeight != null
		? window.innerHeight			// W3C
		: docEl.clientHeight;			// IE
	var windowWidth =
		window.innerWidth != null
		? window.innerWidth				// W3C
		: docEl.clientWidth;			// IE
	var scrollY = 
		window.pageYOffset != null
		? window.pageYOffset			// W3C
		: docEl.scrollTop;				// IE

	var popupWidth = e.offsetWidth;
	var popupHeight = e.offsetHeight;

	var x = (null == left || isNaN(left)) ? (windowWidth - popupWidth) / 2 : Number(left);
	var y = (null == top || isNaN(top)) ? (windowHeight - popupHeight) / 2 : Number(top);

    // Check horizontal position of popup
    if (x + popupWidth > windowWidth)
    {  
        // Reset popup position so that right of popup is at right of window
        x = windowWidth - popupWidth;    
    }

	if (x < 0) {
		x = 0;
	}

    // Check vertical position of popup
    if (y + popupHeight > windowHeight + scrollY)
    { 
        // Reset popup position so that bottom of popup is at bottom of window   
        y = windowHeight - popupHeight;
    }

    if (y < 0) {
    	y = 0;
    }

	e.style.position = "absolute";
	e.style.left = x + "px";
	e.style.top = y + "px";
}


StandardDialogRenderer.prototype.getButtonClicked = function(button)
{
	// Get the button number from the id
	var buttonNumber = button.id.slice(-1);

	// Get the available button types for this type of standard dialog
	var buttonTypes = StandardDialogRenderer.BUTTON_MAP[this.m_type];
	
	// Get the button type clicked based on its button number
	var clickedButtonType = buttonTypes[buttonNumber];
	
	return clickedButtonType;
}



StandardDialogRenderer.BUTTON_MAP = [
	[StandardDialogButtonTypes.OK],
	[StandardDialogButtonTypes.OK, StandardDialogButtonTypes.CANCEL],
	[StandardDialogButtonTypes.YES, StandardDialogButtonTypes.NO],
	[StandardDialogButtonTypes.YES, StandardDialogButtonTypes.NO, StandardDialogButtonTypes.CANCEL]
];


StandardDialogRenderer.BUTTON_LABELS = [
	"OK",
	"Cancel",
	"Yes",
	"No"
];
//==================================================================
//
// StandardDialogManager.js
//
// Implements Standard Prompt Dialogs that display a message and
// allow the user to select between available options by clicking
// on one of the buttons on the Popup's ActionBar.
//
//==================================================================


function StandardDialogManager()
{
}


StandardDialogManager.m_instances = new Array();

StandardDialogManager.m_allocatedCount = 0;

StandardDialogManager.DIALOG_ID_PREFIX = "fw_standard_dialog_";

StandardDialogManager._getInstance = function()
{
	// Create new instances if all existing instances are allocated.
	if(StandardDialogManager.m_instances.length <= StandardDialogManager.m_allocatedCount)
	{
		StandardDialogManager.m_instances[StandardDialogManager.m_instances.length] = StandardDialogManager._createInstance()
	}
	
	// Get the first available StandardDialogManager
	var d = StandardDialogManager.m_instances[StandardDialogManager.m_allocatedCount++];
	
	return d;
}


StandardDialogManager._createInstance = function()
{
	var fc = FormController.getInstance();

	var form = fc.getFormAdaptor();
	
	var formElement = form.getElement();

	// Create HTML View 
	var d = StandardDialogRenderer.createAsChild(formElement, StandardDialogManager.DIALOG_ID_PREFIX + StandardDialogManager.m_instances.length);
	
	var view = fc.getFormView();
	var cm = view.getConfigManager();
	
	var buttons = d.getButtons();
	// Create configuration for popup and buttons
	for(var i = 0, l = buttons.length; i < l; i++)
	{
		// Do this in its own method so that we get a closure for each button
		StandardDialogManager._createActionBinding(cm, d, buttons[i]);
	}
	
	// Call GUIAdaptorFactory to produce set of adaptors for the popup
	var factory = view.getGUIAdaptorFactory();
	var popupAdaptors = factory.parseElement(d.getElement(), form)
	
	// Add adaptors to FormController
	fc.addAdaptors(popupAdaptors);
	
	return d;
}


StandardDialogManager._createActionBinding = function(cm, sd, b)
{
	cm.setConfig(b.id, { actionBinding: function() { StandardDialogManager._handleButtonClick(sd, b); } });
}


StandardDialogManager.showDialog = function(type, callback, message, title, width, top, left)
{
	// Get an instance of a StandardDialog - they are reused for the life time of a form
	var sd = StandardDialogManager._getInstance();

	// Do we need to provide a default title based on dialog type?
	
	// If the input argument "title" is null use name of project
	if(null == title)
	{
	    title = StandardDialogManager._getProjectName();
	}
	sd.setTitle(title);
	
	// Set message.
	sd.setMessage(message);
	
	// Set type
	sd.setType(type);

	// Delete the callback here rather than in _handleButtonClick because
	// with standard dialogs called in sequence:
	// 1) A button is clicked on a standard dialog
	// 2) The callback function is called
	// 3) The callback function shows another standard dialog, setting up a
	//    callback in the process
	// 4) _handleButtonClick() for the button clicked in 1) is called
	//    This would delete the callback function we have just setup in 3)
	// 5) Clicking a button on the dialog shown in 3) would result in a callback
	//    is null error
	delete sd.callback;

	// Hack!
	sd.callback = callback;

	sd.setWidth(width);

	// Position the popup in the iframe
	sd.positionPopup(top, left);

	// Show the popup	
	Services.dispatchEvent(sd.getElement().id, PopupGUIAdaptor.EVENT_RAISE);
}


StandardDialogManager._handleButtonClick = function(sd, button)
{
	// Free up the dialog for re-use
	StandardDialogManager.m_allocatedCount--;

	// Hide the popup
	Services.dispatchEvent(sd.getElement().id, PopupGUIAdaptor.EVENT_LOWER);

	// Get the button which was clicked.
	var buttonClicked = sd.getButtonClicked(button);
	
	// Call the callback
	sd.callback.call(null, buttonClicked);

	//delete sd.callback;
}

/**
 * Method returns name of project as defined in the application
 * configuration XML file. If no project name is defined an empty
 * string will be returned.
 *
*/
StandardDialogManager._getProjectName = function()
{
    var ac = Services.getAppController();
    
    return ac.getProjectName();
}
//==================================================================
//
// LoginGUIAdaptor.js
//
// Class for adapting a text style input element for use in the
// framework
//
//==================================================================


/**
 * Base class for adapting html input elements for use in the
 * framework.
 *
 * @param e the input element to manage
 * @constructor
 * @private
 */
function LoginGUIAdaptor()
{
	//this.m_keys = new Array();
	//this.retrieveOn = new Array();
	this.successForm = null ;
	this.failureForm = null ;
}

LoginGUIAdaptor.m_logger = new Category("LoginGUIAdaptor");

/**
 * Username and password input boxes data bindings
 */
LoginGUIAdaptor.USERNAME_DATA_BINDING = "/ds/private/username";
LoginGUIAdaptor.PASSWORD_DATA_BINDING = "/ds/private/password";

LoginGUIAdaptor.LOGIN_ERROR_MSG = "Invalid Username or Password";

/**
 * LoginGUIAdaptor is a sub class of InputElementGUIAdaptor
 */                             
LoginGUIAdaptor.prototype = new HTMLElementGUIAdaptor();
LoginGUIAdaptor.prototype.constructor = LoginGUIAdaptor;

/**
 * Add the required protocols to the CheckboxInputElementGUIAdaptor
 * Note: Does not use FieldElement etc. as did not want to inherit mandatory protocol
 */
 
GUIAdaptor._setUpProtocols('LoginGUIAdaptor'); 

/**
 * Clean up after the component
 */
LoginGUIAdaptor.prototype._dispose = function()
{
	if(LoginGUIAdaptor.m_logger.isInfo()) LoginGUIAdaptor.m_logger.info("LoginGUIAdaptor.dispose()");

	// Break circular reference in HTML
	this.m_element.__renderer = null;
}

/**
 * Create a new LoginGUIAdaptor
 *
 * @param e the text input element to manage
 * @return the new LoginGUIAdaptor
 * @type LoginGUIAdaptor
 */
LoginGUIAdaptor.create = function(e)
{
	if(LoginGUIAdaptor.m_logger.isInfo()) LoginGUIAdaptor.m_logger.info("LoginGUIAdaptor.create()");
	var a = new LoginGUIAdaptor();
	a._initLoginGUIAdaptor(e);
	
	return a;
}


/**
 * Initialise the LoginGUIAdaptor
 *
 * @param e the HTMLElement for the select element to be managed
 * @private
 */
LoginGUIAdaptor.prototype._initLoginGUIAdaptor = function(e)
{
	if(LoginGUIAdaptor.m_logger.isInfo()) LoginGUIAdaptor.m_logger.info("LoginGUIAdaptor._initLoginGUIAdaptor");
	this.m_element = e;
}

LoginGUIAdaptor.DEFAULT_MAX_LENGTH = 10;

/**
 * Perform any GUIAdaptor specific configuration - this also creates the config
 * objects for the sub-components dynamically
 */
LoginGUIAdaptor.prototype._configure = function(cs)
{
	if(LoginGUIAdaptor.m_logger.isInfo()) LoginGUIAdaptor.m_logger.info("LoginGUIAdaptor._configure()");

	var thisObj = this ;
	var id = this.m_element.id;
    	
	var ctor1 = function() {};
	window[id+"_username"] = ctor1;
	ctor1.dataBinding = LoginGUIAdaptor.USERNAME_DATA_BINDING;
	ctor1.isMandatory = function () {return true;} ;
	
	var ctor2 = function() {} ;
	window[id+"_password"] = ctor2;
	ctor2.dataBinding = LoginGUIAdaptor.PASSWORD_DATA_BINDING;
	ctor2.isMandatory = function () {return true;} ;
	
	for(var i=0; i<cs.length; i++)
	{
		var c = cs[i];
		if(this.m_successForm == null && c.successForm != null)
		{
			this.m_successForm = c.successForm;
		}
	}
	
	if(this.m_successForm == null)
	{
		throw new ConfigurationException("the successForm configuration is mandatory for Login adaptor");
	}
	
	var ctor = function() {};
	window[id + "_button"] = ctor;
	ctor.actionBinding = function() 
	{
		var ue = document.getElementById(id + "_username");
		var pe = document.getElementById(id + "_password");
		var username = ue.value;
		var password = pe.value;
	    
		if (null == username || "" == username)
		{
			thisObj._showAlert(LoginGUIAdaptor.LOGIN_ERROR_MSG, id + "_username");
		}
		else if (null == password || "" == password)
		{
			thisObj._showAlert(LoginGUIAdaptor.LOGIN_ERROR_MSG, id + "_password");
		}
		else
		{		
			var callback = new Object() ;
			callback.controller = thisObj ;
			callback.method = thisObj.loginCallBack ;
	
			Services.login(callback, username.toLowerCase(), password);
		}
	};
	// configure key binding for return key in username or password field
	ctor.additionalBindings = {
		eventBinding: {
			keys: [ { key: Key.Return, element: id + "_username" },
					{ key: Key.Return, element: id + "_password" } ]
		}
	};
	
	// configure max length on username
	var ue = document.getElementById(id + "_username");
	ue.maxLength = LoginGUIAdaptor.DEFAULT_MAX_LENGTH;
}

/**
* Receives call back from the login
* @param SecurityContext
* @authenticationResult, result returned from the Security.login call
*/
LoginGUIAdaptor.prototype.loginCallBack = function(SecurityContext,authenticationResult)
{
	var id = this.getId() + "_password";

	// If we have successfully logged in or there is an error then remove the
	// password from the data model because it is stored as clear text
	Services.setValue(LoginGUIAdaptor.PASSWORD_DATA_BINDING, "");
	
	if ( null != authenticationResult)
	{
		if (true == authenticationResult.error)
		{
			this._showAlert(
				"An Error occurred calling the Login Service: " + authenticationResult.detail,
				id
			);
		}
		else
		{
			if ( null != authenticationResult.value && authenticationResult.value.length > 0)
			{
				var ac = Services.getAppController();
				ac._showUser() ;
				
				// We don't navigate to the successForm until we have loaded the ref data needed by security
				var securityService = ac.getSecurityServiceByName("getHomeCourt");
				var serviceParams = LoginGUIAdaptor.getSecurityServiceParams("getHomeCourt");
				var username = Services.getValue(LoginGUIAdaptor.USERNAME_DATA_BINDING).toLowerCase();
				
				serviceParams.addSimpleParameter("userId", username);
				serviceParams.addSimpleParameter("getHomeCourt", "true");

				// This is a bit filthy because callService does not allow you to pass in a object to be used
				// as the context object for the callback, i.e. this instance of the login gui adaptor, but there
				// should only be one instance of a login adaptor active at any one time so this should work.
				LoginGUIAdaptor.m_successForm = this.m_successForm;
				var callback = new Object() ;
				callback.onSuccess = LoginGUIAdaptor.getCourtIdCallback;
				callback.onError = LoginGUIAdaptor.onGetCourtIdError;
				Services.callService(securityService.getName(), serviceParams, callback, true);
			}
			else
			{
			    this._showAlert(LoginGUIAdaptor.LOGIN_ERROR_MSG, id);
			}
		}
	}
	else
	{
		this._showAlert("Error in calling Login Service", id);
	}
}

/**
 * Shows a message in an OK dialog and then sets focus on the supplied field
 *
 * @param msg the text message to display in the dialog
 * @param fieldId the identifier of the field to focus on
*/
LoginGUIAdaptor.prototype._showAlert = function(msg, fieldId)
{
	var ac = Services.getAppController();
	var thisObj = this;
    var callbackFunction = function(userResponse)
    {
		setTimeout(function() { thisObj._setFocus(fieldId); }, 0);
    }
    
	if (ac.getDialogStyle() == AppConfig.FRAMEWORK_DIALOG_STYLE)
	{
		Services.showAlert(msg, callbackFunction);
	}
	else
	{
		alert(msg);
		setTimeout(function() { thisObj._setFocus(fieldId); }, 0);
	}
}

/**
 * Set focus on the supplied field
 *
 * @param fieldId the identifier of the field to focus on
*/
LoginGUIAdaptor.prototype._setFocus = function(fieldId)
{
	// Clear out tabbing events queue first to prevent the focus jumping
	// from the user name field to the password field
	TabbingManager._processTabbingEvents();
	Services.setFocus(fieldId);
}

LoginGUIAdaptor.onGetCourtIdError = function(ex)
{
	Services.showAlert("Error loading home court for user");
}

/**
 *
 <UserPersonalDetails>
	<HomeCourt/>
	<UserId/>
	<Forenames/>
	<Surname/>
	<Title/>
	<UserShortName/>
	<JobTitle/>
	<Extension/>
	<IsActive/>
	<StyleProfile/>
	<DefaultPrinter/>
</UserPersonalDetails>
 
 */
LoginGUIAdaptor.getCourtIdCallback = function(resultDom)
{
	var ac = Services.getAppController();
	var securityService = ac.getSecurityServiceByName("getHomeCourt");
	Services.setValue(securityService.getDataBinding(), XML.selectNodeGetTextContent(resultDom, "//HomeCourt"));
	Services.setValue("/ds/var/app/StyleProfile", XML.selectNodeGetTextContent(resultDom, "//StyleProfile"));
	Services.setValue("/ds/var/app/DefaultPrinter", XML.selectNodeGetTextContent(resultDom, "//DefaultPrinter"));

	var styleName = Services.getValue("/ds/var/app/StyleProfile");
	if(null != styleName && "" != styleName)
	{
		// Would use exception to report unrecognised style name,
		// but we're dealing with a different frame here and 
		// exceptions don't propogate well across frames so we
		// use simple return value to indicate success or failure
		var result = ac.getStyleManager().setStyle(styleName);
		if(!result)
		{
			// Unrecognised style, so tell the stylemanager to use the default
			Services.showAlert("Unrecognised style name '" + styleName + "' in user profile. Using default style instead.");
			ac.getStyleManager().setStyle(null);
		}
	}

	var getRolesSecurityService = ac.getSecurityServiceByName("getRoles");
	var serviceParams = LoginGUIAdaptor.getSecurityServiceParams("getRoles");
	// The getRoles method now requires the userId because it can be called from the maintain users page so
	// we can't assume it always for the current user, even though it is in this instance
	serviceParams.addSimpleParameter("userId", ac.getSecurityContext().getCurrentUser().getUserName());

	var callback = new Object() ;
	callback.onSuccess = LoginGUIAdaptor.getRolesCallback ;
	callback.onError = LoginGUIAdaptor.onGetRolesError ;
	Services.callService(getRolesSecurityService.getName(), serviceParams, callback, true);
}

LoginGUIAdaptor.getRolesCallback = function(resultDom)
{
	var securityService = Services.getAppController().getSecurityServiceByName("getRoles");
	
	var db = securityService.getDataBinding();
	// Remove any existing roles in case we are logging in for a second time
	Services.removeNode(db);
	// We want to remove the trailing 'roles' node because the xml that is returned contains
	// a top node that is also 'roles'.
	db = XPathUtils.removeTrailingNode(db);
	Services.addNode(resultDom, db);

	Services.navigate(LoginGUIAdaptor.m_successForm, false);
}

LoginGUIAdaptor.onGetRolesError = function(ex)
{
	Services.showAlert("Error loading roles for user");
}

LoginGUIAdaptor.getSecurityServiceParams = function(name)
{
	var service = Services.getAppController().getSecurityServiceByName(name);
	var params = new ServiceParams();
	var value = null;
	var serviceParams = service.getParameters();
	for(var i=0; i<serviceParams.length; i++)
	{
		var serviceParam = serviceParams[i];
		value = Services.getValue(serviceParam.value);
		params.addSimpleParameter(serviceParam.name, value);
	}
	return params;
}

