//==================================================================
//
// FramedFieldRenderer.js
//
// Implementation of FramedField rendering class. This is a base
// class for components which consist of a text field and some other
// user interface components that are all enclosed by a frame.
// Examples are buttonfields (which in turn are used as the basis
// for dropdown fields and subsequently for datepickers
// and autocompletes, and also zoomable text fields) that are a
// fields with an associated button.
// The frame and the input field are used to represent the state of
// the field. e.g. The frame is rendered red when the field is
// invalid or the background of the input field is rendered purple
// when the field is mandatory.
//
//==================================================================


/**
 * Constructor for the FramedFieldRenderer - use FramedFieldRenderer.create
 * to create actual instances.
 *
 * @constructor
 * @private
 */ 
function FramedFieldRenderer()
{
}

/**
 * The Logging Category for the FramedFieldRenderer
 *
 * @type Category
 * @private
 */
FramedFieldRenderer.m_logger = new Category("FramedFieldRenderer");


/**
 * The CSS Class names for the elements that represents the framed field
 *
 * @type String
 */
FramedFieldRenderer.TABLE_BORDER_CSS_CLASS_NAME = "framedfield_table_border"
FramedFieldRenderer.LAYOUT_TABLE_CSS_CLASS_NAME = "framedfield_container"


/**
 * Flag to indicate whether or not the field should be rendered as disabled
 *
 * @type Boolean
 */
FramedFieldRenderer.prototype.m_disabled = false;


/**
 * Flag to indicate whether or not the field should be rendered as focussed
 *
 * @type Boolean
 */
FramedFieldRenderer.prototype.m_focussed = false;


/**
 * Flag to indicate whether or not the field should be rendered as mandatory
 *
 * @type Boolean
 */
FramedFieldRenderer.prototype.m_mandatory = false;


/**
 * Flag to indicate whether or not the field should be rendered as invalid
 *
 * @type Boolean
 */
FramedFieldRenderer.prototype.m_invalid = false;
FramedFieldRenderer.prototype.m_serverInvalid = false;


/**
 * Flag to indicate whether or not the field should be rendered as readonly
 *
 * @type Boolean
 */
FramedFieldRenderer.prototype.m_readonly = false;


/**
 * Flag to indicate whether or not the field should be rendered as inactive
 *
 * @type Boolean
 */
FramedFieldRenderer.prototype.m_inactive = false;




/**
 * Create the framed field as a child of another element
 *
 * @param p the parent element to create the child under
 * @param className the outer div element's class name
 * @param multiline determines what the input field is rendered as
 *        If true it is rendered as a text area otherwise as a text input box
 * @return a new ButtonFieldRenderer instance
 * @type ButtonFieldRenderer
 */
FramedFieldRenderer.createAsChild = function(p, className, multiline)
{
	// Create the outer div element
	var e = document.createElement("div");
	  
	// Append the framed field to it's parent element
	p.appendChild(e);
	
	// Create the rest of the dropdown field
	return FramedFieldRenderer._create(e, className, multiline);
}


/**
 * Create the framed field.
 *
 * The html (with additional whitespace for clarity) for a dropdown is:
 *
 *  <div class="cN">
 *   <div>
 *    <table class="buttonfield_table" cellspacing="0px" cellpadding="0px">
 *      <tbody>
 *        <tr>
 *          <td class="buttonfield_field_container">
 *            <input class="buttonfield_field" />
 *          </td>
 *          <td class="buttonfield_button_container">
 *            <div class="button"></div>
 *          </td>
 *        </tr>
 *      </tbody>
 *    </table>
 *   </div>
 *  </div>
 *
 * The additional whitespace must not be included! Styling is
 * provided by the associated ButtonField.css
 *
 * @param p the parent element to which the framed field will be added.
 * @param className the outer div element's class name
 * @param multiline determines what the input field is rendered as
 *        If true it is rendered as a text area otherwise as a text input box
 */
FramedFieldRenderer._create = function(e, cN, multiline)
{
	var f = new FramedFieldRenderer();

	// Set the className of the outer element
	e.className = cN;

	// Keep the class name
	f.m_className = cN;

	// Keep reference to the outer element
	f.m_element = e;

	// D695 - Table borders in IE cause problems when subforms are closed.
	// Use a div surrounding the table as a border
	f.m_borderDiv = document.createElement("div");
	f.m_borderDiv.className = FramedFieldRenderer.TABLE_BORDER_CSS_CLASS_NAME;
	f.m_element.appendChild(f.m_borderDiv);

	var table = document.createElement("table");
	table.className = FramedFieldRenderer.LAYOUT_TABLE_CSS_CLASS_NAME;

	// Ideally these attributes could be specified in the stylesheet,
	// but CSS support in this area is too flaky.
	table.setAttribute("cellspacing", "0px");
	table.setAttribute("cellpadding", "0px");
	
	// Add the table to the container.
	f.m_borderDiv.appendChild(table);
	
	// Create table body
	var tBody = document.createElement("tbody");
	table.appendChild(tBody);
	
	// Create table row
	f.m_row = document.createElement("tr");
	tBody.appendChild(f.m_row);
	
	// Create table cell which will contain the input field
	var inputCell = document.createElement("td");
	inputCell.className = "framedfield_field_container";
	f.m_row.appendChild(inputCell);

	if(multiline) {
		// Create input field as a single row text area
		f.m_inputField = document.createElement("textarea");
		f.m_inputField.setAttribute("rows", 1);
		// Field width is 100% in style sheet, this amount of characters fills
		// the input field's default width
		f.m_inputField.setAttribute("cols", 19);
		f.m_inputField.setAttribute("wrap", "soft");
	}
	else {
		// Create input field as a text input box
		f.m_inputField = document.createElement("input");
		f.m_inputField.setAttribute("type", "text");
	}

	f.m_inputField.className = "framedfield_field";

	inputCell.appendChild(f.m_inputField);

	// Make a cache for the offsetWidth of the parent node
	// This is a workaround for an IE bug which causes the screen to
	// flash under some circumstances when the offsetWidth is read.
	f.m_offsetWidth = 0;

	return f;
}


/**
 * Perform any required cleanup
 */
FramedFieldRenderer.prototype.dispose = function()
{
	// Remove reference to adaptor
	this.m_guiAdaptor = null;
}


/**
 * Get the input text field element
 *
 * @return the reference the fields text input element 
 * @type HTMLInputElement
 */
FramedFieldRenderer.prototype._getInputFieldElement = function()
{	
	return this.m_inputField;
}


/**
 * Add a container to the right of the input field, to which
 * content may be added
 *
 * @return an HTMLElement to which content may be added
 * @type HTMLElement
 */
FramedFieldRenderer.prototype.addCellAfterField = function()
{
	var c = document.createElement("td");
	this.m_row.appendChild(c);
	return c;
}


/**
 * Render the FramedField according to it's state
 *
 * @param disabled true if the field is to be rendered as disabled
 * @param focussed true if the field is to be rendered as focussed
 * @param mandatory true if the field is to be rendered as mandatory
 * @param invalid true if the field is to be rendered as invalid
 * @param readonly true if the field is to be rendered as readonly
 * @param inactive true if the field is to be rendered as inactive
 * @param isServerValidationActive true if the field is to be rendered as server validation active
 */
FramedFieldRenderer.prototype.render = function(disabled, focussed, mandatory, invalid, serverInvalid, readonly, inactive, isServerValidationActive)
{
	this.m_disabled = disabled;
	this.m_focussed = focussed;
	this.m_mandatory = mandatory;
	this.m_invalid = invalid;
	this.m_serverInvalid = serverInvalid;
	this.m_readonly = readonly;
	this.m_inactive = inactive;
	this.m_isServerValidationActive = isServerValidationActive;
	
	this._render();
}


/**
 * Determine the classname of the external div based on the state of the
 * frame field.
 *
 * @return the CSS className of the field to set on the external div
 * @type String
 */
FramedFieldRenderer.prototype._getClassName = function()
{
	var className = this.m_className;

	if(this.m_disabled || this.m_inactive)
	{
		className += " framedfield_disabled";
	}
	else
	{
		if(this.m_focussed)
		{
			className += " framedfield_focus";
		}
			
		if(this.m_guiAdaptor.hasValue())
		{
			if(this.m_invalid)
			{
				if(this.m_serverInvalid)
				{
					// If server validation in process colour text area orange. If
					// server invalid and process complete colour text area red.
					if(this.m_isServerValidationActive)
					{
						className += " framedfield_server_invalid";
					}
					else
					{
						className += " framedfield_invalid";
					}
				}
				else
				{
					className += " framedfield_invalid";
				}
			}
		}
		else
		{
			if(this.m_mandatory)
			{
				className += " framedfield_mandatory";
			}
		}
		
		if(this.m_readonly)
		{
			className += " framedfield_readonly";
		}	
	}
	
	return className;
}


FramedFieldRenderer.prototype._render = function()
{
	// This fix is only required on IE which appears to have problems
	// correctly interpretting width: 100% CSS styles on input fields...
	//
	// Dirty hack to fix the "framedfield resizing problem". The symptoms
	// of the problems are that when text wider than the input field is 
	// entered into framed field, the field resizes so that it is wide enough
	// to accomodate its contained text. This means that the width of the
	// parents is entirely ignored, causing layout problems for the whole
	// form. 
	// The field only resizes when it's layout is recalculated, and IE interprets
	// width="100%" as 100% of content. The layout is recalulated when the
	// CSS classes of its parents are changed (as happens below).
	// The workaround is to explicitly set the the width of the input field
	// so override the class style of "width: 100%". This is done immediately
	// below. The same fix is applied in the drop down code. The dropdown code
	// needs to be re-implemented to make use of the Framed Field.

	if(this.m_offsetWidth == 0 
	   && this.m_inputField.parentNode.offsetWidth > 0)
	{
		var borderStyle = getCalculatedStyle(this.m_borderDiv);
	
		var borderLeftWidth = borderStyle.borderLeftWidth.slice(0, -2);
		// If stylesheet hasn't loaded then this will be "medium", if so default to 2px
		borderLeftWidth = isNaN(borderLeftWidth) ? 2 : Number(borderLeftWidth);
	
		var borderRightWidth = borderStyle.borderRightWidth.slice(0, -2);
		// If stylesheet hasn't loaded then this will be "medium", if so default to 2px
		borderRightWidth = isNaN(borderRightWidth) ? 2 : Number(borderRightWidth);
	
		var elementStyle = getCalculatedStyle(this.m_guiAdaptor.getElement());
		var elementWidth = elementStyle.width.slice(0, -2);
		// If stylesheet hasn't loaded then this will be "auto", if so default to 160px
		elementWidth = isNaN(elementWidth) ? 160 : Number(elementWidth);

		var buttonElement = this.m_guiAdaptor._getPopupButton().m_element;
		var buttonCellWidth = buttonElement.parentNode.offsetWidth;
		// If stylesheet hasn't loaded then button width won't be set, if so default to 18px
		buttonCellWidth = isNaN(buttonCellWidth) ? 18 : Number(buttonCellWidth);
		
		// Input field width is overall width minus the border and button widths
		var inputFieldWidth = elementWidth - borderLeftWidth - buttonCellWidth - borderRightWidth;
		// Subtract left and right 1px padding for two table cells
		inputFieldWidth -= 4;

		// Set input field and offset width cache widths
		this.m_inputField.style.width = inputFieldWidth + "px";
		this.m_offsetWidth = this.m_inputField.style.width; 
	}
	else
	{
		this.m_inputField.style.width = this.m_offsetWidth;
	}

	this.m_inputField.disabled = this.m_disabled || this.m_inactive;
	this.m_inputField.readOnly = this.m_readonly;

	if(this.m_disabled || this.m_inactive)
	{
		// Disable adaptor help text
		if (this.m_guiAdaptor.getHelpText() != null) {
			this.m_guiAdaptor.unbindHelp();
		}
	}
	else
	{
		// Enable adaptor help text
		if (this.m_guiAdaptor.getHelpText() != null) {
			this.m_guiAdaptor.bindHelp();
		}
	}

	// Set the Element's CSS class so that it is rendered appropriately
	this.m_element.className = this._getClassName();
}


//==================================================================
//
// ButtonFieldRenderer.js
//
// Implementation of ButtonField rendering class. This is a base
// class for components which consist of a text field and an
// associated button.
//
//==================================================================



function ButtonFieldRenderer()
{
}

ButtonFieldRenderer.m_logger = new Category("ButtonFieldRenderer");

/**
 * The main container element for the component
 *
 * @type HTMLDivElement
 * @private
 */
//ButtonFieldRenderer.prototype.m_element = null;


/**
 * The input field for the component
 *
 * @type HTMLInputElement
 * @private
 */
//ButtonFieldRenderer.prototype.m_inputField = null;


/**
 * The button which raises the dropdown for the component
 *
 * @type Button
 * @private
 */
ButtonFieldRenderer.prototype.m_button = null;




/**
 * CSS class for the dropdown container
 *
 * @type String
 */
ButtonFieldRenderer.CSS_CLASS_NAME = "buttonfield";


/**
 * Create the drop down field as a child of another element
 *
 * @param p the parent element to create the child under
 * @param multiline determines what the input field is rendered as
 *        If true it is rendered as a text area otherwise as a text input box
 * @return a new ButtonFieldRenderer instance
 * @type ButtonFieldRenderer
 */
ButtonFieldRenderer.createAsChild = function(p, multiline)
{
	var f = new ButtonFieldRenderer();
	f.m_framedField = FramedFieldRenderer.createAsChild(p, ButtonFieldRenderer.CSS_CLASS_NAME, multiline);
	
	// Create table cell which will contain the button
	var buttonCell = f.m_framedField.addCellAfterField();
	buttonCell.className = "buttonfield_button_container";
	
	// Create button to trigger drop down
	f.m_button = Button.createAsChild(buttonCell, null, "buttonfield_button");

	return f;
}


ButtonFieldRenderer.prototype.dispose = function()
{
	// Clean up the button
	this.m_button.dispose();
	
	// Get rid of the framedField
	this.m_framedField.dispose();
}


ButtonFieldRenderer.prototype.startEventHandlers = function()
{
	this.m_button.startEventHandlers();
}


ButtonFieldRenderer.prototype.stopEventHandlers = function()
{
	this.m_button.stopEventHandlers();
}


ButtonFieldRenderer.prototype.render = function(disabled, focussed, mandatory, invalid, serverInvalid, readonly, inactive, isServerValidationActive)
{
	if(disabled || inactive)
	{
		this.stopEventHandlers();
	}
	else
	{
		this.startEventHandlers();
	}
	this.m_framedField.render(disabled, focussed, mandatory, invalid, serverInvalid, readonly, inactive, isServerValidationActive);
}
//==================================================================
//
// ZoomFieldRenderer.js
//
// Implementation of ZoomField rendering class. Creates a field with
// a button next to it that raises a popup containing an enlarged
// text area and ok/cancel buttons.
//
//==================================================================



/**
 * ZoomFieldRenderer constructor - never used. Use factory methods
 * below to either render an ZoomField into an HTML page, or create
 * an ZoomField as a child of another element
 *
 * @private
 * @constructor
 */
function ZoomFieldRenderer()
{
}


/**
 * ZoomFieldRenderer is a sub class of Renderer
 */
ZoomFieldRenderer.prototype = new Renderer();
ZoomFieldRenderer.prototype.constructor = ZoomFieldRenderer;


/**
 * Logging category for the ZoomFieldRenderer
 *
 * @type Category
 * @private
 */
ZoomFieldRenderer.m_logger = new Category("ZoomFieldRenderer");


/**
 * Position of the bottom of any menu bar on the form
 *
 * @type Category
 * @private
 */
ZoomFieldRenderer.m_menuBarBottom = null;


/**
 * Default number of rows in the expanded text area
 *
 * @type Integer
 */
ZoomFieldRenderer.DEFAULT_NO_ROWS = 20;


/**
 * Default number of columns in the expanded text area
 *
 * @type Integer
 */
ZoomFieldRenderer.DEFAULT_NO_COLS = 80;


/**
 * CSS Class name of the outermost div of the zoom field
 *
 * @type String
 */
ZoomFieldRenderer.CSS_CLASS_NAME = "zoom_field";

ZoomFieldRenderer.CONTAINER_CSS_CLASS_NAME = "zoomfield_container";


/*
 * Create a zoom field at the current location in the document while document
 * is parsing.
 *
 * @param id the id of the zoom field being created
 * @param r the number of rows in the zoom field text area
 * @param c the number of columns in the zoom field text area
 * @param multiline determines what the input field is rendered as
 *        If true it is rendered as a text area otherwise as a text input box
 */
ZoomFieldRenderer.createInline = function(id, r, c, multiline)
{
	// Create the outer div by writing to the document.
	var e = Renderer.createInline(
		id,			// The id of the zoom field being created
		false		// The zoom field has an internal input element which can accept focus, so the div should not accept focus
	);

	return ZoomFieldRenderer._create(e, r, c, multiline);
}


/**
 * Create a zoom field in the document relative to the supplied element
 *
 * @param refElement the element relative to which the zoom field should be rendered
 * @param relativePos the relative position of the zoom field to "refElement".
 * Valid values are:
 *     Renderer.CHILD_ELEMENT    Created as a child of "refElement"
 *     Renderer.BEFORE_ELEMENT   Created as preceeding sibling of "refElement"
 *     Renderer.AFTER_ELEMENT    Created as following sibling of "refElement"
 * @param id the id of the zoom field being created
 * @param r the number of rows in the zoom field text area
 * @param c the number of columns in the zoom field text area
 * @param multiline determines what the input field is rendered as
 *        If true it is rendered as a text area otherwise as a text input box
 */
ZoomFieldRenderer.createAsInnerHTML = function(refElement, relativePos, id, r, c, multiline)
{
	var e = Renderer.createAsInnerHTML(
		refElement,		// The element relative to which to create the outer div in the document
		relativePos,	// Relative position of the outer div to the reference element
		id,				// The id of the zoom field being created
		false			// The zoom field has an internal input element which can accept focus, so the div should not accept focus
	);
	
	return ZoomFieldRenderer._create(e, r, c, multiline);
}


/**
 * Create a zoom field as a child of another element
 *
 * @param id the id of the zoom field being created
 * @param r the number of rows in the zoom field text area
 * @param c the number of columns in the zoom field text area
 * @param multiline determines what the input field is rendered as
 *        If true it is rendered as a text area otherwise as a text input box
 */
ZoomFieldRenderer.createAsChild = function(p, id, r, c, multiline)
{
	var e = Renderer.createAsChild(id);

	// Append the zoom field's outer div to it's parent element
	p.appendChild(e);	
	
	return ZoomFieldRenderer._create(e, r, c, multiline);
}


ZoomFieldRenderer._create = function(e, r, c, multiline)
{
	e.className = ZoomFieldRenderer.CSS_CLASS_NAME;

	var f = new ZoomFieldRenderer();

	// Initialise sets main element and the reference to the renderer in the dom
	f._initRenderer(e);	

	var zoomId = e.id;

	// Default the number of rows in the expanded text area, if value not supplied
	if(null == r)
	{
		r = ZoomFieldRenderer.DEFAULT_NO_ROWS;
	}
	
	// Default the number of columns in the expanded text area, if value not supplied
	if(null == c)
	{
		c = ZoomFieldRenderer.DEFAULT_NO_COLS;
	}
	
	// Require a container div whose CSS position attribute is
	// set to relative so that we can position the popup relative
	// to it. We can't use the outer div for this, because otherwise
	// the 
	var container = document.createElement("div");
	container.className = ZoomFieldRenderer.CONTAINER_CSS_CLASS_NAME;
	e.appendChild(container);

	// Default to single line input box if multiline not defined
	f.m_multiline = (null == multiline) ? false : multiline;

	f.m_buttonField = ButtonFieldRenderer.createAsChild(container, f.m_multiline);
	
	// Create popup
	f.m_popup = PopupRenderer.createAsChild(
		container, 
		zoomId + "_popup",
		[
			{id: zoomId + "_ok", label: "OK"},
			{id: zoomId + "_cancel", label: "Cancel"}
		]
	);	

	var popupContentsElement = f.m_popup.getContentsContainerElement();
	var panel = document.createElement("div");
	panel.className = "panel";
	popupContentsElement.appendChild(panel);

	// Create the textarea element
	f.m_textarea = document.createElement("textarea");
	f.m_textarea.setAttribute("rows", r);
	f.m_textarea.setAttribute("cols", c);
	f.m_textarea.setAttribute("wrap", "soft");
	f.m_textarea.id = zoomId + "_textarea";
	panel.appendChild(f.m_textarea);

	f.startEventHandlers();

	return f;
}


ZoomFieldRenderer.prototype.dispose = function()
{
	this.m_buttonField.dispose();
}


ZoomFieldRenderer.prototype.startEventHandlers = function()
{
	this.m_buttonField.startEventHandlers();
}


ZoomFieldRenderer.prototype.stopEventHandlers = function()
{
	this.m_buttonField.stopEventHandlers();
}


ZoomFieldRenderer.prototype.positionPopup = function()
{
	var p = this.m_popup.getElement();
	var zf = p.parentNode;

	// Get the popup height and width
	var ph = p.offsetHeight;
	var pw = p.offsetWidth;
	
	// Get the field height and width
	var zfh = zf.offsetHeight;
	var zfw = zf.offsetWidth;
	
	// Get the document relative position of the container
	var zfPos = getAbsolutePosition(zf);
	
	// Get the <html> tag for the document in which this DropDownField exists
	var docEl = zf.ownerDocument.documentElement;

	var windowHeight = 
		window.innerHeight != null
		? window.innerHeight			// W3C
		: docEl.clientHeight;			// IE
				
	var windowWidth =
		window.innerWidth != null
		? window.innerWidth				// W3C
		: docEl.clientWidth;			// IE

	var scrollY =
		window.scrollY != null
		? window.scrollY				// W3C
		: docEl.scrollTop;				// IE

	var scrollX =
		window.scrollX != null
		? window.scrollX				// W3C
		: docEl.scrollLeft;				// IE
	
	// Determine the popup's left border width
	var borderStyle = getCalculatedStyle(p);
	
	var borderLeftWidth = borderStyle.borderLeftWidth.slice(0, -2);
    // If stylesheet hasn't loaded then this will be "medium", if so default to 2px
    borderLeftWidth = isNaN(borderLeftWidth) ? 2 : Number(borderLeftWidth);
    
	if(null == ZoomFieldRenderer.m_menuBarBottom)
	{
		// Determine the position of the bottom of any menu bar	on the form	
		var divs = docEl.getElementsByTagName("DIV");
		
		ZoomFieldRenderer.m_menuBarBottom = 0;
		
		for(var i = 0, l = divs.length; i < l; i++)
		{
			var div = divs[i];
			
			if(div.className == MenuBarRenderer.MENU_BASE_DIV)
			{
				// Get the document relative position of the menu bar div
				var mbPos = getAbsolutePosition(div);
			    ZoomFieldRenderer.m_menuBarBottom = mbPos.top + div.offsetHeight;
			    
				// Assumes that there is only ever one menu bar per form
				break;
			}
		}
	}
	
	// Document relative position of the top of the drop down, if it
	// were positioned below the container
	var bottomOfPopupBelow = zfPos.top + zfh + ph;
	
	// Determine position of popup - by default popup will be positioned below
	// the field with the left hand borders aligned, however available screen space
	// may mean that this is not possible and an alternative postion will be
	// calculated.
	var popupTop = null;
	
	if(bottomOfPopupBelow <= (windowHeight + scrollY))
	{
		// Not clipped when positioned below, so let's do that
		popupTop = zfh;
	}
	else
	{
		// Get the document relative position of the container
		var zfPos = getAbsolutePosition(zf);
		
		// Document relative position of the top of the popup if it
		// were positioned above the container
		var topOfPopupAbove = ZoomFieldRenderer.m_menuBarBottom + ph;
		
		if(topOfPopupAbove <= (zfPos.top - scrollY))
		{
			// Not clipped when positioned above, so let's do that
			popupTop = p.offsetHeight;
		}
		else
		{
			// Determine the popup's top and bottom border widths
			var borderTopWidth = borderStyle.borderTopWidth.slice(0, -2);
			// If stylesheet hasn't loaded then this will be "medium", if so default to 2px
			borderTopWidth = isNaN(borderTopWidth) ? 2 : Number(borderTopWidth);
			
			var borderBottomWidth = borderStyle.borderBottomWidth.slice(0, -2);
			// If stylesheet hasn't loaded then this will be "medium", if so default to 2px
			borderBottomWidth = isNaN(borderBottomWidth) ? 2 : Number(borderBottomWidth);
			
			// Add the borders to the overall popup height
			ph += (borderTopWidth + borderBottomWidth);
			
			// Centre the popup vertically about the zoom field's centre
			popupTop = (ph - zfh) / 2;
			
			// Check again for top and bottom clipping
			bottomOfPopupBelow = zfPos.top + zfh + popupTop;
			topOfPopupAbove = zfPos.top - popupTop;

			if(bottomOfPopupBelow > (windowHeight + scrollY) || topOfPopupAbove < ZoomFieldRenderer.m_menuBarBottom)
			{
				// Clipped top or bottom, so position the popup in the centre of the form
				var gap = (windowHeight + scrollY - ph) / 2;
				popupTop = zfPos.top - gap - (ZoomFieldRenderer.m_menuBarBottom / 2);
			}
		}
		
		popupTop = -popupTop;
	}
	
	// Determine the horizontal positioning. By default we align the left hand
	// edges of the zoom field and the popup, but space may dictate that we
	// slide the popup left relative to the zoomfield to avoid clipping the
	// right hand edge.
	var popupLeft = -borderLeftWidth;
	
	// Calculate the gap between the right hand edge of the popup and the right
	// hand edge of its containing frame.
	var gapToRight = scrollX + windowWidth - (zfPos.left + pw);

	// If the gapToRight is negative, it indicates that popup right hand side
	// will be clipped by gapToRight pixels, so shift the popup left by gapToRight
	// pixels to compensate.
	if(gapToRight < 0)
	{
		popupLeft += gapToRight;
	}
	
	// Set the position of the popup div - remember this is relative to the
	// zoomfield element, as it has position: relative set in the .css file.
	p.style.top = popupTop + "px";
	p.style.left = popupLeft + "px";
	
	zf.className = 	ZoomFieldRenderer.CONTAINER_CSS_CLASS_NAME + " raised";
}


ZoomFieldRenderer.prototype.lowerPopup = function()
{
	this.m_popup.getElement().parentNode.className = ZoomFieldRenderer.CONTAINER_CSS_CLASS_NAME;
}


ZoomFieldRenderer.prototype.getTextArea = function()
{
	return this.m_textarea;
}


ZoomFieldRenderer.prototype.render = function(disabled, focussed, mandatory, invalid, serverInvalid, readonly, inactive, isServerValidationActive)
{
	this.m_buttonField.render(disabled, focussed, mandatory, invalid, serverInvalid, readonly, inactive, isServerValidationActive);
}

ZoomFieldRenderer.prototype._setAdaptor = function(adaptor)
{
	this.m_buttonField.m_framedField.m_guiAdaptor = adaptor;
}

ZoomFieldRenderer.prototype.getInputField = function()
{
	return this.m_buttonField.m_framedField.m_inputField;
}


ZoomFieldRenderer.prototype.getPopupButton = function()
{
	return this.m_buttonField.m_button;
}

ZoomFieldRenderer.prototype.getMultiline = function()
{
	return this.m_multiline;
}
//==================================================================
//
// ZoomFieldGUIAdaptor.js
//
// Class for integrating a zoomable text field with the Framework.
//
//==================================================================


/**
 * Class for integrating a zoomable text field with the Framework.
 *
 * @constructor
 * @private
 */
function ZoomFieldGUIAdaptor() {}



ZoomFieldGUIAdaptor.m_logger = new Category("ZoomFieldGUIAdaptor");

/**
 * DatePickerGUIAdaptor is a sub class of InputElementGUIAdaptor
 */
ZoomFieldGUIAdaptor.prototype = new HTMLElementGUIAdaptor();

/**
 * Add the required protocols to the ZoomFieldGUIAdaptor
 */
GUIAdaptor._setUpProtocols('ZoomFieldGUIAdaptor');
GUIAdaptor._addProtocol('ZoomFieldGUIAdaptor', 'DataBindingProtocol');			 // Supports binding to data model
GUIAdaptor._addProtocol('ZoomFieldGUIAdaptor', 'EnablementProtocol');            // Supports enablement
GUIAdaptor._addProtocol('ZoomFieldGUIAdaptor', 'FocusProtocol');                 // Supports focusing
GUIAdaptor._addProtocol('ZoomFieldGUIAdaptor', 'FocusProtocolHTMLImpl');         // Include the default HTML implementation of focus
GUIAdaptor._addProtocol('ZoomFieldGUIAdaptor', 'HelpProtocol');                  // Supports helptext
GUIAdaptor._addProtocol('ZoomFieldGUIAdaptor', 'HelpProtocolHTMLImpl');          // Include the default HTML implementation of help
GUIAdaptor._addProtocol('ZoomFieldGUIAdaptor', 'InitialiseProtocol');            // Supports custom initialisation
GUIAdaptor._addProtocol('ZoomFieldGUIAdaptor', 'MandatoryProtocol');             // Supports mandatory
GUIAdaptor._addProtocol('ZoomFieldGUIAdaptor', 'NameProtocol');                  // Supports naming of the element
GUIAdaptor._addProtocol('ZoomFieldGUIAdaptor', 'ReadOnlyProtocol');            	 // Supports read only protocol
GUIAdaptor._addProtocol('ZoomFieldGUIAdaptor', 'TemporaryProtocol');             // Supports temporary behaviour
GUIAdaptor._addProtocol('ZoomFieldGUIAdaptor', 'ValidationProtocol');            // Supports validation protocol
GUIAdaptor._addProtocol('ZoomFieldGUIAdaptor', 'KeybindingProtocol');       	 // Supports key binding


ZoomFieldGUIAdaptor.prototype.constructor = ZoomFieldGUIAdaptor;

/**
 * Maximum length of the text field
 *
 * @configuration
 * @merge-rule Most specific maxLength takes precedence
 */
ZoomFieldGUIAdaptor.prototype.maxLength = null;

/**
 * Boolean flag recording whether, or not, user input validation
 * should include a check for whitespace only entry.
 *
 * @configuration
 * @type Boolean
*/
ZoomFieldGUIAdaptor.prototype.m_validateWhitespaceOnlyEntry = null;


/**
 * Create a new ZoomFieldGUIAdaptor
 *
 * @param e the text input element to manage
 * @param f the gui adaptor factory
 * @return the new ZoomFieldGUIAdaptor
 * @type ZoomFieldGUIAdaptor
 */
ZoomFieldGUIAdaptor.create = function(e, factory)
{
	if(ZoomFieldGUIAdaptor.m_logger.isTrace()) ZoomFieldGUIAdaptor.m_logger.trace("create()");
	var a = new ZoomFieldGUIAdaptor();
	a._initialiseAdaptor(e);
	return a;
}


/**
 * Initialise the ZoomFieldGUIAdaptor
 *
 * @param e the HTMLElement for the select element to be managed
 * @private
 */
ZoomFieldGUIAdaptor.prototype._initialiseAdaptor = function(e)
{
	if(ZoomFieldGUIAdaptor.m_logger.isTrace()) ZoomFieldGUIAdaptor.m_logger.trace("_initialiseAdaptor()");
	
	// Call parent class initialisation
	HTMLElementGUIAdaptor.prototype._initialiseAdaptor.call(this, e);
	
	this.m_keyBindings = new Array();
	
	this.m_renderer._setAdaptor(this);
}


/**
 * Clean up after the component
 */
ZoomFieldGUIAdaptor.prototype._dispose = function()
{
	if(ZoomFieldGUIAdaptor.m_logger.isTrace()) ZoomFieldGUIAdaptor.m_logger.trace("ZoomFieldGUIAdaptor.dispose()");

	// Dispose of the renderer
	this.m_renderer.dispose();
	this.m_renderer = null;

	// Remove the popup configuration
	var cm = FormController.getInstance().getFormView().getConfigManager();
	var zoomId = this.getId();

	cm.removeConfig(zoomId + "_popup");
	cm.removeConfig(zoomId + "_ok");
	cm.removeConfig(zoomId + "_cancel");
	cm.removeConfig(zoomId + "_textarea");

	// Dispose of any key bindings
	for (var i = 0, l = this.m_keyBindings.length; i < l; i++)
		this.m_keyBindings[i].dispose();
}


/**
 * Perform any GUIAdaptor specific configuration - this also creates the config
 * objects for the sub-components dynamically
 */
ZoomFieldGUIAdaptor.prototype._configure = function(cs)
{
	if(ZoomFieldGUIAdaptor.m_logger.isTrace()) ZoomFieldGUIAdaptor.m_logger.trace("_configure()");

	// Iterate through the configuration, using most specific configurations first
	for(var i = 0; i < cs.length; i++)
	{
		var c = cs[i];
		if(null != c.maxLength && null == this.maxLength)
		{
			this.maxLength = c.maxLength;

			// Provide default validation rule based on maxLength
			this.validate = this._validateMaxLength;
		}
		
		// Check for whitespace only entry validation
		if(FormController.getValidateWhitespaceOnlyEntryActive())
		{
		    if(null != c.validateWhitespaceOnlyEntry && this.m_validateWhitespaceOnlyEntry == null)
		    {
		        this.m_validateWhitespaceOnlyEntry = c.validateWhitespaceOnlyEntry;
		    }
		}
		
	}

	// Configure the input box
	if(null != this.maxLength) this._getInputField().maxLength = this.maxLength;
	
	// Configure whitespace only entry validation if required.
	if(FormController.getValidateWhitespaceOnlyEntryActive() &&
	   this.m_validateWhitespaceOnlyEntry != false)
	{
	    if(this.maxLength != null)
	    {
	        // Maxlength validation in operation so add whitespace validation
	        // as additional configuration object
	        this._addWhitespaceOnlyEntryValidation();
	    }
	    else
	    {
	        // Add whitespace validation as default validation
	        this.validate = this._validateWhitespaceOnlyEntry;
	    }
	}
	
	// Configure zoom field sub components

	var fc = FormController.getInstance();
	var cm = fc.getFormView().getConfigManager();
	var zoomId = this.getId();
	var thisObj = this;
	var popupId = zoomId + "_popup";

	// Configure the action binding for the OK button
	cm.setConfig(
		zoomId + "_ok",
		{
			actionBinding: function() { thisObj._handleOk(); }
		}
	);
	
	// Configure the action and key bindings for the Cancel button
	cm.setConfig(
		zoomId + "_cancel",
		{
			actionBinding: function() { thisObj._handleCancel(); },
			additionalBindings: {
				eventBinding: {
					keys: [ { key: Key.F4, element: popupId } ]
				}
			}
		}
	);
	
	// Configure the text area
	var textAreaId = zoomId + "_textarea";
	
	this.m_textAreaDataBinding = DataModel.DEFAULT_TMP_BINDING_ROOT + "/" + textAreaId;
	
	// The configuration specific to this field - propogate some of it to the
	// textArea.
	//var fieldConfig = cs[0];
	
	var textAreaConfigObj = {
			                    includeInValidation: false,
			                    dataBinding: this.m_textAreaDataBinding,
			                    maxLength: this.maxLength
		                    };
		                      
    if(FormController.getValidateWhitespaceOnlyEntryActive())
    {
        textAreaConfigObj[ "m_validateWhitespaceOnlyEntry" ] = this.m_validateWhitespaceOnlyEntry;
    }
    
	cm.setConfig( textAreaId, textAreaConfigObj );

	// Override the text area's default "onchange" event handler with the
	// Zoom Field's GUI adaptor's handler
	var a = fc.getAdaptorById(textAreaId);
	a._handleBlur = thisObj._handleTextAreaBlur;

	// Set up configuration of the popup	
	cm.setConfig(
		popupId,
		{
			// Make sure focus is returned to this field when the popup is lowered
			nextFocusedAdaptorId: function() { return zoomId; }
		}
	);

	// Setup the field's button to raise the popup
	this._getPopupButton().addClickListener(function() { thisObj._raisePopup(); });
	
	// Setup default key binding of Atl+Z to raise popup. NB: we don't want to
	// use the popup raise event binding as the adaptor's _raisePopup method is 
	// not called (because the PopupGUIAdaptor shows the popup). This results in
	// the input box value not being copied to the text area and the popup not
	// being positioned correctly.
	var keyObj = new Object();
	var qualObj = new Object();
	qualObj.alt = true;

	if(HTMLView.isIE) {
		// Bind upper case z for IE
		keyObj.m_keyCode = Key.CHAR_Z.m_keyCode;
	}
	else {
		// Bind lower case z for Mozilla
		keyObj.m_keyCode = Key.CHAR_z.m_keyCode;
	}

	this.m_keyBindings[0] = new ElementKeyBindings(this);
	this.m_keyBindings[0].bindKey(keyObj, function() { thisObj._handleDefaultKey(); }, qualObj);	
}


/**
 * Handle a click on the OK button
 *
 * @private
 */
ZoomFieldGUIAdaptor.prototype._handleOk = function()
{
	// Lower the popup
	this._lowerPopup();

	// Get the popup's textarea's value
	var textAreaValue = this._getTextArea().value;

	// Does input field accept linefeeds and carriage returns
	if(!this._getMultiline())
	{
		// No, so convert linefeeds and carriage returns to space characters
		textAreaValue = textAreaValue.replace(new RegExp("[\\n\\r]", "gm"), " ");
	}

	// Copy the value from the popup text area to the main input field
	this._getInputField().value = textAreaValue;

	// Update the data model
	this.update();
}


/**
 * Handle a click on the Cancel button
 *
 * @private
 */
ZoomFieldGUIAdaptor.prototype._handleCancel = function()
{
	// Just hide the popup
	this._lowerPopup();
	
}


ZoomFieldGUIAdaptor.prototype._lowerPopup = function()
{
	// Hide the popup
	Services.dispatchEvent(this.getId() + "_popup", PopupGUIAdaptor.EVENT_LOWER);

	// Notify the renderer that the popup is being lowered.
	this.m_renderer.lowerPopup();
}


/**
 * Handle a click on the field's button which shows the popup
 *
 * @private
 */
ZoomFieldGUIAdaptor.prototype._raisePopup = function()
{
	// Copy the value for the input area into the text area
	Services.setValue(this.m_textAreaDataBinding, this._getInputField().value);

	// Apply the OK button and text area states before the popup is positioned
	// otherwise the button is not rendered and the popup height and width
	// are not set
	this._prePopupPrepare();
	
	// Position popup.
	this.m_renderer.positionPopup();

	// Show the popup
	Services.dispatchEvent(this.getId() + "_popup", PopupGUIAdaptor.EVENT_RAISE);
}


/**
 * Get the value from the view.
 *
 * @return the value of the input field
 * @type String
 */
ZoomFieldGUIAdaptor.prototype._getValueFromView = function()
{
	// Get the value of the input field
	return this._getInputField().value;
}


/**
 * Method invoked by tabbing manager to notify the component that it has lost focus
 *
 */
ZoomFieldGUIAdaptor.prototype.onBlur = function()
{
	// Update the model when the Tabbing Manager notifies us that we've lost focus
	this.update();
}


ZoomFieldGUIAdaptor.prototype.renderState = function()
{
	if(ZoomFieldGUIAdaptor.m_logger.isDebug())
	{
		ZoomFieldGUIAdaptor.m_logger.debug(this.getId() + ":ZoomFieldGUIAdaptor.renderState() this.m_enabled=" + this.m_enabled + ", this.m_readOnly=" + this.m_readOnly + ", this.getValid()=" + this.getValid() + ", this.m_mandatory=" + this.m_mandatory + ", this.isActive()=" + this.isActive());
	}

	// Set up value
	if(this.m_valueChanged)
	{
		// On IE input elements cannot have null as a value, they have to have an empty string instead
		this._getInputField().value = (null == this.m_value ? "" : this.m_value);
		this.m_valueChanged = false;
	}


	// Hightlight text on focus
	if(this.m_focusChanged)
	{
		if(this.m_focus)
		{
			this._getInputField().select();
		}
		this.m_focusChanged = false;
	}
	
	// Propogate readOnly changes to textarea
/*
	if(this.m_readOnlyChanged)
	{
		var ta = this._getTextArea();
		ta.readOnly = this.m_readOnly;
		ta.className = this.m_readOnly ? "readOnly" : "";
		
		this.m_readOnlyChanged = false;
	}
*/

	// Set up all states other than value
	this.m_renderer.render(
		!this.m_enabled,
		this.m_focus,
		this.m_mandatory,
		!this.getValid(),
		!this.getServerValid(),
		this.m_readOnly,
		!this.isActive(),
		this.isServerValidationActive()
	);
}


/**
 * Get the element to set focus on. For the ZoomField this
 * is the FramedField's input text field
 */
ZoomFieldGUIAdaptor.prototype.getFocusElement = function()
{
	return this._getInputField();
}


/**
 * Get the component's input field.
 *
 * @return the component's input field
 * @type HTMLInputElement
 * @private
 */
ZoomFieldGUIAdaptor.prototype._getInputField = function()
{
	return this.m_renderer.getInputField();
}


/**
 * Get the textarea on the component's popup
 * 
 * @return the component's popup textarea field
 * @type HTMLTextAreaElement
 * @private
 */
ZoomFieldGUIAdaptor.prototype._getTextArea = function()
{
	return this.m_renderer.getTextArea();
}


ZoomFieldGUIAdaptor.prototype._getPopupButton = function()
{
	return this.m_renderer.getPopupButton();
}


ZoomFieldGUIAdaptor.prototype._getMultiline = function()
{
	return this.m_renderer.getMultiline();
}


/**
 * Handle the Alt+Z default key binding
 * 
 * @private
 */
ZoomFieldGUIAdaptor.prototype._handleDefaultKey = function()
{
	if (!AbstractPopupGUIAdaptor._isPopupRaised(this.getId()+ "_popup"))
	{
		// Only raise the popup if it is not already raised
		this._raisePopup();
	}
}


/**
 * Override for the text area's "onchange" handler.
 *
 * Applies the zoom field's validate, mandatory and read only rules to the
 * popup's text area.
 *
 * Validation etc rules can be written to get the zoom field's value and then
 * do some processing with that value. Just copying the rules to the text area
 * and letting the Framework invoke them when the text area is updated can cause
 * problems if the coding in the rule does not account for this.
 *
 * If the user has clicked anywhere other than the OK or Cancel buttons then
 * this method does the following:
 * 1) Stores the zoom field's model value
 * 2) Gets the text area value and copies it into the zoom field's input box
 * 3) Updates the text area
 * 4) Applies the valid, mandatory and read only states of the zoom field to
 *    the text area
 * 5) Restores the zoom field's original model value
 *
 * @param evt the onchange event
 * @private
 */
ZoomFieldGUIAdaptor.prototype._handleTextAreaBlur = function(evt)
{
	// If IE then use the global event object
	evt = (evt) ? evt : ((event) ? event : null);
	
	// Get the element in which the event occurred
	var eventX = SUPSEvent.getPageX(evt);
	var eventY = SUPSEvent.getPageY(evt);
	var pointElement = document.elementFromPoint(eventX, eventY);
	
	if(pointElement != null)
	{
		var pointElementId = pointElement.id;
		// NB: 'this' references the text area not the zoom field
		var textAreaId = this.getId();
		var zoomFieldId = textAreaId.substring(0, textAreaId.lastIndexOf("_textarea"));

		if(pointElementId != (zoomFieldId + "_ok") && pointElementId != (zoomFieldId + "_cancel"))
		{
			var fc = FormController.getInstance();
			var dm = fc.getDataModel();

			// Get the zoom field's adaptor and original model value	
			var zf = fc.getAdaptorById(zoomFieldId);
			var db = zf.dataBinding;
			var origValue = dm.getValue(db);

			// Copy the text area value into the zoom field
			var mv = this._getValueFromView();
			dm.setValue(db, mv);

			// Update the text area
			this.update();

			// Set the valid, server valid, mandatory and read only states of the text area
			this.setValid(zf.getValid());
			this.m_serverValid = zf.getServerValid();
			this.setMandatory(zf.getMandatory());
			this.setReadOnly(zf.getReadOnly());

			// Restore the zoom field's original model value
			dm.setValue(db, origValue);
		}
		else
		{
			// OK or Cancel button clicked, just update the text area
			this.update();
		}
	}
	else
	{
		// Cannot determine an element in which the event occurred,
		// just update the text area
		this.update();
	}
}


/**
 * Called before the Zoom Field's popup is raised. Sets up the state of the
 * OK button and the popup's text area
 *
 * @private
 */
ZoomFieldGUIAdaptor.prototype._prePopupPrepare = function()
{
	var zoomId = this.getId();
	
	// Disable the popup OK button if this Zoom Field is read only
	var a = Services.getAdaptorById(zoomId + "_ok");
	var readOnly = this.getReadOnly();

	if(a.setEnabled(!readOnly))
	{
		// Ensure state gets applied to the OK button if changed
		a.renderState();
	}

	// Popup could be raised by clicking button after typing in the field
	// without tabbing or clicking off the field, so we need to update it
	if(!readOnly) this.update();
	
	// Set the valid, server valid, mandatory and read only states
	// of the Zoom Field's popup text area based upon the state of
	// the Zoom Field
	a = Services.getAdaptorById(zoomId + "_textarea");

	var validChanged = a.setValid(this.getValid());
	var mandatoryChanged =  a.setMandatory(this.getMandatory());
	var readOnlyChanged = a.setReadOnly(readOnly);

	var serverValidChanged = a.m_serverValid;
	a.m_serverValid = this.getServerValid();
	serverValidChanged = !(serverValidChanged == a.m_serverValid);
	
	if(validChanged || mandatoryChanged || readOnlyChanged || serverValidChanged)
	{
		// Ensure states get applied to the text area if changed
		a.renderState();
	}
}
