//==================================================================


/**
 * Base class for adapting html input elements for use in the
 * framework.
 *
 * @constructor
 * @private
 */
function DatePickerRenderer()
{
}

/**
 * DatePickerRenderer is a sub class of Renderer
 */
DatePickerRenderer.prototype = new Renderer();
DatePickerRenderer.prototype.constructor = DatePickerRenderer;


DatePickerRenderer.m_logger = new Category("DatePickerRenderer");

/**
 * The month currently displayed in the drop down
 *
 * @private
 */
DatePickerRenderer.prototype.m_currentMonth = null;


/**
 * The year currently displayed in the drop down
 *
 * @private
 */
DatePickerRenderer.prototype.m_currentYear = null;


/**
 * Day of the week on which each row starts
 *
 * @private
 */
DatePickerRenderer.prototype.m_startDay = 1;


/**
 * The currently selected date
 *
 * @private
 */
DatePickerRenderer.prototype.m_selectedDate = null;


/**
 * The position of selected date in the date cell array.
 * May be null if the selected date is not one of the
 * dates displayed in the currently displayed month
 */
DatePickerRenderer.prototype.m_selectedDatePosition = 0;

/*
 * The position of today's date in the date cell array.
 * May be null if the today's date is not one of the
 * dates displayed in the currently displayed month
 */
DatePickerRenderer.prototype.m_todayDatePosition = 0;


/**
 * The dropdown field which implements this DatePicker.
 */
DatePickerRenderer.prototype.m_dropDownField = null;



/**
 * The actual text value of date - may not be a valid date
 */
DatePickerRenderer.prototype.m_value = null;

/*
 * CSS class name for the main div for the date picker
 */
DatePickerRenderer.CSS_CLASS_NAME = "datepicker";

DatePickerRenderer.LOSE_FOCUS_MODE = "loseFocusMode";
DatePickerRenderer.CLICK_CELL_MODE = "clickCellMode";

/**
 * Create a date picker at the current location in the document while document
 * is parsing.
 *
 * @param id the id of the date picker being created
 */
DatePickerRenderer.createInline = function(id)
{
	// Create the outer div by writing to the document.
	var e = Renderer.createInline(
		id,			// The id of the date picker being created
		false		// The date picker has an internal input element which can accept focus, so the div should not accept focus
	);

	return DatePickerRenderer._create(e);
}

/**
 * Create a date picker in the document relative to the supplied element
 *
 * @param refElement the element relative to which the date picker should be rendered
 * @param relativePos the relative position of the date picker to "refElement".
 * Valid values are:
 *     Renderer.CHILD_ELEMENT    Created as a child of "refElement"
 *     Renderer.BEFORE_ELEMENT   Created as preceeding sibling of "refElement"
 *     Renderer.AFTER_ELEMENT    Created as following sibling of "refElement"
 * @param id the id of the date picker being created
 */
DatePickerRenderer.createAsInnerHTML = function(refElement, relativePos, id)
{
	var e = Renderer.createAsInnerHTML(
		refElement,		// The element relative to which to create the outer div in the document
		relativePos,	// Relative position of the outer div to the reference element
		id,				// The id of the date picker being created
		false			// The date picker has an internal input element which can accept focus, so the div should not accept focus
	);
	
	return DatePickerRenderer._create(e);
}

/**
 * Create a date picker as a child of another element
 *
 * @param p the parent element to add the date picker to
 * @param id the id to give the newly created date picker component
 */
DatePickerRenderer.createAsChild = function(p, id)
{
	var e = Renderer.createAsChild(id);

	// Append the date picker's outer div to it's parent element
	p.appendChild(e);	
	
	return DatePickerRenderer._create(e);
}

DatePickerRenderer._create = function(e)
{
	e.className = DatePickerRenderer.CSS_CLASS_NAME;

	var dp = new DatePickerRenderer();

	// Initialise sets main element and the reference to the renderer in the dom
	dp._initRenderer(e);	
	
	// Initialise the DropDownField part of the renderer
	dp.m_dropDownField = DropDownFieldRenderer.createAsChild(e);
		
	// Create new callback list for value change listeners
	//ac.m_callbackList = new CallbackList();
	
	var dropdown = dp.m_dropDownField._getDropDownElement();
	
	// Create container to hold both the tables
	var container = document.createElement("div");
	container.className = "calendar_container";
	dropdown.appendChild(container);

	// Prevent selection of content
	preventSelection(dropdown);
	
	// Create the table that contains the navigation elements
	var navTable = document.createElement("table");
	navTable.className = "navtable";
	container.appendChild(navTable);
	
	var navTableBody = document.createElement("tbody");
	navTable.appendChild(navTableBody);
	
	var navRow = document.createElement("tr");
	navTableBody.appendChild(navRow);

	// Cell to select previous month	
	var prevMonth = document.createElement("td");
	prevMonth.className = "calendar_prevmonth";
	//prevMonth.onclick = function() { dp._handlePrevMonthClick(); return true; };
	dp.m_prevMonthClickHandler = SUPSEvent.addEventHandler(prevMonth, "click", function() { dp._handlePrevMonthClick(); return true; });
	navRow.appendChild(prevMonth);
	
	// Cell which contains Month and Year
	dp.m_currentMonthCell = document.createElement("td");
	dp.m_currentMonthCell.className = "calendar_controls";
	dp.m_currentMonthCell.innerHTML = "&nbsp;";
	navRow.appendChild(dp.m_currentMonthCell);

	// Controls for month and year in the drop down have been
	// commented out, as including then will involve the 
	// date picker changing size.
/*	
	// Create the month dropdown with options
	var monthSelect = document.createElement("select");
	dp.m_currentMonthCell.appendChild(monthSelect);
	for(var i = 0, l = FWDateUtil.months.length; i < l; i++)
	{
		var monthOption = document.createElement("option");
		monthOption.innerHTML = FWDateUtil.months[i];
		monthSelect.appendChild(monthOption);
	}
	
	// Create the year text field - limited to 4 characters
	var yearField = document.createElement("input");
	yearField.setAttribute("maxLength", "4");
	dp.m_currentMonthCell.appendChild(yearField);
*/
	
	// Cell to select next month
	var nextMonth = document.createElement("td");
	nextMonth.className = "calendar_nextmonth";
	//nextMonth.onclick = function() { dp._handleNextMonthClick(); return true; };
	dp.m_nextMonthClickHandler = SUPSEvent.addEventHandler(nextMonth, "click", function() { dp._handleNextMonthClick(); return true; });
	navRow.appendChild(nextMonth);


	// Create the table which contains the days for the
	// currently selected month.	
	var calTable = document.createElement("table");
	calTable.className = "caltable";
	container.appendChild(calTable);
	
	var calTableBody = document.createElement("tbody");
	calTable.appendChild(calTableBody);
	
	var dayRow = document.createElement("tr");
	calTableBody.appendChild(dayRow);
	
	// Render the days
	for(var i = 0, l = FWDateUtil.shortDays.length; i < l ; i++)
	{
		var dayCell = document.createElement("th");
		dayCell.innerHTML = FWDateUtil.shortDays[(i + dp.m_startDay)%l];
		dayRow.appendChild(dayCell);
	}
	
	var noOfDayRows = 6;
	var noOfCalendarDays = noOfDayRows * FWDateUtil.NO_OF_WEEKDAYS;
	
	// Create the day days
	dp.m_dayCells = new Array(noOfCalendarDays);
	
	var position = 0;
	
	// Click event handler function
	dp.m_cellClickEventHandler = SUPSEvent.addEventHandler(calTable, "click", function(BALLS) { dp._handleCellClick(BALLS); return true; });
	
	for(var i = 0; i < noOfDayRows ; i++)
	{
		// Create the day row.
		var dayRow = document.createElement("tr");
		calTableBody.appendChild(dayRow);
		
		for(var j = 0; j < FWDateUtil.NO_OF_WEEKDAYS; j++)
		{
			var dayCell = document.createElement("td");
			dayCell.innerHTML = "&nbsp;";
			
			// Record position of cell in Cell array on the HTML Element
			dayCell.__position = position;
			
			// Set the click handler for the cell
			//dayCell.onclick = handleCellClick;

			dayRow.appendChild(dayCell);
			
			// Keep array of cells
			dp.m_dayCells[position++] = dayCell;
		}
	}
	
	// Show current date
	dp._showDateInDropDown(null);
	
	// Handle key events on the input field
	//dp.m_dropDownField._getInputFieldElement().onkeyup = function() { dp._handleInputFieldKeyUp(); return true; };
	dp.m_keyEventUpHandlerKey = SUPSEvent.addEventHandler(dp.m_dropDownField._getInputFieldElement(), "keyup", function() { dp._handleInputFieldKeyUp(); return true; }, false);
	
	return dp;
}


DatePickerRenderer.prototype.dispose = function()
{
	// Remove selection prevention event handler from drop down
	unPreventSelection(this.m_dropDownField._getDropDownElement());

	for(var i = 0, l = this.m_dayCells.length; i < l; i++)
	{
		delete this.m_dayCells[i];
	}
	delete this.m_dayCells;

	SUPSEvent.removeEventHandlerKey(this.m_prevMonthClickHandler);
	this.m_prevMonthClickHandler = null;
	
	SUPSEvent.removeEventHandlerKey(this.m_nextMonthClickHandler);
	this.m_nextMonthClickHandler = null;
	
	SUPSEvent.removeEventHandlerKey(this.m_cellClickEventHandler);
	this.m_cellClickEventHandler = null;
	
	SUPSEvent.removeEventHandlerKey(this.m_keyEventUpHandlerKey);
	this.m_keyEventUpHandlerKey = null;
	
	this.m_dropDownField.dispose();

	this.m_guiAdaptor = null;
}


DatePickerRenderer.prototype._setCellClass = function(cellPosition)
{
	// Make the day correspond to the Array of Days in FWDateUtil.
	var mappedDay = (cellPosition + this.m_startDay)%7;	

	// Set CSS class of date cell approriately
	if(cellPosition >= this.m_dayCells.length)
	{
		if (DatePickerRenderer.m_logger.isWarn()) DatePickerRenderer.m_logger.warn("DatePickerRenderer._setCellClass() warning, cellPosition >= this.m_dayCells.length");
	}
	else
	{
		this.m_dayCells[cellPosition].className = 
			(this.m_selectedDatePosition == cellPosition ? "selected " : "") +	// If this cell is the selected date set class appropriately
			(this.m_todayDatePosition  == cellPosition ? "today " : "") +		// If this cell is the today set the class appropriately
			((0 == mappedDay || 6 == mappedDay) ? "weekend" : "");				// Sunday (0) and Saturday(6) are considered weekend days
	}
}


DatePickerRenderer.prototype._handleInputFieldKeyUp = function()
{
	var value = this.m_dropDownField._getInputFieldElement().value;
	var date = FWDateUtil.parseDate(value);

	if(!FWDateUtil.compareDates(date, this.m_selectedDate))
	{
		this._selectDate(date);
	}
}



DatePickerRenderer.prototype._selectDate = function(date)
{
	// Set the selected date
	this.m_selectedDate = date;

	var refreshed = this._showDateInDropDown(date);

	// If show did not perform a refresh, then just refresh
	// the selected date now.		
	if(!refreshed)
	{
		// Unselect the currently selected date
		this._renderCurrentlySelectedDateUnselected();

		// Update the cell which is currenly selected
		this._updateSelectedDatePosition();

		// Render the newly selected cell as selected
		if(this.m_selectedDatePosition != null)
		{
			this._setCellClass(this.m_selectedDatePosition);
		}
	}
}


DatePickerRenderer.prototype._showDateInField = function()
{
	var date = this.m_selectedDate;
	
	if(null != date)
	{
		// Convert date to string, padding single digit dates
		var day = date.getDate();
		day = (day < 10) ? "0" + day : day;

		// Show the date in the input field
		this.m_dropDownField._getInputFieldElement().value = 
			day + "-" +
			FWDateUtil.shortMonths[date.getMonth()] + "-" +
			date.getFullYear();
	}
	else
	{
		// Set the value of the input field to the string value - make sure
		// that null value doesn't get displayed as 'null' on IE
		this.m_dropDownField._getInputFieldElement().value = (null == this.m_value ? '' : this.m_value) ;
	}
}

/**
 * Method handles a mouse click whilst cursor over data picker
 * date selection table.
 *
 * @param evt Details of mouse click event
 *
*/
DatePickerRenderer.prototype._handleCellClick = function(evt)
{
	// Get the clicked cell, depending on which browser we're using
	evt = (null == evt) ? window.event : evt;
	var clickCell = SUPSEvent.getTargetElement(evt);
		
	// Get the position of the clicked cell in the array of cells.
	var position = clickCell.__position;
	if(null != position)
	{
		if(this.m_selectedDatePosition != position)
		{
			this._renderCurrentlySelectedDateUnselected();
	
			// Calculate the clicked date
			var clickedDate = new Date(this.m_firstDate);				// Get the first date displayed in the drop down
			clickedDate.setDate(clickedDate.getDate() + position);		// Add the position to the date to add the appropriate number of days
	
			// Unselect the currently selected date
			this._renderCurrentlySelectedDateUnselected();
	
			// Set the selected date
			this.m_selectedDate = clickedDate;
	
			// Render the newly selected cell as selected	
			this.m_selectedDatePosition = position;
			this._setCellClass(position);
	
			// Show the date in the input field
			this._showDateInField();
		}
		
		// Hide the dropdown
		this.m_dropDownField.hideDropDown();
		
		// Defect 1051. Move this block of code inside section of code
		// executed following click on date cell only. We do not want
		// to update adaptor for a click on a date cell border.
		if(this.m_guiAdaptor.getUpdateMode() == DatePickerRenderer.CLICK_CELL_MODE)
	    {
	        // Update adaptor value.
		    this.m_guiAdaptor._handleValueChange();
	    }
	}

}


DatePickerRenderer.prototype._renderCurrentlySelectedDateUnselected = function()
{
	// Render the previously selected cell as not selected
	var prevSelectedCell = this.m_selectedDatePosition;
	if(null != prevSelectedCell)
	{
		this.m_selectedDatePosition = null;
		this._setCellClass(prevSelectedCell);
	}
}


DatePickerRenderer.prototype._handleNextMonthClick = function()
{
	this._changeMonth(1);
}


DatePickerRenderer.prototype._handlePrevMonthClick = function()
{
	this._changeMonth(-1);
}


DatePickerRenderer.prototype._changeMonth = function(delta)
{
	var month = new Date(this.m_currentYear, this.m_currentMonth, 1);
	month.setMonth(month.getMonth() + delta);
	
	this._showDateInDropDown(month);
}


DatePickerRenderer.prototype._showDateInDropDown = function(d)
{
	// Has dropdown been refreshed?
	var refreshed = false;

	var today = new Date();  // Get current time
	
	// Only want date components...
	today = new Date(today.getFullYear(), today.getMonth(), today.getDate());

	// If null date, the default to showing today's date
	if(null == d) d = new Date(today);

	var month = d.getMonth();
	var year = d.getFullYear();

	// Check to see if the date has changed
	if(this.m_currentMonth != month || this.m_currentYear != year)
	{
		this.m_currentMonth = month;
		this.m_currentYear = year;

		// Calculate the first date displayed on the popup calendar
		this.m_firstDate = new Date(d);
		this.m_firstDate.setDate(1);
		this.m_firstDate.setDate(1 - (7 + this.m_firstDate.getDay() - this.m_startDay) % 7);

		// Get absolute time of the day after the last date displayed on the calendar
		this.m_lastDate = new Date(this.m_firstDate);
		this.m_lastDate.setDate(this.m_lastDate.getDate() + this.m_dayCells.length);
		
		// Get absolute time of the first date	
		firstDateTime = this.m_firstDate.getTime();

		// Calculate absolute time of the start of the day after the last date displayed on the calendar
		var lastDateTime = this.m_lastDate.getTime() + FWDateUtil.MILLISECONDS_PER_DAY;
	
		// Get absolute time of today's date
		var todayTime = today.getTime();
	
		// Set the position of today's date in the date cell array
		this.m_todayDatePosition = 
			(todayTime >= firstDateTime && todayTime < lastDateTime)	// Is today one of the displayed dates on the drop down
			? FWDateUtil.getDaysDifference(today, this.m_firstDate)		// Yes - get it's position in the cell array
			: null;														// No - set today's date position to null

		// Update the selected date position
		this._updateSelectedDatePosition();

		// Show the current month on the drop down
		this.m_currentMonthCell.innerHTML = FWDateUtil.months[month] + " " + year;
	
		// Start at the first date
		var currentDay = new Date(this.m_firstDate);
		
		for(var i = 0, l = this.m_dayCells.length; i < l; i++)
		{
			var cell = this.m_dayCells[i];
			var date = currentDay.getDate();
			cell.innerHTML = date;

			// Set the style of the cell
			this._setCellClass(i);

			cell.style.color = (currentDay.getMonth() == month) ? "black" : "gray";

			currentDay.setDate(date + 1);
		}
		
		refreshed = true;
	}
	
	return refreshed;
}


DatePickerRenderer.prototype._updateSelectedDatePosition = function()
{
	// Calculate the position of selected date in the date cell array
	if(null == this.m_selectedDate)
	{
		// No selected date, so set position to null
		this.m_selectedDatePosition = null;
	}
	else
	{
		// Get absolute time of the selected date
		var selTime = this.m_selectedDate.getTime();
	
		// Get absolute time of the first date	
		firstDateTime = this.m_firstDate.getTime();

		// Calculate absolute time of the start of the day after the last date displayed on the calendar
		var lastDateTime = this.m_lastDate.getTime() + FWDateUtil.MILLISECONDS_PER_DAY;

		if(DatePickerRenderer.m_logger.isTrace()) DatePickerRenderer.m_logger.trace("DatePickerRenderer._updateSelectedDatePosition() this.m_firstDate=" + this.m_firstDate.toString() + ", this.m_selectedDate=" + this.m_selectedDate.toString() + ", days difference=" + FWDateUtil.getDaysDifference(this.m_selectedDate, this.m_firstDate));

		// Set the position of the selected date in the date cell array
		this.m_selectedDatePosition = 
			(selTime >= firstDateTime && selTime < lastDateTime)				// Is selected date one of the displayed dates on the drop down
			? FWDateUtil.getDaysDifference(this.m_selectedDate, this.m_firstDate)	// Yes - get it's position in the cell array
			: null;																// No - set selected date's position to null
	}
}

DatePickerRenderer.prototype._calculateFirstDisplayedDate = function(d)
{
	// Calculate the first date to show in the calendar if
	// the month and year of the supplied date were used.
	var firstDay = new Date(d);
	firstDay.setDate(1);
	firstDay.setDate(1 - (7 + firstDay.getDay() - this.m_startDay) % 7);
	
	return firstDay;
}


/**
 * Get the date selected by the date picker
 *
 * @return the date selected by the date picker - may be null if no valid date picked
 * @type Date
 */
DatePickerRenderer.prototype.getSelectedDate = function()
{
	return this.m_selectedDate;
}


DatePickerRenderer.prototype.getValue = function()
{
	return this.m_dropDownField._getInputFieldElement().value;
}


/**
 * Set the date selected by the date picker
 *
 * @param the Date object which represents the date to be selected
 */
DatePickerRenderer.prototype.setValue = function(value)
{
	this.m_value = value;
	
	var date = FWDateUtil.parseXSDDate(value);

	if(!FWDateUtil.compareDates(date, this.m_selectedDate))
	{
		// Select the date 
		this._selectDate(date);
	}
	// Show the date in the field
	this._showDateInField();
}



DatePickerRenderer.prototype.render = function(disabled, focussed, mandatory, invalid, serverInvalid, readonly, inactive, isServerValidationActive)
{
	this.m_dropDownField.render(disabled, focussed, mandatory, invalid, serverInvalid, readonly, inactive, null, isServerValidationActive);
}
//==================================================================
//
// AddressGUIAdaptor.js
//
// Class for adapting a text style input element for use in the
// framework
//
//==================================================================


/**
 * Base class for adapting html input elements for use in the
 * framework.
 *
 * @param e the input element to manage
 * @constructor
 * @private
 */
function DatePickerGUIAdaptor()
{
}

DatePickerGUIAdaptor.m_logger = new Category("DatePickerGUIAdaptor");

/**
 * Default maximum number of characters for the input box
 */
DatePickerGUIAdaptor.DEFAULT_MAX_LENGTH = 11;

/**
 * DatePickerGUIAdaptor is a sub class of InputElementGUIAdaptor
 */
DatePickerGUIAdaptor.prototype = new HTMLElementGUIAdaptor();
DatePickerGUIAdaptor.prototype.constructor = DatePickerGUIAdaptor;

/**
 * Add the required protocols to the CheckboxInputElementGUIAdaptor
 * Note: Does not use FieldElement etc. as did not want to inherit mandatory protocol
 */
 
GUIAdaptor._setUpProtocols('DatePickerGUIAdaptor'); 
GUIAdaptor._addProtocol('DatePickerGUIAdaptor', 'DataBindingProtocol');			// Supports binding to data model
GUIAdaptor._addProtocol('DatePickerGUIAdaptor', 'EnablementProtocol');            // Supports enablement
GUIAdaptor._addProtocol('DatePickerGUIAdaptor', 'FocusProtocol');                 // Supports focusing
GUIAdaptor._addProtocol('DatePickerGUIAdaptor', 'FocusProtocolHTMLImpl');         // Include the default HTML implementation of focus
GUIAdaptor._addProtocol('DatePickerGUIAdaptor', 'HelpProtocol');                  // Supports helptext
GUIAdaptor._addProtocol('DatePickerGUIAdaptor', 'HelpProtocolHTMLImpl');          // Include the default HTML implementation of help
GUIAdaptor._addProtocol('DatePickerGUIAdaptor', 'InitialiseProtocol');            // Supports custom initialisation
GUIAdaptor._addProtocol('DatePickerGUIAdaptor', 'MandatoryProtocol');            // Supports mandatory
GUIAdaptor._addProtocol('DatePickerGUIAdaptor', 'NameProtocol');                  // Supports naming of the element
GUIAdaptor._addProtocol('DatePickerGUIAdaptor', 'ReadOnlyProtocol');            // Supports keybinding
GUIAdaptor._addProtocol('DatePickerGUIAdaptor', 'TemporaryProtocol');             // Supports temporary behaviour
GUIAdaptor._addProtocol('DatePickerGUIAdaptor', 'ValidationProtocol');            // Supports validation protocol


/**
 * Clean up after the component
 */
DatePickerGUIAdaptor.prototype._dispose = function()
{
	if(DatePickerGUIAdaptor.m_logger.isTrace()) DatePickerGUIAdaptor.m_logger.trace("DatePickerGUIAdaptor.dispose()");

	// Dispose of the renderer
	this.m_renderer.dispose();

	this.m_renderer = null;
}

/**
 * Create a new DatePickerGUIAdaptor
 *
 * @param e the text input element to manage
 * @param f the gui adaptor factory
 * @return the new DatePickerGUIAdaptor
 * @type DatePickerGUIAdaptor
 */
DatePickerGUIAdaptor.create = function(e, factory)
{
	if(DatePickerGUIAdaptor.m_logger.isTrace()) DatePickerGUIAdaptor.m_logger.trace("DatePickerGUIAdaptor.create()");
	var a = new DatePickerGUIAdaptor();
	a._initDatePickerGUIAdaptor(e);
	return a;
}


/**
 * Initialise the DatePickerGUIAdaptor
 *
 * @param e the HTMLElement for the select element to be managed
 * @private
 */
DatePickerGUIAdaptor.prototype._initDatePickerGUIAdaptor = function(e)
{
	if(DatePickerGUIAdaptor.m_logger.isTrace()) DatePickerGUIAdaptor.m_logger.trace("DatePickerGUIAdaptor._initDatePickerGUIAdaptor()");
	this.m_element = e;
	
	// Get a handle to the renderer instance
	this.m_renderer = e.__renderer;

	// Break circular reference in HTML
	this.m_element.__renderer = null;
	
	this.m_renderer.m_guiAdaptor = this;
	this.m_renderer.m_dropDownField.m_guiAdaptor = this;
}


/**
 * Handle a change in the value of the date picker
 *
 * @private
 */ 
DatePickerGUIAdaptor.prototype._handleValueChange = function()
{
	// Invoke DateBindingProtocol.update
	this.update();
}

DatePickerGUIAdaptor.prototype.getUpdateMode = function()
{
	return this.updateMode;
}

/**
 * Perform any GUIAdaptor specific configuration - this also creates the config
 * objects for the sub-components dynamically
 */
DatePickerGUIAdaptor.prototype._configure = function(cs)
{
	if(DatePickerGUIAdaptor.m_logger.isInfo()) DatePickerGUIAdaptor.m_logger.info("DatePickerGUIAdaptor._configure()");

	for(var i = cs.length - 1; i >= 0; i--)
	{
		var c = cs[i];
		
		if(null != c.weekends && null == this.weekends) 
		{
			this.weekends = c.weekends;
		}

		if(null != c.updateMode) 
		{
			this.updateMode = c.updateMode;
			if(this.updateMode != DatePickerRenderer.LOSE_FOCUS_MODE && this.updateMode != DatePickerRenderer.CLICK_CELL_MODE)
			{
				if(DatePickerGUIAdaptor.m_logger.isError()) DatePickerGUIAdaptor.m_logger.error("DatePickerGUIAdaptor._configure() unknown updateMode in configuration for adaptor id=" + this.getId() + ", reverting to default of DatePickerRenderer.LOSE_FOCUS_MODE");
				this.updateMode = DatePickerRenderer.LOSE_FOCUS_MODE;
			}
		}
		else
		{
			this.updateMode = DatePickerRenderer.LOSE_FOCUS_MODE;
		}
	}
	
	if(this.weekends == null)
	{
		this.weekends = "true";
	}
	
	// previously all transformations for dates where to / from XSD format. Therefore we are discarding
	// any existing transformations because they will throw exceptions because they are expecting SUPS
	// format for internal values but we now use XSD format.
	this.transformToModel = null;
	this.transformToDisplay = null;

	// Configure the input box
	this._getInputField().maxLength = DatePickerGUIAdaptor.DEFAULT_MAX_LENGTH;
}

/**
 * Get the value from the view, i.e. the HTML element. Default behaviour is to get the
 * value property from the HTML element, but this will need to be overridden for most adaptors
 *
 * @return the value of the component, usually a string but it could be a complicated multi-value
 * @type ???
 */
DatePickerGUIAdaptor.prototype._getValueFromView = function()
{
	var d = this.m_renderer.getSelectedDate();
	
	var ret = null;
	
	if(d != null)
	{
		ret = FWDateUtil.ConvertDateToXSDString(d);
    }
	else
	{
		// Unknown format - simply return input field string
		ret = this.m_renderer.getValue();
		if(ret == "") ret = null;
	}
	
	return ret;
}


/*
 * Default validation method.
 *
 * @param event the DataModelEvent that triggered this method
 * @returns An error code if model validation fails
 */
DatePickerGUIAdaptor.prototype.validate = function(event)
{
	var mV = FormController.getInstance().getDataModel().getValue(this.dataBinding);
	var val = this.invokeTransformToDisplay(mV);

	if(DatePickerGUIAdaptor.m_logger.isInfo()) DatePickerGUIAdaptor.m_logger.info(this.m_element.id + ":DatePickerGUIAdaptor.validate() data model value = " + mV + ", transformed to display value = " + val);
    
    
    return FWDateUtil.validateXSDDate(val, this.weekends)

}


DatePickerGUIAdaptor.prototype.onBlur = function()
{
	this.update();
}

/**
 * Update the value in the data model. Default implementation is
 * to set the value of a single node in the underlying DOM.
 *
 * @return true if the DataModel changed as a result of the update
 * @type boolean
 * @configuration
 * @merge-rule Most specific configuration overrides
 */
DatePickerGUIAdaptor.prototype.update = function()
{
	var db = this.dataBinding;
	if(null != db)
	{
		var fm = FormController.getInstance();
		var dm = fm.getDataModel();
		
		// this is not the correct place to set this, it should be inside a handleChange() method
		// on the adaptor because we need to handle the case where we start typing in a field, then
		// click on a button, BUT in this case the browser ensures we get the button click event before
		// we get the loseFocus() event from the text field. We may want to re-order events then at some 
		// point, and storing this information will help us.
		fm.startDataTransaction(this);
		
		var mV = this._getValueFromView();
		var dV = this.invokeTransformToModel(mV);
		
		var origValue = dm.getValue(db);
		var result = null;
		if(origValue == dV)
		{
			// This is to force the datePicker to re-render it's state even if the only change a user
			// makes is to enter the same date into a different format (WHY???)
			this.m_valueChanged = true;
			this.renderState();
			result = false;
		}
		else
		{
			result = dm.setValue(db, dV);
			// Trigger a StateChangeEvent if the value has changed
			var e = StateChangeEvent.create(StateChangeEvent.VALUE_TYPE, dV, this);
			this.changeAdaptorState(e);
		}
		fm.endDataTransaction(this);
		return result;
	}
	else
	{
		throw new DataBindingError("DataBindingProtocol.update(), no dataBinding specified for adaptor id = " + this.getId());
	}	
}


DatePickerGUIAdaptor.prototype.renderState = function()
{
	if(DatePickerGUIAdaptor.m_logger.isDebug())
	{
		DatePickerGUIAdaptor.m_logger.debug(this.getId() + ":DatePickerGUIAdaptor.renderState() this.m_enabled=" + this.m_enabled + ", this.m_readOnly=" + this.m_readOnly + ", this.getValid()=" + this.getValid() + ", this.m_mandatory=" + this.m_mandatory);
	}

	// Actions to take if fields focus state changes.
	if(this.m_focusChanged)
	{
		// Reset this immediately so that we don't end up recursing through this again
		this.m_focusChanged = false;

		if(this.m_focus)
		{
			// Highlight text on focus
			this.m_renderer.m_dropDownField._getInputFieldElement().select();
		}
		else
		{
			// Hide the drop down when the focus is lost
			this.m_renderer.m_dropDownField.hideDropDown();
		}
	}
	else
	{
	    if(this.m_valueChanged)
	    {
			// D927 - Only update the status bar message when this date picker has the focus
	        if(this.getUpdateMode() == DatePickerRenderer.CLICK_CELL_MODE && this.m_focus)
	        {
	            // Defect 758. Data value has changed. Update status bar message as appropriate
	            FormController.getInstance().getFormAdaptor()._setCurrentFocusedField(this);
	        }
	    }
	}

	// Set up value
	if(this.m_valueChanged)
	{
		this.m_renderer.setValue(this.m_value);
		this.m_valueChanged = false;
	}

	// Set up all states other than value
	this.m_renderer.render(
		!this.m_enabled,
		this.m_focus,
		this.m_mandatory,
		!this.getValid(),
		!this.getServerValid(),
		this.m_readOnly,
		!this.isActive(),
		this.isServerValidationActive()
	);
}

/**
 * Get the element to set focus on. For the DatePicker this
 * is the input text field
 */
DatePickerGUIAdaptor.prototype.getFocusElement = function()
{
	return this._getInputField();
}

/**
 * Get the component's input field.
 *
 * @return the component's input field
 * @type HTMLInputElement
 * @private
 */
DatePickerGUIAdaptor.prototype._getInputField = function()
{
	return this.m_renderer.m_dropDownField._getInputFieldElement();
}
/**
 * WordProcessingGUIAdaptor
 *
 * Implementation based on FCKEditor (version 2.0) and JSpell.
 *
 * Integrated witht the framework and implements the Focus,Active,Enablement
 * and DataBindingProtocols.
 *
 * General Comments / Explanations:
 *
 * Onload handlers and initialisation:
 * The FCKEditor consists of two iframes which are initialised asyncronousy.
 * This leads to problems with the framework interacting with it as it
 * is highly possible that the editor has either a) not loaded the script
 * required into the iframe or b) The script has loaded, but the FCKEditor's
 * internal state is not ready, and runtime errors occur. Two strategies
 * are employed.
 * The first in onload handlers placed on the two iframes -
 * these are used for configuring the FCKEditor at the appropriate time as
 * well as starting the required event handlers.  See .setupFCKEditor() and
 * .setupFCKEditor2().
 * The second is in used for when other parts of the
 * framework look to interact with the adaptor, which may not be ready yet.
 * The two methods in question are renderstate() and focus() - which may
 * be called as part of general initiasation - but then require items
 * which may not yet be ready.  To counter this  the function
 * checkFCKEditorReady() checks whether the script is loaded and the function
 * exists, if it is not ready then a timeout is set before checking again
 * and finally calling the function when everything is loaded. Note - this is
 * not 100% bulletproof as there is no way that we know of to check if the
 * internal state of the FCKEditor is actually ready yet - however in testing
 * a runtime error has not been seen using this method.
 *
 * RWW 4/01/06. FCKeditor actually provides for a callback function,
 * FCKeditor_OnComplete, which the editor invokes when it believes
 * it is fully loaded. To solve initial loading problems (defect 838)
 * I have implemented this method. The FormController stores a list
 * of WordProcessingGUIAdaptors. Initially, the adaptors are flagged
 * as not being loaded. When the FCKeditor_OnComplete function is
 * invoked the associated adaptor is modified to indicate the load
 * is complete. I have also modified the FormController such that
 * when a form contains instances of the class WordProcessingGUIAdaptor
 * the second stage of initialisation is not allowed to start until
 * all instances of FCKeditor have been loaded. This should allow
 * the adaptor state initialisation to set the default contents
 * of the editor document.
 *
 * Rendering problems:
 * IE has problems rendering "paste" operations in iframes - this exists on all
 * platforms but is much more pronounced on slower and/or SP1 machines.  Basically
 * doing multiple pastes causes the screen to freeze, and the effect of the
 * pastes is not seen sometimes for up to 10 seconds later and/or when the mouse
 * is moved.  To counter this an handler has been placed on "onpaste" and "ondrop"
 * operations and it bascially just adds a blank space to the current text. This
 * has been found to solve the rendering problems in 98% of scenarios.
 *
 * Focusing issues:
 * IE does not remember the focus location within an editable iframe.  To be
 * able to remember when the focus was last if the user clicks off then tabs
 * back on a "onkeydown" handler has been implemented which basically just remembers
 * the focus for each keypress.  An important point is that obviously the
 * focus is destroyed if the databinding for the FCKEditor changes AND the value
 * that is changes to is different to that currently held. If for some reason
 * you are losing this focussing information it is almost definately that the
 * comparison between the two values(performed in renderstate) is returning false
 * when it should be true (changes in transformToX can cause these type of issues).
 *
 */
function WordProcessingGUIAdaptor()
{
}

WordProcessingGUIAdaptor.m_logger = new Category("WordProcessingGUIAdaptor");
WordProcessingGUIAdaptor.CSS_CLASS_NAME = "wordProcessing" ;
WordProcessingGUIAdaptor.TRANSPORT_TAG = "p" ;
WordProcessingGUIAdaptor.m_initialHTML = "";
WordProcessingGUIAdaptor.m_setHTMLCounter = 0;
WordProcessingGUIAdaptor.replacingContent = false;

/**
* Subclass of HTMLElementGUIAdaptor
*/
WordProcessingGUIAdaptor.prototype = new HTMLElementGUIAdaptor();
WordProcessingGUIAdaptor.prototype.constructor = WordProcessingGUIAdaptor;


/**
 * Add the required protocols to the adaptor
 */
GUIAdaptor._setUpProtocols('WordProcessingGUIAdaptor');
GUIAdaptor._addProtocol('WordProcessingGUIAdaptor', 'BusinessLifeCycleProtocol');
GUIAdaptor._addProtocol('WordProcessingGUIAdaptor', 'FocusProtocol');
GUIAdaptor._addProtocol('WordProcessingGUIAdaptor', 'ActiveProtocol');
GUIAdaptor._addProtocol('WordProcessingGUIAdaptor', 'DataBindingProtocol');
GUIAdaptor._addProtocol('WordProcessingGUIAdaptor', 'EnablementProtocol');


/**
 * References to the FCKeditor's iframes.
 */
WordProcessingGUIAdaptor.prototype.m_mainIframe = null;
WordProcessingGUIAdaptor.prototype.m_editableIframe = null;

/**
 * Flag recording whether or not FCKeditor has indicated
 * that loading is complete.
 *
*/
WordProcessingGUIAdaptor.prototype.m_FCKeditorLoadComplete = false;



/*
 *  Invokes the wordprocessor's creation method (wrapping the
 *  output in a div)
 */
WordProcessingGUIAdaptor.createInline = function(id)
{
	document.write("<div id='" + id + "' class='" + WordProcessingGUIAdaptor.CSS_CLASS_NAME + "' tabindex='1' hideFocus='true'>");
//	document.write("<img id=\"wp_image" + id +"\" GALLERYIMG=\"no\" class=\"wordProcessing\" src=\"./images/inactive.gif\">");
	var inactiveGifURL = Services.getAppController().m_config.getAppBaseURL() +
	    "/images/inactive.gif";
	document.write("<img id=\"wp_image" + id +"\" GALLERYIMG=\"no\" class=\"wordProcessing\" src="+inactiveGifURL+">");

	var wpId = id + "_wordprocessor";
	document.write("<textarea id=\"" + wpId + "\"></textarea>");

	document.write("</div>");

};

/**
 * Create a new WordProcessingGUIAdaptor
 * @param e the logic element to manage
 * @return the new WordProcessingGUIAdaptor
 * @type WordProcessingGUIAdaptor
 */
WordProcessingGUIAdaptor.create = function(e)
{
	var a = new WordProcessingGUIAdaptor();
	a._initWordProcessingGUIAdaptor(e);
	return a;
};

/**
 * Get the element to set focus on. For the wordprocessor this
 * is the content window of the editableIframe.
 */
WordProcessingGUIAdaptor.prototype.getFocusElement = function()
{
	// First time this is invoked the editableIframe may
	// not be fully setup yet.
	if (this.m_editableIframe)
	{
		return this.m_editableIframe.contentWindow.document.body;
	}
	return this.m_element;
};

/**
 * Initialise the WordProcessingGUIAdaptor.  Creates
 * an empty array to hold the eventHandlerKeys
 *
 * @param e the HTMLElement for the select element to be managed
 */
WordProcessingGUIAdaptor.prototype._initWordProcessingGUIAdaptor = function(e)
{
	if(WordProcessingGUIAdaptor.m_logger.isInfo()) WordProcessingGUIAdaptor.m_logger.info(e.id + ":WordProcessingGUIAdaptor._initWordProcessingGUIAdaptor");

	this.m_element = e;
	var a = this;

	// Setup the array of event handling keys.
	a.m_eventHandlerKeys = new Array();

	// Add adaptor to FormController array containing references
	// to instances of class WordProcessingGUIAdaptor
	FormController.getInstance().addWordProcessingGUIAdaptor(a);

	return a;
};

/**
 * Configure the WordProcessingGUIAdaptor. It is possible to have a select with a set of options hardcoded
 * into the HTML in which case the only JS configuration required would be dataBinding from
 * the DataBindingProtocol.
 *
 * @param cs an Array of configuration objects ordered with
 *   most specific items first.
 */
WordProcessingGUIAdaptor.prototype._configure = function(cs)
{
	// Run through configuration specific to this element
	for(var i = 0, l = cs.length; i < l; i++)
	{
		var c = cs[i];

		if(c.toolBarSet && this.m_toolBarSet == null)
		{
			this.m_toolBarSet = c.toolBarSet;
		}
/*
		if(c.toolBar && this.m_toolBar == null)
		{
			this.m_toolBar = c.toolBar;
		}
*/
		if(c.width && this.m_width == null)
		{
			this.m_width = c.width;
		}

		if(c.height && this.m_height == null)
		{
			this.m_height = c.height;
		}

		if(c.saveAction && this.m_saveAction == null)
		{
			this.m_saveAction = c.saveAction;
		}

		if(c.printAction && this.m_printAction == null)
		{
			this.m_printAction = c.printAction;
		}

		if(c.previewAction && this.m_previewAction == null)
		{
			this.m_previewAction = c.previewAction;
		}
	}

	// Use the default ToolBar set if one is not defined
	if (this.m_toolBarSet == null)
	{
		this.m_toolBarSet = "SUPSDefault";
	}

	// Set up default methods on user definable functions.
	if (this.m_saveAction == null)
	{
		this.m_saveAction = function()
		{
			Services.showAlert("In default save action");
		};
	}
	if (this.m_printAction == null)
	{
		this.m_printAction = function()
		{
			Services.showAlert("In default print action");
		};
	}
	if (this.m_previewAction == null)
	{
		this.m_previewAction = function()
		{
			Services.showAlert("In default preview action");
		};
	}

	// Now actually start up the wordprocessor
	var wpId = this.getId() + "_wordprocessor";
	var oFCKeditor = new FCKeditor(wpId, this.m_width, this.m_height, this.m_toolBarSet) ;

	// Set up the URL for the custom configuration file
	var ac = Services.getAppController();
	var baseURL = ac.m_config.getAppBaseURL() + "/com/sups/client/gui/wordProcessing/fckeditor";
	oFCKeditor.Config["CustomConfigurationsPath"] = baseURL + "/WordProcessingConfig.js";

	oFCKeditor.ReplaceTextarea();

	// Find the main iframe of the fckeditor and remember it.
	this.m_mainIframe = document.getElementById(wpId + "___Frame");


	// Add onload event for the editor iframe so we can start up all the required
	// handlers etc.
	var thisObj = this;

	this.m_eventHandlerKeys.push(SUPSEvent.addEventHandler(this.m_mainIframe,
	                             "load",
	                             function() {thisObj._setupFCKEditor();},
	                             false));

	// Create a link to the "enablement" image
    this.m_inactiveImage = document.getElementById("wp_image" + this.getId());

 	// Start the mousedown event handler to cater for when IE decides to take ages
 	// to fire the above onload event.
	this.m_eventHandlerKeys.push(SUPSEvent.addEventHandler(this.m_inactiveImage,
                                      "mousedown",
                                      function(evt) { thisObj.stopPropagationHandler(evt); },
                                      false));

	// Get the correct size of the wordprocessor
    var div = document.getElementById(this.getId());
    this.m_inactiveImage.style.width = div.offsetWidth;
    this.m_inactiveImage.style.height = div.offsetHeight;

};

/*
 * This function is called when the first (of 2) iframes is created
 * by the FCKeditor.
 *
 * Invoked at the end of _config when the adaptor is setup.
 *
 * It sets up the next onload handler to be called when the second
 * iframe is initialised.
 */
WordProcessingGUIAdaptor.prototype._setupFCKEditor = function()
{
    var editorIframe = this.m_mainIframe.contentWindow.document.getElementById("xEditingArea");

    // Pass in GUI adaptor reference to iframe
    this.m_mainIframe.contentWindow.GUIAdaptorRef = this;

    if(editorIframe.firstChild != null)
    {
        var thisObj = this;
        this.m_editableIframe = editorIframe.firstChild;

        // Add in any configuration required for the FCKEditor before the editor examines
        // its configuration.
        //this.addFCKConfig();



        this.m_eventHandlerKeys.push(SUPSEvent.addEventHandler(editorIframe.firstChild,
                                     "load",
                                     function() {thisObj._setupFCKEditor2();},
                                     false));
    }
};

/* Called when the editor iframe is initialised (and again if the formcontroller is
 * not available).  Responsible for setting up the event handlers and sizing the
 * "inactive" gif.
 */
WordProcessingGUIAdaptor.prototype._setupFCKEditor2 = function()
{
    this.checkEditableIFrame();
    
    this.addCSSToDocument();

	// Stop all event handlers (some may have been started already due to IE's ropey handling of
	// the "onload" meaning that we needed them before getting here - best to clear down
	// just to be sure)
	this.stopEventHandlers();

	// Start all event handlers up.
	this.startEventHandlers();
};

/*
 * Attach the wordprocessing.css to the editor document.
 */
WordProcessingGUIAdaptor.prototype.addCSSToDocument = function()
{
    var ac = top.AppController.getInstance();
    var cssLoc = ac.m_config.getAppBaseURL() + "/fw_IE.css";
    this.checkEditableIFrame();
	this.m_editableIframe.contentWindow.document.createStyleSheet(cssLoc);
};

/*
 *  Checks whether the editableIframe has been initialised successfully.
 */
WordProcessingGUIAdaptor.prototype.checkEditableIFrame = function()
{
    if(this.m_editableIframe == null)
    {
        this.m_editableIframe = this.m_mainIframe.contentWindow.document.getElementById("xEditingArea").firstChild;
    }
};

/**
 * Invoked from _setupFCKEditor - this method adds all of the
 * configuration required to the FCKEditor.
 * It dynamically adds to the FCKConfig object used by the FCKEditor
 */
WordProcessingGUIAdaptor.prototype.addFCKConfig = function()
{
	var configObj = this.m_mainIframe.contentWindow.FCKConfig;

	// Add the custom toolbarset to the object in the mainIframe before the editor needs it.
	if (this.m_toolBarSet == "custom")
	{
		configObj.ToolbarSets["custom"] = this.m_toolBar;
	}

	// Add in each of the plugins.
	var plugins = WordProcessingPlugins.plugins;
    var i;
	if (plugins)
	{
		for (i = 0; i < plugins.length; i++)
		{
			configObj.Plugins.Add(plugins[i],'en');
		}
	}

	// Add in each of the default toolbar types.
	var toolBarSets = WordProcessingToolBarSets.toolBarSets;
	if (toolBarSets)
	{
		for (i = 0; i < toolBarSets.length; i++)
		{
			configObj.ToolbarSets[toolBarSets[i][0]] = toolBarSets[i][1];
		}
	}
    configObj.FullPage = true;
};

/*
 *  Sets up all eventHandlers for the object - adding them to m_eventHandlerKeys.
 */
WordProcessingGUIAdaptor.prototype.startEventHandlers = function()
{
	var tm = FormController.getInstance().getTabbingManager();
	var thisObj = this;


	// Add handler to parent document.
	this.m_eventHandlerKeys.push(SUPSEvent.addEventHandler(thisObj.m_mainIframe.contentWindow.document,
                                      "mousedown",
                                      function(evt) { tm._handleComponentClick(thisObj,evt); },
                                      false));

	this.m_eventHandlerKeys.push(SUPSEvent.addEventHandler(this.m_inactiveImage,
                                      "mousedown",
                                      function(evt) { thisObj.stopPropagationHandler(evt); },
                                      false));

	// And now the rest for the current document
	this.m_eventHandlerKeys.push(SUPSEvent.addEventHandler(thisObj.m_editableIframe.contentWindow.document,
                                      "keydown",
                                      function(evt) {thisObj.processKeyDown(evt); },
                                      false));

    this.m_eventHandlerKeys.push(SUPSEvent.addEventHandler(thisObj.m_editableIframe.contentWindow.document,
                                      "keyup",
                                      function(evt) {thisObj.processKeyUp(evt); },
                                      false));

	this.m_eventHandlerKeys.push(SUPSEvent.addEventHandler(thisObj.m_editableIframe.contentWindow.document,
									  "click",
									  function(evt) {thisObj.processClick(evt); },
									  false));

	this.m_eventHandlerKeys.push(SUPSEvent.addEventHandler(thisObj.m_editableIframe.contentWindow.document,
                                      "mousedown",
                                      function(evt) { tm._handleComponentClick(thisObj,evt); },
                                      false));

    // Paste and Drop handlers - only required for SP1 versions of XP
	this.m_eventHandlerKeys.push(SUPSEvent.addEventHandler(thisObj.m_editableIframe.contentWindow.document.body,
                                      "paste",
                                      function(evt) { thisObj.processPaste(evt); },
                                      false));
	this.m_eventHandlerKeys.push(SUPSEvent.addEventHandler(thisObj.m_editableIframe.contentWindow.document.body,
                                      "drop",
                                      function(evt) { thisObj.processPaste(evt); },
                                      false));

	// Prevent F1 key press activating browser help
	this.m_eventHandlerKeys.push(SUPSEvent.addEventHandler(thisObj.m_editableIframe.contentWindow.document,
                                      "help",
                                      function() { return false; },
                                      false));
};

/*
 *  Sets in initial HTML which has been loaded by the user (the template).
 */
WordProcessingGUIAdaptor.prototype.setInitialState = function ()
{
    try
    {
        var fckEd = this.getFCKEditor();
        this.m_initialHTML = fckEd.GetData();
        this.m_setHTMLCounter = 0;
    }
    catch(exception)
    {
        //Every so often you get a permission denied error
        this.m_setHTMLCounter++;
        if(this.m_setHTMLCounter <= 5)
        {
            var thisObj = this;
            setTimeout(function() {thisObj.setInitialState();}, 100);
        }
    }
};

/*
 *  Checks whether the user has edited the HT
 */
WordProcessingGUIAdaptor.prototype.hasContentChanged = function ()
{
    return (this.m_initialHTML != this.getHTML());
};

/*
 *  Stops the propagation of the current event
 */
WordProcessingGUIAdaptor.prototype.stopPropagationHandler = function(e)
{
		SUPSEvent.stopPropagation(e);		// Prevent the event from propograting any further up the DOM
        return false;
};

/*
 * Removes all event handlers defined in m_eventHandlerKeys
 * then reinitialises that array.
 */
WordProcessingGUIAdaptor.prototype.stopEventHandlers = function()
{
	for(var i=0; i < this.m_eventHandlerKeys.length; i++)
	{
		SUPSEvent.removeEventHandlerKey(this.m_eventHandlerKeys[i]);
	}

	this.m_eventHandlerKeys = new Array();
};

/*
 * Intercepts a keydown event so as to remember the current selection
 * (hitting tab appears to disturb the selection, so the selection must
 *  be remembered before a tab key is hit)
 * If the key is a tab then insert 4 spaces and move the focus back to
 * this element.
 */
WordProcessingGUIAdaptor.prototype.processKeyDown = function(e)
{
	if(null == e)
	{
		e = window.event;
	}

    // Due to bug in IE - need to stop key events hitting the
    // span in question (even though they should be ignored
    // due to contenteditable="false"
    if (e.srcElement.className == "SUPSVAR" || e.srcElement.className == "SUPSVAR_NONEDITABLE")
    {
        WordProcessingGUIAdaptor.m_logger.info("className is: " + e.srcElement.className);
        SUPSEvent.stopPropagation(e);
        return false;
    }

	if(e.keyCode == Key.Tab.m_keyCode)
	{
		// If a tab character just insert 4 spaces.
		var fckEd = this.getFCKEditor();
		this.focus();
		fckEd.InsertHtml("&nbsp;&nbsp;&nbsp;&nbsp;");

		// Get the new range
        this.setRange();

		// Move the focus back to the element (the tab key may move it off at some point)
		var thisObj = this;
		setTimeout(function(){thisObj.focus(); }, 5);
	}
    else
	{
		// If normal key press then get the range just after the key
		// has been pressed.
		// Comment out as testing key up replacement
		//var thisObj = this;
		//setTimeout(function(){thisObj.setRange()}, 200);
	}

	// Backspace key is usually blocked if the HTML element cannot absorb the backspace key.
	// In the FCK Editor's case it can but the HTMLView._canAcceptBackspaceKeyEvents blocks
	// it because the node name is BODY
	if(e.keyCode != Key.Backspace.m_keyCode)
	{
	    // If Alt key is pressed in W3C use 'keyCode' property otherwise 'which'
	    var keyCode = (HTMLView.isIE || e.altKey) ? e.keyCode : e.which;

		// Prevent default keybindings actions in the editor document
    	if(e.altKey ||
    	   HTMLView._isFunctionKey(keyCode) ||
    	   e.ctrlKey && (Key.CHAR_F.m_keyCode == keyCode || Key.CHAR_f.m_keyCode == keyCode ||
				  		 Key.CHAR_R.m_keyCode == keyCode || Key.CHAR_r.m_keyCode == keyCode ||
						 Key.CHAR_O.m_keyCode == keyCode || Key.CHAR_o.m_keyCode == keyCode ||
						 Key.CHAR_L.m_keyCode == keyCode || Key.CHAR_l.m_keyCode == keyCode ||
						 Key.CHAR_N.m_keyCode == keyCode || Key.CHAR_n.m_keyCode == keyCode ||
						 Key.CHAR_W.m_keyCode == keyCode || Key.CHAR_w.m_keyCode == keyCode ||
						 Key.CHAR_P.m_keyCode == keyCode || Key.CHAR_p.m_keyCode == keyCode ||
						 Key.CHAR_E.m_keyCode == keyCode || Key.CHAR_e.m_keyCode == keyCode ||
						 Key.CHAR_H.m_keyCode == keyCode || Key.CHAR_h.m_keyCode == keyCode))
    	{
    		return HTMLView._cancelKeyPress(e);
    	}
    }

	// Prevent the event from propograting any further up the DOM
	SUPSEvent.stopPropagation(e);
};

/**
 * Modification method for all keys except Tab record selection
 * on key up event. Attempt to remove dependency on time out
 * associated with key down event handler.
 *
*/
WordProcessingGUIAdaptor.prototype.processKeyUp = function(e)
{
    if(null == e)
    {
        e = window.event;
    }

    // Stop events hitting special span
    if (e.srcElement.className == "SUPSVAR" || e.srcElement.className == "SUPSVAR_NONEDITABLE")
    {
        WordProcessingGUIAdaptor.m_logger.info("className is: " + e.srcElement.className);
        SUPSEvent.stopPropagation(e);
        return false;
    }

    if(e.keyCode != Key.Tab.m_keyCode)
    {
        // Define current selection
        this.setRange();
    }

    SUPSEvent.stopPropagation(e);
};

/*
 * Sets the range of the currently selected text in the WordProcessingGUIAdaptor
 *
 */
WordProcessingGUIAdaptor.prototype.setRange = function()
{
    this.checkEditableIFrame();
	var selection = this.m_editableIframe.contentWindow.document.selection;
	this.m_textSelectRange = selection.createRange();
};


/*
 * Handler for a click, simply need to remember the current selection
 */
WordProcessingGUIAdaptor.prototype.processClick = function(e)
{
	if(null == e)
	{
		e = window.event;
	}
    // Another hack to get around flaky IE functionality where it sometimes
    // seems to ignore the onkeydown handler when the user repeatedly
    // clicks on the element - leading to characters being inserted
    // into the span.
    if (e.srcElement.className == "SUPSVAR_NONEDITABLE")
    {
        Services.showAlert("This variable type cannot be edited.");
        this.focus();
    }
    else
    {
	   this.setRange();
    }
};

/*
 * This function (hack) is required by SP1 version of XP - where IE
 * doesn't refresh properly after a paste event. Adding
 * an empty string to the page forces a refresh under most
 * conditions.
 *
 * Only needed when the object is a textrange. (the collapse
 * is there to stop the InsertHtml deleting the newly
 * pasted item.
 */
WordProcessingGUIAdaptor.prototype.processPaste = function()
{
	var fckEd = this.getFCKEditor();
	var thisObj = this;
	setTimeout(function(){
                          var selection = fckEd.EditorDocument.selection;
                          if (selection.type == "Control")
                          {
                              return;
                          }
                          thisObj.m_textSelectRange = selection.createRange();
                          thisObj.m_textSelectRange.collapse(false);
                          thisObj.focus();
                          fckEd.InsertHtml("");},
               10);
};

WordProcessingGUIAdaptor.prototype._dispose = function()
{
	if(null != this.m_invoke)
	{
		this.m_invoke.dispose();
		this.m_invoke = null;
	}

	this.stopEventHandlers();
	delete this.m_eventHandlerKeys;
	this.m_eventHandlerKeys = null;

	// Remove main iframe content window configuration
	var configObj = this.m_mainIframe.contentWindow.FCKConfig;
	var i, j, l;

	// Remove plugins
	for(i = 0, l = configObj.Plugins.Items.length; i < l; i++)
	{
		delete configObj.Plugins.Items[i];
	}
	configObj.Plugins.Items = null;

	// Remove toolbar sets
	for(i in configObj.ToolbarSets)
	{
		for(j = 0, l = configObj.ToolbarSets[i].length; j < l; j++)
		{
			delete configObj.ToolbarSets[i][j];
		}
		configObj.ToolbarSets[i] = null;
	}
	configObj.ToolbarSets = null;

	// Remove the rest of the configuration from the main iframe content window
	for(i in configObj)
	{
		delete configObj[i];
	}
	configObj = null;

	// Remove the FCK editor object
	var fckEd = this.getFCKEditor();

	for(i in fckEd)
	{
		delete fckEd[i];
	}
	fckEd = null;

	// Remove tool bar set
	delete this.m_toolBarSet;
	this.m_toolBarSet = null;

	// Remove GUI adaptor reference in iframe
	this.m_mainIframe.contentWindow.GUIAdaptorRef = null;

	// Remove main iframe
	this.m_mainIframe = null;

	// Remove editable iframe
	this.m_editableIframe = null;

	// Remove "enablement" image reference
	delete this.m_inactiveImage;
	this.m_inactiveImage = null;

	// Remove text select range
	delete this.m_textSelectRange;
	this.m_textSelectRange = null;
};

/*
 *  Retrieve the XHTML document fragment.
 */
WordProcessingGUIAdaptor.prototype.getHTML = function()
{
	var fckEd = this.getFCKEditor();

    return fckEd.GetData();
};

/*
 *  Set the XHTML document fragment to be edited.
 */
WordProcessingGUIAdaptor.prototype.setHTML = function(html)
{
	this.stopEventHandlers();

	// De-select text range as old selection is no longer valid.
	this.m_textSelectRange = null;

	var fckEd = this.getFCKEditor();
    fckEd.SetData(html, true);
    if(html != "")
    {
        var thisObj = this;
        if(!this.replacingContent)
        {
            setTimeout(function() {thisObj.setInitialState();}, 300);
            // Re-apply framework style sheet
            this.replacingContent = true;
        }
        this.m_editableIframe = null;
        
        this.checkEditableIFrame();
        
        this.addCSSToDocument();

        this.startEventHandlers();
    }
};

/*
 * Used by the databinding protocol to find out the displayValue.
 */
WordProcessingGUIAdaptor.prototype._getValueFromView = function()
{
	return this.getHTML();
};

/*
 * Render the wordprocessor - including set the focus if
 * required.
 * If the focus has changed the datamodel will be informed
 * via update().
 */
WordProcessingGUIAdaptor.prototype.renderState = function()
{
    // Another ugly "need to check if FCKEditor is ready"
    // part of the code. (renderstate is called during
    // initialisation - sometimes before the editor is
    // loaded / setup.  The issue is with the call to
    // getHTML - which then calls GetData
    if (!this.checkFCKEditorReady("GetData", "renderState"))
    {
        return;
    }

	if (this.m_valueChanged)
	{
		this.m_valueChanged = false;

		// If nothing has changed don't set the value as this
		// destroys our focus information.(value changed is
		// in the context of the datamodel - whereas the m_value
		// of the wordprocessor may already be up to date)
		if (this.getHTML() != this.m_value)
		{
			this.setHTML(this.m_value);
		}
	}

	// Actions to take if fields focus state changes.
	if(this.m_focusChanged)
	{
		// Reset this immediately so that we don't end up recursing through this again
		this.m_focusChanged = false;

		if(this.m_focus)
		{
			this.focus();
		}
		else
		{
			this.update();
		}
	}

	// Render for enablement and activity as appropriate.
	if((this.supportsProtocol("EnablementProtocol") && !this.getEnabled())
	    || (this.supportsProtocol("ActiveProtocol") && !this.isActive()))
	{
		this.m_inactiveImage.style.visibility = "visible";
	}
	else
	{
		this.m_inactiveImage.style.visibility = "hidden";
	}
};

/*
 * Sets the focus to the previous selection (if there
 * was one - otherwise just focuses the element
 */
WordProcessingGUIAdaptor.prototype.focus = function()
{
	// If there was a previous selection select it again.
	if (this.m_textSelectRange)
	{
		this.m_textSelectRange.select();
	}
	else
	{
        // This is a bit tricky as the editor may not be
        // initialised yet - and sometimes the code for it
        // is not even loaded - best to check, and if it
        // is not try again a while later.
        if (this.checkFCKEditorReady("Focus", "focus")){
    		this.getFCKEditor().Focus();
        }
	}
};

/**
 * This method is checks whether the code for the FCKEditor has been loaded
 * by the browser, and then also checks to see if the method in question
 * exists.
 * If not ready, then the method defined in the callback will be called again
 * using a timeout
 *
 * @param method - is a string with the name of the method on the FCKEditor to be called.
 * @param callbackMethod - is a string of the name of the method on the WordProcessingGUIAdaptor
 *                         to be called if the editor is not yet ready.
 */
WordProcessingGUIAdaptor.prototype.checkFCKEditorReady = function(method, callbackMethod)
{
    if (window.FCKeditorAPI !== undefined && this.getFCKEditor()[method]){
        return true;
    }
    else
    {
        var thisObj = this;
        // Wait a decent chunk of time to let the FCKEditor load itself.
        // Waiting less is a bit dangerous as the function may exist, but
        // other internal variables have not been set up yet.
        setTimeout(function(){thisObj[callbackMethod]();},1500);
        return false;
    }
};

/*
 * Returns an instance of the FCKEditor object
 */
WordProcessingGUIAdaptor.prototype.getFCKEditor = function()
{
	return FCKeditorAPI.GetInstance(this.getId() + "_wordprocessor");
};

WordProcessingGUIAdaptor.prototype.setConfig = function(configItem, newValue)
{
	oFCKeditor.Config[ configItem ] = newValue;
};

/**
 * Method sets value of flag indicating whether, or not,
 * the associated instance of FCKeditor has loaded completely.
 *
*/
WordProcessingGUIAdaptor.prototype.setFCKeditorLoadComplete = function(value)
{
    this.m_FCKeditorLoadComplete = value;
};

/**
 * Method returns value of flag indicating whether, or not, the
 * associated instance of FCKeditor has loaded completely.
 *
*/
WordProcessingGUIAdaptor.prototype.getFCKeditorLoadComplete = function()
{
    return this.m_FCKeditorLoadComplete;
};

// Callback functions invoked from the plugins on the
// wordprocessor.

/*
 * Invoke JSpellcheck
 */
WordProcessingGUIAdaptor.prototype.doSpellCheck = function()
{
	// process config to get the label for the JSpell dictionary:
    var ac = Services.getAppController();
    var appConfig = ac.m_config;
    var courtXPath = appConfig.getSpellCheckCourtXPath();
    var dictionaryLabel = appConfig.getSpellCheckDictionaryLabel();
    var actualLabel = dictionaryLabel;
    if (dictionaryLabel != null && courtXPath != null)
    {
        if (Services.hasValue(courtXPath))
        {
            var courtId = Services.getValue(courtXPath);
            if (courtId != null)
            {
                actualLabel = dictionaryLabel.replace("${court}", courtId);
            }
        }
    }
    if (actualLabel == null)
    {
        actualLabel = "English (US)"; // dont have a UK dictionary yet ...
    }

    this.checkEditableIFrame();
	parent.ActionSpellCheck(this.m_editableIframe.contentWindow, actualLabel);
};

/*
 * Invoke custom save action
 */
WordProcessingGUIAdaptor.prototype.doSave = function()
{
	this.m_saveAction();
};

/*
 * Invoke preview action
 */
WordProcessingGUIAdaptor.prototype.doPreview = function()
{
	this.m_previewAction();
};

/*
 * Invoke print action
 */
WordProcessingGUIAdaptor.prototype.doPrint = function()
{
	this.m_printAction();
};

/*
 * Add in "contenteditable=false" to all spans of class SUPSVAR
 */
WordProcessingGUIAdaptor.prototype.transformToDisplay = function(modelValue)
{
    if (modelValue == null)
    {
        return null;
    }

    var regexStr = "< *span *class *= *\"SUPSVAR([^\"]*)\"";
    var regex = new RegExp(regexStr,"g");
    return modelValue.replace(regex, "<span class=\"SUPSVAR$1\" contenteditable=\"false\"" );
};

/*
 * Strip all "contenteditable=false" string.
 */
WordProcessingGUIAdaptor.prototype.transformToModel = function(displayValue)
{
    if (displayValue == null)
    {
        return null;
    }

    var regexStr = " contenteditable=\"?false\"?";
    var regex = new RegExp(regexStr,"g");
    return displayValue.replace(regex, "");
};

/**
 * General function invoked by FCKeditor when loading of
 * an instance of the word processor is complete.
 *
*/
function FCKeditor_OnComplete( editorInstance )
{

    var wordProcessingGUIAdaptorEditorInstanceName = null;

    var instanceName = editorInstance.Name;

    // Retrieve array of word processing GUI adaptors
    // from FormController.
    var wordProcessingGUIAdaptors = FormController.getInstance().getWordProcessingGUIAdaptors();

    for(var i = 0, l = wordProcessingGUIAdaptors.length; i < l; i++)
    {
        wordProcessingGUIAdaptorEditorInstanceName = wordProcessingGUIAdaptors[i].getId() + "_wordprocessor";

        if(wordProcessingGUIAdaptorEditorInstanceName == instanceName)
        {
            wordProcessingGUIAdaptors[i].setFCKeditorLoadComplete(true);
            break;
        }
    }
}//==================================================================
//
// AutocompletionGUIAdaptor.js
//
// Class for implementing tabbed diaglouges for use in the
// framework
//
//==================================================================

/**
 * Base class for adapting DIV elements with a TabSelector class 
 * for use in the framework.
 *
 * @constructor
 * @private
 */
function AutocompletionGUIAdaptor() 
{
//	this.m_enteredValue = null;
	
	// Only used if component has strictValidation configured as true.
	// If strictValidation is enabled, then this value is true if the
	// entered text is one of the values in the dropdown list, or false
	// if it isn't.
	this.m_usingListEntry = true;
};

AutocompletionGUIAdaptor.m_logger = new Category("AutocompletionGUIAdaptor");
 
/**
 * AutocompletionGUIAdaptor is a sub class of HTMLElementGUIAdaptor
 */
AutocompletionGUIAdaptor.prototype = new HTMLElementGUIAdaptor();

/**
 * Add the required protocols to the AutocompletionGUIAdaptor
 */
GUIAdaptor._setUpProtocols('AutocompletionGUIAdaptor'); 
GUIAdaptor._addProtocol('AutocompletionGUIAdaptor', 'DataBindingProtocol');			// Supports binding to data model
GUIAdaptor._addProtocol('AutocompletionGUIAdaptor', 'ListSrcDataProtocol');			// Supports binding to data model
GUIAdaptor._addProtocol('AutocompletionGUIAdaptor', 'RecordsProtocol');				// Supports form dirty
GUIAdaptor._addProtocol('AutocompletionGUIAdaptor', 'EnablementProtocol');            // Supports enablement
GUIAdaptor._addProtocol('AutocompletionGUIAdaptor', 'FocusProtocol');                 // Supports focusing
GUIAdaptor._addProtocol('AutocompletionGUIAdaptor', 'FocusProtocolHTMLImpl');         // Include the default HTML implementation of focus
GUIAdaptor._addProtocol('AutocompletionGUIAdaptor', 'HelpProtocol');                  // Supports helptext
GUIAdaptor._addProtocol('AutocompletionGUIAdaptor', 'HelpProtocolHTMLImpl');          // Include the default HTML implementation of help
GUIAdaptor._addProtocol('AutocompletionGUIAdaptor', 'InitialiseProtocol');            // Supports custom initialisation
GUIAdaptor._addProtocol('AutocompletionGUIAdaptor', 'KeybindingProtocol');            // Supports keybinding
GUIAdaptor._addProtocol('AutocompletionGUIAdaptor', 'MandatoryProtocol');            // Supports mandatory
GUIAdaptor._addProtocol('AutocompletionGUIAdaptor', 'NameProtocol');                  // Supports naming of the element
GUIAdaptor._addProtocol('AutocompletionGUIAdaptor', 'ReadOnlyProtocol');            // Supports keybinding
GUIAdaptor._addProtocol('AutocompletionGUIAdaptor', 'TemporaryProtocol');             // Supports temporary behaviour
GUIAdaptor._addProtocol('AutocompletionGUIAdaptor', 'ValidationProtocol');            // Supports validation protocol
GUIAdaptor._addProtocol('AutocompletionGUIAdaptor', 'MouseWheelBindingProtocol');	  // Supports mouse wheel scrolling

/**
 * Set the constructor property after setting up protocols
 */
AutocompletionGUIAdaptor.prototype.constructor = AutocompletionGUIAdaptor;

/**
 * Maximum length of the text field
 *
 * @configuration
 * @merge-rule Most specific maxLength takes precedence
 */
AutocompletionGUIAdaptor.prototype.maxLength = null;


/**
 * Determines whether or not strict validation is enabled or not.
 * If no configuration is specified (neither true nor false assigned)
 * then this configuration item will default to false.
 *
 * @configuration
 * @type Boolean
 */
AutocompletionGUIAdaptor.prototype.strictValidation = null;

/**
 * Boolean flag recording whether, or not, user input validation
 * should include a check for whitespace only entry.
 *
 * @configuration
 * @type Boolean
*/
AutocompletionGUIAdaptor.prototype.m_validateWhitespaceOnlyEntry = null;

/**
 * String storing autocompletion element selection mode
 *
*/
AutocompletionGUIAdaptor.prototype.m_selectionMode = null;

/**
 * Flag indicating whether, or not, the single matching functionality
 * of the renderer/adaptor is enabled.
 *
 * @configuration
 * @type Boolean
 *
*/
AutocompletionGUIAdaptor.prototype.m_singleMatchingEnabled = null;


/**
 * Create a new AutocompletionGUIAdaptor
 *
 * @param e the checkbox input element to manage
 * @return the new AutocompletionGUIAdaptor
 * @type AutocompletionGUIAdaptor
 */
AutocompletionGUIAdaptor.create = function(element)
{
	if (AutocompletionGUIAdaptor.m_logger.isTrace())
	{
		AutocompletionGUIAdaptor.m_logger.trace("AutocompletionGUIAdaptor.create");
	}
	var a = new AutocompletionGUIAdaptor();
	a._initAutocompletionGUIAdaptor(element);
	return a;
}

/**
 * Initialises the instance (called from creation)
 *
 * @param element the element to manage
 */
AutocompletionGUIAdaptor.prototype._initAutocompletionGUIAdaptor = function(element)
{
	this.m_element = element;
	this.m_renderer = element.__renderer;
	element.__renderer = null;
	fc_assert(this.m_renderer != null, "AutocompletionGUIAdaptor._initAutocompletionGUIAdaptor(): the renderer is not defined!");
	this.m_renderer.m_guiAdaptor = this;
	this.m_renderer.m_dropDownField.m_guiAdaptor = this;

	// GUIAdaptor acts as the model for the AutoCompletionRenderer.
	this.m_renderer.setModel(this);
	
	var thisObj = this;
	this.m_renderer.addValueChangeListener(function(){thisObj._valueChangeCallback()});	
}


/**
 * Disposes of all resources (event handlers and references to renderer)
 */
AutocompletionGUIAdaptor.prototype._dispose = function()
{
	this.m_renderer.dispose();
	this.m_renderer = null;
}

/*
 * Override the ReadOnlyProtocol version to start and stop the appropriate
 * event handlers, before calling the parent version
 */
AutocompletionGUIAdaptor.prototype.setReadOnly = function(readOnly)
{
  // Start or stop listeners.
  if (readOnly)
  {
  	this.m_renderer.stopEventHandlers();
  }
  else
  {
  	this.m_renderer.startEventHandlers();
  }
  
  // Call parent method.
  return ReadOnlyProtocol.prototype.setReadOnly.call(this.m_renderer.m_guiAdaptor,readOnly);
}


AutocompletionGUIAdaptor.prototype.setMatchString = function(match)
{
	// Set the match string
	if(this.m_match != match)
	{
		this.m_match = match;
		
		this.m_matches = this._getMatchesFromDOM(this.m_match);
	}
	
	return (this.m_matches == null) ? 0 : this.m_matches.length;
}


AutocompletionGUIAdaptor.prototype.isKeyForMatchSubmissible = function(matchNumber)
{
	var key = this.getKeyForMatch(matchNumber);
	var isSubmissible = this.getAggregateState().isKeySubmissible(key);
	if (AutocompletionGUIAdaptor.m_logger.isTrace()) AutocompletionGUIAdaptor.m_logger.trace("AutocompletionGUIAdaptor.isKeyForMatchSubmissible() key=" + key + ", isSubmissible=" + isSubmissible);
	return isSubmissible;
}

AutocompletionGUIAdaptor.prototype.getKeyForMatch = function(matchNumber)
{
	var match = this.m_matches[matchNumber];
	var keyValueNode = null;
	if(match !=null)
	{
		keyValueNode = match.selectSingleNode(this.keyXPath);
	}
	return keyValueNode == null ? "" : XML.getNodeTextContent(keyValueNode);
}

AutocompletionGUIAdaptor.prototype.getMatch = function(matchNumber)
{
	var match = this.m_matches[matchNumber];
	var displayValueNode = null ;
	if (match != null)
	{
		displayValueNode = match.selectSingleNode(this.m_displayXPath);
	}
	return displayValueNode == null ? "" : XML.getNodeTextContent(displayValueNode);
}

AutocompletionGUIAdaptor.prototype._getMatchesFromDOM = function(matchString)
{
	//  With match string, each row XPath should be of the form
	//    /var/grid/type1[starts-with(translate(displayXPath, 'abcdefghijklmnopqrstuvwxyz', 'ABCDEFGHIJKLMNOPQRSTUVWXYZ'), 'matchString')]
	//  Without match string, each row XPath should be of the form - will select all rows.
	//    /var/grid/type1

    // Create a matchString to use with the predicate - must be upper 
    // case and have all current escaped characters doubly escaped 
    matchString = matchString.toUpperCase();
    
	var predicateMatchString = Services.xPathToConcat(matchString);
	
	// Create a xpath fragment which selects the nodes which match the
	// matching string.
	var matchDisplayXPath = 
		((matchString == null || matchString == "")
		? ""											// No match string so don't add predicate
		: "[starts-with(" + this._translateXPathValueToUpperCase(this.m_displayXPath) + ", " + predicateMatchString +")]");	// Select nodes which start with the match
		
	// Select nodes which start with the supplied matchString (ignoring case)
	return this._getRowNodesFromDOM(matchDisplayXPath);
}


AutocompletionGUIAdaptor.prototype._getExactMatchesFromDOM = function(matchString)
{
	// The xpath to select row nodes who's display value exactly matches
	// the supplied match string will be of the form:
	//   /var/grid/type1[translate(displayXPath, 'abcdefghijklmnopqrstuvwxyz', 'ABCDEFGHOIJKLMNOPQRSTUVWXYZ') = '<matchString>']
	
	// Create an xpath fragment which will select nodes who's display value
	// exactly matches (ignoring case!) the supplied string
	var upperMatchString = matchString.toUpperCase();
	var predicateMatchString = Services.xPathToConcat(upperMatchString);
	var matchDisplayXPath = "[" + this._translateXPathValueToUpperCase(this.m_displayXPath) + " = " + predicateMatchString + "]";
	
	// Select nodes which exactly match the supplied string (ignoring case)
	return this._getRowNodesFromDOM(matchDisplayXPath);
}


AutocompletionGUIAdaptor.prototype._getRowNodesFromDOM = function(predicate)
{
	// Select the rows resticted by the supplied predicate
	var xpath = this.getRowXPathWithSuffix(predicate);
	//alert("xpath is : " + xpath);
	var nodeArray = FormController.getInstance().getDataModel().getInternalDOM().selectNodes(xpath);
	
	// Sort nodeArray if required.
	if (nodeArray != null 
	    && nodeArray.length > 0 
	    && this.comparator != null ){	

		// IE returns a type of nodeset - need to turn into an array for sorting.
		var newArray = Array(nodeArray.length);
		for(var i = 0, l = nodeArray.length; i < l; i++)
		{
			newArray[i] = nodeArray[i];	
		}
	
		// Create locals for use in closure
		var displayXPath = this.m_displayXPath;
		var comparatorFn = this.comparator;
		newArray.sort( function(a,b) { 
									var aNode = a.selectSingleNode(displayXPath);
									var bNode = b.selectSingleNode(displayXPath);
									var aText = (aNode == null ? "" : XML.getNodeTextContent(aNode));
									var bText = (bNode == null ? "" : XML.getNodeTextContent(bNode));
									return comparatorFn(aText,bText);
								  } );
		nodeArray = newArray;
	}
	return nodeArray;	
}

AutocompletionGUIAdaptor.prototype._sortDisplayValues = function(a,b) 
{
return 1;
	var aNode = a.selectSingleNode(displayXPath);
	var bNode = b.selectSingleNode(displayXPath);
	var aText = XML.getNodeTextContent(aNode);
	var bText = XML.getNodeTextContent(bNode);
  	if (aText == bText) {
	  return 0;
	}
	if (aText > bText) {
	  return 1;
	}
	if (aText < bText) {
	  return -1;
	}
}

AutocompletionGUIAdaptor.prototype._getMatchesForKeyFromDOM = function(key)
{
	var predicateMatchString = Services.xPathToConcat(key);
	var matchKeyXPath = "[" + this.keyXPath + " = " + predicateMatchString + "]";
	
	return this._getRowNodesFromDOM(matchKeyXPath);
}

AutocompletionGUIAdaptor.prototype._valueChangeCallback = function()
{
	if(AutocompletionGUIAdaptor.m_logger.isDebug())
	{
		AutocompletionGUIAdaptor.m_logger.debug("AutocompletionGUIAdaptor._valueChangeCallback()");
	}
	this.update();
}

/**
 * Get the value from the view, ...???
 *
 * @return the value of the component, usually a string but it could be a complicated multi-value
 * @type ???
 */
AutocompletionGUIAdaptor.prototype._getValueFromView = function()
{
	var selectedMatch = this.m_renderer.getSelectedMatch();
	var matchNode = null;
	var keyNode = null;
	var ret = null;

	// Set flag to indicate that value entered is in the list of possible values.
	// This may be overridden later on.
	this.m_usingListEntry = true;
	
	if(null == selectedMatch)
	{
		var enteredValue = this.m_renderer.getTextFieldValue();
		
		// Attempt to match entered value
		var matches = this._getExactMatchesFromDOM(enteredValue);
		
		if(0 == matches.length)
		{
			// No matches found for entered value
			// Set flag to indicate that value entered was not in the list
			this.m_usingListEntry = false;
		}
		else
		{
			// Use the first match returned.
			matchNode = matches[0];
		}
	}
	else
	{
		matchNode = this.m_matches[selectedMatch];
	}
	
	if(matchNode == null)
	{
		// Get the value entered into the field and use this.
		ret = this.m_renderer.getTextFieldValue();
		
		if(this.m_displayXPath != this.keyXPath)
		{
		    // In some cases when an autocomplete field uses both key and display values
		    // a user may type in the key value directly. To accommodate this check whether
		    // input text matches key values using case insensitive match. If a match is
		    // found set return value to key value.
		
		    var exactKeyNode = this._getCaseInsensitiveExactMatchForKeyFromDOM(ret);
		    
		    if(exactKeyNode.length == 1)
		    {
		        
		        keyNode = exactKeyNode[0].selectSingleNode(this.keyXPath);
		        
		        if(null == keyNode)
		        {
		            ret = null;
		        }
		        else
		        {
		            ret = XML.getNodeTextContent(keyNode);
		            
		            // Check if return value matches value currently
		            // stored in adaptor
		            if(ret == this.m_value)
		            {
		                // In this case the model value will not be updated and
		                // the view value will not be refreshed. Therefore, we
		                // must refresh the display explicitly.
		                var displayNode = exactKeyNode[0].selectSingleNode(this.m_displayXPath);
		                
		                if(null != displayNode)
		                {
		                    var displayValue = XML.getNodeTextContent(displayNode);
		                    
		                    if(null != displayValue)
		                    {
		                        this.m_renderer.setValue(displayValue);
		                    }
		                    
		                }
		                
		            } // End of if(ret == this.m_value)
		            
		        }
		    }
		    
		}
	}
	else
	{
		// Get the key for the selected node
		
	    keyNode = matchNode.selectSingleNode(this.keyXPath);
		
		if (null == keyNode)
		{
			// No key - this is strictly an error, however just return null
			ret = null;
		}
		else
		{
			ret = XML.getNodeTextContent(keyNode);
		}
	}
	
	return ret;
/*
	// m_usingListEntry used to determine validity when performing strict validation
	// i.e. validation of value against keys in srcData
	this.m_usingListEntry = true;
	var dataValue = this._transformDisplayValue(this.m_enteredValue);
	if(null == dataValue)
	{
		// If no match, validation against the list is off, used the display value
		dataValue = this.m_enteredValue;
		this.m_usingListEntry = false;
	}
	return dataValue;
*/
}


AutocompletionGUIAdaptor.prototype._getRowsMatchingKey = function(keyValue)
{
	// xpath to get row corresponding to the key
	//  /ds/grid/type1[<keyXPath> = '<this.m_value>']
	var predicateMatchString = Services.xPathToConcat(keyValue);
	var matchKeyPredicate = "[" + this.keyXPath + " = " + predicateMatchString + "]";
	
	return this._getRowNodesFromDOM(matchKeyPredicate)		
}


AutocompletionGUIAdaptor.prototype.onBlur = function()
{
	this.update();
}


/**
 * Renders the visual state and event handlers for this
 * adaptor based on its current state
 */
AutocompletionGUIAdaptor.prototype.renderState = function()
{
	if(this.m_focusChanged)
	{
		// Reset this immediately so that we don't end up recursing through this again
		this.m_focusChanged = false;

		if(this.m_focus)
		{
			// Hightlight text on focus
			this.m_renderer.m_dropDownField._getInputFieldElement().select();
		}
		else
		{
			// Hide the drop down when the focus is lost
			this.m_renderer.m_dropDownField.hideDropDown();
		}
	}

	// Set up value
	if(this.m_valueChanged)
	{
		this._refreshDisplayedValue();
		this.m_valueChanged = false;
	}

	// Set up all states other than value - we only use the areChildrenSubmissible here for the
	// orange state because the mandatory and invalid states are supported on this adaptor type
	// and we don't want to overwrite the red border etc.
	this.m_renderer.render(
		!this.m_enabled,
		this.m_focus,
		this.m_mandatory,
		!this.getValid(),
		!this.getServerValid(),
		this.m_readOnly,
		!this.isActive(),
		this.getAggregateState().areChildrenSubmissible(),
		this.isServerValidationActive()
	);
}


AutocompletionGUIAdaptor.prototype._refreshDisplayedValue = function()
{
	// Value defaults to the key value
	var val = this.m_value;

	// Get rowNodes which match the current key value
	var rowNodes = this._getRowsMatchingKey(val);

	// Default the flag to no key found
	var keyFound = false;
	
	if(rowNodes.length != 0)
	{
		// Key found, so set the flag and get the display value for the key
		keyFound = true;
		
		var displayValueNode = rowNodes[0].selectSingleNode(this.m_displayXPath);
		
		if(null != displayValueNode)
		{
			// Get the display value
			val = XML.getNodeTextContent(displayValueNode);
		}
	}
	
	if(true == this.strictValidation)
	{
		// Configured for strict validation, so set the single matching flag
		// on the renderer
		this.m_renderer.setMatchSingle(keyFound);
	}
	
	// Write the value to the view
	this.m_renderer.setValue(val);
}


AutocompletionGUIAdaptor.CLICK_MODE = "onClickMode";
AutocompletionGUIAdaptor.DBL_CLICK_MODE = "onDblClickMode";

/*
 * No custom configuration for this component, but does registger
 * callbacks on page elements at this point.
 */
AutocompletionGUIAdaptor.prototype._configure = function(cs)
{	
	// Run through configuration specific to this element
	for(var i = 0, l = cs.length; i < l; i++)
	{
		var c = cs[i];
		if(c.displayXPath && this.m_displayXPath == null)
		{
			this.m_displayXPath = XPathUtils.removeLeadingSlash(c.displayXPath);
		}
		
		// If strict validation specified in this configuration and we haven't
		// previously set strict validation
		if(c.strictValidation && null == this.strictValidation)
		{
			// Set strict validation flag on this adaptor
			this.strictValidation = c.strictValidation;
			
			// If strict validation was enabled, then assign the validate
			// function on this adaptor
			if(true == this.strictValidation)
			{
				this.validate = this._strictValidate;
			}
		}

		if(null != c.selectionMode && this.m_selectionMode == null) 
		{
			this.m_selectionMode = c.selectionMode;
	    }
		
		if(null != cs[i].sortMode)
		{
			if (cs[i].sortMode == "numerical")
			{
				this.comparator = Comparators.numericalSort;
			}
			else if (cs[i].sortMode == "alphabetical")
			{
				this.comparator = Comparators.alphabeticalSort;
			}
			else if (cs[i].sortMode == "alphabeticalLowToHigh")
			{
				this.comparator = Comparators.alphabeticalSortLowToHigh;
			}
			else if (cs[i].sortMode == "alphabeticalLocaleCompare")
			{
				this.comparator = Comparators.alphabeticalLocaleCompareSort;
			}
			else if (cs[i].sortMode == "alphanumerical")
			{
				this.comparator = Comparators.alphanumerical;
			}
			else if (cs[i].sortMode == "alphabeticalCaseInsensitive")
			{
				this.comparator = Comparators.alphabeticalCaseInsensitiveSort ;
			}
			else
			{
				this.comparator = null;	
			}
		}
		if(null != c.maxLength && this.maxLength == null)
		{
			// Override this adaptor maxLength configuration
			this.maxLength = c.maxLength;
			
			// Provide default validation rule based on maxLength
			this.validate = this._validateMaxLength;
			
			// Set the text fields maximum length to correspond to the
			// maximum allowable length
			this.m_renderer.getInputElement().maxLength = this.maxLength;
		}
		
		// Check for single matching enablement
		if(null != c.singleMatchingEnabled && this.m_singleMatchingEnabled == null)
		{
		    this.m_singleMatchingEnabled = c.singleMatchingEnabled;
		}
		
		// Check for whitespace only entry validation
		if(FormController.getValidateWhitespaceOnlyEntryActive())
		{
		    if(null != c.validateWhitespaceOnlyEntry && this.m_validateWhitespaceOnlyEntry == null)
		    {
		        this.m_validateWhitespaceOnlyEntry = c.validateWhitespaceOnlyEntry;
		    }
		}
		
	}
	
	// Check state of configuration 
	this._checkConfiguration();
	
	this.m_renderer.setSelectionMode(this.m_selectionMode);
	
	// Append displayValue xpaths to set of xpaths which trigger a refresh of source data
	var displayXPaths = this.getRowXPathArrayWithSuffix()
	this.srcDataOn = (null == this.srcDataOn) ? displayXPaths : this.srcDataOn.concat(displayXPaths);
	
	// If required set up adaptor to run strict validation if source data changes
	if(true == this.strictValidation)
	{
	    if(null != this.validateOn)
	    {
	        this.validateOn = this.validateOn.concat(this.srcDataOn);
	    }
	    else
	    {
	        this.validateOn = this.srcDataOn;
	    }
	}
	
	// Check single matching enablement value
	if(this.m_singleMatchingEnabled != false)
	{
	    this.m_singleMatchingEnabled = true;
	}
	
	// Configure whitespace only entry validation if required.
	if((this.strictValidation != true) &&
	   FormController.getValidateWhitespaceOnlyEntryActive() &&
	   this.m_validateWhitespaceOnlyEntry != false)
	{
	    if(this.maxLength != null)
	    {
	        // Maxlength validation in operation so add whitespace validation
	        // as additional configuration object
	        this._addWhitespaceOnlyEntryValidation();
	    }
	    else
	    {
	        // Add whitespace validation as default validation
	        this.validate = this._validateWhitespaceOnlyEntry;
	    }
	}
	
}

AutocompletionGUIAdaptor.prototype._checkConfiguration = function()
{
	// srcData is mandatory
	if(null == this.srcData)
	{
		throw new ConfigurationException("srcData must be specified for adaptor: " + this.getId());
	}
	// keyXPath is mandatory
	if(null == this.keyXPath)
	{
		throw new ConfigurationException("keyXPath must be specified for adaptor: " + this.getId());
	}
	// D829 - Invalid to have both maximum length and strict validation configured
	if(this.maxLength != null && true == this.strictValidation)
	{
		throw new ConfigurationException("Cannot have both 'maxLength' and 'strictValidation' configured for adaptor: " + this.getId());
	}

	// Determine selection mode
	if(null != this.m_selectionMode)
	{
	    if(this.m_selectionMode != AutocompletionGUIAdaptor.CLICK_MODE && 
		   		this.m_selectionMode != AutocompletionGUIAdaptor.DBL_CLICK_MODE)
		{
		    if(AutocompletionGUIAdaptor.m_logger.isError())
			{
	            AutocompletionGUIAdaptor.m_logger.error("AutocompletionGUIAdaptor._configure() unknown selectionMode in configuration for adaptor id=" + this.getId() + ", reverting to default of AutocompletionGUIAdaptor.CLICK_MODE");
	        }
			
			this.m_selectionMode = AutocompletionGUIAdaptor.CLICK_MODE;
		}
		
	}
	else
	{
	    this.m_selectionMode = AutocompletionGUIAdaptor.CLICK_MODE;
	}

	// row is optionaly configured and derived from srcData if null
	this.m_absoluteRowXPath = this.rowXPath ? this.srcData + '/' + this.rowXPath : this.srcData;
	
	// displayXPath is optionally configured and derived from key if null
	this.m_displayXPath = this.m_displayXPath != null ? this.m_displayXPath : this.keyXPath;
	this.m_absoluteDisplayXPath = this.m_absoluteRowXPath + '/' + this.m_displayXPath;

	this.srcDataOn[this.srcDataOn.length] = this.m_absoluteDisplayXPath;
}


AutocompletionGUIAdaptor.prototype._strictValidate = function(modelValue)
{
	if(this.m_reevaluateValidity)
	{
		var enteredValue = this.m_value;

		// Attempt to match entered value
//		var matches = this._getExactMatchesFromDOM(enteredValue);
		var matches = this._getMatchesForKeyFromDOM(enteredValue);
		this.m_usingListEntry = true;
		
		if(0 == matches.length)
		{
			// No matches found for entered value
			// Set flag to indicate that value entered was not in the list
			this.m_usingListEntry = false;
		}
		
		this.m_reevaluateValidity = false;
	}

	if(this.m_usingListEntry)
	{
		return null;
	}
	else
	{
		var ec = ErrorCode.getErrorCode('InvalidFieldLength');
		ec.m_message = "Field value not in source data";
		return ec;
	}
}


AutocompletionGUIAdaptor.prototype.retrieve = function(event)
{
	this.m_reevaluateValidity = true;

	var db = this.dataBinding;
	if(null != db)
	{
		var mV = FormController.getInstance().getDataModel().getValue(db);
		var dV = this.invokeTransformToDisplay(mV);
		
		var valueChanged = this._setValue(dV);

		// If the value changed during this repaint cycle keep track of it.
		if(!this.m_valueChanged) this.m_valueChanged = valueChanged;

		if(valueChanged)
		{
			// this is to solve D255 because getValueFromView checks the selected match which
			// isn't overwritten by setting the internal value in m_value
			this.m_renderer.resetSelectedMatch();
			
			// Trigger a StateChangeEvent if the value has changed
			var e = StateChangeEvent.create(StateChangeEvent.VALUE_TYPE, dV, this);
			this.changeAdaptorState(e);
		}
		return valueChanged;
	}
	else
	{
		throw new DataBindingError("DataBindingProtocol.retrieve(), no dataBinding specified for adaptor id = " + this.getId());
	}
}


AutocompletionGUIAdaptor.prototype.retrieveSrcData = function(event)
{
	if(AutocompletionGUIAdaptor.m_logger.isInfo())
	{
		AutocompletionGUIAdaptor.m_logger.info(this.getId() + ":SelectElementGUIAdaptor.retrieveSrcData()");
	}
	
	// Trigger a StateChangeEvent if the srcData has changed
	// ToDo: this should take into account deltas
	var e = StateChangeEvent.create(StateChangeEvent.SRCDATA_TYPE, null, this);
	this.changeAdaptorState(e);
	
	// Ensure that matches are re-evaluated.
	this.m_match = null;
	
	// Notify the renderer that the data has changed.
	this.m_renderer.dataUpdate();

	// Cause displayed value to be updated during renderState
	this.m_valueChanged = true;
	
	// Need to re-evaluate our validity state in strictValidationMode
	this.m_reevaluateValidity = true;

	// State has changed, so we need to be refreshed so return true.
	return true;
}


/**
 * Get the element to set focus on. For the autocomplete this
 * is the input text field
 */
AutocompletionGUIAdaptor.prototype.getFocusElement = function()
{
	return this.m_renderer.getInputElement();
}

/**
 * Method looks for case insensitive match for key.
 *
*/
AutocompletionGUIAdaptor.prototype._getCaseInsensitiveExactMatchForKeyFromDOM = function(keyMatch)
{
    var upperCaseKeyMatch = keyMatch.toUpperCase();
    
    var predicateKeyMatchString = Services.xPathToConcat(upperCaseKeyMatch);
    
    var matchKeyXPath = "[" + 
                        this._translateXPathValueToUpperCase(this.keyXPath) + 
                        " = " +
                        predicateKeyMatchString +
                        "]"; 
                          
    return this._getRowNodesFromDOM( matchKeyXPath );
}

AutocompletionGUIAdaptor.prototype._translateXPathValueToUpperCase = function(xpath)
{
	return "translate(" + xpath + ", 'abcdefghijklmnopqrstuvwxyz', 'ABCDEFGHIJKLMNOPQRSTUVWXYZ')";
}

/**
 * Override for the Validation protocol's default maximum length validation.
 * The default maximum length validation checks the model value. This can
 * cause problems for an autocomplete because the model/key value can be
 * different from the display value.
 *
 * @return Error code if maximum length exceeded otherwise null
 * @private
 */
AutocompletionGUIAdaptor.prototype._validateMaxLength = function()
{
	var ec = null;
	var value = this._getValue();

	// Get any matches for the entered value
	var matches = this._getMatchesForKeyFromDOM(value);
	
	// Only check maximum length if entered value does not match a key
	if(0 == matches.length && value != null && value.length > this.maxLength)
	{
		ec = ErrorCode.getErrorCode('FW_TEXTINPUT_InvalidFieldLength');
		ec.m_message = ec.getMessage() + this.maxLength;
	}
	
	return ec;
}

/**
 * Method called when the mouse wheel is 'rotated'.
 *
 * @param evt the event structure.
 */
AutocompletionGUIAdaptor.prototype.handleScrollMouse = function(evt)
{
    var propagateEvent = true;
    
	// Only handle mouse wheel rotate if drop down is showing
	if(this.m_renderer.m_dropDownField.isRaised())
	{		
		if(evt.wheelDelta > 0)
		{
			// Scroll up, move highlighting up one row in drop down
			this.m_renderer._selectPreviousMatch();
		}
		else
		{
			// Scroll down, move highlighting down one row in drop down		
			this.m_renderer._selectNextMatch();
		}
		
		// Prevent propagation of event to prevent scroll
		// being passed to any outer scrolling div
		propagateEvent = false;
	}
	
	return propagateEvent;
}

/**
 * Get the number of rows in the source data
 *
 * @return the number of rows in the source data
 */
AutocompletionGUIAdaptor.prototype.getSrcDataRowCount = function()
{
	return Services.countNodes(this.srcData + "/" + this.rowXPath);
}
