ButtonInputElementGUIAdaptor.prototype._dispose = function()
{
    if(null != this.m_clickEventHandler)
    {
	    // Remove the click event handler
	    SUPSEvent.removeEventHandlerKey(this.m_clickEventHandler);
	    this.m_clickEventHandler = null;
	}
	
	this.actionBinding = null;
}


/**
 * Configure the GUIAdaptor
 *
 * @param cs an Array of configuration objects ordered with
 *   most specific items first.
 */
ButtonInputElementGUIAdaptor.prototype._configure = function(cs)
{
	var actionBusinessLifeCycle = new ButtonActionBusinessLifeCycle();
	actionBusinessLifeCycle.initialise(this);
	this.addBusinessLifeCycle(actionBusinessLifeCycle);

	// Additional event bindings for button
	var actionEventBinding = null;

	// Run through configuration specific to this element
	for(var i = 0, l = cs.length; i < l; i++)
	{
		var c = cs[i];
		
		// Count number of action bindings associated
		// with button
		if(null != c.actionBinding)
		{
		    this.m_noOfActionBindings++;
		} 
		
		// Get the event configuration objects for RAISE
		if(c.additionalBindings && null == actionEventBinding)
		{
			actionBusinessLifeCycle.configure(c.additionalBindings);

			actionEventBinding = actionBusinessLifeCycle.getEventBinding();			
		}
		
		// Check for flag indicating active state when handling event
		if(null != c.inactiveWhilstHandlingEvent && null == this.m_inactiveWhilstHandlingEvent)
		{
		    this.m_inactiveWhilstHandlingEvent = c.inactiveWhilstHandlingEvent;
		}
	}
	
	if(this.m_noOfActionBindings > 0)
	{
	    // As the button has associated event bindings add "onclick" handler
	    var thisObj = this;
	    this.m_clickEventHandler = SUPSEvent.addEventHandler( this.m_element,
	                                                          "click",
	                                                          function(evt){ return thisObj._handleClick(); } );
	}
	
	// Define flag indicating active state when handling event
	if(this.m_inactiveWhilstHandlingEvent != false)
	{
	    this.m_inactiveWhilstHandlingEvent = true;
	}

	// Start addtional event bindings
	if(null != actionEventBinding) actionEventBinding.start();
}


/**
 * Handle a click event on the button.
 *
 * Dispatches an event to cause the button's own actionBinding to be invoked.
 * Queuing the event in this way rather than invoking the actionBinding
 * immediately allows other components to update the DataModel before
 * the button action is invoked.
 *
 * @private
 */
ButtonInputElementGUIAdaptor.prototype._handleClick = function()
{                                                
	Services.dispatchEvent(this.getId(), ButtonInputElementGUIAdaptor.EVENT_ACTION, null);
}


/**
 * Invoke the button's action bindings
 *
 * The buttons actionBinding's are usually invoked by dispatching an
 * "action" event to the button via the Services.dispatchEvent interface.
 *
 * @private
 */
ButtonInputElementGUIAdaptor.prototype._invokeActionBindings = function()
{
	if (this.getEnabled()) 
	{
		// Get configurations
		var cs = this.getConfigs();
		
		// On click invoke all the actionBindings
		for(var i = 0, l = cs.length - 1; i < l; i++)
		{
			if(null != cs[i].actionBinding)
			{
				cs[i].actionBinding.call(this);
			}
		}
	}
}


/**
 * Render the button appropriately to reflect it's current state
 *
 */
ButtonInputElementGUIAdaptor.prototype.renderState = function()
{
	if((this.supportsProtocol("EnablementProtocol") && !this.m_enabled)
	    || (this.supportsProtocol("ActiveProtocol") && !this.isActive()))
	{
	  this.m_element.disabled = true;
	}
	else
	{
	  this.m_element.disabled = false;
	}

	//this.m_viewClass

	var css = this.m_viewClass
	if(!this.getAggregateState().isSubmissible())
	{
		css = css + " " + ButtonInputElementGUIAdaptor.BUTTON_NOT_SUBMISSIBLE_CSS_CLASS;
	}
	this.m_element.className = css;
	
	/*
	 * Fix for release 2 - stops buttons included on form but with no config
	 * having their labels blown away. Does mean that dynamically you can set 
	 * button to have an empty label but not a null label (which would be rendered
	 * badly in IE in any case
	 */
	if(null != this.m_label)
	{
		this.m_element.value = this.m_label;
	}
	this.m_labelChanged = false;
}

/**
 * Method sets button to active state providing adaptor is not in
 * list of adaptors deactivated owing to the raising of a popup.
 *
*/
ButtonInputElementGUIAdaptor.prototype.reactivate = function()
{
    var reactivate = true;
    
    // Before reactivating adaptor check that adaptor has not been
    // deactivated owing to raising of popup also. If deactivated by popup
    // do not reactivate.
    var deactivatedButtonAdaptors = AbstractPopupGUIAdaptor.m_buttonsDeactivatedWhilstHandlingEventOnRaise;
    
    if(null != deactivatedButtonAdaptors)
    {
        var deactivatedAdaptor = null;
        
        for(var i = 0, l = deactivatedButtonAdaptors.length; i < l; i++)
        {
            deactivatedAdaptor = deactivatedButtonAdaptors[i];
            
            if(this.getId() == deactivatedAdaptor.getId())
            {
                reactivate = false;
                break;
            }
        }
        
    }
    
    if(reactivate)
    {
        this.setActive(true);       
        this.renderState();
    }
    
    if(this.m_inactiveWhilstHandlingEvent)
    {
        // Reset flag indicating that button action bindings are executing
        this.m_deactivatedWhilstHandlingEvent = false;
    }
}

/**
 * Method returns a boolean value indicating whether, or not, button is
 * currently deactivated owing to its action bindings being executed.
 *
 * @returns Boolean value set to "true" if action bindings executing, otherwise "false"
 *
*/
ButtonInputElementGUIAdaptor.prototype.isDeactivatedWhilstHandlingEvent = function()
{
    return this.m_deactivatedWhilstHandlingEvent;
}

/**
 * Method sets value of boolean flag recording whether, or not, button is
 * currently deactivated owing to its action binding being executed.
 *
 * @param deactivated Boolean variable defining new value of flag
 *
*/
ButtonInputElementGUIAdaptor.prototype.setDeactivatedWhilstHandlingEvent = function( deactivated )
{
    this.m_deactivatedWhilstHandlingEvent = deactivated;
}


/**
 * BusinessLifeCycle to activate a buttons action
 */
function ButtonActionBusinessLifeCycle() {}

// ButtonActionBusinessLifeCycle is a sub class of BusinessLifeCycle
ButtonActionBusinessLifeCycle.prototype = new BusinessLifeCycle();
ButtonActionBusinessLifeCycle.prototype.constructor = ButtonActionBusinessLifeCycle;


/**
 * Get the name of the BusinessLifeCycle.
 *
 * @return the name of the BusinessLifeCycle
 * @type String
 */
ButtonActionBusinessLifeCycle.prototype.getName = function()
{
	return BusinessLifeCycleEvents.EVENT_ACTION;
}


/**
 * Invoke the business logic associated with this BusinessLifeCycle.
 * In this case this cause the button's actionBinding function to be invoked
 *
 * @param e the BusinessLifeCycleEvent
 */
ButtonActionBusinessLifeCycle.prototype.invokeBusinessLifeCycle = function(e)
{
	var buttonId = e.getComponentId();
	
	var button = FormController.getInstance().getAdaptorById(buttonId);
	
	if(null != button)
	{
	    if(button.m_noOfActionBindings > 0 && 
	       button.m_inactiveWhilstHandlingEvent && 
	       button.isActive())
	    {
	        button.setActive(false);
	        button.renderState();
	        button.setDeactivatedWhilstHandlingEvent(true);
	    }
	    
	    try
	    {
		    button._invokeActionBindings();
		}
		catch(ex)
		{
		    if(button.m_noOfActionBindings > 0 && 
		       button.m_inactiveWhilstHandlingEvent)
		    {
		        button.reactivate();
		    }
		    
		    throw ex;
		}
		
		if(button.m_noOfActionBindings > 0 &&
		   button.m_inactiveWhilstHandlingEvent)
		{
		    button.reactivate();
		}
		
	}
}


//==================================================================
//
// CheckboxInputElementGUIAdaptor.js
//
// Class for adapting a text style input element for use in the
// framework
//
//==================================================================


/**
 * Base class for adapting html input elements for use in the
 * framework.
 *
 * @param e the input element to manage
 * @constructor
 * @private
 */
function CheckboxInputElementGUIAdaptor()
{
}

CheckboxInputElementGUIAdaptor.m_logger = new Category("CheckboxInputElementGUIAdaptor");
CheckboxInputElementGUIAdaptor.INVALID_CSS_CLASS = 'invalid';
CheckboxInputElementGUIAdaptor.READONLY_CSS_CLASS = 'readOnly';

/**
 * CheckboxInputElementGUIAdaptor is a sub class of HTMLElementGUIAdaptor
 */
CheckboxInputElementGUIAdaptor.prototype = new HTMLElementGUIAdaptor();

/**
 * Add the required protocols to the CheckboxInputElementGUIAdaptor
 * Note: Does not use FieldElement etc. as did not want to inherit mandatory protocol
 */
GUIAdaptor._setUpProtocols('CheckboxInputElementGUIAdaptor'); 
GUIAdaptor._addProtocol('CheckboxInputElementGUIAdaptor', 'DataBindingProtocol');			// Supports binding to data model
GUIAdaptor._addProtocol('CheckboxInputElementGUIAdaptor', 'EnablementProtocol');            // Supports enablement
GUIAdaptor._addProtocol('CheckboxInputElementGUIAdaptor', 'FocusProtocol');                 // Supports focusing
GUIAdaptor._addProtocol('CheckboxInputElementGUIAdaptor', 'FocusProtocolHTMLImpl');         // Include the default HTML implementation of focus
GUIAdaptor._addProtocol('CheckboxInputElementGUIAdaptor', 'HelpProtocol');                  // Supports helptext
GUIAdaptor._addProtocol('CheckboxInputElementGUIAdaptor', 'HelpProtocolHTMLImpl');          // Include the default HTML implementation of help
GUIAdaptor._addProtocol('CheckboxInputElementGUIAdaptor', 'InitialiseProtocol');            // Supports custom initialisation
GUIAdaptor._addProtocol('CheckboxInputElementGUIAdaptor', 'KeybindingProtocol');            // Supports keybinding
GUIAdaptor._addProtocol('CheckboxInputElementGUIAdaptor', 'NameProtocol');                  // Supports naming of the element
GUIAdaptor._addProtocol('CheckboxInputElementGUIAdaptor', 'TemporaryProtocol');             // Supports temporary behaviour
GUIAdaptor._addProtocol('CheckboxInputElementGUIAdaptor', 'ValidationProtocol');            // Supports validation protocol
GUIAdaptor._addProtocol('CheckboxInputElementGUIAdaptor', 'ReadOnlyProtocol');            // Supports readonly protocol

CheckboxInputElementGUIAdaptor.prototype.constructor = CheckboxInputElementGUIAdaptor;

CheckboxInputElementGUIAdaptor.prototype.modelValue = {checked: "true", unchecked: "false"};

/**
 * Create a new CheckboxInputElementGUIAdaptor
 *
 * @param e the checkbox input element to manage
 * @return the new CheckboxInputElementGUIAdaptor
 * @type CheckboxInputElementGUIAdaptor
 */
CheckboxInputElementGUIAdaptor.create = function(e)
{
	if (CheckboxInputElementGUIAdaptor.m_logger.isTrace()) CheckboxInputElementGUIAdaptor.m_logger.trace("CheckboxInputElementGUIAdaptor.create");

	var a = new CheckboxInputElementGUIAdaptor();
	a._initCheckboxInputElementGUIAdaptor(e);
	return a;
}


CheckboxInputElementGUIAdaptor.prototype.keyBindings = 
[
	{	key: Key.CHAR_Y,
		action: function()
		{
			if(!this.getReadOnly())
			{
				Services.setValue(this.dataBinding, this.modelValue.checked );
			}
		}
	},
	{	key: Key.CHAR_N,
		action: function()
		{
			if(!this.getReadOnly())
			{
				Services.setValue(this.dataBinding, this.modelValue.unchecked);
			}
		}
	},
	{	key: Key.CHAR_y,
		action: function()
		{
			if(!this.getReadOnly())
			{
				Services.setValue(this.dataBinding, this.modelValue.checked);
			}
		}
	},
	{	key: Key.CHAR_n,
		action: function()
		{
			if(!this.getReadOnly())
			{
				Services.setValue(this.dataBinding, this.modelValue.unchecked);
			}
		}
	}
];

/**
 * Initialise CheckboxInputElementGUIAdaptor
 *
 * @param e the checkbox input element to manage
 */
CheckboxInputElementGUIAdaptor.prototype._initCheckboxInputElementGUIAdaptor = function(e)
{
	if (CheckboxInputElementGUIAdaptor.m_logger.isTrace()) CheckboxInputElementGUIAdaptor.m_logger.trace("CheckboxInputElementGUIAdaptor._initCheckboxInputElementGUIAdaptor");
	
	this.m_element = e;
	this._registerEventHandlers();
}

CheckboxInputElementGUIAdaptor.prototype._registerEventHandlers = function()
{
	var a = this;
	this.m_evtHandler = SUPSEvent.addEventHandler(this.m_element, "click", function(evt) { return a._handleClick(evt); });
}



CheckboxInputElementGUIAdaptor.prototype._dispose = function()
{
	SUPSEvent.removeEventHandlerKey(this.m_evtHandler);
	this.m_evtHandler = null;
}


/**
 * Get the value from the view, i.e. the HTML element. Default behaviour is to get the
 * value property from the HTML element, but this will need to be overridden for most adaptors
 *
 * @return the value of the component, usually a string but it could be a complicated multi-value
 * @type string
 */
CheckboxInputElementGUIAdaptor.prototype._getValueFromView = function()
{
	if(CheckboxInputElementGUIAdaptor.m_logger.isTrace()) CheckboxInputElementGUIAdaptor.m_logger.trace(this.getId() + ":CheckboxInputElementGUIAdaptor._getValueFromView()");
	if(null == this.m_element)
	{
		throw new GUIAdaptorError("CheckboxInputElementGUIAdaptor._getValueFromView(), this.m_element == null");
	}
	return this.m_element.checked;
}

/*
 * Called when mouse click on checkbox to set value
 */
CheckboxInputElementGUIAdaptor.prototype._handleClick = function(evt)
{
	if (CheckboxInputElementGUIAdaptor.m_logger.isTrace()) CheckboxInputElementGUIAdaptor.m_logger.trace("CheckboxInputElementGUIAdaptor._handleClick");
	var propagateEvent = true;
	
	if(this.getReadOnly())
	{
		// Checkbox is read only, so prevent default checkbox action
	
		// If IE the use the global event
	    evt = (null != evt) ? evt : window.event;
	    
		SUPSEvent.preventDefault(evt);
		propagateEvent = false;
	}
	else
	{
		this.update();
	}
	
	return propagateEvent;
}

/**
 * Configure the GUIAdaptor
 *
 * @param cs an Array of configuration objects ordered with
 *   most specific items first.
 * @throws ConfigurationException when modelValue missing properties or validation function defined
 */
CheckboxInputElementGUIAdaptor.prototype._configure = function(cs)
{
	if (CheckboxInputElementGUIAdaptor.m_logger.isTrace()) CheckboxInputElementGUIAdaptor.m_logger.trace("CheckboxInputElementGUIAdaptor.init");
	
	// Run through configuration specific to this element (no point checking the last)
	for(var i = 0, l = cs.length - 1; i < l; i++)
	{
		/*
		 * Process the modelValue object which determines how the 
		 */
		if(null != cs[i].modelValue)
		{
			// Set the modelValue property
			this.modelValue = cs[i].modelValue;
		
			// Ensure that checked and unchecked are specified
			// fc_assert(null != this.modelValue.checked && null != this.modelValue.unchecked);
			if(null == this.modelValue.checked || null == this.modelValue.unchecked)
			{
				throw new ConfigurationException("Must define checked and unchecked for modelValue");
			}
		}
		if(null != cs[i].transformToModel)
		{
			// if we find another transformToModel function throw an assert cos we don't support it
			throw new ConfigurationException("Cannot define transformToModel function for checkbox");
		}
		if(null != cs[i].transformToDisplay)
		{
			// if we find another transformToDisplay function throw an assert cos we don't support it
			throw new ConfigurationException("Cannot define transformToDisplay function for checkbox");
		}				
	}
}



/*
 * Always returns true as checkbox always has a validate function
 * @returns true
 */
CheckboxInputElementGUIAdaptor.prototype.hasValidate = function()
{
	return true;
}


/*
 * Validates that model matches configured checkbox options
 * @param val Value stored in datamodel
 * @returns An error code if model validation fails
 */
CheckboxInputElementGUIAdaptor.prototype.validate = function()
{
	var val = FormController.getInstance().getDataModel().getValue(this.dataBinding);
	if (CheckboxInputElementGUIAdaptor.m_logger.isTrace()) CheckboxInputElementGUIAdaptor.m_logger.trace("CheckboxInputElementGUIAdaptor._validateModelValue");
	
	// Checking that the model value matches the modelValue as configured
	var ec = null;
	
	if(val != this.modelValue.checked && val != this.modelValue.unchecked)
	{
		/*
		 * The model and the configured allowable values do not match, this
		 * indicates an issue with the configuration code or the server side services
		 * rather than a data input error
		 * Note: Method of throwing error not ideal but will be refactored when ErrorCode allows
		 */
		ec = ErrorCode.getErrorCode('FW_CHECKBOX_InvalidFieldLength');
	}
	return ec;
}

CheckboxInputElementGUIAdaptor.prototype.isNoneEmptyValue = function(mV)
{
     //return !(null == mV || "" == mV); // Can't use this a (""==false) is true
     return !(null == mV);
}

/*
 * transforms the true or false value of the checkbox into the model value
 * specified by the modelValue object
 */
CheckboxInputElementGUIAdaptor.prototype.transformToModel = function(dV)
{
	if (CheckboxInputElementGUIAdaptor.m_logger.isTrace()) CheckboxInputElementGUIAdaptor.m_logger.trace("CheckboxInputElementGUIAdaptor._transformToModel");

	if(dV == true)
	{
		return this.modelValue.checked;
	}
	else
	{
		return this.modelValue.unchecked;
	}	
}

/*
 * transforms the value held in the model to true or false as specified by 
 * the modelValue object for use in checkbox HTML element
 */
CheckboxInputElementGUIAdaptor.prototype.transformToDisplay = function(mV)
{
	if (CheckboxInputElementGUIAdaptor.m_logger.isTrace()) CheckboxInputElementGUIAdaptor.m_logger.trace("CheckboxInputElementGUIAdaptor._transformToDisplay");
    
    if (mV == null)
    {
        return; // return a null if null held in datamodel so both
                // m_value and model value are in sync
    }

	if(mV == this.modelValue.checked)
	{
		return true;
	}
	else
	{
		return false;
	}	
}


CheckboxInputElementGUIAdaptor.prototype.renderState = function()
{
	var disabled = false;
	var className = null;

	if(this.m_valueChanged)
	{
		this.m_element.checked = this.m_value;
		
		// Reset valueChanged flag so we don't refresh unnecessarily
		this.m_valueChanged = false;
	}
	
	if((this.supportsProtocol("EnablementProtocol") && !this.m_enabled)
	    || (this.supportsProtocol("ActiveProtocol") && !this.isActive()))
	{
		disabled = true;
	}
	else
	{
		if(this.hasValue())
		{
			if(!this.getValid())
			{
				if(!this.getServerValid())
				{
					// If server validation in process colour text area orange. If
					// server invalid and process complete colour text area red.
					if(this.isServerValidationActive())
					{
						className += " notSubmissible";
					}
					else
					{
						className += " " + CheckboxInputElementGUIAdaptor.INVALID_CSS_CLASS;
					}
				}
				else
				{
					className += " " + CheckboxInputElementGUIAdaptor.INVALID_CSS_CLASS;
				}
			}
		}
		
		if(this.m_readOnly)
		{
			className += " " + CheckboxInputElementGUIAdaptor.READONLY_CSS_CLASS;
			/*
			 * D1015 - Logic on for another adaptor made a checkbox read only.
			 * Checkbox was clicked straight after the other adaptor generating
			 * a tabbing event. By the time the Tabbing Manager had processed
			 * this event the checkbox had changed state to disabled. Causing
			 * the Tabbing Manager and browser to get themselves tied in a knot.
			 * When checkbox is read only prevent the default action in the
			 * _handleClick method.
			disabled = true;
			*/
		}
	}
	
	this.m_element.disabled = disabled;
	this.m_element.className = className;
}
//==================================================================
//
// SelectElementGUIAdaptor.js
//
// Class for adapting a select style dropdown element for use in the
// framework. Select elements can either be configured to set their
// options from somewhere specified in the data model using xpaths, or
// can be hardcoded into the HTML. A default validate method is supplied
// that checks if the value in the datamodel binding matches a value
// in the options list.
//
//==================================================================


/**
 * Constructor for the Select GUI adaptor. SelectElementGUIAdaptor is a 
 * sub class of HTMLElementGUIAdaptor. The following protocols are implemented 
 * by the select adaptor: DataBindingProtocol, EnablementProtocol, FocusProtocol, 
 * HelpProtocol, HelpProtocolHTMLImpl, InitialiseProtocol, KeybindingProtocol, 
 * MandatoryProtocol, NameProtocol, ReadOnlyProtocol, 
 * TemporaryProtocol, ValidationProtocol.
 *
 * @constructor
 * @private
 */
function SelectElementGUIAdaptor()
{
}

SelectElementGUIAdaptor.m_logger = new Category("SelectElementGUIAdaptor");

/**
 * SelectElementGUIAdaptor is a sub class of HTMLElementGUIAdaptor (which adds
 * no protocols).
 */
SelectElementGUIAdaptor.prototype = new HTMLElementGUIAdaptor();
SelectElementGUIAdaptor.prototype.constructor = SelectElementGUIAdaptor;

SelectElementGUIAdaptor.SELECT_NOT_SUBMISSIBLE_CSS_CLASS = "selectNotSubmissible";
SelectElementGUIAdaptor.SELECT_OPTION_SUBMISSIBLE_CSS_CLASS = "selectOptionSubmissible";
SelectElementGUIAdaptor.SELECT_OPTION_NOT_SUBMISSIBLE_CSS_CLASS = "selectOptionNotSubmissible";

/**
 * Add the required protocols to the SelectElementGUIAdaptor
 * Note: Does not use InputElement because this is not derived from a HTML input tag
 */
 
GUIAdaptor._setUpProtocols('SelectElementGUIAdaptor'); 
GUIAdaptor._addProtocol('SelectElementGUIAdaptor', 'DataBindingProtocol');			// Supports binding to data model
GUIAdaptor._addProtocol('SelectElementGUIAdaptor', 'ListSrcDataProtocol');			// Supports binding of the src data to the data model
GUIAdaptor._addProtocol('SelectElementGUIAdaptor', 'RecordsProtocol');				// Supports form dirty
GUIAdaptor._addProtocol('SelectElementGUIAdaptor', 'EnablementProtocol');            // Supports enablement
GUIAdaptor._addProtocol('SelectElementGUIAdaptor', 'FocusProtocol');                 // Supports focusing
GUIAdaptor._addProtocol('SelectElementGUIAdaptor', 'FocusProtocolHTMLImpl');         // Include the default HTML implementation of focus
GUIAdaptor._addProtocol('SelectElementGUIAdaptor', 'HelpProtocol');                  // Supports helptext
GUIAdaptor._addProtocol('SelectElementGUIAdaptor', 'HelpProtocolHTMLImpl');          // Include the default HTML implementation of help
GUIAdaptor._addProtocol('SelectElementGUIAdaptor', 'InitialiseProtocol');            // Supports custom initialisation
GUIAdaptor._addProtocol('SelectElementGUIAdaptor', 'MandatoryProtocol');            // Supports mandatory
GUIAdaptor._addProtocol('SelectElementGUIAdaptor', 'NameProtocol');                  // Supports naming of the element
GUIAdaptor._addProtocol('SelectElementGUIAdaptor', 'ReadOnlyProtocol');            // Supports keybinding
GUIAdaptor._addProtocol('SelectElementGUIAdaptor', 'TemporaryProtocol');             // Supports temporary behaviour
GUIAdaptor._addProtocol('SelectElementGUIAdaptor', 'ValidationProtocol');            // Supports validation protocol
GUIAdaptor._addProtocol('SelectElementGUIAdaptor', 'KeybindingProtocol');            // Supports keybinding

/**
 * XPath relative to srcData + rowXPath which provides a unique
 * value to display for the row.
 *
 * @type String
 * @configuration Optional.
 */
SelectElementGUIAdaptor.prototype.displayXPath = null;

/**
 * Reference to adaptor onChange event handler.
 *
*/

SelectElementGUIAdaptor.prototype.m_onChangeHandler = null;

/**
 * Create a new SelectElementGUIAdaptor
 
 * @param e the select element to manage
 * @return the new SelectElementGUIAdaptor
 * @type SelectElementGUIAdaptor
 */
SelectElementGUIAdaptor.create = function(e)
{
	var a = new SelectElementGUIAdaptor();
	a._initSelectElementGUIAdaptor(e);
	return a;
}


/**
 * Initialise the SelectElementGUIAdaptor, and adds an event handler to
 * the HTML element to callback when a 'change' event is received.
 *
 * @param e the HTMLElement for the select element to be managed
 * @private
 */
SelectElementGUIAdaptor.prototype._initSelectElementGUIAdaptor = function(e)
{
	if(SelectElementGUIAdaptor.m_logger.isInfo()) SelectElementGUIAdaptor.m_logger.info(e.id + ":SelectElementGUIAdaptor._initSelectElementGUIAdaptor");
	this.m_element = e;
}


/**
 * Callback function to handle a selection change and update the data model
 */
SelectElementGUIAdaptor.prototype._handleChange = function()
{
	if(SelectElementGUIAdaptor.m_logger.isDebug()) SelectElementGUIAdaptor.m_logger.debug(this.getId() + ":SelectElementGUIAdaptor");	
	this.update();
}

/**
 * Get XPath that defines a the value to display in the dropdown
 */
SelectElementGUIAdaptor.prototype.getDisplayXPath = function()
{
	return XPathUtils.concatXPaths(this._getRowXPath(), this.displayXPath);
	return this.keyXPath;
}


SelectElementGUIAdaptor.LOSE_FOCUS_MODE = "loseFocusMode";
SelectElementGUIAdaptor.ON_CHANGE_MODE = "onChangeMode";

/**
 * Configure the GUIAdaptor. It is possible to have a select with a set of options hardcoded 
 * into the HTML in which case the only JS configuration required would be dataBinding from
 * the DataBindingProtocol.
 *
 * @param cs an Array of configuration objects ordered with
 *   most specific items first.
 * @throws ConfigurationException when modelValue missing properties or validation function defined
 */
SelectElementGUIAdaptor.prototype._configure = function(cs)
{
	if(SelectElementGUIAdaptor.m_logger.isInfo()) SelectElementGUIAdaptor.m_logger.info(this.getId() + ":SelectElementGUIAdaptor._configure");

	// Run through configuration specific to this element (no point checking the last)
	for(var i = 0; i < cs.length; i++)
	{
		if(null != cs[i].displayXPath) this.displayXPath = cs[i].displayXPath;
		if(null != cs[i].validate) this.validate = cs[i].validate;
		if(null != cs[i].nullDisplayValue) this.nullDisplayValue = cs[i].nullDisplayValue;
		if(null != cs[i].updateMode) 
		{
			this.updateMode = cs[i].updateMode;
			if(this.updateMode != SelectElementGUIAdaptor.LOSE_FOCUS_MODE && this.updateMode != SelectElementGUIAdaptor.ON_CHANGE_MODE)
			{
				if(SelectElementGUIAdaptor.m_logger.isError()) SelectElementGUIAdaptor.m_logger.error("SelectElementGUIAdaptor._configure() unknown updateMode in configuration for adaptor id=" + this.getId() + ", reverting to default of SelectElementGUIAdaptor.ON_CHANGE_MODE");
				this.updateMode = SelectElementGUIAdaptor.ON_CHANGE_MODE;
			}
		}
		else
		{
			this.updateMode = SelectElementGUIAdaptor.ON_CHANGE_MODE;
		}
	}
	if(null == this.nullDisplayValue)
	{
		this.nullDisplayValue = "";
	}
	if(null == this.displayXPath)
	{
		this.displayXPath = this.keyXPath;
	}
	this.displayXPath = XPathUtils.removeLeadingSlash(this.displayXPath);

	this.m_hardcodedOptions = !(this.srcData && ("" != this.srcData));

	var a = this;
	if(this.updateMode == SelectElementGUIAdaptor.ON_CHANGE_MODE)
	{
		this.m_onChangeHandler = SUPSEvent.addEventHandler(this.m_element, "change", function(evt) { return a._handleChange(); });
	}
	else
	{
		this.m_onChangeHandler = SUPSEvent.addEventHandler(this.m_element, "blur", function(evt) { return a._handleChange(); });
	}
}

/**
 * Get the value from the view, i.e. the HTML element. Default behaviour is to get the
 * value property from the HTML element, but this will need to be overridden for most adaptors
 *
 * @return the value of the component, usually a string but it could be a complicated multi-value
 * @type string
 */
SelectElementGUIAdaptor.prototype._getValueFromView = function()
{
	if(SelectElementGUIAdaptor.m_logger.isTrace())SelectElementGUIAdaptor.m_logger.trace(this.getId() + ":SelectElementGUIAdaptor._getValueFromView()");
	var value = null;
	if(null == this.m_element)
	{
		throw new GUIAdaptorError("SelectElementGUIAdaptor._getValueFromView(), this.m_element == null");
	}
	for(var i=0; i<this.m_element.options.length; i++)
	{
		var option = this.m_element.options[i];
		if(option.selected)
		{
			value = option.value;
			if(SelectElementGUIAdaptor.m_logger.isTrace())SelectElementGUIAdaptor.m_logger.trace(this.getId() + ":SelectElementGUIAdaptor._getValueFromView(), value = " + value);
			break;
		}
	}

	return value;
}

/**
 * Method invoked to refresh the options data when the dataSrc changes, as set in srcDataOn attribute
 *
 * @ToDo use the event param to restrict the amount of updates by checking against the xpath that caused this event.
 * @param event the DataModelEvent that triggered this call
 * @throws ConfigurationException when the sizeof keys and values don't match
 */
SelectElementGUIAdaptor.prototype.retrieveSrcData = function(event)
{
	if(SelectElementGUIAdaptor.m_logger.isInfo()) SelectElementGUIAdaptor.m_logger.info(this.getId() + ":SelectElementGUIAdaptor.retrieveSrcData()");

	// Trigger a StateChangeEvent if the srcData has changed
	// ToDo: this should take into account deltas
	var e = StateChangeEvent.create(StateChangeEvent.SRCDATA_TYPE, null, this);
	this.changeAdaptorState(e);
	
	var changed = false;
	if(!this.m_hardcodedOptions)
	{
		changed = true;
		// remove old options
		var options = this.m_element.options;
		var length = options.length;
	
		for(var p=0; p<length; p++)
		{
			options[p] = null;
		}
		options.length = 0;
		// add a default empty value
		options[0] = new Option(this.nullDisplayValue, "");
		
		var rows = FormController.getInstance().getDataModel().getInternalDOM().selectNodes(this._getRowXPath());
		for(var i=0; i<rows.length; i++)
		{
			var n = rows[i];
			var key = ListSrcDataProtocol.selectValueFromNodeByXPath(n, this.keyXPath);
			var displaySrc = ListSrcDataProtocol.selectValueFromNodeByXPath(n, this.displayXPath);

			// Allow the display values of the select box to be transformed - note
			// we are transforming source data here.
			display = this.invokeTransformToDisplay(displaySrc);

			// generate options
			options[i+1] = new Option(display, key);
			if(options[i+1].value == this.m_value)
			{
				options[i+1].selected = true;
			}
		}
	}
	return changed;
}

SelectElementGUIAdaptor.prototype.areOptionsHardcoded = function()
{
	return this.m_hardcodedOptions;
}

/*
 * Method called to render the changed state of the select element. The rendering is managed by applying 
 * stylesheet classes and setting the disabled property of the HTML element.
 *
 */
SelectElementGUIAdaptor.prototype.renderState = function()
{
	if(SelectElementGUIAdaptor.m_logger.isInfo()) SelectElementGUIAdaptor.m_logger.info(this.getId() + ":SelectElementGUIAdaptor.renderState() this.m_value=" + this.m_value + ", this.m_enabled=" + this.m_enabled + ", this.m_readOnly=" + this.m_readOnly + ", this.getValid()=" + this.getValid() + ", this.m_mandatory=" + this.m_mandatory);

	var disabled = false;
	var readOnly = false;
	var className = null;
	
	var length = this.m_element.options.length;
	
	var aggregateState = this.getAggregateState();
	
	var foundValue = false;
	for(var p=0; p<length; p++)
	{
		var option = this.m_element.options[p];
		var optionValue = option.value;
		if(optionValue == this.m_value)
		{
			if(SelectElementGUIAdaptor.m_logger.isInfo()) SelectElementGUIAdaptor.m_logger.info(this.getId() + ":SelectElementGUIAdaptor.renderState() setting selected=true at options[" + p + "]");
			foundValue = true;
			option.selected = true;
		}
		else
		{
			option.selected = false;
		}
		if(!aggregateState.isKeySubmissible(optionValue))
		{
			option.className = SelectElementGUIAdaptor.SELECT_OPTION_NOT_SUBMISSIBLE_CSS_CLASS;
		}
		else
		{
			option.className = "";
		}
	}
	
	if(!foundValue && this.m_value == null && length>0)
	{
	    // D207. Select element has no selected value. This can occur
	    // at initialisation or when the select adaptor is bound
	    // to a data binding with no value.
	    
	    if(!this.m_hardcodedOptions)
	    {
	        // Use "nothing selected" default
	        this.m_element.options[0].selected = true;
	    }
	    // Note - Hardcoded select boxes will default to option 1
	}
		
	// Don't attempt to validate if there are no options in the select element
	if(this.m_value && (this.m_value!="") && length>0 && (this.m_element.options[0].value!="" || length>1) )
	{
		if(!foundValue)
		{
			if(SelectElementGUIAdaptor.m_logger.isInfo()) SelectElementGUIAdaptor.m_logger.info(this.getId() + ":SelectElementGUIAdaptor.renderState() could not match this.m_value to a valid option, setting the class to invalid")
			this.setValid(false);
			// If the value does not exist in the options list then set to the first 
			// option if this contains an empty string, otherwise do nothing
			if(length>0 && this.m_element.options[0].value=="")
			{
				this.m_element.options[0].selected = true;
			}
		}
		else
		{
			if(!this.validate)
			{
				// Only set the internal valid state to true if we don't have a user configured
				// validate method
				if(SelectElementGUIAdaptor.m_logger.isInfo()) SelectElementGUIAdaptor.m_logger.info(this.getId() + ":SelectElementGUIAdaptor.renderState() matched this.m_value to a valid option, setting the class to valid")
				this.setValid(true);
			}
		}
	}
		
	if(!aggregateState.isSubmissible())
	{
		className = SelectElementGUIAdaptor.SELECT_NOT_SUBMISSIBLE_CSS_CLASS;
	}

	// render the select states
	if((this.supportsProtocol("EnablementProtocol") && !this.getEnabled())
	    || (this.supportsProtocol("ActiveProtocol") && !this.isActive()))
	{
		className = "disabled";
		disabled = true;
	}
	else
	{
		if(this.hasValue())
		{
			if(!this.getValid())
			{
				if(!this.getServerValid())
				{
					// If server validation in process colour text area orange. If
					// server invalid and process complete colour text area red.
					if(this.isServerValidationActive())
					{
						className = SelectElementGUIAdaptor.SELECT_NOT_SUBMISSIBLE_CSS_CLASS;
					}
					else
					{
						className = "invalid";
					}
				}
				else
				{
					className = "invalid";
				}
			}
		}
		else
		{
			if(this.m_mandatory)
			{
				className = "mandatory";
			}
		}
		
		if(this.m_readOnly)
		{
			className = "readOnly";
			// The readOnly attribute is only a member of the input box, I have therefore applied a class
			// and set it to be disabled to prevent the user from changing it's value
			//readOnly = true;
			disabled = true;
		}
	}
	
	this.m_element.disabled = disabled;
	this.m_element.className = className;
	this.m_element.readOnly = readOnly;

	if(SelectElementGUIAdaptor.m_logger.isInfo()) SelectElementGUIAdaptor.m_logger.info(this.getId() + ":SelectElementGUIAdaptor.renderState() element className =" + className);
}

/**
 * Remove onChange event handler assigned on initialisation
 *
*/

SelectElementGUIAdaptor.prototype._dispose = function()
{

    if(this.m_onChangeHandler != null)
    {
        SUPSEvent.removeEventHandlerKey(this.m_onChangeHandler);
    }
}


//==================================================================
//
// FwSelectElementGUIAdaptor.js
//
// Class implements a multi option select component similar
// in functionality to the HTML select component.
//
//==================================================================

/**
 *
 * @constructor
 * @private
 */
function FwSelectElementGUIAdaptor() 
{
};

FwSelectElementGUIAdaptor.m_logger = new Category("FwSelectElementGUIAdaptor");
 
/**
 * FwSelectElementGUIAdaptor is a sub class of HTMLElementGUIAdaptor
 */
FwSelectElementGUIAdaptor.prototype = new HTMLElementGUIAdaptor();

/**
 * Add the required protocols to the FwSelectElementGUIAdaptor
 */
GUIAdaptor._setUpProtocols('FwSelectElementGUIAdaptor'); 
GUIAdaptor._addProtocol('FwSelectElementGUIAdaptor', 'DataBindingProtocol');			// Supports binding to data model
GUIAdaptor._addProtocol('FwSelectElementGUIAdaptor', 'ListSrcDataProtocol');			// Supports binding to data model
GUIAdaptor._addProtocol('FwSelectElementGUIAdaptor', 'RecordsProtocol');				// Supports form dirty
GUIAdaptor._addProtocol('FwSelectElementGUIAdaptor', 'EnablementProtocol');            // Supports enablement
GUIAdaptor._addProtocol('FwSelectElementGUIAdaptor', 'FocusProtocol');                 // Supports focusing
GUIAdaptor._addProtocol('FwSelectElementGUIAdaptor', 'FocusProtocolHTMLImpl');         // Include the default HTML implementation of focus
GUIAdaptor._addProtocol('FwSelectElementGUIAdaptor', 'HelpProtocol');                  // Supports helptext
GUIAdaptor._addProtocol('FwSelectElementGUIAdaptor', 'HelpProtocolHTMLImpl');          // Include the default HTML implementation of help
GUIAdaptor._addProtocol('FwSelectElementGUIAdaptor', 'InitialiseProtocol');            // Supports custom initialisation
GUIAdaptor._addProtocol('FwSelectElementGUIAdaptor', 'KeybindingProtocol');            // Supports keybinding
GUIAdaptor._addProtocol('FwSelectElementGUIAdaptor', 'MandatoryProtocol');            // Supports mandatory
GUIAdaptor._addProtocol('FwSelectElementGUIAdaptor', 'NameProtocol');                  // Supports naming of the element
GUIAdaptor._addProtocol('FwSelectElementGUIAdaptor', 'ReadOnlyProtocol');            // Supports keybinding
GUIAdaptor._addProtocol('FwSelectElementGUIAdaptor', 'TemporaryProtocol');             // Supports temporary behaviour
GUIAdaptor._addProtocol('FwSelectElementGUIAdaptor', 'ValidationProtocol');            // Supports validation protocol
GUIAdaptor._addProtocol('FwSelectElementGUIAdaptor', 'MouseWheelBindingProtocol');	   // Supports mouse wheel scrolling

FwSelectElementGUIAdaptor.CLICK_MODE = "onClickMode";
FwSelectElementGUIAdaptor.DBL_CLICK_MODE = "onDblClickMode";

FwSelectElementGUIAdaptor.LOSE_FOCUS_MODE = "loseFocusMode";
FwSelectElementGUIAdaptor.ON_CHANGE_MODE = "onChangeMode";

/**
 * Set the constructor property after setting up protocols
 */
FwSelectElementGUIAdaptor.prototype.constructor = FwSelectElementGUIAdaptor;

/**
 * Array containing current data for select
 *
*/
FwSelectElementGUIAdaptor.prototype.m_selectDataRows = null;

/**
 * Boolean flag indicating whether select uses hardcoded
 * options or data from client side data model
 *
*/
FwSelectElementGUIAdaptor.prototype.m_hardcodedOptions = false;

/**
 * String storing value to display when no value selected
 *
*/
FwSelectElementGUIAdaptor.prototype.nullDisplayValue = null;

/**
 * String storing select element selection mode
 *
*/
FwSelectElementGUIAdaptor.prototype.m_selectionMode = null;

/**
 * String storing update mode for select element
 *
*/
FwSelectElementGUIAdaptor.prototype.m_updateMode = null;

/**
 * Create a new FwSelectElementGUIAdaptor
 *
 * @param e the checkbox input element to manage
 * @return the new FwSelectElementGUIAdaptor
 * @type FwSelectElementGUIAdaptor
 */
FwSelectElementGUIAdaptor.create = function(element)
{
	if (FwSelectElementGUIAdaptor.m_logger.isTrace())
	{
		FwSelectElementGUIAdaptor.m_logger.trace("FwSelectElementGUIAdaptor.create");
	}
	var a = new FwSelectElementGUIAdaptor();
	a._initFwSelectElementGUIAdaptor(element);
	return a;
}

/**
 * Initialises the instance (called from creation)
 *
 * @param element the element to manage
 */
FwSelectElementGUIAdaptor.prototype._initFwSelectElementGUIAdaptor = function(element)
{
	this.m_element = element;
	this.m_renderer = element.__renderer;
	
	// Break circular reference associated with renderer
	element.__renderer = null;
	
	fc_assert(this.m_renderer != null, "FwSelectElementGUIAdaptor._initFwSelectElementGUIAdaptor(): the renderer is not defined!");

	// GUIAdaptor acts as the model for the FwSelectElementRenderer.
	this.m_renderer.setModel(this);
	
	// Check renderer for presence of hard coded options
	var hardcodedOptions = this.m_renderer.getHardcodedOptions();
	
	if(null != hardcodedOptions)
	{
	    this.m_hardcodedOptions = true;
	    
	    // Load hard coded options
	    this.m_selectDataRows = this._getAllRowsFromHardcodedOptions( hardcodedOptions );
	}
	
	var thisObj = this;
	this.m_renderer.addValueChangeListener(function(){thisObj._valueChangeCallback()});	
}


/**
 * Disposes of all resources (event handlers and references to renderer)
 */
FwSelectElementGUIAdaptor.prototype._dispose = function()
{
	this.m_renderer.dispose();
	this.m_renderer = null;
	
	this.m_selectDataRows = null;
	this.m_element = null;
}

/*
 * Override the ReadOnlyProtocol version to start and stop the appropriate
 * event handlers, before calling the parent version
 */
FwSelectElementGUIAdaptor.prototype.setReadOnly = function(readOnly)
{
  // Start or stop listeners.
  if (readOnly)
  {
  	this.m_renderer.stopEventHandlers();
  }
  else
  {
  	this.m_renderer.startEventHandlers();
  }
  
  // Call parent method.
  return ReadOnlyProtocol.prototype.setReadOnly.call(this ,readOnly);
}

/**
 * Method returns current number of select options.
 *
*/
FwSelectElementGUIAdaptor.prototype.getNumberOfSelectRows = function()
{   
    return (this.m_selectDataRows == null) ? 0 : this.m_selectDataRows.length;
}

/**
 * Method returns flag indicating whether or not select options
 * are currently loaded.
 *
*/
FwSelectElementGUIAdaptor.prototype.selectOptionsLoaded = function()
{
    return this.getNumberOfSelectRows() > 0;
}

/**
 * Method checks whether key associated with current match is submissible.
 *
*/
FwSelectElementGUIAdaptor.prototype.isKeyForMatchSubmissible = function(matchNumber)
{
	var key = this.getKeyForMatch(matchNumber);
	var isSubmissible = this.getAggregateState().isKeySubmissible(key);
	if (FwSelectElementGUIAdaptor.m_logger.isTrace()) FwSelectElementGUIAdaptor.m_logger.trace("FwSelectElementGUIAdaptor.isKeyForMatchSubmissible() key=" + key + ", isSubmissible=" + isSubmissible);
	return isSubmissible;
}

/**
 * Return key value associated with row number.
 *
 * @param matchNumber The currently selected row on the renderer.
 *
*/
FwSelectElementGUIAdaptor.prototype.getKeyForMatch = function(matchNumber)
{
    var keyValue = null;
    
    if(this.selectOptionsLoaded())
    {
	    var match = this.m_selectDataRows[matchNumber];
	    keyValue = match.getKey();
	}

	return keyValue == null ? "" : keyValue;
}

/**
 * Return display value associated with row number.
 *
 * @param matchNumber The currently selected row on the renderer.
 *
*/
FwSelectElementGUIAdaptor.prototype.getMatch = function(matchNumber)
{
    var match = null;
    
    if(this.selectOptionsLoaded())
    {
	    match = this.m_selectDataRows[matchNumber];
	}

	return match == null ? "" : match.getDisplay();
}

/**
 * Method returns all rows associated with select from data model.
 *
*/
FwSelectElementGUIAdaptor.prototype._getAllRowNodesFromDOM = function()
{
    // Use row XPath to retrieve all data from DOM
    var xpath = this._getRowXPath();
    
    var nodeArray = FormController.getInstance().getDataModel().getInternalDOM().selectNodes(xpath);
    
    // Generate array of select element entries
    var selectElementArray = nodeArray;
    
    if(nodeArray != null && nodeArray.length > 0)
    {
        selectElementArray = new Array(nodeArray.length);
        
        for(var i = 0, l = nodeArray.length; i < l; i++)
        {
            selectElementArray[i] = this._createSelectElementArrayEntry( nodeArray[i] );
        }
        
        if(null != this.comparator)
        {
            
            this._sortArray( selectElementArray );
                                                    
        }
        
        // Add nothing selected value
        selectElementArray = this._addNothingSelected( selectElementArray );
        
    }
    
    return selectElementArray;
}

FwSelectElementGUIAdaptor.prototype._sortArray = function(array)
{
    var comparatorFn = this.comparator;
    
    array.sort( function( a, b ) {
                                     var aValue = a.getDisplay();
                                     var bValue = b.getDisplay();
                                     
                                     return comparatorFn( aValue, bValue );
                                 } );
}

FwSelectElementGUIAdaptor.prototype._valueChangeCallback = function()
{
	if(FwSelectElementGUIAdaptor.m_logger.isDebug())
	{
		FwSelectElementGUIAdaptor.m_logger.debug("FwSelectElementGUIAdaptor._valueChangeCallback()");
	}
	 
	if(this.m_updateMode == FwSelectElementGUIAdaptor.ON_CHANGE_MODE)
	{   
	    this.update();
    }
}

/**
 * Get value to be stored in data model using current displayed value
 *
 * @return the value of the component, usually a string but it could be a complicated multi-value
*/
FwSelectElementGUIAdaptor.prototype._getValueFromView = function()
{	
	var selectedRow = null;
	var returnValue = null;
	
	// First attempt to retrieve selected row number from renderer
	var selectedRowNo = this.m_renderer.getSelectedMatch();
	
	if(null == selectedRowNo)
	{
	    // Renderer value may be set to null for defect 255 (see
	    // retrieve method). If so search for row number in source
	    // data.
	    selectedRowNo = this.getRowNoFromDisplayValue(this.m_renderer.getTextFieldValue());
	}
	
	if(null != selectedRowNo && this.selectOptionsLoaded())
	{
		selectedRow = this.m_selectDataRows[selectedRowNo];
	}
	
	if(null == selectedRow)
	{
		// Get the value entered into the field and use this.
		returnValue = this.m_renderer.getTextFieldValue();
	}
	else
	{
		// Get the key for the selected row
		returnValue = selectedRow.getKey();
	}
	
	return returnValue;
}

FwSelectElementGUIAdaptor.prototype.onBlur = function()
{
    if(this.m_updateMode == FwSelectElementGUIAdaptor.LOSE_FOCUS_MODE)
    {
	    this.update();
	}
}


/**
 * Renders the visual state and event handlers for this
 * adaptor based on its current state
 */
FwSelectElementGUIAdaptor.prototype.renderState = function()
{   
	if(this.m_focusChanged)
	{
		// Reset this immediately so that we don't end up recursing through this again
		this.m_focusChanged = false;

		if(!this.m_focus)
		{
			// Hide the drop down when the focus is lost
			this.m_renderer.m_dropDownField.hideDropDown();
		}
	}
	else
	{
	    if(this.m_valueChanged)
	    {
	        if(this.m_updateMode == FwSelectElementGUIAdaptor.ON_CHANGE_MODE && this.m_focus)
	        {
	            // Similar to defect 927 for the DataPicker we must update status bar
	            // message when select component has focus.
	            FormController.getInstance().getFormAdaptor()._setCurrentFocusedField(this);
	        }
	    }
	}

	if(this.m_valueChanged)
	{
	    // Update renderer display   
		this._refreshDisplayedValue();
		
		this.m_valueChanged = false;
	}
	
	// Set default selection first time render state
	// with select options loaded
	if(this.m_value == null &&
	   this.selectOptionsLoaded() &&
	   this.m_renderer.getSelectedMatch() == null)
	{
	    this.m_renderer.setSelectedRow(0);
	    
	    this.m_renderer.setValue(this.m_selectDataRows[0].getDisplay());
	    
	    if(this.m_hardcodedOptions)
	    {   
	        // If options are hard coded update data model because
	        // default key value may not be a blank string.
	        this.update();
	    }
	}   

	// Set up all states other than value - we only use the areChildrenSubmissible here for the
	// orange state because the mandatory and invalid states are supported on this adaptor type
	// and we don't want to overwrite the red border etc.
	this.m_renderer.render(
		!this.m_enabled,
		this.m_focus,
		this.m_mandatory,
		!this.getValid(),
		!this.getServerValid(),
		this.m_readOnly,
		!this.isActive(),
		this.getAggregateState().areChildrenSubmissible(),
		this.isServerValidationActive()
	);
}

/**
 * Method sets value displayed on renderer based on current adaptor
 * value.
 *
 */
FwSelectElementGUIAdaptor.prototype._refreshDisplayedValue = function()
{
	// Value defaults to the key value
	var val = this.m_value;
	
	// Note rowNo may be null when either
	
	//  i) The value stored in the adaptor does not match one of the option keys
    //     (this may occur if the source data is changed)
    
    //  or
    
    //  ii) Render state is executed before the adaptor's data has been loaded
    
	var rowNo = this._getRowNoFromKey(val);
	    
	var currentSelectedRow = this.m_renderer.getSelectedMatch();
	    
	if(null == rowNo)
	{
	    // Adaptor value does not match an option key.
	        
	    // Defect 973. Display invalid value.
	    if(null != currentSelectedRow)
	    {
	        this.m_renderer.resetSelectedMatch();
	    }
	}
	else
	{
	    // Selected row has changed probably owing to
	    // change in source data
	    this.m_renderer.setSelectedRow(rowNo);
	            
	    val = this.m_selectDataRows[rowNo].getDisplay();    
	}

	// Write the value to the view
	this.m_renderer.setValue(val);
}

/**
 * Configure the select adaptor.
 * 
 */
FwSelectElementGUIAdaptor.prototype._configure = function(cs)
{	
	// Run through configuration specific to this element
	for(var i = 0, l = cs.length; i < l; i++)
	{
		var c = cs[i];
		
		if(!this.m_hardcodedOptions)
		{
		    if(c.displayXPath && this.m_displayXPath == null)
		    {
			    this.m_displayXPath = XPathUtils.removeLeadingSlash(c.displayXPath);
		    }
		}
		
		if(null != c.selectionMode && this.m_selectionMode == null) 
		{
			this.m_selectionMode = c.selectionMode;
	    }
	    
	    if(null != c.updateMode && this.m_updateMode == null)
	    {
	        this.m_updateMode = c.updateMode;
	    }
		
		if(null != cs[i].sortMode)
		{
			if (cs[i].sortMode == "numerical")
			{
				this.comparator = Comparators.numericalSort;
			}
			else if (cs[i].sortMode == "alphabetical")
			{
				this.comparator = Comparators.alphabeticalSort;
			}
			else if (cs[i].sortMode == "alphabeticalLowToHigh")
			{
				this.comparator = Comparators.alphabeticalSortLowToHigh;
			}
			else if (cs[i].sortMode == "alphabeticalLocaleCompare")
			{
				this.comparator = Comparators.alphabeticalLocaleCompareSort;
			}
			else if (cs[i].sortMode == "alphanumerical")
			{
				this.comparator = Comparators.alphanumerical;
			}
			else if (cs[i].sortMode == "alphabeticalCaseInsensitive")
			{
				this.comparator = Comparators.alphabeticalCaseInsensitiveSort ;
			}
			else
			{
				this.comparator = null;	
			}
		}
		
		if(null != c.nullDisplayValue && this.nullDisplayValue == null)
		{
		    this.nullDisplayValue = c.nullDisplayValue;
		}
		
	}
	
	// Determine selection mode
	if(null != this.m_selectionMode)
	{
	    if(this.m_selectionMode != FwSelectElementGUIAdaptor.CLICK_MODE && 
		   this.m_selectionMode != FwSelectElementGUIAdaptor.DBL_CLICK_MODE)
		{
		    if(FwSelectElementGUIAdaptor.m_logger.isError())
			{
	            FwSelectElementGUIAdaptor.m_logger.error("FwSelectElementGUIAdaptor._configure() unknown selectionMode in configuration for adaptor id=" + this.getId() + ", reverting to default of FwSelectElementGUIAdaptor.CLICK_MODE");
	        }
			
			this.m_selectionMode = FwSelectElementGUIAdaptor.CLICK_MODE;
		}
		
	}
	else
	{
	    this.m_selectionMode = FwSelectElementGUIAdaptor.CLICK_MODE;
	}
	
	// Determine update mode
	if(null != this.m_updateMode)
	{
	    if(this.m_updateMode != FwSelectElementGUIAdaptor.LOSE_FOCUS_MODE &&
	       this.m_updateMode != FwSelectElementGUIAdaptor.ON_CHANGE_MODE)
	    {
	        if(FwSelectElementGUIAdaptor.m_logger.isError())
			{
	            FwSelectElementGUIAdaptor.m_logger.error("FwSelectElementGUIAdaptor._configure() unknown updateMode in configuration for adaptor id=" + this.getId() + ", reverting to default of FwSelectElementGUIAdaptor.ON_CHANGE_MODE");
	        }
	        
	        this.m_updateMode = FwSelectElementGUIAdaptor.ON_CHANGE_MODE;
	    }
	    
	}
	else
	{
	    this.m_updateMode = FwSelectElementGUIAdaptor.ON_CHANGE_MODE;
	}
	
	// Set default value for nothing selected
	if(null == this.nullDisplayValue)
	{
	    this.nullDisplayValue = "";
	}
	
	if(!this.m_hardcodedOptions)
	{
	    // Check state of configuration 
	    this._checkConfiguration();
	
	    // Append displayValue xpaths to set of xpaths which trigger a refresh of source data
	    var displayXPaths = this.getRowXPathArrayWithSuffix()
	    this.srcDataOn = (null == this.srcDataOn) ? displayXPaths : this.srcDataOn.concat(displayXPaths);
	    
	    // Set up adaptor to run validate if source data changes
	    if(null != this.validateOn)
	    {
	        this.validateOn = this.validateOn.concat(this.srcDataOn);
	    }
	    else
	    {
	        this.validateOn = this.srcDataOn;
	    }
	    
	}
	
}

FwSelectElementGUIAdaptor.prototype._checkConfiguration = function()
{
	// srcData is mandatory
	if(null == this.srcData)
	{
		throw new ConfigurationException("srcData must be specified for adaptor: " + this.getId());
	}
	// keyXPath is mandatory
	if(null == this.keyXPath)
	{
		throw new ConfigurationException("keyXPath must be specified for adaptor: " + this.getId());
	}

	// Row is optionaly configured and derived from srcData if null
	if(null != this.rowXPath)
	{
	    if(this.rowXPath.indexOf('/') == 0)
	    {
	        this.m_absoluteRowXPath = this.srcData + this.rowXPath;
	    }
	    else
	    {   
	        this.m_absoluteRowXPath = this.srcData + '/' + this.rowXPath;
	    }
	}
	else
	{
	    this.m_absoluteRowXPath = this.srcData;
	}
	
	// displayXPath is optionally configured and derived from key if null
	this.m_displayXPath = this.m_displayXPath != null ? this.m_displayXPath : this.keyXPath;
	
	if(this.m_displayXPath.indexOf('/') == 0)
	{
	    this.m_absoluteDisplayXPath = this.m_absoluteRowXPath + this.m_displayXPath;
	}
	else
	{
	    this.m_absoluteDisplayXPath = this.m_absoluteRowXPath + '/' + this.m_displayXPath;
	}

	this.srcDataOn[this.srcDataOn.length] = this.m_absoluteDisplayXPath;
}


FwSelectElementGUIAdaptor.prototype.retrieve = function(event)
{
	var db = this.dataBinding;
	if(null != db)
	{
		var mV = FormController.getInstance().getDataModel().getValue(db);
		
		// Should we really be doing this? Use transform to display to
		// convert data for display but here we are setting selected value
		// on adaptor based on key.
		var dV = this.invokeTransformToDisplay(mV);
		
		var valueChanged = this._setValue(dV);

		// If the value changed during this repaint cycle keep track of it.
		if(!this.m_valueChanged) this.m_valueChanged = valueChanged;

		if(valueChanged)
		{
			// this is to solve D255 because getValueFromView checks the selected match which
			// isn't overwritten by setting the internal value in m_value
			this.m_renderer.resetSelectedMatch();
			
			// Trigger a StateChangeEvent if the value has changed
			var e = StateChangeEvent.create(StateChangeEvent.VALUE_TYPE, dV, this);
			this.changeAdaptorState(e);
		}
		return valueChanged;
	}
	else
	{
		throw new DataBindingError("DataBindingProtocol.retrieve(), no dataBinding specified for adaptor id = " + this.getId());
	}
}


FwSelectElementGUIAdaptor.prototype.retrieveSrcData = function(event)
{
	if(FwSelectElementGUIAdaptor.m_logger.isInfo())
	{
		FwSelectElementGUIAdaptor.m_logger.info(this.getId() + ":SelectElementGUIAdaptor.retrieveSrcData()");
	}
	
	// Trigger a StateChangeEvent if the srcData has changed
	// ToDo: this should take into account deltas
	var e = StateChangeEvent.create(StateChangeEvent.SRCDATA_TYPE, null, this);
	this.changeAdaptorState(e);
	
	var changed = false;
	
	if(!this.m_hardcodedOptions)
	{
	    // State has changed, so ensure view refreshed
	    changed = true;
	    
	    // Retrieve data from data model
	    this.m_selectDataRows = this._getAllRowNodesFromDOM();
	
	    // Notify the renderer that the data has changed.
	    this.m_renderer.dataUpdate();

	    // Cause displayed value to be updated during renderState
	    this.m_valueChanged = true;
	}
	
	return changed;
}

/**
 * Method provides a dedicated validate method for the framework select
 * component.
 *
 * @param event Detail describing data model event which caused validate to execute.
 *
 * @return Returns null if valid or an error code instance if not.
 *
 */
FwSelectElementGUIAdaptor.prototype.validate = function( event )
{
    var ec = null;
    
    // Look up current adaptor key value in source data
    var rowNo = this._getRowNoFromKey(this.m_value);
    
    if(null == rowNo)
    {
        // Current value is not in source data
        ec = ErrorCode.getErrorCode( "FW_FWSELECT_InvalidKey" );
    }
    
    return ec;
}

/**
 * Get the element to set focus on. For the framework select this
 * is the input text field
 */
FwSelectElementGUIAdaptor.prototype.getFocusElement = function()
{
	return this.m_renderer.getInputElement();
}

/**
 * Method converts a select entry node retrieved from
 * the data model into the format used to store select
 * entries for interaction with the select element
 * renderer.
 *
 * @param node Node retrieved from data model data for select.
*/
FwSelectElementGUIAdaptor.prototype._createSelectElementArrayEntry = function( node )
{
    var keyNode;
    var keyValue;
    var displayNode;
    var displaySrcValue;
    var displayValue;
    var upperCaseDisplayValue;
    
    // Extract key value
    
    keyNode = node.selectSingleNode(this.keyXPath);
    
    if(null != keyNode)
    {
        keyValue = XML.getNodeTextContent(keyNode);
    }
    else
    {
        keyValue = null;
    }
    
    // Extract display value and determine upper case value
    displayNode = node.selectSingleNode(this.m_displayXPath);
    
    if(null != displayNode)
    {
        displaySrcValue = XML.getNodeTextContent(displayNode);
        displayValue = this.invokeTransformToDisplay(displaySrcValue);
        upperCaseDisplayValue = this._convertToUpperCase( displayValue );
    }
    else
    {
        if(this.m_displayXPath != this.keyXPath)
        {
            displaySrcValue = "";
            displayValue = this.invokeTransformToDisplay(displaySrcValue);
            upperCaseDisplayValue = this._convertToUpperCase( displayValue );
        }
        else
        {
            // Display XPaths not used, display uses key value
            displaySrcValue = keyValue;
            displayValue = this.invokeTransformToDisplay(displaySrcValue);
            upperCaseDisplayValue = this._convertToUpperCase( displayValue );
        }
            
    }
    
    return new FwSelectElementArrayEntry( keyValue,
                                          displayValue,
                                          upperCaseDisplayValue );
}

/**
 * Method adds default "nothing selected" value to array
 * of entries for select.
 *
*/
FwSelectElementGUIAdaptor.prototype._addNothingSelected = function( selectElementArray )
{
    var newArray = Array( selectElementArray.length + 1 );
    
    var nothingSelectedValue = this.nullDisplayValue;
    
    var upperCaseValue = this._convertToUpperCase( nothingSelectedValue );
    
    newArray[0] = new FwSelectElementArrayEntry( "", 
                                                 nothingSelectedValue,
                                                 upperCaseValue );
                                                 
    if(selectElementArray.length > 0)
    {
        for( var i = 0, l = selectElementArray.length; i < l; i++ )
        {
            newArray[ i + 1 ] = selectElementArray[ i ];
        }
    }
    
    return newArray; 
}

/**
 * Method returns row number for given key value.
 *
*/
FwSelectElementGUIAdaptor.prototype._getRowNoFromKey = function(keyValue)
{
    var returnValue = null;
    
    if(this.selectOptionsLoaded() && null != keyValue)
    {
        var selectArrayEntry = null;
        
        for(var i = 0, l = this.m_selectDataRows.length; i < l; i++)
        {
            selectArrayEntry = this.m_selectDataRows[i];
            
            // Note, custom retrieve method transforms key value
            // using invokeTransformToDisplay such that value stored
            // in adaptor is transformed value.
            if(keyValue == this.invokeTransformToDisplay( selectArrayEntry.getKey() ))
            {
                returnValue = i;
                break;
            }
        }
        
    }
    
    return returnValue;
}

/**
 * Method returns row number for given display value.
 *
*/
FwSelectElementGUIAdaptor.prototype.getRowNoFromDisplayValue = function(displayValue)
{
    var returnValue = null;
    
    if(this.selectOptionsLoaded() && null != displayValue)
    {
        var selectArrayEntry = null;
        
        for(var i = 0, l = this.m_selectDataRows.length; i < l; i++)
        {
            selectArrayEntry = this.m_selectDataRows[i];
            
            if(displayValue == selectArrayEntry.getDisplay())
            {
                returnValue = i;
                break;
            }
        }
        
    }
    
    return returnValue;
}

/**
 * Method loads source data for adaptor from array of hard coded options
 * passed as an argument into the corresponding renderer instance.
 *
 * @param hardcodedOptions Array of objects defining select options.
 *
*/
FwSelectElementGUIAdaptor.prototype._getAllRowsFromHardcodedOptions = function(hardcodedOptions)
{
    var selectElementArray = hardcodedOptions;
    
    var length = hardcodedOptions.length;
    
    if(length > 0)
    {
        selectElementArray = new Array(length);
        
        for(var i = 0; i < length; i++)
        {
            selectElementArray[i] = this._createArrayEntryFromHardcodedOption( hardcodedOptions[i] );
        }
        
        if(null != this.comparator)
        {
            this._sortArray( selectElementArray );
        }
    }
    
    return selectElementArray;
}

/**
 * Method creates an instance of the class FwSelectElementArrayEntry from
 * a hard coded select option object.
 *
*/
FwSelectElementGUIAdaptor.prototype._createArrayEntryFromHardcodedOption = function( hardcodedOption )
{
    // Determine key value
    
    var keyValue;
    
    if(null == hardcodedOption[ "key" ])
    {
        throw new ConfigurationException( "Hard coded select option for select '" +
                                          this.getId() +
                                          "'\n does not define value for key" );
    }
    else
    {
        keyValue = hardcodedOption[ "key" ];
    }
    
    // Determine display value
    
    var displaySrcValue = hardcodedOption[ "display" ];
    
    if(null == displaySrcValue)
    {
        displaySrcValue = keyValue;
    }
    
    var displayValue = this.invokeTransformToDisplay( displaySrcValue );
    
    var upperCaseDisplayValue = this._convertToUpperCase( displayValue );
    
    return new FwSelectElementArrayEntry( keyValue,
                                          displayValue,
                                          upperCaseDisplayValue );
} 

FwSelectElementGUIAdaptor.prototype._convertToUpperCase = function(value)
{
    var upperCaseValue;
    
    if(value != "")
    {
        upperCaseValue = value.toUpperCase();
    }
    else
    {
        upperCaseValue = "";
    }
    
    return upperCaseValue;
    
}

FwSelectElementGUIAdaptor.prototype.areOptionsHardcoded = function()
{
    return this.m_hardcodedOptions;
}

FwSelectElementGUIAdaptor.prototype.matchFirstCharacter = function(firstChar)
{
    var matchedRow = null;
    
    var upperCaseFirstChar = firstChar.toUpperCase();
    
    var selectedDataRows = this.m_selectDataRows;
    
    if(null != selectedDataRows)
    {
    
        // Search array for matches to first character
        var selectArrayEntry;
        var upperCaseDisplayValue;
    
        var selectDataRowsLength = selectedDataRows.length;
        var matchedEntries = new Array();
    
        for( var i = 0; i < selectDataRowsLength; i++)
        {
            selectArrayEntry = selectedDataRows[i];
            
            upperCaseDisplayValue = selectArrayEntry.getUpperCaseDisplay();
            
            if(upperCaseFirstChar == upperCaseDisplayValue.charAt(0))
            {
                matchedEntries[matchedEntries.length] = selectArrayEntry;
                matchedEntries[matchedEntries.length - 1]["index"] = i;
            }
        }
        
        var matchedEntriesLength = matchedEntries.length;
        
        if(matchedEntriesLength > 0)
        {
            var currentTextFieldValue = this.m_renderer.getTextFieldValue();
            
            var currentPosition = null;
            var entryDisplayValue = null;
            
            for( var j = 0; j < matchedEntriesLength; j++ )
            {
                entryDisplayValue = matchedEntries[j].getDisplay();
                
                if(entryDisplayValue == currentTextFieldValue)
                {
                    currentPosition = j;
                    break;
                }
            }
            
            if(null == currentPosition)
            {
                // Use first match
                matchedRow = matchedEntries[0]["index"];
            }
            else
            {
                // If more than one match move to next match
                if(matchedEntriesLength > 1)
                {
                    currentPosition += 1;
                    
                    if(currentPosition > matchedEntriesLength - 1)
                    {
                        currentPosition = 0;
                    }
                    
                    matchedRow = matchedEntries[currentPosition]["index"];
                }
                
            }
            
        } // Matched entries > 0
        
    }
    
    return matchedRow;
    
}

/**
 * Method called when the mouse wheel is 'rotated'.
 *
 * @param evt the event structure.
 */
FwSelectElementGUIAdaptor.prototype.handleScrollMouse = function(evt)
{
	if(evt.wheelDelta > 0)
	{
		// Scroll up, move highlighting up one row in drop down
		this.m_renderer._selectPreviousOption();
	}
	else
	{
		// Scroll down, move highlighting down one row in drop down		
		this.m_renderer._selectNextOption();
	}
}

/**
 * Method initialise is called when initialising adaptor states in
 * the second phase of form initialisation. As such it is a good
 * time to create the contents of framework select components
 * with hard coded select lists because any associated style
 * sheets will have been loaded.
 *
 * For framework select components with source data in the client side DOM
 * the drop down contents are created in the method retrieveSrcData. 
*/
FwSelectElementGUIAdaptor.prototype.initialise = function()
{
    if(this.m_hardcodedOptions)
    {
        // Create contents of framework select drop down
        this.m_renderer._createDynamicDropDownContent();
    }
}

/**
 * Class used to store entries in select element array
 *
*/
function FwSelectElementArrayEntry( key, display, upperCaseDisplay )
{
    this.m_key = key;
    this.m_display = display;
    this.m_upperCaseDisplay = upperCaseDisplay;
}

FwSelectElementArrayEntry.prototype.getKey = function()
{
    return this.m_key;
}

FwSelectElementArrayEntry.prototype.getDisplay = function()
{
    return this.m_display;
}

FwSelectElementArrayEntry.prototype.getUpperCaseDisplay = function()
{
    return this.m_upperCaseDisplay;
}
//==================================================================
//
// TextInputElementGUIAdaptor.js
//
// Class for adapting a text style input element for use in the
// framework
//
//==================================================================


/**
 * Base class for adapting html input elements for use in the
 * framework.
 *
 * @param e the input element to manage
 * @constructor
 * @private
 */
function TextInputElementGUIAdaptor()
{
}

TextInputElementGUIAdaptor.m_logger = new Category("TextInputElementGUIAdaptor");

/**
 * TextInputElementGUIAdaptor is a sub class of InputElementGUIAdaptor
 */
TextInputElementGUIAdaptor.prototype = new InputElementGUIAdaptor();


/**
 * Make sure that the parent class' protocols are set up correctly for this GUIAdaptor
 */
GUIAdaptor._setUpProtocols("TextInputElementGUIAdaptor");


/**
 * Add the required protocols to the TextInputElementGUIAdaptor
 */
GUIAdaptor._addProtocol('TextInputElementGUIAdaptor', 'DataBindingProtocol');		// Supports databinding
GUIAdaptor._addProtocol('TextInputElementGUIAdaptor', 'ReadOnlyProtocol');			// Supports read only

TextInputElementGUIAdaptor.prototype.constructor = TextInputElementGUIAdaptor;

/**
 * Define default style for input text box managed by adaptor
 *
*/
TextInputElementGUIAdaptor.CSS_CLASS_NAME = "textInputElementDefaultStyle";

/**
 * Maximum length of the text field
 *
 * @configuration
 * @merge-rule Most specific maxLength takes precedence
 */
TextInputElementGUIAdaptor.prototype.maxLength = null;

/**
 * Boolean flag recording whether, or not, user input validation
 * should include a check for whitespace only entry.
 *
*/
TextInputElementGUIAdaptor.prototype.m_validateWhitespaceOnlyEntry = null;


/**
 * Create a new TextInputElementGUIAdaptor
 *
 * @param e the text input element to manage
 * @return the new TextInputElementGUIAdaptor
 * @type TextInputElementGUIAdaptor
 */
TextInputElementGUIAdaptor.create = function(e)
{
	var a = new TextInputElementGUIAdaptor();
	a._initTextInputElementGUIAdaptor(e);
	return a;
}


TextInputElementGUIAdaptor.prototype._initTextInputElementGUIAdaptor = function(e)
{
	this._initInputElementGUIAdaptor(e);

	var a = this;
	this.m_changeEventKey = SUPSEvent.addEventHandler(e, "change", function(evt) { return a._handleBlur(evt); });
	
	// Prevent autocompletion in Mozilla which can cause focussing problems
	e.setAttribute("autocomplete", "OFF");
}


TextInputElementGUIAdaptor.prototype._dispose = function()
{
	SUPSEvent.removeEventHandlerKey(this.m_changeEventKey);
	this.m_changeEventKey = null;
}


/**
 * Configure the GUIAdaptor
 *
 * @param cs an Array of configuration objects ordered with
 *   most specific items first.
 */
TextInputElementGUIAdaptor.prototype._configure = function(cs)
{
	// Run through configuration specific to this element
	for(var i = 0, l = cs.length; i < l; i++)
	{
		var c = cs[i];
		
		// additionalStylingClasses used by grid filtering
		if(c.additionalStylingClasses && this.m_additionalStylingClasses == null)
		{
			this.m_additionalStylingClasses = c.additionalStylingClasses;
		}
		// Check for whitespace only entry validation
		if(FormController.getValidateWhitespaceOnlyEntryActive())
		{
		    if(null != c.validateWhitespaceOnlyEntry && this.m_validateWhitespaceOnlyEntry == null)
		    {
		        this.m_validateWhitespaceOnlyEntry = c.validateWhitespaceOnlyEntry;
		    }
		}
		// Check for maxLength validation
		if(null != c.maxLength)
		{
			// Override this adaptor maxLength configuration
			this.maxLength = c.maxLength;
			
			// Provide default validation rule based on maxLength
			this.validate = this._validateMaxLength;
			
			// Set the text fields maximum length to correspond to the
			// maximum allowable length
			this.getElement().maxLength = this.maxLength;
			
			// As soon as a maxLength configuration is found don't 
			// look for any more.
			break;
		}
	}
	
	// If whitespace only entry validation required create additional
	// configuration object with validate property and add to
	// adaptor configuration
	if(FormController.getValidateWhitespaceOnlyEntryActive() &&
	   this.m_validateWhitespaceOnlyEntry != false)
	{
	    if(this.maxLength != null)
	    {
	        this._addWhitespaceOnlyEntryValidation();
	    }
	    else
	    {
	        // Add whitespace validation as default validation
	        this.validate = this._validateWhitespaceOnlyEntry;
	    }
	}
	
}


TextInputElementGUIAdaptor.prototype._handleBlur = function()
{
	if(TextInputElementGUIAdaptor.m_logger.isDebug()) TextInputElementGUIAdaptor.m_logger.debug("TextInputElementGUIAdaptor._handleBlur(): performing update() for adaptor: " + this.getId());
	this.update();
}


TextInputElementGUIAdaptor.prototype.renderState = function()
{
	// On IE input elements cannot have null as a value, they have to have an empty string instead
	this.m_element.value = null == this.m_value ? "" : this.m_value;

	var disabled = false;
	var readOnly = false;
	
	// Defect 1123. Set default class type.
	var className = TextInputElementGUIAdaptor.CSS_CLASS_NAME;
	
	if((this.supportsProtocol("EnablementProtocol") && !this.getEnabled())
	    || (this.supportsProtocol("ActiveProtocol") && !this.isActive()))
	{
		className = "disabled";
		disabled = true;
	}
	else
	{
		if(this.hasValue())
		{
			if(!this.getValid())
			{
				if(!this.getServerValid())
				{
					    // If server validation in process colour text area orange. If
					    // server invalid and process complete colour text area red.
					    if(this.isServerValidationActive())
					    {
						    className += " notSubmissible";
						}
						else
						{
						    className += " invalid";
						}
				}
				else
				{
					className += " invalid";
				}
			}
		}
		else
		{
			if(this.m_mandatory)
			{
				className += " mandatory";
			}
		}
		
		if(this.m_readOnly)
		{
			className += " readOnly";
			readOnly = true;
		}

		if(this.m_additionalStylingClasses != null)
		{
		    className += " " + this.m_additionalStylingClasses;
		}
	}
	
	// Make sure that the class of the actual GUI Element is maintained.
/*
	var defaultClass = this._getClassName();
	if(null != defaultClass)
	{
		className += " " + defaultClass;
	}
*/
	
	this.m_element.disabled = disabled;
	this.m_element.className = className;
	this.m_element.readOnly = readOnly;

	if(this.m_focusChanged)
	{
		// Hightlight text on focus
		if(this.m_focus)
		{
			this.m_element.select();
		}
		this.m_focusChanged = false;
	}
	
}
//==================================================================
//
// TextAreaElementGUIAdaptor.js
//
// Class for adapting a text area style element for use in the
// framework
//
//==================================================================

/**
 * Base class for adapting html elements for use in the
 * framework.
 *
 * @constructor
 * @private
 */
function TextAreaElementGUIAdaptor()
{
}
 
TextAreaElementGUIAdaptor.m_logger = new Category( "TextAreaElementGUIAdaptor" );
 
/**
 * TextAreaElementGUIAdaptor is a sub class of TextInputElementGUIAdaptor
 *
*/
TextAreaElementGUIAdaptor.prototype = new TextInputElementGUIAdaptor();
TextAreaElementGUIAdaptor.prototype.constructor = TextAreaElementGUIAdaptor;

/**
 * Define instance members
 *
 * Reference to key press event handler used for both IE and Mozilla
 *
*/
TextAreaElementGUIAdaptor.prototype.m_keyPressEventKey = null;

/**
 * Create a new TextAreaElementGUIAdaptor
 *
 * @param e the text area element to manage
 * @return the new TextAreaElementGUIAdaptor
 * @type TextAreaElementGUIAdaptor
 */
TextAreaElementGUIAdaptor.create = function(e)
{
    var a = new TextAreaElementGUIAdaptor();
    
    // Use initialization method inherited from text input adaptor
    a._initTextInputElementGUIAdaptor(e);
    
    return a;
}

/**
 * Clean up memory used by adaptor
 *
*/
TextAreaElementGUIAdaptor.prototype._dispose = function()
{

    if(null != this.maxLength)
    {
        // Remove event handlers created to maintain maximum length
        SUPSEvent.removeEventHandlerKey(this.m_keyPressEventKey);
        this.m_keyPressEventKey = null;
        
        if(HTMLView.isIE)
        {
            // Remove IE specific event handlers for paste and drop
            SUPSEvent.removeEventHandlerKey(this.m_beforePasteEventKey);
            this.m_beforePasteEventKey = null;
            
            SUPSEvent.removeEventHandlerKey(this.m_pasteEventKey);
            this.m_pasteEventKey = null;        
        }
    }
    
    // Invoke dispose on parent adaptor
    TextInputElementGUIAdaptor.prototype._dispose.call(this);
    
}

/**
 * Configure the GUIAdaptor
 *
 * @param cs an Array of configuration objects ordered with
 *   most specific items first.
 */
TextAreaElementGUIAdaptor.prototype._configure = function(cs)
{
    // Invoke configure method on parent adaptor
    TextInputElementGUIAdaptor.prototype._configure.call(this, cs);
    
    if(null != this.maxLength)
    {
    
        // Add event handlers required to maintain maximum length
        var thisObj = this;
        
        this.m_keyPressEventKey = SUPSEvent.addEventHandler( this.m_element,
                                                             "keypress",
                                                             function(evt){return thisObj._handleKeyPress(evt);} );
                                                             
        if(HTMLView.isIE)
        {
            // Add IE specific event handlers to cope with paste and drop
            this.m_beforePasteEventKey = SUPSEvent.addEventHandler( this.m_element,
                                                                    "beforepaste",
                                                                    function(){return thisObj._handleBeforePaste();} );
                                                                    
            this.m_pasteEventKey = SUPSEvent.addEventHandler( this.m_element,
                                                              "paste",
                                                              function(){return thisObj._handlePaste();} );
        }
        
    }
    
}

/**
 * Method handles key press events. Key press events are allowed to flow freely
 * until the length of the contents of the text area is equal to the maximum
 * allowed length (if set). Subsequently, only function key presses will be
 * passed on for processing.
 *
 * @param evt When using Mozilla the associated event
 *
*/
TextAreaElementGUIAdaptor.prototype._handleKeyPress = function(evt)
{
    evt = (evt) ? evt : ((event) ? event : null );
    
    if(null != evt)
    {
    	// Create text range object corresponding to current document selection in text area
   	 	var currentSelection = document.selection.createRange();

        // Retrieve current length of text in text area, subtracting the length of
        // the selected text because this will be replaced by the key press
        var currentLength = this.m_element.value.length - currentSelection.text.length;	

        var maxLength = this.maxLength;
        
        if(currentLength >= maxLength)
        {
            // Text length maintainance is browser specific
            if(HTMLView.isIE)
            {
                // In IE function keys and keys qualified with
                // ctrl and alt are not passed to the key press event.
                // Therefore, key press indicates attempted addition
                // of a new character.
                
                // Stop event
                evt.returnValue = false;
            }
            else
            {
                // In Mozilla all key presses are routed to the key press event.
                // However, the value of charCode can be used to distinguish
                // between function and character keys.
                
                if(evt.charCode == 0)
                {
                    // Allow all function keys to continue except "return"
                    if(evt.keyCode == Key.Return)
                    {
                        evt.preventDefault();
                    }
                }
                else
                {
                    // Stop all characters unless they are qualified
                    // with either "ctrl" or "alt"
                    var qualifier = evt.ctrlKey || evt.altKey;
                    
                    if(!qualifier)
                    {
                        evt.preventDefault();
                    }
                }
                    
            }
            
        } // if(currentLength >= maxLength)
        
    } // if(null != evt)
    
}

/**
 * IE specific event handler method cancels "beforePaste" event
 * allowing custom "paste" event handler to replace default
 * event action.
 *
*/
TextAreaElementGUIAdaptor.prototype._handleBeforePaste = function()
{
    var event = window.event;
    
    if(null != event)
    {
        event.returnValue = false;
    }
    
}

/**
 * IE specific event handler method replaces default "onpaste"
 * event processing.
 *
*/
TextAreaElementGUIAdaptor.prototype._handlePaste = function()
{
    var event = window.event;
    
    if(null != event)
    {
        // Prevent default event processing
        event.returnValue = false;
        
        // Retrieve text to be pasted in from clipboard
        var clipboardText = window.clipboardData.getData( "Text" );
        
        // Insert text into text area
        this._insertText( clipboardText );
    }
    
}

/**
 * IE specific method inserts text from clipboard or drag data transfer object
 * into text area ensuring that the maximum length set for the text area is
 * not exceeded.
 *
 * @param insertionText String containing text to be inserted into text area
 *
*/
TextAreaElementGUIAdaptor.prototype._insertText = function(insertionText)
{
    var maxLength = this.maxLength;
    
    // Determine length of current text area contents
    var currentLength = this.m_element.value.length;
    
    // Create text range object corresponding to current document selection in text area
    var currentSelection = document.selection.createRange();
    
    // Determine length of currently selected text in text area
    var currentSelectionLength = currentSelection.text.length;
    
    // Determine length of text to be inserted into text area
    var insertionTextLength = insertionText.length;
    
    // Calculate change in text area owing to text insertion
    var lengthChange = insertionTextLength - currentSelectionLength;
    
    if(lengthChange > 0)
    {
        // Check if new length exceeds maximum length
        if(currentLength + lengthChange > maxLength)
        {
            var modifiedInsertionTextLength = insertionTextLength - (currentLength + lengthChange - maxLength);
            
            if(modifiedInsertionTextLength > 0)
            {
                currentSelection.text = insertionText.substr(0, modifiedInsertionTextLength);
            }
            
        }
        else
        {
            currentSelection.text = insertionText;
        }
        
    }
    else
    {
        currentSelection.text = insertionText;
    }
    
}
//==================================================================
//
// TabSelectorGUIAdaptor.js
//
// Class for implementing tabbed diaglouges for use in the
// framework
//
//==================================================================

/**
 * Base class for adapting DIV elements with a TabSelector class 
 * for use in the framework.
 *
 * @constructor
 * @private
 */
function TabSelectorGUIAdaptor(){};


TabSelectorGUIAdaptor.m_logger = new Category("TabSelectorGUIAdaptor");
 

/**
 * TabSelectorGUIAdaptor is a sub class of HTMLElementGUIAdaptor
 */
TabSelectorGUIAdaptor.prototype = new HTMLElementGUIAdaptor();
TabSelectorGUIAdaptor.prototype.constructor = TabSelectorGUIAdaptor;


/**
 * Add the required protocols to the TabSelectorGUIAdaptor
 */
GUIAdaptor._setUpProtocols('TabSelectorGUIAdaptor'); 
GUIAdaptor._addProtocol('TabSelectorGUIAdaptor', 'EnablementProtocol');             // Supports enablement
GUIAdaptor._addProtocol('TabSelectorGUIAdaptor', 'FocusProtocol');                  // Supports tabbing and focussing
GUIAdaptor._addProtocol('TabSelectorGUIAdaptor', 'FocusProtocolHTMLImpl');          // Include the default HTML implementation of focus
GUIAdaptor._addProtocol('TabSelectorGUIAdaptor', 'KeybindingProtocol');


/**
 * Holds the currently net enablement state of the adaptor. This takes
 * into account both enablement and activation protocols.
 *
 * @type boolean
 * @private
 */
TabSelectorGUIAdaptor.prototype.m_netEnablementState = true;




/**
 * Create a new TabSelectorGUIAdaptor
 *
 * @param e the checkbox input element to manage
 * @return the new TabSelectorGUIAdaptor
 * @type TabSelectorGUIAdaptor
 */
TabSelectorGUIAdaptor.create = function(element)
{
	if (TabSelectorGUIAdaptor.m_logger.isTrace()) TabSelectorGUIAdaptor.m_logger.trace("TabSelectorGUIAdaptor.create");

	var a = new TabSelectorGUIAdaptor();
	a._initialiseAdaptor(element);
	return a;
}

/**
 * Configure the GUIAdaptor
 *
 * @param cs an Array of configuration objects ordered with
 *   most specific items first.
 */
TabSelectorGUIAdaptor.prototype._configure = function(cs)
{
	this.includeInValidation = false;
}

/**
 * Initialises the instance (called from creation)
 *
 * @param element the element to manage
 */
TabSelectorGUIAdaptor.prototype._initialiseAdaptor = function(e)
{
	HTMLElementGUIAdaptor.prototype._initialiseAdaptor.call(this, e);
	
	// Set tab click handler - overrides the temporary click handler set up by the renderer
	// which allows the tabbed area to function without any adaptors being created.
	var thisObj = this;
	this.m_renderer.setTabClickHandler( function(clickedTab) {thisObj._onTabClick(clickedTab);} );
	
	// Get id of pagedarea
	var pagedAreaId = this.m_renderer._getAssociatedPagedArea().id;
	
	// Copy enablement protocol configuration items from the pagedArea onto this adaptor
	// - saves application developers having to duplicate this configuration.
	var cm = FormController.getInstance().getFormView().getConfigManager();
	var cs = cm.getConfig(pagedAreaId);
	for(var i = 0, l = cs.length; i < l; i++)
	{
		var c = cs[i];
		if((null == this.isEnabled) && (null != c.isEnabled)) this.isEnabled = c.isEnabled;
		if((null == this.enableOn) && (null != c.enableOn)) this.enableOn= c.enableOn;
	}

	// Ensures that the bottom border of the spacer cell is wide enough
	this.m_renderer._setTabSelectorWidth();
}


/**
 * Disposes of all resources (event handlers and references to renderer)
 */
TabSelectorGUIAdaptor.prototype._dispose = function()
{
	this.m_renderer.dispose();	
	this.m_renderer = null;
	this.m_element = null;
}


/**
 * Renders the visual state and event handlers for this
 * adaptor based on its current state
 */
TabSelectorGUIAdaptor.prototype.renderState = function()
{
	if (renderStateChanged (this, this.m_netEnablementState))
	{
		this.m_netEnablementState = !this.m_netEnablementState;
		
		if(this.m_renderer.setEnabled(this.m_netEnablementState))
		{
			this.m_renderer.renderState();
		}
		
		this.m_enabledChanged = false;
	}
	
	if(this.m_focusChanged)
	{
		this.m_renderer.setFocus(this.m_focus);
		this.m_focusChanged = false;
	}
}


TabSelectorGUIAdaptor.prototype._getAssociatedPagedAreaGUIAdaptor = function()
{
	if(null == this.m_associatedPagedArea)
	{
		// Get the paged area associated with the tab selector
		var pagedAreaDiv = this.m_renderer._getAssociatedPagedArea();
		
		if(null == pagedAreaDiv)
		{
			throw new ConfigurationException("TabSelector '" + this.getId() + "' failed to find associated PagedArea div element");
		}

		this.m_associatedPagedArea = Services.getAdaptorById(pagedAreaDiv.id);
		
		if(null == this.m_associatedPagedArea)
		{
			throw new ConfigurationException("TabSelector '" + this.getId() + "' failed to find associated PagedAreaGUIAdaptor '" + pagedAreaDiv.id + "'");
		}
	}
	
	// If the focus changed, then if there is a currently selected tab update it's focussed state appropriately.
	if(this.m_focusChanged)
	{
		var tab = this.m_renderer.getCurrentlySelectedTab();
		if(null != tab)
		{
			if(tab.setFocus(this.m_focus))
			{
				tab.renderState();
			};
		}
	
		this.m_focusChanged = false;
	}
	
	return this.m_associatedPagedArea;
}


TabSelectorGUIAdaptor.prototype._onTabClick = function(clickedTab)
{
	// Get the PagedAreaGUIAdaptor for the PagedArea associated with this TabSelector
	var pagedArea = this._getAssociatedPagedAreaGUIAdaptor();
	
	// Show the page with the associated page
	pagedArea.showPage(clickedTab.getPageId());
}


/**
 * Handle enablement state change for the pagedArea's pages
 *
 * @param pageId the id of the page whose enablement state has changed.
 * @param enabled true if the page is enabled or false if it is disabled
 */
TabSelectorGUIAdaptor.prototype._handlePagedAreaEnablementChanged = function(pageId, enabled)
{
	// One of the pages has changed it's enablement state
	// Get the tab associated with the page
	var tab = this.m_renderer._getTabForPageId(pageId);

	// Not all pages are required to have tabs!
	if(null != tab)
	{
		this.m_renderer.setTabEnablementState(tab, enabled);
	}
}


TabSelectorGUIAdaptor.prototype._handlePagedAreaVisibilityChanged = function(pageId, visible)
{
	var tab = this.m_renderer._getTabForPageId(pageId);

	// Not all pages are required to have tabs!
	if(null != tab)
	{
		this.m_renderer.setTabSelectionState(tab, visible);
	}
}


TabSelectorGUIAdaptor.prototype._handlePagedAreaLabelChanged = function(pageId, label)
{
	var tab = this.m_renderer._getTabForPageId(pageId);

	if(null != tab)
	{
		this.m_renderer.setTabLabel(tab, label)
	}
}


/**
 * Method overridden from FocusProtocol. Can't accept the focus if
 * we don't have any enabled tabs
 *
 * @return true if the component can accept the focus or false to refuse it
 * @type boolean
 */
TabSelectorGUIAdaptor.prototype.acceptFocus = function()
{
	return !this._getAllTabsDisabled();
}


/**
 * Checks whether all tabs on the tabselector are disabled or not
 *
 * @return true if all tabs on the tab selector are disabled, false otherwise
 * @type boolean
 * @private
 */
TabSelectorGUIAdaptor.prototype._getAllTabsDisabled = function()
{
	return this.m_renderer.getAllTabsDisabled();
}


/**
 * Method handles press of left arrow key when tab selector is
 * in focus.
 *
 */
TabSelectorGUIAdaptor.prototype._handleKeyArrowLeft = function()
{
	this.m_renderer.selectPreviousTab();
}


/**
 * Method handles press of right arrow key when tab selector is
 * in focus.
 *
 */
TabSelectorGUIAdaptor.prototype._handleKeyArrowRight = function()
{
	this.m_renderer.selectNextTab();
}


/**
 * Method to handle press of arrow down key when tab selector
 * is in focus.
 *
*/
TabSelectorGUIAdaptor.prototype._handleKeyArrowDown = function()
{
	var tab = this.m_renderer.getCurrentlySelectedTab();
	
	if(null != tab)
	{
		var pageId = tab.getPageId();
	
		var fc = FormController.getInstance();
		
		// Retrieve adaptor for currently selected page
		var pageAdaptor = fc.getAdaptorById(pageId);
        
        // Use the firstFocusedAdaptorId to determine if the application has
        // specified which field should be focussed first when entering the page
        var focusAdaptorId = pageAdaptor.invokeFirstFocusedAdaptorId();
        
        // If none specified then use the first child of the page
        if(null == focusAdaptorId)
        {
        	if(pageAdaptor.m_containedChildren.length > 0)
        	{
        		focusAdaptorId = pageAdaptor.m_containedChildren[0].getId();
        	}
        }
        
        // If we have an adaptor id, then ask TabbingManager to focus on it.
        // TabbingManager will sort out whether or not adaptor can accept focus etc.
        if(null != focusAdaptorId)
        {
        	Services.setFocus(focusAdaptorId);
        }
    }
}


/**
 * Define key bindings
 *
*/
TabSelectorGUIAdaptor.prototype.keyBindings =
[
	{key: Key.ArrowLeft, action: TabSelectorGUIAdaptor.prototype._handleKeyArrowLeft},
	{key: Key.ArrowRight, action: TabSelectorGUIAdaptor.prototype._handleKeyArrowRight},
	{key: Key.ArrowDown, action: TabSelectorGUIAdaptor.prototype._handleKeyArrowDown}
];


//==================================================================
//
// PagedAreaGUIAdaptor.js
//
// Class for adapting a text style input element for use in the
// framework
//
//==================================================================

/**
 * Base class for adapting Page class DIV elements for use in the
 * framework.
 *
 * @param e the input element to manage
 * @constructor
 * @private
 */
function PagedAreaGUIAdaptor(){};


PagedAreaGUIAdaptor.m_logger = new Category("PagedAreaGUIAdaptor");


/**
 * PagedAreaGUIAdaptor is a sub class of HTMLElementGUIAdaptor
 */
PagedAreaGUIAdaptor.prototype = new HTMLElementGUIAdaptor();
PagedAreaGUIAdaptor.prototype.constructor = PagedAreaGUIAdaptor;


/**
 * Add the required protocols to the PagedAreaGUIAdaptor
 */
GUIAdaptor._setUpProtocols('PagedAreaGUIAdaptor'); 
GUIAdaptor._addProtocol('PagedAreaGUIAdaptor', 'ComponentContainerProtocol');		// Contains child components
GUIAdaptor._addProtocol('PagedAreaGUIAdaptor', 'DataBindingProtocol');				// Supports binding to data model
GUIAdaptor._addProtocol('PagedAreaGUIAdaptor', 'EnablementProtocol');				// Supports enablement
GUIAdaptor._addProtocol('PagedAreaGUIAdaptor', 'ReadOnlyProtocol');					// Supports enablement/disablement
GUIAdaptor._addProtocol('PagedAreaGUIAdaptor', 'NameProtocol');						// Supports naming of the element
GUIAdaptor._addProtocol('PagedAreaGUIAdaptor', 'DynamicLoadingProtocol');			// Supports dynamic loading and unloading of pages as a result of DataModel changes


/**
 * CSS classes used to render the page in different states
 */
PagedAreaGUIAdaptor.CSS_CLASS_NAME = "pagedArea";
PagedAreaGUIAdaptor.DISABLED_CSS_CLASS_NAME = "pagedAreaDisabled";
PagedAreaGUIAdaptor.READONLY_CSS_CLASS_NAME = "pagedAreaReadOnly";
PagedAreaGUIAdaptor.NOT_SUBMISSIBLE_CSS_CLASS = "pagedAreaNotSubmissible";


/**
 * The id of the currently selected page. Null if no page selected.
 * Note that this is not necessarily the same as the m_currentPage
 * which is the currently displayed page. m_selectedPageId is used
 * to communicate a newly selected page between showPage() and 
 * getValueFromView().
 *
 * @type String
 * @private
 */
PagedAreaGUIAdaptor.prototype.m_selectedPageId = null;


/**
 * Map of dynamic page configurations, keyed by page id
 *
 * @type Map[Object]
 * @private
 */
PagedAreaGUIAdaptor.prototype.m_dynamicPageConfigs = null



/**
 * Create a new PagedAreaGUIAdaptor
 *
 * @param e the element to manage
 * @return the new PagedAreaGUIAdaptor
 * @type PagedAreaGUIAdaptor
 */
PagedAreaGUIAdaptor.create = function(e)
{
	if (PagedAreaGUIAdaptor.m_logger.isTrace()) PagedAreaGUIAdaptor.m_logger.trace("PagedAreaGUIAdaptor.create");

	var a = new PagedAreaGUIAdaptor();
	a._initialiseAdaptor(e);
	return a;
}


/**
 * Initialises the adaptor instance
 * @private
 */
PagedAreaGUIAdaptor.prototype._initialiseAdaptor = function(e)
{
	// Call the super class.
	HTMLElementGUIAdaptor.prototype._initialiseAdaptor.call(this, e);
}



/**
 * Clean up after the component
 */
PagedAreaGUIAdaptor.prototype._dispose = function()
{
	// Don't think this is necessary, but just incase...
    this.m_element = null;

    // Remove dynamic page configurations
    if(this.m_dynamicPageConfigs != null)
    {
		var cm = FormController.getInstance().getFormView().getConfigManager();
	    			
    	for(var i in this.m_dynamicPageConfigs)
    	{   		
    		// Remove dynamic page configuration from window - only present
    		// if page has been loaded
    		cm.removeConfig(this.m_dynamicPageConfigs[i].id);
    		
    		// Remove dynamic page configuration from array - only present if
    		// if page has never been loaded
    		for(var j in this.m_dynamicPageConfigs[i])
    		{
	    		delete j;
    		}
    		delete this.m_dynamicPageConfigs[i];
    	}
    	this.m_dynamicPageConfigs = null;
    }
}


/**
 * Configure the GUIAdaptor
 *
 * @param cs an Array of configuration objects ordered with
 *   most specific items first.
 * @private
 */
PagedAreaGUIAdaptor.prototype._configure = function(cs)
{
	this.includeInValidation = false;
	
	// No configuration objects
	this._registerStaticPageListeners();
	
	// Dynamic Page Configurations loaded into a map keyed by page id
	var dps = new Object();
	
	for(var i = 0, l = cs.length; i < l; i++)
	{
		var c = cs[i];
		var _showProgress = false;
		
		// Set dynamic page show progress flag from paged area configuration
		if(c.showProgress != null) _showProgress = c.showProgress;
		
		var dynamicPages = c.dynamicPages;
		
		if(dynamicPages != null)
		{
			for(var j = 0, m = dynamicPages.length; j < m; j++)
			{
				var dp = dynamicPages[j];

				this._checkMandatoryCfg(dp, "id");
				this._checkMandatoryCfg(dp, "viewURL");
				this._checkMandatoryCfg(dp, "configURL");
				// ToDo - Do we want the stylesheet to be mandatory?
				//this._checkMandatoryCfg(dp, "styleURL");
				
				// Check for duplicate page ids
				if(dps[dp.id] != null) throw new ConfigurationException("Duplicate dynamic page id: " + dp.id + " in Paged Area: " + this.getId());
				
				// Add show progress bar property for dynamic page. Note that
				// dynamic page configuration overrides paged area configuration
				if(dp.showProgress == null) dp.showProgress = _showProgress;
				
				// Add the page configuration to the map of dynamic pages
				dps[dp.id] = dp;
			}
		}
	}
	
	this.m_dynamicPageConfigs = dps;
}


PagedAreaGUIAdaptor.prototype._checkMandatoryCfg = function(config, propertyName)
{
	var property = config[propertyName];
	if(null == property || "" == property) throw new ConfigurationException(propertyName + " is a madatory configuration property for dynamic pages");
}


/**
 * Register a set of state change listeners with the pages on the paged area.
 *
 * @private
 */
PagedAreaGUIAdaptor.prototype._registerStaticPageListeners = function()
{
	var pageAdaptors = this._getPages();
	
	for(var i = 0, l = pageAdaptors.length; i < l; i++)
	{
		this._registerPageListeners(pageAdaptors[i]);
	}
}


PagedAreaGUIAdaptor.prototype._registerPageListeners = function(pageAdaptor)
{
	var hasAssociatedTabSelector = (this._getAssociatedTabSelector() != null);

	var thisObj = this;
	
	pageAdaptor.addVisibilityChangeListener(function(pageId, visible) { thisObj._pageVisibilityCallback(pageId, visible); });

	// Only care about enablement and label change events on pages if we have a tab selector to reflect them on.
	if(hasAssociatedTabSelector)
	{
		pageAdaptor.addEnablementChangeListener(function(pageId, enabled) { thisObj._pageEnablementCallback(pageId, enabled); });
		pageAdaptor.addLabelChangeListener(function(pageId, label) { thisObj._pageLabelCallback(pageId, label); });
	}
}


/**
 * Update the components visual state based on its internal logical state
 */
PagedAreaGUIAdaptor.prototype.renderState = function()
{   
	if(this.m_valueChanged)
	{
		// Hide currently displayed page.
		if(null != this.m_currentPage)
		{
			this.m_currentPage.show(false);
			
			this.m_currentPage = null;
		}
	
		// If we have a none null pageId, then attempt to locate the page
		if(null != this.m_value && "" != this.m_value)
		{
			// See if current page is staticly defined or dynamic page already loaded
			this.m_currentPage = this._getPageById(this.m_value);
			
			// Page not found - could be a dynamic page
			if(null == this.m_currentPage)
			{
				this.m_currentPage = this._findAndLoadDynamicPage(this.m_value);
			}

			// If we have a page then show it			
			if(null != this.m_currentPage)
			{   
				this.m_currentPage.show(true);
			}
		}
		
		// Reset value changed flag to indicate that adaptor has updated it's value
		this.m_valueChanged = false;
	}
	
	if (renderStateChanged (this, this.m_netEnablementState))
	{
		this.m_netEnablementState = !this.m_netEnablementState;
		
		var className = PagedAreaGUIAdaptor.CSS_CLASS_NAME;
        
		if (this.m_netEnablementState)
		{
			if(!this.getAggregateState().isSubmissible())
			{
				className += " " + PagedAreaGUIAdaptor.NOT_SUBMISSIBLE_CSS_CLASS;
			}
			
			// If paged area is readonly, set appropriate CSS class
			if(this.getReadOnly())
			{
				className += " " + PagedAreaGUIAdaptor.READONLY_CSS_CLASS_NAME;
			}
	    }
	    else
	    {
            className += " " + PagedAreaGUIAdaptor.DISABLED_CSS_CLASS_NAME;
        }
		this.m_element.className = className;
		
		this.m_enabledChanged = false;
	}
}


PagedAreaGUIAdaptor.prototype._getPageById = function(pageId)
{
	var page = null;
	
	// Search through array of statically defined pages and currently loaded pages
	var pageAdaptors = this._getPages();
	for(var i = 0, l = pageAdaptors.length ; i < l ; i++)
	{
		if(pageAdaptors[i].getId() == pageId)
		{
			page = pageAdaptors[i];
			
			// Have found the page referenced by the datamodel
			break;
		}
	}
	
	return page;
}


PagedAreaGUIAdaptor.prototype._findAndLoadDynamicPage = function(pageId)
{
	// The dynamic page GUIAdaptor
	var dynamicPage = null;
	
	// Look up the page using it's id in the configs.
	var pageConfig = this.m_dynamicPageConfigs[pageId];
	
	if(null != pageConfig)
	{
		var fc = FormController.getInstance();
		
		// Show the progress bar if required
		// Defect 1081 fix. Reposition display of
		// progress bar to renderState.
		//if(pageConfig.showProgress == true)
		//{
	    //    var ac = fc.getAppController();
	    //    ac._showProgress();
        //}
        
		// Create and setup the dynamic page div
		var pageDiv = document.createElement("div");
		pageDiv.id = pageId;
		pageDiv.className = DynamicPageGUIAdaptor.CSS_CLASS_NAME;
		pageDiv.innerHTML = "Page Loading...";
		
		// Append the page element to the pagedArea.
		this.m_element.appendChild(pageDiv);
		
		var fv = fc.getFormView();
		var cm = fv.getConfigManager();
		
		// Create the configuration for the page
		cm.setConfig(pageId, pageConfig);
		
		// Create the DynamicPageGUIAdaptor and add it to the FormController
		var gaf = fv.getGUIAdaptorFactory();
		
		var adaptors = gaf._parseElement(pageDiv, this, true);
		
		fc_assert(null != adaptors, "Failed to create DynamicPageGUIAdaptor");
		fc_assert(1 == adaptors.length, "Unexpected number of adaptors created when parsing DynamicPageGUIAdaptor. Expected 1 adaptor, got " + adaptors.length);
		
		dynamicPage = adaptors[0];
		
		// Add the page to the list of pages for the PagedArea.
		this.m_pages.push(dynamicPage);
		
		// Register listeners with page so that the paged area get notified when the page state changes
		this._registerPageListeners(dynamicPage);
		
		// Add the page to the FormController
		fc.addAdaptors(adaptors);
		
	}
	
	return dynamicPage;
}


PagedAreaGUIAdaptor.prototype._destroyDynamicPage = function(pageId)
{
	var page = null;
	
	// Remove required page from list of pages by rebuilding page array without requested page
	var pageAdaptors = this._getPages();
	var newPageAdaptors = [];
	var removedPage = null;
	for(var i = 0, l = pageAdaptors.length ; i < l ; i++)
	{
		var pa = pageAdaptors[i];
		if(pa.getId() != pageId)
		{
			newPageAdaptors.push(pa);
		}
		else
		{
			removedPage = pa;
		}
	}
	
	// Set the m_pages array to the new array which doesn't contain the page being destroyed
	this.m_pages = newPageAdaptors;
	
	// AL - this method can be invoked prior to the page being loaded
	if(removedPage != null)
	{
		// Get the div that represents the page
		var pageDiv = removedPage.getElement();
		
		// If the PagedArea has an associated TabSelector, then notify the TabSelector
		// of the visibility change, so it can update its visual if necessary state.
		var tabbedSelector = this._getAssociatedTabSelector();
		if(null != tabbedSelector)
		{
			tabbedSelector._handlePagedAreaVisibilityChanged(pageId, false);
		}

		// Remove the page and it's children from the FormController
		var fc = FormController.getInstance();
		fc.removeAdaptor(removedPage);

/*
	D874 - This also removes the configuration from m_dynamicPageConfigs, preventing the
	same page from being reloaded. Configuration is now removed in _dispose method

		// Remove dynamic page configuration
		var fv = fc.getFormView();
		var cm = fv.getConfigManager();
		
		cm.removeConfig(pageId);
*/
		// Remove the HTML node so that the page is removed from the view
		pageDiv.parentNode.removeChild(pageDiv);
		
		// If the currently displayed page was removed, remove the reference to the page
		if(removedPage == this.m_currentPage)
		{
			this.m_currentPage = null;
		}
	}
}


/**
 * Get all the pages contained in this Paged Area
 *
 * @return an array of DIV elements which represent the pages inside
 *         this page area.
 * @type Array[HTMLElement]
 * @private
 */
PagedAreaGUIAdaptor.prototype._getPages = function()
{
	if(null == this.m_pages)
	{
		this.m_pages = new Array();
	
		var pageAreaChildren = this.m_element.childNodes;
		for(var i = 0, l = pageAreaChildren.length; i < l; i++)
		{
			var child = pageAreaChildren[i];
			
			// Only interested in child element nodes (ignore text and comment nodes)
			if(child.nodeType == 1)
			{
				// Look for children that are pages
				if(child.nodeName == "DIV" && child.className.indexOf(PageGUIAdaptor.CSS_CLASS_NAME) == 0)
				{
					if(child.id.length > 0)
					{
						var pageAdaptor = Services.getAdaptorById(child.id)
						
						// Page found - add to the array
						this.m_pages.push(pageAdaptor);
					}
				}
				else
				{
					// All children should be divs with class "page" - log an error if this is not the case!
					PagedAreaGUIAdaptor.m_logger.error("PageAreaGUIAdaptor._getPages(): PageArea '" + this.getId() + "' has children which are not pages!");
				}
			}
		}
	}
	
	return this.m_pages;
}


/**
 * Return the tabselector associated with this PagedArea, or null if there is no
 * tabselector associated with this PagedArea
 * 
 * @return the TabSelectorGUIAdaptor associated with this PagedArea or null if
 *   there is no TabSelector associated with this paged area.
 * @type TabSelectorGUIAdaptor
 */
PagedAreaGUIAdaptor.prototype._getAssociatedTabSelector = function()
{
	if(null == this.m_associatedTabSelector)
	{
		// TabSelector and PagedArea should be siblings
		var kids = this.m_element.parentNode.childNodes;
		
		for(var i = 0, l = kids.length; i < l; i++)
		{
			var kid = kids[i];
			
			// Only care about elements of type div with className that corresponds to the tabbed area
			if(1 == kid.nodeType && "DIV" == kid.nodeName && TabSelector.TABSEL_WRAPPER_CSS_CLASS_NAME == kid.className)
			{
				if(kid.id.length > 0)
				{
					this.m_associatedTabSelector = Services.getAdaptorById(kid.id);
				}
				else
				{
					throw new ConfigurationException("TabSelector associated with PagedArea '" + this.getId() + "' must have an id");
				}
				break;
			}
		}
	}
	
	return this.m_associatedTabSelector;
}


/**
 * Show a page given its Id
 *
 * @param pageId the id of page to show
 */
PagedAreaGUIAdaptor.prototype.showPage = function(pageId)
{
	// Set the m_selectedPageId member variable, so that _getValueFromView() can
	// return it when update asks for the components value.
	this.m_selectedPageId = pageId;
	
	// Set the value of the paged area to the pageId and update the model
	this.update();
}


/**
 * Return the adaptors value, which in this case is the selected page (note -
 * not necessarily the same as the m_currentPage (currently displayed page, until
 * after renderState() has been called.
 *
 * @return the selected page id
 * @type String
 * @private
 */
PagedAreaGUIAdaptor.prototype._getValueFromView = function()
{
	return this.m_selectedPageId;
}


/**
 * Handler to process changes in a page's visibility
 *
 * @param pageId the id of page who's visibility has changed
 * @param visible whether the page was made visible (true) or invisible (false)
 * @private
 */
PagedAreaGUIAdaptor.prototype._pageVisibilityCallback = function(pageId, visible)
{
	// If a page is made visible using the visibility protocol, we need to update
	// the PagedArea's value in the DataModel
	if(visible)
	{
		this.showPage(pageId);
	}
	else
	{
		// If the current page has been hidden then the paged area no longer
		// displays a page (has null value)
		if(this.m_currentPage.getId() == pageId)
		{
			this.showPage(null);
		}
	}
	
	// If the PagedArea has an associated TabSelector, then notify the TabSelector
	// of the visibility change, so it can update its visual if necessary state.
	var tabbedSelector = this._getAssociatedTabSelector();
	if(null != tabbedSelector)
	{
		tabbedSelector._handlePagedAreaVisibilityChanged(pageId, visible);
	}
}


/**
 * Handler to process changes in a page's enablement state
 *
 * @param pageId the id of page who's enablement state has changed
 * @param enabled whether the page was enabled (true) or disabled (false)
 * @private
 */
PagedAreaGUIAdaptor.prototype._pageEnablementCallback = function(pageId, enabled)
{
	// If the PagedArea has an associated TabSelector, then notify the TabSelector
	// of the enablement change, so it can update its visual if necessary state.
	var tabbedSelector = this._getAssociatedTabSelector();
	if(null != tabbedSelector)
	{
		tabbedSelector._handlePagedAreaEnablementChanged(pageId, enabled);
	}
}


/**
 * Handler to process changes in a page's label
 *
 * @param pageId the id of page who's label has changed
 * @param label the new label for the page
 * @private
 */
PagedAreaGUIAdaptor.prototype._pageLabelCallback = function(pageId, label)
{
	var tabbedSelector = this._getAssociatedTabSelector();
	if(null != tabbedSelector)
	{
		tabbedSelector._handlePagedAreaLabelChanged(pageId, label);
	}
}


/**
 * Override register method of DynamicLoadingProtocol as we need to
 * register listeners with additional detail to identify which page
 * should be loaded/unloaded
 *
 * @param db 
 */
PagedAreaGUIAdaptor.prototype.getListenersForDynamicLoadingProtocol = function(db)
{
    var listenerArray = new Array();

	// Get configurations
	var cs = this.getConfigs();
	
	// Get paged area dataBinding - pages should always be checked for unloading
	// when this changes
	var dataBinding = this.getDataBinding();

	for(var i = 0, l = cs.length; i < l; i++)
	{
		var c = cs[i];
		
		var dynamicPages = c.dynamicPages;
		
		if(dynamicPages != null)
		{
			for(var j = 0, m = dynamicPages.length; j < m; j++)
			{
				var dp = dynamicPages[j];
				
				var on = dp.loadOn;
				if(null != on && on.length > 0)
				{
					var listener = FormControllerListener.create(this, FormController.LOAD, dp.id);
					
					for(var k = 0, n = on.length; k < n; k++)
					{
                        listenerArray.push({xpath: on[k], listener: listener});
					}
				}

				// Each page monitors the paged area's databinding to see if it can
				// be unloaded (when it is not displayed).
				var listener = FormControllerListener.create(this, FormController.UNLOAD, dp.id);
				listenerArray.push({xpath: dataBinding, listener: listener});
				
				on = dp.unloadOn;				
				if(null != on && on.length > 0)
				{
					for(var k = 0, n = on.length; k < n; k++)
					{
                        listenerArray.push({xpath: on[k], listener: listener});
					}
				}
			}
		}
	}
    
    return listenerArray;
}


/**
 * Method overridden by adaptor to handle a load of a dynamic page
 */
PagedAreaGUIAdaptor.prototype.handleLoad = function(d)
{
	var page = this._getPageById(d);

	// Check if page is already loaded	
	if(null == page)
	{		
		// Create the dynamic page
		page = this._findAndLoadDynamicPage(d);
		
		// If we have a page then show it
		if(page != null)
		{
			this.showPage(d);
		}
	}
}


/**
 * Method overridden by adaptor to handle an unload of a dynamic page
 */
PagedAreaGUIAdaptor.prototype.handleUnload = function(d)
{
	var page = this._getPageById(d);

	// Check if page is loaded	
	if(page != null)
	{
		// Destroy the dynamic page
		this._destroyDynamicPage(d);
	}
}


/**
 * Get load configurations which are to be invoked. Overrides 
 * default method in DynamicLoadingProtocol
 *
 * @param d additional detail parameter registered with listener
 */
PagedAreaGUIAdaptor.prototype.getOnLoadConfigs = function(d)
{
	// Get configurations
	var cs = this.getConfigs();
	
	// Build array of load function configurations
	var configs = [];
	for(var i = 0, l = cs.length; i < l; i++)
	{
		var dynamicPages = cs[i].dynamicPages;
		
		if(null != dynamicPages)
		{
			for(var j = 0, m = dynamicPages.length; j < m; j++)
			{
				if(dynamicPages[j].id == d)
				{
					if(null != dynamicPages[j].load) configs.push(dynamicPages[j].load);
				}
			}
		}
	}
	
	return configs;
}


/**
 * Get unload configurations which are to be invoked. Overrides 
 * default method in DynamicLoadingProtocol
 *
 * @param d additional detail parameter registered with listener
 */
PagedAreaGUIAdaptor.prototype.getOnUnloadConfigs = function(d)
{
	// Get configurations
	var cs = this.getConfigs();
	
	// Build array of load function configurations
	var configs = [];

	// Add configurations for individual pages	
	for(var i = 0, l = cs.length; i < l; i++)
	{
		var dynamicPages = cs[i].dynamicPages;
		
		if(null != dynamicPages)
		{
			for(var j = 0, m = dynamicPages.length; j < m; j++)
			{
				if(dynamicPages[j].id == d)
				{
					// Add a dynamically generated unload() function that prevents
					// the page being unloaded if it is currently displayed
					var thisObj = this;
					configs.push( function(d) { return thisObj.m_value != d; });
					
					// Add any unload configuration methods that the user has configured
					if(null != dynamicPages[j].unload) configs.push(dynamicPages[j].unload);
				}
			}
		}
	}
	
	return configs;
}


/**
 * Return all the id's of the DynamicPages defined on the PagedArea,
 * so that they can be loaded at initialisation time if necessary
 *
 */
PagedAreaGUIAdaptor.prototype._getDynamicLoadingDetails = function()
{
	// Get configurations
	var cs = this.getConfigs();
	
	var details = [];
	
	for(var i = 0, l = cs.length; i < l; i++)
	{
		var dynamicPages = cs[i].dynamicPages;
		
		if(null != dynamicPages)
		{
			for(var j = 0, m = dynamicPages.length; j < m; j++)
			{
				details.push({m_detail: dynamicPages[j].id});
			}
		}
	}
	
	return details;
}
//==================================================================
//
// PageGUIAdaptor.js
//
// Class for implementing tabbed diaglouges for use in the
// framework
//
//==================================================================

/**
 * Base class for adapting html input elements for use in the
 * framework.
 *
 * @param e the input element to manage
 * @constructor
 * @private
 */
function PageGUIAdaptor(){};


/**
 * PageGUIAdaptor is a sub class of HTMLElementGUIAdaptor
 */
PageGUIAdaptor.prototype = new HTMLElementGUIAdaptor();
PageGUIAdaptor.prototype.constructor = PageGUIAdaptor;


/**
 * Add the required protocols to the PageGUIAdaptor
 * Note: Does not use FieldElement etc. as did not want to inherit mandatory protocol
 */
GUIAdaptor._setUpProtocols('PageGUIAdaptor'); 
GUIAdaptor._addProtocol('PageGUIAdaptor', 'EnablementProtocol');            // Supports enablemen
GUIAdaptor._addProtocol('PageGUIAdaptor', 'ReadOnlyProtocol');			// Supports enablement/disablement
GUIAdaptor._addProtocol('PageGUIAdaptor', 'LabelProtocol');            // Supports labelling
GUIAdaptor._addProtocol('PageGUIAdaptor', 'ComponentContainerProtocol');				// 
GUIAdaptor._addProtocol('PageGUIAdaptor', 'ComponentVisibilityProtocol');


/**
 * CSS classes used to render the page in different states
 */
PageGUIAdaptor.CSS_CLASS_NAME = "page";
PageGUIAdaptor.DISABLED_CSS_CLASS_NAME = "pageDisabled";
PageGUIAdaptor.READONLY_CSS_CLASS_NAME = "pageReadOnly";
PageGUIAdaptor.NOT_SUBMISSIBLE_CSS_CLASS = "pageNotSubmissible";


/**
 * Holds the currently net enablement state of the adaptor. This takes
 * into account both enablement and activation protocols.
 *
 * @type boolean
 * @private
 */
PageGUIAdaptor.prototype.m_netEnablementState = true;


/**
 * Callback list containing listeners to page enablement state changes
 *
 * @type CallbackList
 * @private
 */
PageGUIAdaptor.prototype.m_enablementCallbackList = null;


/**
 * Callback list containing listeners to page label changes
 *
 * @type CallbackList
 * @private
 */
PageGUIAdaptor.prototype.m_label_callbacklist = null;


/**
 * Callback list containing listeners to page visibility state changes
 *
 * @type CallbackList
 * @private
 */
PageGUIAdaptor.prototype.m_visibility_callbacklist = null;


/**
 * Create a new PageGUIAdaptor
 *
 * @param e the checkbox input element to manage
 * @return the new PageGUIAdaptor
 * @type PageGUIAdaptor
 */
PageGUIAdaptor.create = function(element)
{
	Logging.logMessage("PageGUIAdaptor.create", Logging.LOGGING_LEVEL_TRACE);

	var a = new PageGUIAdaptor();
	a._initialiseAdaptor(element);
	return a;
}


/**
 * Initialise the adaptor - override method in HTMLGUIAdaptor
 *
 * @param e the outermost html div element that represents the page
 * @private
 */
PageGUIAdaptor.prototype._initialiseAdaptor = function(e)
{
	// Call the super class.
	HTMLElementGUIAdaptor.prototype._initialiseAdaptor.call(this, e);
	
	// Setup callback lists
	this.m_enablementCallbackList = new CallbackList();
	this.m_label_callbacklist = new CallbackList() ;
	this.m_visibility_callbacklist = new CallbackList() ;
}


/**
 * Cleanup any reference loops between the JavaScript and the DOM 
 */
PageGUIAdaptor.prototype._dispose = function()
{
    // Clean up callback function lists    
	this.m_enablementCallbackList.dispose();
	this.m_label_callbacklist.dispose();
	this.m_visibility_callbacklist.dispose();
	
	this.m_enablementCallbackList = null;
	this.m_label_callbacklist = null;
	this.m_visibility_callbacklist = null;
}

/**
 * Configure the GUIAdaptor
 *
 * @param cs an Array of configuration objects ordered with
 *   most specific items first.
 */
PageGUIAdaptor.prototype._configure = function(cs)
{
	this.includeInValidation = false;
}


/**
 * Add listener that wants to hear changes in the page's enablement state
 *
 * @param callbackMethod the function to call when the page's enablement state changes
 */
PageGUIAdaptor.prototype.addEnablementChangeListener = function(callbackMethod)
{
	this.m_enablementCallbackList.addCallback(callbackMethod);
}


/**
 * Add listener that wants to hear changes in the page's label
 *
 * @param callbackMethod the function to call when the page's label changes
 */
PageGUIAdaptor.prototype.addLabelChangeListener = function(callbackMethod)
{
	this.m_label_callbacklist.addCallback(callbackMethod);
}


/**
 * Add listener that wants to hear changes in the page's visibility
 *
 * @param callbackMethod the function to call when the page's visibility changes
 */
PageGUIAdaptor.prototype.addVisibilityChangeListener = function(callbackMethod)
{	
	this.m_visibility_callbacklist.addCallback(callbackMethod);
}


/**
 * Update the components visual state based on its internal logical state
 */
PageGUIAdaptor.prototype.renderState = function()
{
    // Check to see if the adaptor needs to be re-rendered.
    if (renderStateChanged (this, this.m_netEnablementState))
    {
        this.m_netEnablementState = !this.m_netEnablementState;
        
        var className = PageGUIAdaptor.CSS_CLASS_NAME;
        if (this.m_netEnablementState)
        {
			if(!this.getAggregateState().isSubmissible())
			{
				className += " " + PageGUIAdaptor.NOT_SUBMISSIBLE_CSS_CLASS;
			}

			// If page is readonly, set appropriate CSS class
			if(this.getReadOnly())
			{
				className += " " + PageGUIAdaptor.READONLY_CSS_CLASS_NAME;
			}
	    }
	    else
	    {
            className += " " + PageGUIAdaptor.DISABLED_CSS_CLASS_NAME;
        }
		this.m_element.className = className;

		// Notify any listeners (usually the parent PagedAreaGUIAdaptor) of
		// the enablement state change. This is so that the PagedAreaGUIAdaptor
		// can notify the tab associated with this page that the page is disabled
		// so that the tab can be rendered as disabled.		
		this.m_enablementCallbackList.invoke(this.getId(), this.m_netEnablementState);
		
		this.m_enabledChanged = false;
	}	
	if ( true == this.m_labelChanged )
	{
		// Notify any label change listeneres (usually the parent PagedAreaGUIAdaptor)
		// of the label change. This is so that the PagedAreaGUIAdaptor can notify
		// the tab associated with this page that the page's label has change and so
		// the label on the tab should change.
		this.m_label_callbacklist.invoke(this.getId(), this.m_label);
		this.m_labelChanged = false ;
	}
}


/**
 * Show the page (implements required method supplied by the 
 * ComponentVisibilityProtocol).
 *
 * @param showMe true if the page is to shown or false if it is to hidden.
 */
PageGUIAdaptor.prototype.show = function(showMe)
{
	// Make the page visibile or not. Note that VISIBILITY_INHERIT means that page becomes visible if
	// it's parents are visible - our definition of visible in this case.
	this.m_element.style.visibility = showMe ? TabSelector.VISIBILITY_INHERIT : TabSelector.VISIBILITY_HIDDEN;

	// D231 - stop the hidden pages border showing through autocompletes etc drop downs by 
	// raising the visible page above the hidden pages in the z-order. (The default stacking
	// order is bottom-to-top in the order that the elements appear in the HTML source.)
	this.m_element.style.zIndex = showMe ? 1 : 0;

	// Notify any visibility change listeners (usually the parent PagedAreaGUIAdaptor)
	// of the visibility state change. This is so that the PagedAreaGUIAdaptor can notify
	// the tab associated with this page that the page's visibility has changed so
	// that the 
	this.m_visibility_callbacklist.invoke(this.m_element.id, showMe);
}

//==================================================================
//
// DynamicPageGUIAdaptor.js
//
// Class for implementing Dynamic pages (loaded during the lifetime
// of the form) within Paged Areas
//
//==================================================================


/**
 * Dynamic Page GUIAdaptor for pages on PagedArea
 *
 * @constructor
 * @private
 */
function DynamicPageGUIAdaptor(){};


/**
 * DynamicPageGUIAdaptor is a sub class of PageGUIAdaptor
 */
DynamicPageGUIAdaptor.prototype = new PageGUIAdaptor();

/**
 * Add the required protocols to the DynamicPageGUIAdaptor
 */
GUIAdaptor._setUpProtocols('DynamicPageGUIAdaptor'); 


DynamicPageGUIAdaptor.prototype.constructor = DynamicPageGUIAdaptor;


/**
 * CSS classes used to render the page in different states
 */
DynamicPageGUIAdaptor.CSS_CLASS_NAME = "dynamicPage " + PageGUIAdaptor.CSS_CLASS_NAME;


/**
 * Loading states of a DynamicPage
 */
DynamicPageGUIAdaptor.STATE_CREATED = 0;
DynamicPageGUIAdaptor.STATE_LOADING = 1;
DynamicPageGUIAdaptor.STATE_LOADED = 2;


/**
 * Regular expression used to re-write inline component creation
 * scripts from the form:
 *  xxxRenderer.createInline(param1, param2);
 * to:
 *  xxxRenderer.createAsInnerHTML(document.getElementById("_scriptId", Renderer.AFTER_ELEMENT, param1, param2);
 *
 * @type RegExp
 * @private
 */
DynamicPageGUIAdaptor.SCRIPT_REWRITE_REGEX = new RegExp("createInline([^(]*)\\(");


/**
 * Loading state of the DynamicPage
 *
 * @type integer
 * @private
 */
DynamicPageGUIAdaptor.prototype.m_loadingState = DynamicPageGUIAdaptor.STATE_CREATED;


/**
 * URL of the HTML containing the dynamic panel
 *
 * @type String
 * @private
 */
DynamicPageGUIAdaptor.prototype.m_viewURL = null;

/**
 * Reference to script tag which contains configuration for
 * dynamic page
 *
*/
DynamicPageGUIAdaptor.prototype.m_configScript = null;


/**
 * Reference to LINK element which loads the CSS styles for the Dynamic Page
 *
 * @type HTMLElement
 * @private
 */
DynamicPageGUIAdaptor.prototype.m_stylesheetLink = null;


/**
 * Reference to the Dynamic Page's CSS styles onload event handler
 *
 * @type Object
 * @private
 */
DynamicPageGUIAdaptor.prototype.m_onLoadHandlerKey = null;

/**
 * Reference to exception raised whilst creating and configuring
 * the contents of the dynamic page.
 *
 * @type Object
 * @private
*/
DynamicPageGUIAdaptor.prototype.m_pageCreationException = null;

/**
 * Create a new PageGUIAdaptor
 *
 * @param e the div element that represents the outer div of the page
 * @return the new PageGUIAdaptor
 * @type PageGUIAdaptor
 */
DynamicPageGUIAdaptor.create = function(e)
{
	Logging.logMessage("PageGUIAdaptor.create", Logging.LOGGING_LEVEL_TRACE);

	var a = new DynamicPageGUIAdaptor();
	a._initialiseAdaptor(e);
	return a;
}


/**
 * Initialise the adaptor - override method in PageGUIAdaptor
 *
 * @param e the outermost html div element that represents the page
 * @private
 */
DynamicPageGUIAdaptor.prototype._initialiseAdaptor = function(e)
{
	// Call the super class.
	PageGUIAdaptor.prototype._initialiseAdaptor.call(this, e);
}


/**
 * Clean up after the component 
 */
DynamicPageGUIAdaptor.prototype._dispose = function()
{
    // Remove configuration script from document
    if(null != this.m_configScript)
    {
        this.m_configScript.parentNode.removeChild(this.m_configScript);
        this.m_configScript = null;
    }
    
    // Remove style sheet reference from document
	if(null != this.m_stylesheetLink)
	{
		// Remove the HTML LINK node so that the dynamic page's stylesheet is removed from the document
		this.m_stylesheetLink.parentNode.removeChild(this.m_stylesheetLink);
		this.m_stylesheetLink = null;
	}
	
	// Clean references to general properties
	this.m_viewURL = null;
	this.m_configURL = null;
	this.m_styleURL = null;
	this.m_cssLoaded = null;
	
	// In case of CSS load failure remove style sheet onload handler
	if(null != this.m_onLoadHandlerKey)
	{
		SUPSEvent.removeEventHandlerKey(this.m_onLoadHandlerKey);
		this.m_onLoadHandlerKey = null;
	}
	
	// Call the super class.
	PageGUIAdaptor.prototype._dispose.call(this);
}


/**
 * Configure the GUIAdaptor
 *
 * @param cs an Array of configuration objects ordered with
 *   most specific items first.
 * @private
 */
DynamicPageGUIAdaptor.prototype._configure = function(cs)
{
	for(var i = 0, l = cs.length; i < l; i++)
	{
		var c = cs[i];
		if(null == this.m_viewURL && null != c.viewURL) this.m_viewURL = c.viewURL;
		if(null == this.m_configURL && null != c.configURL) this.m_configURL = c.configURL;
		if(null == this.m_styleURL && null != c.styleURL) this.m_styleURL = c.styleURL;
		if(null == this.m_showProgress && null != c.showProgress) this.m_showProgress = c.showProgress;
	}
	
	// Default page specific CSS loaded flag if no style URL
	if(null == this.m_styleURL) this.m_cssLoaded = true;
	
	// Default value for show progress bar
	if(null == this.m_showProgress) this.m_showProgress = false;	
}


/**
 * Show the page. If the dynamic page is not loaded it starts loading
 *
 * @param showMe true if the page is to shown or false if it is to hidden.
 */
DynamicPageGUIAdaptor.prototype.show = function(showMe)
{
	// Call the super class show method
	PageGUIAdaptor.prototype.show.call(this, showMe);

	// Load the page if necessary
	if(showMe)
	{
	    if(this.m_loadingState == DynamicPageGUIAdaptor.STATE_CREATED)
	    {
	        // Note that the progress bar need be displayed only if
	        // the dynamic page is being created for the first time.
	        // Some applications do not load and unload a dynamic
	        // page each time it is displayed.
	        if(this.m_showProgress == true)
	        {
	            var ac = FormController.getInstance().getAppController();
	            ac._showProgress();
	        }
	    }
	    
		// Invoke the page load in a timeout to allow the "Page loading ..."
		// message and/or progress bar to be rendered
		var thisObj = this;
		setTimeout(function() { thisObj._loadPage(); }, 0);
	}
}


/**
 * Load's the contents of the dynamic page if necessary
 *
 * @private
 */
DynamicPageGUIAdaptor.prototype._loadPage = function()
{
	// If we haven't already loaded the page, and aren't in the process
	// of loading it, then start loading it now 
	if(DynamicPageGUIAdaptor.STATE_CREATED == this.m_loadingState)
	{
		var thisObj = this;

		this.m_loadingState = DynamicPageGUIAdaptor.STATE_LOADING;
		this.m_configLoadingState = DynamicPageGUIAdaptor.STATE_LOADING;
		
		// Attach the javascript config file
		this.m_configScript = document.createElement("script");
		
		// Defect 1081. Following the delay in loading dynamic pages
		// to allow the progress bar to be raised the order of the 
		// next two statements has been important. Previously, the
		// script source code was loaded before the script tag was 
		// attached to the document body. However, this seemed to
		// cause IE to crash which is not desirable.
		document.body.appendChild(this.m_configScript);
		this.m_configScript.src = this.m_configURL;

		// Load the page specific stylesheet
		if(this.m_styleURL != null)
		{
			var headElement = GUIUtils.getDocumentHeadElement(document);
			this.m_stylesheetLink = GUIUtils.createStyleLinkElement(headElement, this.m_styleURL, null);
			
			// Set stylesheet not yet loaded
			this.m_cssLoaded = false;
			
			if(HTMLView.isIE)
			{
			    // Add onload event handler to page specific stylesheet link element
			    this.m_onLoadHandlerKey = SUPSEvent.addEventHandler(this.m_stylesheetLink, "load", function() { thisObj._pageCSSLoaded(); });
			}
			else
			{
				// Invoke onload event handler immediately on non IE browsers
				this._pageCSSLoaded();
			}
		}

		// Create a temporary iframe into which the dynamic page content will be loaded		
		var iframe = document.createElement("iframe");
		iframe.style.visibility = "hidden";

		// Temporarily append the iframe to the page - it is removed once page loading is completed.
		document.body.parentNode.appendChild(iframe);
		
		// Create a fwFrameManager around the iframe to handle the actual content loading.
		this.m_iframe = fwFrameManager.create(iframe);
		this.m_iframe.addLoadCompleteListener(function(errMsg) {thisObj._iframeLoaded(errMsg);});
			
		// Start loading the view
		this.m_iframe.load(this.m_viewURL);
	}
}

/**
 * Method sets up and configures dynamic page. The innerHTML of the temporary
 * iframe is copied into the dynamic page div. The javascript tags within
 * the HTML DOM are modified and then executed. Lastly, the method
 * _pageAndConfigReady is invoked to create and configure the corresponding
 * adaptors.
 *
 * @param errorMessage If an error occurs loading the HTML, or a later
 *                     error is raised by this method and the method invoked 
 *                     a second time by the caller method, the parameter
 *                     errorMessage contains details of the error.
 *
*/
DynamicPageGUIAdaptor.prototype._iframeLoaded = function(errorMessage)
{
    var destroyIframe = true;

	if(null == errorMessage)
	{
	    
	    try
	    {
		    // Get iframe's document
		    var iframe = this.m_iframe.getFrame();
		    var iframeDoc = getIframeDocument(iframe);
		
		    // Search for the dynamic panel - looking for a div with CSS class=DynamicPageGUIAdaptor.CSS_CLASS_NAME ("dynamicPage page")
		    var divs = iframeDoc.getElementsByTagName("DIV");
		
		    var i = 0;
		    var l = divs.length;
		    for(i = 0; i < l; i++)
		    {
			    if(DynamicPageGUIAdaptor.CSS_CLASS_NAME == divs[i].className) break;
		    }
	
		    if(i < l)
		    {
			    // Found dynamic page div, so copy across the html.
			    var innerHTML = divs[i].innerHTML;
			    this.m_element.innerHTML = innerHTML;
			
			    // Rewrite and execute each inline script
			    var scripts = this.m_element.getElementsByTagName("SCRIPT");
			    for(i = 0, l = scripts.length; i < l; i++)
			    {
				    var script = scripts[i];
				    var scriptText = script.innerHTML.replace(
					    DynamicPageGUIAdaptor.SCRIPT_REWRITE_REGEX,
					    "createAsInnerHTML$1(scriptTag, Renderer.AFTER_ELEMENT, "
				    );
				
				    // Create a new function to execute rewritten function in.
				    var fn = new Function(
					    "scriptTag",		// Re-written function requires scriptTag argument
					    scriptText			// The re-written script which makes up the body of the Function
				    );
				
				    // Call the function, passing in the script element reference in as an argument.
				    fn.call(null, script);
			    }
	
			    // View is ready.
			    this.m_loadingState = DynamicPageGUIAdaptor.STATE_LOADED;

			    // Check if config is loaded and if it is start adding adaptors to the form controller.
			    if(DynamicPageGUIAdaptor.STATE_LOADED == this.m_configLoadingState)
			    {
				    this._pageAndConfigReady(true);
			    }
		    }
		    else
		    {
			    // Failed to find dynamic page div
			    throw new fwException( "Failed to load page. Couldn't find DynamicPanel." );
		    }
		    
		}
		catch(ex)
		{
		    // Exception may be caused by exception in page creation or failure to locate
		    // dynamic page div.
            
            // Exception handling depends on debug mode of application
            if(FormController.getDebugMode() == false)
            {
                // First hide progress bar
                this._hideProgressBar();
                
                // Production mode so handle exception as fatal error
                destroyIframe = false;
                
                // Store exception for delayed handling
                this.m_pageCreationException = ex;
                
                var thisObj = this;
                setTimeout( function(){ thisObj._handlePageCreationException(); }, 0 );
            }
            else
            {
                // Debug mode. Throw exception to be handled by loading mechanism.
                throw ex;
            }
		}
	}
	else
	{
	    // Input error message was not null.
		this.m_element.innerHTML = "Failed to load page. Error message was:<br>" + errorMessage;

		this._hideProgressBar();
	}
		
	if(destroyIframe)
	{	
	    // Remove iframe - needs to be done after event handler has finished executing
	    var thisObj = this;
	    setTimeout(function() { thisObj._destroyIframe(); }, 0);
	}
}


DynamicPageGUIAdaptor.prototype._configLoaded = function()
{
	this.m_configLoadingState = DynamicPageGUIAdaptor.STATE_LOADED;
	
	if(DynamicPageGUIAdaptor.STATE_LOADED == this.m_loadingState)
	{
		this._pageAndConfigReady();
	}
}

/**
 * Method sets up dynamic page adaptors after the associated HTML, javascript
 * configuration and stylesheet pages have been loaded.
 *
 * @param exceptionsHandledExternally Optional boolean flag that indicates
 *                                    whether or not exceptions thrown by
 *                                    the method will be handled in a
 *                                    try/catch method further up the
 *                                    call stack. If not defined the value is
 *                                    assumed to be "false".
 *
*/
DynamicPageGUIAdaptor.prototype._pageAndConfigReady = function( exceptionsHandledExternally )
{
	// If stylesheet is loaded as well then we're all good, so add adaptors
	// to page. Otherwise wait a while to give stylesheet a chance to load.
	if(this.m_cssLoaded)
	{
	    if(exceptionsHandledExternally == true)
	    {
	        // Set up adaptors for dynamic page components
		    this._createAndConfigureAdaptors();
		
		    // If necessary hide progress bar
		    this._hideProgressBar();
		}
		else
		{
		    // Exceptions must be handled by this method
		    var progressBarHidden = false;
		    
		    try
		    {
		        // Set up adaptors for dynamic page components
		        this._createAndConfigureAdaptors();
		
		        // If necessary hide progress bar
		        this._hideProgressBar();
		        
		        progressBarHidden = true;
		        
		    }
		    catch(ex)
		    {
		        if(!progressBarHidden)
		        {
		            this._hideProgressBar();
		        }
		        
		        // Handle exception
		        if(FormController.getDebugMode() == false)
		        {
		            var fwEx = ex instanceof fwException ? ex : new fwException( ex.message );
		            
		            fwException.invokeFatalExceptionHandler( fwEx );
		        }
		        else
		        {
		            // Set content of dynamic page inner HTML
		            this.m_element.innerHTML = "Failed to load page. Error message was:<br>" +
		                                       ex.message;
		        }
		    }  // End of catch block
		}
	}
	else
	{   
		var thisObj = this;
		setTimeout(function() { thisObj._pageAndConfigReady(); }, 50);
	}
	
}


DynamicPageGUIAdaptor.configLoadComplete = function(pageId)
{
	Services.getAdaptorById(pageId)._configLoaded();
}


DynamicPageGUIAdaptor.prototype._destroyIframe = function()
{
	// Hang on to iframe itself
	var iframe = this.m_iframe.getFrame();
	
	// Dispose of the fwFrameManager class
	this.m_iframe.dispose();
	this.m_iframe = null;
	
	// Remove the iframe
	iframe.parentNode.removeChild(iframe);
}


DynamicPageGUIAdaptor.prototype._pageCSSLoaded = function()
{
	// Set stylesheet now loaded
	this.m_cssLoaded = true;
	
	// Remove page stylesheet onload handler
	if(null != this.m_onLoadHandlerKey)
	{
		SUPSEvent.removeEventHandlerKey(this.m_onLoadHandlerKey);
		this.m_onLoadHandlerKey = null;
	}
}

DynamicPageGUIAdaptor.prototype._handlePageCreationException = function()
{
    // Process stored exception
    var ex = this.m_pageCreationException;
    this.m_pageCreationException = null;
    
    ex = ex instanceof fwException ? ex : new fwException( ex.message );
    
    // Remove temporary iframe
    this._destroyIframe();
    
    // Handle exception
    fwException.invokeFatalExceptionHandler( ex );
}     

/**
 * Method creates, configures and, if necessary, initialises the
 * adaptors for the dynamic page's components.
 *
*/
DynamicPageGUIAdaptor.prototype._createAndConfigureAdaptors = function()
{
    var fc = FormController.getInstance();
    
    // Create the DynamicPageGUIAdaptor and add it to the Form Controller
	var gaf = fc.getFormView().getGUIAdaptorFactory();
		
	// Get adaptors which are children of this page
	var adaptors = gaf._parseElement(this.m_element, this, false);
		
	// Add the page to the Form Controller
	fc.addAdaptors(adaptors);
		
	// Run initialise methods for dynamic page adaptors
	fc.runInitialiseLifecycle(adaptors);
}

/**
 * Method hides progress bar if dynamic page has been configured
 * to display progress bar when loaded.
 *
 */
DynamicPageGUIAdaptor.prototype._hideProgressBar = function()
{
    if(this.m_showProgress)
    {
        var ac = FormController.getInstance().getAppController();
        ac._hideProgress();
    }
}
//==================================================================
//
// PanelGUIAdaptor.js
//
// Class for implementing a generic container adaptor used to set container
// level enablement and read-only states that propogate to all contained children.
//
//==================================================================

/**
 * Base class for adapting html input elements for use in the
 * framework.
 *
 * @param e the input element to manage
 * @constructor
 * @private
 */
function PanelGUIAdaptor(){};

/**
 * PanelGUIAdaptor is a sub class of HTMLElementGUIAdaptor
 */
PanelGUIAdaptor.prototype = new HTMLElementGUIAdaptor();
PanelGUIAdaptor.prototype.constructor = PanelGUIAdaptor;

PanelGUIAdaptor.CSS_CLASS_NAME = "panel";
PanelGUIAdaptor.CSS_NO_MARGIN_CLASS_NAME = "panel noMargin";
PanelGUIAdaptor.DISABLED_CSS_CLASS_NAME = "panel_disabled";

/**
 * Add the required protocols to the PanelGUIAdaptor
 * Note: Does not use FieldElement etc. as did not want to inherit mandatory protocol
 */
GUIAdaptor._setUpProtocols('PanelGUIAdaptor'); 
GUIAdaptor._addProtocol('PanelGUIAdaptor', 'EnablementProtocol');            // Supports enablemen
GUIAdaptor._addProtocol('PanelGUIAdaptor', 'ReadOnlyProtocol');			// Supports enablement/disablement
GUIAdaptor._addProtocol('PanelGUIAdaptor', 'ComponentContainerProtocol');				// 


/**
 * The initial CSS class of the panel. Need to keep this as divs
 * with different CSS classes result in a PanelGUIAdaptor being
 * created
 *
 * @private
 * @type String
 */
PanelGUIAdaptor.prototype.m_cssClass = null;


/**
 * Create a new PanelGUIAdaptor
 *
 * @param e the checkbox input element to manage
 * @return the new PanelGUIAdaptor
 * @type PanelGUIAdaptor
 */
PanelGUIAdaptor.create = function(element)
{
	Logging.logMessage("PanelGUIAdaptor.create", Logging.LOGGING_LEVEL_TRACE);

	var a = new PanelGUIAdaptor();
	a._initPanelGUIAdaptor(element);
	return a;
}

PanelGUIAdaptor.prototype._initPanelGUIAdaptor = function(element)
{
	// Store the original CSS class
	this.m_cssClass = element.className;
	
	// Call parent class initialisation
	HTMLElementGUIAdaptor.prototype._initialiseAdaptor.call(this, element);
}

PanelGUIAdaptor.prototype._dispose = function()
{
	this.m_element = null;
}

PanelGUIAdaptor.prototype.renderState = function()
{
	// Start with the original CSS class that the panel was created with
	var className = this.m_cssClass;
	
	// If the panel is disabled or inactive then render it as disabled.
	if((this.supportsProtocol("EnablementProtocol") && !this.getEnabled())
	    || (this.supportsProtocol("ActiveProtocol") && !this.isActive()))
	{
		className += (" " + PanelGUIAdaptor.DISABLED_CSS_CLASS_NAME);
	}
	
	// The elements class name so that it is rendered correctly
	this.m_element.className = className;
}
