/**
 * Methods that are invoked following events on the menu bar
 *
*/

MenuRenderer.prototype._handleMenuOptionMouseOver = function(evt)
{   
    evt = (evt) ? evt : ((event) ? event : null );
    
    var targetElement = SUPSEvent.getTargetElement(evt);
    
    if(targetElement.id == this.m_element.id)
    {
        this.m_menuOptionMouseOver_callbackList.invoke(evt);
    }
}

MenuRenderer.prototype._handleMenuOptionMouseOut = function(evt)
{
    evt = (evt) ? evt : ((event) ? event : null );
    
    var targetElement = SUPSEvent.getTargetElement(evt);
    
    if(targetElement.id == this.m_element.id)
    {
        this.m_menuOptionMouseOut_callbackList.invoke(evt);
    }
}

MenuRenderer.prototype._handleMenuOptionMouseDown = function(evt)
{
    
    evt = (evt) ? evt : ((event) ? event : null );
    
    var targetElement = SUPSEvent.getTargetElement(evt);
    
    if(null != targetElement)
    {
    
        if(targetElement.id == this.m_element.id)
        {
        
            // Genuine click on menu button
    
            if(!this.m_hasMouseCapture)
            {
        
                if(MenuRenderer.isIE)
                {
                    if(!this.m_mouseCaptureLost)
                    {
                        this._captureMouseEvents();
                        
                        //this.m_menuOptionMouseDown_callbackList.invoke(true);
                        this.m_menuOptionMouseDown_callbackList.invoke(null);
                    }
                    
                    SUPSEvent.stopPropagation(evt);
                }
                else if(MenuRenderer.isMoz)
                {
                    this._captureMouseEvents();
                    
                    //this.m_menuOptionMouseDown_callbackList.invoke(true);
                    this.m_menuOptionMouseDown_callbackList.invoke(null);
                }
        
            }
            else
            {
                // IE passes clicks on menu option here even though
                // mouse capture is active
                if(MenuRenderer.isIE)
                {
                    // Redirect to general mouse click handler
                    this._handleClickIE();
                }
        
            }
            
        }
        
    }
    
    // Flag mouse capture lost as false
    if(MenuRenderer.isIE)
    {
        this.m_mouseCaptureLost = false;
    }
    
}

/**
 * Methods to start event handlers on menu button
 *
*/

MenuRenderer.prototype.startMenuEventHandlers = function()
{
    this._startMenuButtonEventHandlers();
}

MenuRenderer.prototype._startMenuButtonEventHandlers = function()
{
    var thisObj = this;
    
    // Start with mouse over and mouse out handlers
    
    if(null == this.m_menuOptionMouseOverHandler)
    {
        this.m_menuOptionMouseOverHandler = SUPSEvent.addEventHandler( this.m_element,
                                                                       "mouseover",
                                                                       function(evt){ return thisObj._handleMenuOptionMouseOver(evt);});
    }
    
    if(null == this.m_menuOptionMouseOutHandler)
    {
        this.m_menuOptionMouseOutHandler = SUPSEvent.addEventHandler( this.m_element,
                                                                      "mouseout",
                                                                      function(evt){ return thisObj._handleMenuOptionMouseOut(evt);});
                                                                      
    }
    
    // Mouse down handler
    
    if(null == this.m_menuOptionMouseDownHandler)
    {
        this.m_menuOptionMouseDownHandler = SUPSEvent.addEventHandler( this.m_element,
                                                                       "click",
                                                                       function(evt){ return thisObj._handleMenuOptionMouseDown(evt);});
                                                                       
    }
    
}

/**
 * Methods to stop event handlers on menu button
 *
*/

MenuRenderer.prototype.stopMenuEventHandlers = function()
{
    this._stopMenuButtonEventHandlers();
}

MenuRenderer.prototype._stopMenuButtonEventHandlers = function()
{

    // Stop mouse over and mouse out handlers
    
    if(null != this.m_menuOptionMouseOverHandler)
    {
        SUPSEvent.removeEventHandlerKey(this.m_menuOptionMouseOverHandler);
        this.m_menuOptionMouseOverHandler = null;
    }
    
    if(null != this.m_menuOptionMouseOutHandler)
    {
        SUPSEvent.removeEventHandlerKey(this.m_menuOptionMouseOutHandler);
        this.m_menuOptionMouseOutHandler = null;
    }
    
    if(null != this.m_menuOptionMouseDownHandler)
    {
        SUPSEvent.removeEventHandlerKey(this.m_menuOptionMouseDownHandler);
        this.m_menuOptionMouseDownHandler = null;
    }

}

/**
 * Methods invoked by menu panel renderers following events
 * on menu panels
 *
*/

MenuRenderer.prototype.handleMenuPanelItemMouseOver = function(menuPanelId,
                                                               menuItemPos)
{
    this.m_menuPanelItemMouseOver_callbackList.invoke(menuPanelId, menuItemPos);
}

MenuRenderer.prototype.handleMenuPanelMouseOut = function(menuPanelId, targetMenuPanelId)
{
    this.m_menuPanelMouseOut_callbackList.invoke( menuPanelId, targetMenuPanelId );
}

/**
 * Method checks that the specified menu panel item is associated
 * with an action component that the current user is authorised 
 * to use.
 *
*/

MenuRenderer.prototype._checkEnabledActionComponent = function(menuPanelId, menuPanelItemPos)
{
    return this.m_checkEnabledActionComponent_callbackList.invokeSelectedCallbackMethod( 0, menuPanelId, menuPanelItemPos );
}

/**
 * Method handles mouse click over menu panel item. This method
 * is invoked as part of the general mouse click event capture
 * process when the menu is displayed.
 *
*/

MenuRenderer.prototype._handleMenuPanelItemMouseClick = function(menuPanelId, menuPanelItemPos)
{
    this.m_menuPanelItemMouseClick_callbackList.invoke(menuPanelId, menuPanelItemPos);
}

/**
 * Method handles a press of the return key. Key presses are initially
 * relayed to the MenuGUIAdaptor through the KeybindingProtocol. Usually
 * such events are handled by the MenuModel. However, the handling of
 * the return key is browser dependent. Therefore, the menu model
 * determines the associated menu panel and menu panel item and relays
 * the handling of the event back to the renderer.
 *
 * @param menuPanelId      The identifier of the active menu panel when the
 *                         return key was pressed.
 * @param menuPanelItemPos The position of the selected menu panel item when
 *                         the return key was pressed.
 *
*/
MenuRenderer.prototype.handleKeyReturn = function(menuPanelId, menuPanelItemPos)
{
    if(MenuRenderer.isIE)
    {
        this._handleKeyReturnIE(menuPanelId, menuPanelItemPos);
    }
    else if(MenuRenderer.isMoz)
    {
        this._handleKeyReturnMoz(menuPanelId, menuPanelItemPos);
    }
}

MenuRenderer.prototype._handleKeyReturnMoz = function( menuPanelId, menuPanelItemPos )
{
    // Remove general capture of mouse events
    this.removeMouseEventCapture();
    
    // Hide menu
    //this.m_menuOptionMouseDown_callbackList.invoke(false);
    this.m_menuOptionMouseDown_callbackList.invoke(null);
    
    // Perform related action. Use mouse click functionality.
    this._handleMenuPanelItemMouseClick( menuPanelId, menuPanelItemPos );
}

MenuRenderer.prototype._handleKeyReturnIE = function( menuPanelId, menuPanelItemPos )
{
    // Store details to be used in method _captureLostIE
    // Essentially treat press of return key in same manner as a click on a menu panel item
    this.m_clickOnMenuPanelItem = true;
    
    this.m_clickOnMenuPanelId = menuPanelId;
    this.m_clickOnMenuPanelItemPos = menuPanelItemPos;
    
    // Release capture of mouse events
    this.m_element.releaseCapture();
}
    

/**
 * Method causes mouse events to be captured when menu displayed
 *
*/

MenuRenderer.prototype._captureMouseEvents = function()
{
    var thisObj = this;
    var container = this.m_element;
    
    if(container.attachEvent)
    {
        
        if(null == this.m_clickEventKey)
        {
            container.setCapture(false);
        
            this.m_clickEventKey = SUPSEvent.addEventHandler( container, "click", function(){thisObj._handleClickIE();}, false);
            
            container.onlosecapture = function(){thisObj._captureLostIE(container); return false; };
            
            this.m_hasMouseCapture = true;
            
        }
                
    }
    else if(container.addEventListener)
    {
        if(null == this.m_clickEventKey)
        {
            this.m_clickEventKey = SUPSEvent.addEventHandler( window, "click", function(evt){thisObj._handleClickMoz(evt);}, true );
            
            this.m_hasMouseCapture = true;
        }
        
    }
    
}

/**
 * General event handlers for mouse clicks when menu displayed
 *
*/

MenuRenderer.prototype._handleClickMoz = function(evt)
{
    // Determine target element
    var e = evt.target;
    
    // Determine whether click was inside a menu panel or not
    var menuPanelId = this._clickInsideMenuPanel(e);
    
    if(null != menuPanelId)
    {
        // Determine menu item over which click occurred
        var cellElement = this._getCellElement(e);
        
        if(null != cellElement)
        {
            // Click on cell element. Determine menu panel item position
            var menuPanel = this.m_menuPanelLookup[menuPanelId];
            
            if(null != menuPanel)
            {
                var menuPanelItemPos = menuPanel.getMenuPanelItemPosFromId(cellElement.id);
                
                if(null != menuPanelItemPos)
                {
                
                    // Check for enabled action component
                
                    if(this._checkEnabledActionComponent(menuPanelId, menuPanelItemPos))
                    {
                        // Remove general event handler
                        if(null != this.m_clickEventKey)
                        {
                            SUPSEvent.removeEventHandlerKey(this.m_clickEventKey);
                            this.m_clickEventKey = null;
            
                            this.m_hasMouseCapture = false;
            
                        }
            
                        // Close the menu
                        //this.m_menuOptionMouseDown_callbackList.invoke(false);
                        this.m_menuOptionMouseDown_callbackList.invoke(null);
            
                        // Invoke action
                        this._handleMenuPanelItemMouseClick(menuPanelId, menuPanelItemPos);
                        
                    }
                    
                }
                
            }
            
        } // End if if cellElement not null
        
    }
    else
    {
    
        // Remove general event handler
        if(null != this.m_clickEventKey)
        {
            SUPSEvent.removeEventHandlerKey(this.m_clickEventKey);
            this.m_clickEventKey = null;
            
            this.m_hasMouseCapture = false;
            
        }
        
        var clickInsideMenuOption = false;
        
        if(e.id == this.m_element.id)
        {
            clickInsideMenuOption = true;
            
            // Stop event propagation
            SUPSEvent.stopPropagation(evt);
        }
        
        // Hide menu
        //this.m_menuOptionMouseDown_callbackList.invoke(clickInsideMenuOption);
        this.m_menuOptionMouseDown_callbackList.invoke(null);
        
    }
    
}

MenuRenderer.prototype._handleClickIE = function()
{
    var event = window.event;
    
    var e = event.srcElement;
    
    // Determine whether click was inside a menu panel or not
    var menuPanelId = this._clickInsideMenuPanel(e);
    
    if(null != menuPanelId)
    {
        var cellElement = this._getCellElement(e);
        
        if(null != cellElement)
        {
        
            // Click on cell element. Determine menu item position
            var menuPanel = this.m_menuPanelLookup[menuPanelId];
            
            if(null != menuPanel)
            {
            
                var menuPanelItemPos = menuPanel.getMenuPanelItemPosFromId(cellElement.id);
                
                if(null != menuPanelItemPos)
                {
                
                    // Check for enabled action component
                    if(this._checkEnabledActionComponent(menuPanelId, menuPanelItemPos))
                    {
                        // Click on menu panel item
                        this.m_clickOnMenuPanelItem = true;
            
                        // Store details of clicked menu item
                        this.m_clickOnMenuPanelId = menuPanelId;
                        this.m_clickOnMenuPanelItemPos = menuPanelItemPos;
            
                        // Release capture
                        this.m_element.releaseCapture();
            
                    }
                    
                }
                
            }
            
        } // End of if cellElement not null
        
    }
    else    
    {
        // Click outside menu panel
        this.m_clickOnMenuPanelItem = false;
        
        // Store details of click event
        this.m_lastClickEventSrcElement = e;
        
        // Release capture
        this.m_element.releaseCapture();
    }
    
}

MenuRenderer.prototype._captureLostIE = function()
{
    if(null != this.m_clickEventKey)
    {
        SUPSEvent.removeEventHandlerKey( this.m_clickEventKey );
        this.m_clickEventKey = null;
        
        this.m_hasMouseCapture = false;
    }
    
    if(null != this.m_clickOnMenuPanelItem)
    {
    
        if(!this.m_clickOnMenuPanelItem)
        {
            // Click outside menu panel. Check location of click.
    
            var clickInsideMenuOption = false;
    
            if(null != this.m_lastClickEventSrcElement)
            {
                if(this.m_lastClickEventSrcElement.id == this.m_element.id)
                {
                    clickInsideMenuOption = true;
                    
                    this.m_mouseCaptureLost = true;
                }
        
                this.m_lastClickEventSrcElement = null;
        
            }
            else
            {
                // Capture lost owing to key event
                clickInsideMenuOption = null;
                
            }
    
            //this.m_menuOptionMouseDown_callbackList.invoke(clickInsideMenuOption);
            this.m_menuOptionMouseDown_callbackList.invoke(null);
            
        }
        else if(this.m_clickOnMenuPanelItem)
        {
            // Click on menu panel item. Hide menu.
            //this.m_menuOptionMouseDown_callbackList.invoke(false);
            this.m_menuOptionMouseDown_callbackList.invoke(null);
            
            // Invoke action
            
            this._handleMenuPanelItemMouseClick( this.m_clickOnMenuPanelId, this.m_clickOnMenuPanelItemPos);
            
            // Clean temporary storage
            this.m_clickOnMenuPanelId = null;
            this.m_clickOnMenuPanelItemPos = null;
            
        }
        
        // Clean flag indicating location of click
        this.m_clickOnMenuPanelItem = null;
        
    }
    else
    {
        // If get here instance member m_clickOnMenuPanelItem is null
        //this.m_menuOptionMouseDown_callbackList.invoke(false);
        this.m_menuOptionMouseDown_callbackList.invoke(null);
    }
            
    // Clean lose capture property
    
    this.m_element.onlosecapture = null;
    
}

/**
 * Remove event handler used to handle mouse events whilst
 * menu is displayed.
 *
*/
MenuRenderer.prototype.removeMouseEventCapture = function()
{
    // Remove general event handler
    if(null != this.m_clickEventKey)
    {
        SUPSEvent.removeEventHandlerKey(this.m_clickEventKey);
        this.m_clickEventKey = null;
            
        this.m_hasMouseCapture = false;        
    }
}

/**
 * Method investigates whether or not a mouse click occurred over a
 * menu panel division.
 *
 * @param targetElement The element which received the mouse click
 * @return Returns the menu panel id if click over menu panel or null
 *
*/

MenuRenderer.prototype._clickInsideMenuPanel = function(targetElement)
{
    var menuPanelId = null;
    
    // First check class name of target element
    var exceptionOccurred = false;
    
    try
    {
        if(targetElement.className == MenuPanelRenderer.MENU_PANEL_DIV_CSS_CLASS)
        {
            menuPanelId = targetElement.id;
        }
        
    }
    catch(ex)
    {
        // Attempting to retrieve class from protected element
        exceptionOccurred = true;
    }
    
    if(!exceptionOccurred)
    {
        if(null == menuPanelId)
        {
            // Check for click on element inside menu panel div
            menuPanelId = MenuPanelRenderer.getParentMenuPanelId(targetElement);
        }
    }
    
    // Return menu panel id
    return menuPanelId;
    
}

/**
 * Method returns reference to menu panel item table cell from mouse
 * click target. Mouse click must have occurred over a menu panel.
 *
*/

MenuRenderer.prototype._getCellElement = function(targetElement)
{
    var cellElement = null;
        
    if(targetElement.tagName == MenuPanelRenderer.CELL_TAG_NAME)
    {
        cellElement = targetElement;
    }
    else if(targetElement.tagName == MenuPanelRenderer.DIV_TAG_NAME)
    {
        var parentElement = targetElement.parentNode;
            
        if(parentElement.tagName == MenuPanelRenderer.CELL_TAG_NAME)
        {
            cellElement = parentElement;
        }
    }
    
    return cellElement;
    
}

/**
 * Method sets class on menu panel item following selection or
 * deselection
 *
*/

MenuRenderer.prototype.setMenuPanelItemClass = function( menuPanelId,
                                                         menuItemPos,
                                                         className )
{
    // Retrieve reference to appropriate menu panel renderer
    var menuPanel = this.m_menuPanelLookup[menuPanelId];
    
    if(null != menuPanel)
    {
        menuPanel.setMenuPanelItemClass( menuItemPos, className );
    }
    
}

/**
 * Method handles loss of focus when menu displayed. This
 * will occur when a user tabs away from a menu onto another
 * component.
 *
*/
MenuRenderer.prototype.handleLostFocusWhilstDisplayed = function()
{
    if(MenuRenderer.isIE)
    {
        this._handleLostFocusWhilstDisplayedIE();
    }
    else if(MenuRenderer.isMoz)
    {
        this._handleLostFocusWhilstDisplayedMoz();
    }
}

/**
 * Mozilla specific handler for loss of focus
 *
*/
MenuRenderer.prototype._handleLostFocusWhilstDisplayedMoz = function()
{
    if(null != this.m_clickEventKey)
    {
        SUPSEvent.removeEventHandlerKey(this.m_clickEventKey)
        this.m_clickEventKey = null;
        
        this.m_hasMouseCapture = false;
    }
    
    this.m_menuOptionMouseDown_callbackList.invoke(null);
}

/**
 * IE specific handler for loss of focus
 *
*/
MenuRenderer.prototype._handleLostFocusWhilstDisplayedIE = function()
{
    this.m_clickOnMenuPanelItem = false;
    
    // Set last click event source element to null to
    // indicate closure not caused by click event
    this.m_lastClickEventSrcElement = null;
    
    // Release capture
    this.m_element.releaseCapture();
}

        
        
                                   
 
  

/**
 * Class MenuPanelRenderer
 *
 * This class is designed to render individual menu panels.
 *
*/


function MenuPanelRenderer(){}

/**
 * Define class variables
 *
*/

MenuPanelRenderer.MENU_PANEL_DIV_CSS_CLASS = "MenuPanelDiv";

// Define additional classes for menu item divisions and cells

MenuPanelRenderer.MENU_ITEM_CELL = "menuItemCell";

MenuPanelRenderer.MENU_ITEM_DIVISIONS_ABOVE_AND_BELOW_CSS_CLASS = "DivisionsAboveAndBelow";
MenuPanelRenderer.MENU_ITEM_DIVISION_ABOVE_CSS_CLASS = "divisionAbove";
MenuPanelRenderer.MENU_ITEM_DIVISION_BELOW_CSS_CLASS = "divisionBelow";
MenuPanelRenderer.MENU_ITEM_NO_DIVISIONS_CSS_CLASS = "NoDivisions";

// Define constants used to store menu item division status

MenuPanelRenderer.MENU_ITEM_NO_DIVISIONS = 0;
MenuPanelRenderer.MENU_ITEM_DIVISION_ABOVE = 1;
MenuPanelRenderer.MENU_ITEM_DIVISION_BELOW = 2;
MenuPanelRenderer.MENU_ITEM_DIVISIONS_ABOVE_AND_BELOW = 3;

// Define constants used to identify mouse over element

MenuPanelRenderer.CELL_TAG_NAME = "TD";
MenuPanelRenderer.DIV_TAG_NAME = "DIV";

MenuPanelRenderer.m_logger = new Category( "MenuPanelRenderer" );

/**
 * Define instance members
 *
 * Reference to HTML div encompassing menu panel
*/

MenuPanelRenderer.prototype.m_element = null;

/**
 * Reference to controlling menu renderer
 *
*/

MenuPanelRenderer.prototype.m_menuRenderer = null;

/**
 * Reference to menu panel mouse over event handler
 *
*/

MenuPanelRenderer.prototype.m_menuPanelMouseOverHandler = null;

/**
 * Reference to menu panel mouse out event handler
 *
*/

MenuPanelRenderer.prototype.m_menuPanelMouseOutHandler = null;

/**
 * Reference to PopupLayer instance used to control visibility
 * of menu panel
 *
*/

MenuPanelRenderer.prototype.m_popupLayer = null;

/**
 * Array used to look up menu item position from identifier
*/

MenuPanelRenderer.prototype.m_menuPanelItemPosLookup = null;

/**
 * Array referencing primary menu item elements
 * These are the HTML Div elements within the table cells
 *
*/

MenuPanelRenderer.prototype.m_menuPanelItemElements = null;

/**
 * Array storing details of divisions for each menu item
 *
*/

MenuPanelRenderer.prototype.m_menuPanelItemDivStatus = null;

/**
 * Create menu panel as a child of another HTML element
 *
 * @param parentElement   The parent HTML element. Note that the parent element
 * @param menuRenderer    Reference to instance of menu renderer
 * @menuPanelId           The identifier for the base menu panel HTML element
 * @menuPanelItems        Array of instances of class MenuPanelItem which
 *                        describe menu items
 *
*/

MenuPanelRenderer.createAsChild = function( parentElement, 
                                            menuRenderer,
                                            menuPanelId,
                                            menuPanelItems )
{
    // Create HTML div which encompasses menu panel
    var menuPanelDiv = document.createElement( "div" );
    
    // Create MenuPanelRenderer instance and define contents of div
    var menuPanelRenderer = MenuPanelRenderer._createMenuPanel( menuPanelDiv,
                                                                menuRenderer,
                                                                menuPanelId,
                                                                menuPanelItems);
                                                                
    // Attach menu panel div to parent element
    //parentElement.appendChild(menuPanelDiv);
    parentElement.appendChild(menuPanelRenderer.m_element);
    
    return menuPanelRenderer;
    
}

/**
 * Method creates an instance of the class MenuPanelRenderer.
 *
*/

MenuPanelRenderer._createMenuPanel = function( menuPanelDiv,
                                               menuRenderer,
                                               menuPanelId,
                                               menuPanelItems)
{
    // Create instance of menu panel renderer
    var mpr = new MenuPanelRenderer();
    
    // Define base element
    mpr.m_element = menuPanelDiv;
    
    mpr.m_element.id = menuPanelId;
    mpr.m_element.className = MenuPanelRenderer.MENU_PANEL_DIV_CSS_CLASS;
    
    // Store reference to menu bar renderer
    mpr.m_menuRenderer = menuRenderer;
    
    // Create storage arrays
    mpr.m_menuPanelItemPosLookup = new Array();
    mpr.m_menuPanelItemElements = new Array();
    mpr.m_menuPanelItemDivStatus = new Array();
    
    // Create table and tbody inside division
    var table = document.createElement( "table" );
    //menuPanelDiv.appendChild(table);
    mpr.m_element.appendChild(table);
    
    // Set table cell style
    table.cellPadding = "0";
    table.cellSpacing = "0";
    
    var tbody = document.createElement( "tbody" );
    table.appendChild( tbody );
    
    // Loop through array of menu panel items creating required
    // table entries
    
    var row = null;
    var cell = null;
    var innerDiv = null;
    var menuPanelItem = null;
    var divisionAbove = null;
    var divisionBelow = null;
    
    var length = menuPanelItems.length;
    var menuItemPos = 0;
    
    for(var i = 0; i < length; i++)
    {
        menuPanelItem = menuPanelItems[i];
        
        if(menuPanelItem.m_type != MenuPanelItem.DIVISION)
        {
            // Add menu item to table
            row = document.createElement( "tr" );
            tbody.appendChild( row );
            
            cell = document.createElement( "td" );
            row.appendChild( cell );
            
            innerDiv = document.createElement( "div" );
            cell.appendChild( innerDiv );
            
            // Define properties of table entries
            cell.id = menuPanelItem.m_id;
            
            // Set base classes on cell and innerDiv
            cell.className = MenuPanelRenderer.MENU_ITEM_CELL;
            
            innerDiv.className = menuPanelItem.m_class;
            
            // Search for presence of division above or below item
            // Note, divisions should not be set in the first and
            // last array positions
            
            divisionAbove = false;
            divisionBelow = false;
            
            if( i - 1 > 0 )
            {
                if(menuPanelItems[i - 1].m_type == MenuPanelItem.DIVISION)
                {
                    divisionAbove = true;
                }
            }
            
            if( i + 1 < length - 1 )
            {
                if(menuPanelItems[i + 1].m_type == MenuPanelItem.DIVISION)
                {
                    divisionBelow = true;
                }
            }
            
            // Modify class lists if necessary and store division details
            
            if(divisionAbove == true && divisionBelow == true)
            {
                cell.className += " " +
                                  MenuPanelRenderer.MENU_ITEM_DIVISION_ABOVE_CSS_CLASS +
                                  " " +
                                  MenuPanelRenderer.MENU_ITEM_DIVISION_BELOW_CSS_CLASS;
                                  
                innerDiv.className += " " +
                                      MenuPanelRenderer.MENU_ITEM_DIVISION_ABOVE_CSS_CLASS +
                                      " " +
                                      MenuPanelRenderer.MENU_ITEM_DIVISION_BELOW_CSS_CLASS;
                                  
                mpr.m_menuPanelItemDivStatus[menuItemPos] = MenuPanelRenderer.MENU_ITEM_DIVISIONS_ABOVE_AND_BELOW;
            }
            else if(divisionAbove == true && divisionBelow == false)
            {
                cell.className += " " + MenuPanelRenderer.MENU_ITEM_DIVISION_ABOVE_CSS_CLASS;
                                 
                innerDiv.className += " " + MenuPanelRenderer.MENU_ITEM_DIVISION_ABOVE_CSS_CLASS;
                                     
                mpr.m_menuPanelItemDivStatus[menuItemPos] = MenuPanelRenderer.MENU_ITEM_DIVISION_ABOVE;
                
            }
            else if(divisionAbove == false && divisionBelow == true)
            {
            
                cell.className += " " + MenuPanelRenderer.MENU_ITEM_DIVISION_BELOW_CSS_CLASS;
                                 
                innerDiv.className += " " + MenuPanelRenderer.MENU_ITEM_DIVISION_BELOW_CSS_CLASS;
                                     
                mpr.m_menuPanelItemDivStatus[menuItemPos] = MenuPanelRenderer.MENU_ITEM_DIVISION_BELOW;
                
            }
            else
            {
                // No division above or below
                mpr.m_menuPanelItemDivStatus[menuItemPos] = MenuPanelRenderer.MENU_ITEM_NO_DIVISIONS;
                
            }
 
            // Set text in inner div
            innerDiv.innerHTML = menuPanelItem.m_label;
            
			// D855 - A sub-menu panel for a menu panel item is a child of a menu panel item.
			// This means it will have the same z-index as the parent menu panel item. As menu
			// panel items below this are higher in the stacking order then they show through
			// the sub-menu panel. To prevent this assign a z-index to each menu item in the
			// panel that decreases from the top to bottom menu items.
            innerDiv.style.zIndex = (length - i);
            
            // Store reference to inner div
            mpr.m_menuPanelItemElements[menuItemPos] = innerDiv;
            
            // Store menu panel item position in look up table
            mpr.m_menuPanelItemPosLookup[menuPanelItem.m_id] = menuItemPos;
            
            // Increment menu item counter
            menuItemPos++;
            
        } // End of if(menuPanelItem.m_type != MenuItemPanel.DIVISION)
        
    } // End of for loop
    
    // Create instance of PopupLayer class that controls
    // visibility of menu panel
    mpr.m_popupLayer = PopupLayer.create(mpr.m_element);
    
    // Start event handlers
    mpr.startMenuPanelEventHandlers();
    
    // Return instance of menu panel renderer class
    return mpr;
    
}

/**
 * Method returns identifier of parent menu panel.
 * If there is no parent menu panel the method returns null.
 *
*/

MenuPanelRenderer.getParentMenuPanelId = function(element)
{
    var menuPanelId = null;
    
    var className = null;
    
    // Retrieve parent element
    var parent = element.parentNode;
    
    while(null != parent)
    {
        className = parent.className;
        
        if(className == MenuPanelRenderer.MENU_PANEL_DIV_CSS_CLASS)
        {
            menuPanelId = parent.id;
            break;
        }
        
        parent = parent.parentNode;
    }
    
    return menuPanelId;
    
}


/**
 * Method cleans up memory used by instance of class
 *
*/

MenuPanelRenderer.prototype._dispose = function()
{
    // Stop menu panel event handlers
    this.stopMenuPanelEventHandlers();
    
    // Set arrays to null
    this.m_menuPanelItemPosLookup = null;
    this.m_menuPanelItemElements = null;
    this.m_menuPanelItemDivStatus = null;

	this.m_popupLayer._dispose();    
    this.m_popupLayer = null;

    this.m_menuRenderer = null;
    this.m_element = null;
    
}
    

/**
 * Method makes menu panel visible
 *
*/

MenuPanelRenderer.prototype.show = function()
{
    this.m_popupLayer.show();
}

/**
 * Method hides menu panel
 *
*/

MenuPanelRenderer.prototype.hide = function()
{
    this.m_popupLayer.hide();
}

/**
 * Method sets class on menu panel item inner div
 *
*/

MenuPanelRenderer.prototype.setMenuPanelItemClass = function( menuItemPos,
                                                              className )
{

    if( menuItemPos >= 0 && menuItemPos < this.m_menuPanelItemElements.length)
    {
        // Retrieve reference to inner division
        var innerDiv = this.m_menuPanelItemElements[menuItemPos];
        
        // Define classes for menu item
        var divClasses = className;
        
        // Add auxilliary classes for division if required
        var menuItemDivStatus = this.m_menuPanelItemDivStatus[menuItemPos];
        
        switch(menuItemDivStatus)
        {
            case MenuPanelRenderer.MENU_ITEM_DIVISIONS_ABOVE_AND_BELOW:
                divClasses += " " +
                              MenuPanelRenderer.MENU_ITEM_DIVISION_ABOVE_CSS_CLASS +
                              " " +
                              MenuPanelRenderer.MENU_ITEM_DIVISION_BELOW_CSS_CLASS;
                break;
                
            case MenuPanelRenderer.MENU_ITEM_DIVISION_ABOVE:
                divClasses += " " + MenuPanelRenderer.MENU_ITEM_DIVISION_ABOVE_CSS_CLASS;
                break;
                
            case MenuPanelRenderer.MENU_ITEM_DIVISION_BELOW:
                divClasses += " " + MenuPanelRenderer.MENU_ITEM_DIVISION_BELOW_CSS_CLASS;
                break;
                
            default:
                break;
                
        }
        
        // Set classes on inner div
        innerDiv.className = divClasses;
                              
    }
    
}

/**
 * Method starts event handlers on menu panel
 *
*/

MenuPanelRenderer.prototype.startMenuPanelEventHandlers = function()
{
    var thisObj = this;
    
    if(null == this.m_menuPanelMouseOverHandler)
    {
        this.m_menuPanelMouseOverHandler = SUPSEvent.addEventHandler( this.m_element,
                                                                      "mouseover",
                                                                      function(evt){return thisObj._handleMenuPanelMouseOver(evt);} );
    }
    
    if(null == this.m_menuPanelMouseOutHandler)
    {
        this.m_menuPanelMouseOutHandler = SUPSEvent.addEventHandler( this.m_element,
                                                                     "mouseout",
                                                                     function(evt){return thisObj._handleMenuPanelMouseOut(evt);} );
    }
    
}

/**
 * Method stops menu panel event handlers
 *
*/

MenuPanelRenderer.prototype.stopMenuPanelEventHandlers = function()
{
    if(null != this.m_menuPanelMouseOverHandler)
    {
        SUPSEvent.removeEventHandlerKey(this.m_menuPanelMouseOverHandler);
        this.m_menuPanelMouseOverHandler = null;
    }
    
    if(null != this.m_menuPanelMouseOutHandler)
    {
        SUPSEvent.removeEventHandlerKey(this.m_menuPanelMouseOutHandler);
        this.m_menuPanelMouseOutHandler = null;
    }
    
}

/**
 * Method handles menu panel mouse over event
 *
*/

MenuPanelRenderer.prototype._handleMenuPanelMouseOver = function(evt)
{

    evt = (evt) ? evt : ((event) ? event : null );
    
    if(null != evt)
    {
        var srcElement = SUPSEvent.getTargetElement(evt);
        
        // Locate mouse over event generated by table cell or inner div
        var cellElement = null;
        
        if(srcElement.tagName == MenuPanelRenderer.CELL_TAG_NAME)
        {
            cellElement = srcElement;
        }
        else if(srcElement.tagName == MenuPanelRenderer.DIV_TAG_NAME)
        {
            var parentElement = srcElement.parentNode;
            
            if(parentElement.tagName == MenuPanelRenderer.CELL_TAG_NAME)
            {
                cellElement = parentElement;
            }
        
        }
        
        if(null != cellElement)
        {
            var menuItemPos = this.m_menuPanelItemPosLookup[ cellElement.id ];
            
            if(null != menuItemPos)
            {
                // Invoke selected method on menu renderer
                this.m_menuRenderer.handleMenuPanelItemMouseOver(this.m_element.id,
                                                                 menuItemPos);
            }
            
        }
        
        // Stop progagtion of mouse out event
        SUPSEvent.stopPropagation(evt);
        
    }
    
}

/**
 * Method handles menu panel mouse out event
 *
*/

MenuPanelRenderer.prototype._handleMenuPanelMouseOut = function(evt)
{
    evt = (evt) ? evt : ((event) ? event : null );
    
    if(null != evt)
    {
        var toElement = null;
        var srcElement = null;
        
        toElement = SUPSEvent.getRelatedElement(evt)
        
        // Identify target of mouse out
        var targetMenuPanelId = null;
        
        if(null != toElement)
        {
            // Take care checking class name as Mozilla can throw
            // permission exception if toElement a Mozilla component
            
            var className = null;
            
            var permissionExceptionOccurred = false;
            
            try
            {
                className = toElement.className;
            }
            catch(ex)
            {
                permissionExceptionOccurred = true;
            }
            
            if(!permissionExceptionOccurred)
            {
                if(className == MenuPanelRenderer.MENU_PANEL_DIV_CSS_CLASS)
                {
                    targetMenuPanelId = toElement.id;
                }
                else
                {
                    targetMenuPanelId = MenuPanelRenderer.getParentMenuPanelId(toElement);
                }
            }
            
        }
        
        if(targetMenuPanelId != this.m_element.id)
        {
            this.m_menuRenderer.handleMenuPanelMouseOut( this.m_element.id,
                                                         targetMenuPanelId );
        }
        
        // Stop progagtion of mouse out event
        SUPSEvent.stopPropagation(evt);
        
    }
    
}

/**
 * Method returns position of menu panel item on menu
 * panel given menu panel item identifier
 *
 * @param menuPanelItemId The identifier associated with a table cell
 *                        containing a menu panel item
 * @return Returns the position of the menu panel within the menu panel
 *
*/

MenuPanelRenderer.prototype.getMenuPanelItemPosFromId = function(menuPanelItemId)
{
    return this.m_menuPanelItemPosLookup[menuPanelItemId];
}

/**
 * Method returns inner div associated with the menu panel item
 * specified by the input argument
 *
 * @param menuItemPos The position of the menu item on the menu panel
 * @return Returns associated table cell
 *
*/

MenuPanelRenderer.prototype.getMenuPanelItem = function(menuItemPos)
{
    var innerDiv = this.m_menuPanelItemElements[menuItemPos];
    
    return innerDiv;
}

/**
 * Method enables position of menu panel to be set. Note position is
 * relative to parent table cell on parent menu panel.
 *
*/

MenuPanelRenderer.prototype.setPosition = function( left, top )
{
    if(null != left)
    {
        this.m_element.style.left = left + "px";
    }
    
    if(null != top)
    {
        this.m_element.style.top = top + "px";
    }
}

/**
 * Class MenuModel
 *
 * This class controls the navigation menu. It receives menu events from
 * the renderer via the menu adaptor. This class responds to these events
 * using a model of the menu built from data held in the application controller.
 *
*/
function MenuModel( menuAdaptor )
{
    this.m_adaptor = menuAdaptor;
    this.m_menuRenderer = menuAdaptor.m_renderer;
    this.m_menuDataSourceId = this.m_menuRenderer.m_menuDataSourceId;
    this.m_menuDataSource = MenuDataSourceFactory.getInstance( this.m_menuDataSourceId );
    
    // Create array to store list of functional menu panel item types
    // configured for menu. At present, allow only one entry for each function type.
    this.m_functionalMenuItemTypes = new Array();
}

/**
 * Define class variables
 *
*/
MenuModel.MENU_PANEL_ID_PREFIX = "_MenuPanel_";
MenuModel.MENU_ITEM_ID_PREFIX = "_MenuItem_";

/**
 * XPath of base menu panel relative to menu bar node
 *
*/
MenuModel.BASE_MENU_PANEL_XPATH = "./panel";

MenuModel.m_logger = new Category( "MenuModel" );


/**
 * Define instance variables
 *
*/
MenuModel.prototype.m_menuPanel = null;


/**
 * Flag recording visibility of menu
 *
*/
MenuModel.prototype.m_menuDisplayed = false;


/**
 * Reference to base menu panel instance
 *
*/
MenuModel.prototype.m_baseMenuPanel = null;


/**
 * Counter used for menu panel identifiers
 *
*/
MenuModel.prototype.m_menuPanelCounter = 0;


/**
 * Menu panel lookup table
 *
*/
MenuModel.prototype.m_menuPanelLookup = new Array();

/**
 * Reference to currently selected menu panel
 *
*/
MenuModel.prototype.m_selectedMenuPanelId = null;

/**
 * Flag indicating position of mouse cursor with
 * respect to menu button
 *
*/
MenuModel.prototype.m_mouseOverMenuOption = null;


/**
 * Clean up memory after use
 *
*/
MenuModel.prototype._dispose = function()
{
    for(var i in this.m_menuPanelLookup)
    {
        this.m_menuPanelLookup[i]._dispose();
        this.m_menuPanelLookup[i] = null;
    }
    
    this.m_menuPanelLookup = null;
    
    this.m_baseMenuPanel = null;
    this.m_menuDataSource = null;
    this.m_menuRenderer = null;
    this.m_adaptor = null;
}


/**
 * Method handles mouse over menu option division
 *
*/
MenuModel.prototype.handleMenuOptionMouseOver = function(evt)
{
    this.m_mouseOverMenuOption = true;
    
    if(this.m_adaptor.m_active)
    {
        this.renderState();
    }
    
}


/**
 * Method handles mouse out on menu option division
 *
*/
MenuModel.prototype.handleMenuOptionMouseOut = function(evt)
{
    this.m_mouseOverMenuOption = false;
    
    if(this.m_adaptor.m_active)
    {
        this.renderState();
    }
    
}


/**
 * Method handles mouse down on menu option division
 *
 * param clickInsideMenuOption This is a boolean value defined when the
 *                             method is invoked following a mouse click.
 *                             If the click occurred over the menu button
 *                             the value will be "true", if not "false".
 *                             If this method is invoked by some other
 *                             mechanism, such as tabbing away from the menu
 *                             when it is displayed, the value will be null.
 *                             11/10/05 This parameter is no longer used.
 *
*/
MenuModel.prototype.handleMenuOptionMouseDown = function(clickInsideMenuOption)
{   
    if(this.m_adaptor.m_active)
    {
        if(!this.m_menuDisplayed)
        {
        
            // Set menu option CSS class
            //this.m_menuRenderer.renderMenuOption( MenuRenderer.MENU_BAR_BUTTON_INSET );
      
            // Display menu
            if(null == this.m_baseMenuPanel)
            {
                // Menu model base menu panel must be created
                // and rendered
        
                // Retrieve menu items on base menu panel
                var baseMenuItems = null;
                var menuComponentEnablement = null;
            
                if(this.m_menuDataSourceId == MenuDataSourceFactory.NAVIGATION_MENU)
                {
                    baseMenuItems = this.m_menuDataSource.getMenuPanelItems( MenuModel.BASE_MENU_PANEL_XPATH );
                
                    if(this.m_menuRenderer.m_includeCoreMenuPanelItems)
                    {
                        // Add core menu functions to base panel
                        this._addCoreMenuPanelItems(baseMenuItems);
                    }
                
                    menuComponentEnablement = false;
                }
                else
                {
                    baseMenuItems = this.m_menuDataSource.getMenuPanelItems(this.m_adaptor);
                
                    menuComponentEnablement = true;
                }
            
                if(null != baseMenuItems)
                {
                    var length = baseMenuItems.length;
                
                    if(length > 0)
                    {
                        // Create menu model base menu panel
                        var menuPanelId = this.m_menuRenderer.getElement().id +
                                          MenuModel.MENU_PANEL_ID_PREFIX + 
                                          this.m_menuPanelCounter;
                    
                        this.m_menuPanelCounter++;
                    
                        this.m_baseMenuPanel = this._createMenuPanel(menuPanelId,
                                                                     null,
                                                                     MenuModel.BASE_MENU_PANEL_XPATH,
                                                                     baseMenuItems,
                                                                     menuComponentEnablement);
                    
                        // Create menu panel lookup array and add base menu panel
                        this.m_menuPanelLookup = new Array();
                    
                        this.m_menuPanelLookup[menuPanelId] = this.m_baseMenuPanel;
                    
                        // Invoke renderer to create menu panel
                        this.m_menuRenderer.renderBaseMenuPanel(menuPanelId,
                                                                baseMenuItems);
                    
                        // Display base menu panel
                        this.m_baseMenuPanel.show();
                    }
                
                }
            
            }
            else
            {
                // Menu model base menu panel already exists
                this.m_baseMenuPanel.show();
            }
        
            this.m_menuDisplayed = true;
            
            // Redraw menu button
            this.renderState();
      
        }
        else
        {
        //if(null != clickInsideMenuOption)
        //{
            // Set menu option class
        //    if(clickInsideMenuOption)
        //    {
        //        this.m_menuRenderer.renderMenuOption( MenuRenderer.MENU_BAR_BUTTON_OUTSET );
        //    }
        //    else
        //    {
        //        this.m_menuRenderer.renderMenuOption( MenuRenderer.MENU_BAR_BUTTON );
        //    }
        //}
        //else
        //{
                //if(this.m_mouseOverMenuOption == true)
                //{
                //    this.m_menuRenderer.renderMenuOption( MenuRenderer.MENU_BAR_BUTTON_OUTSET );
                //}
                //else
                //{
                //    this.m_menuRenderer.renderMenuOption( MenuRenderer.MENU_BAR_BUTTON );
                //}
            
        //}   
      
            // Hide menu
            this.m_baseMenuPanel.hide(false);
        
            // Reset currently selected menu panel
            this.m_selectedMenuPanelId = null;
        
            this.m_menuDisplayed = false;
            
            // Redraw menu button
            this.renderState();
      
        }
        
    }
    else
    {
        // Adaptor made inactive through popup being displayed.
        
        if(this.m_menuDisplayed)
        {
            // Menu may be displayed if user uses short cut keys
            // to navigate off form whilst menu displayed
            
            // Hide menu
            this.m_baseMenuPanel.hide(false);
        
            // Reset currently selected menu panel
            this.m_selectedMenuPanelId = null;
        
            this.m_menuDisplayed = false;
            
            // Redraw menu button
            this.renderState();
            
        }
        
    }
    
    
}


/**
 * Method creates and populates an instance of the class MenuPanel
 * which represents a menu panel in the model
 *
*/
MenuModel.prototype.createMenuPanel = function(parentMenuPanelId,
                                               parentMenuItemPos,
                                               panelXPath)
{
    var menuPanel = null;
    
    // Retrieve details of menu panel items from application controller
    var menuPanelItems = null;
    
    if(this.m_menuDataSourceId == MenuDataSourceFactory.NAVIGATION_MENU)
    {
        menuPanelItems = this.m_menuDataSource.getMenuPanelItems( panelXPath );
    }
    
    if(null != menuPanelItems)
    {
        var length = menuPanelItems.length;
        
        if(length > 0)
        {
            var menuPanelId = this.m_menuRenderer.getElement().id + 
                              MenuModel.MENU_PANEL_ID_PREFIX +
                              this.m_menuPanelCounter;
                              
            this.m_menuPanelCounter++;
            
            // Create menu panel
            menuPanel = this._createMenuPanel(menuPanelId,
                                              parentMenuPanelId,
                                              panelXPath,
                                              menuPanelItems,
                                              false);
                                              
            // Add menu panel to look up array
            this.m_menuPanelLookup[menuPanelId] = menuPanel;
            
            // Instruct menu renderer to create HTML for menu panel
            this.m_menuRenderer.renderExtensionMenuPanel( parentMenuPanelId,
                                                          parentMenuItemPos,
                                                          menuPanelId,
                                                          menuPanelItems );
            
        }
        
    }
    
    return menuPanel;
    
}


/**
 * Method instructs menu renderer to make a menu panel visible
 *
*/
MenuModel.prototype.showMenuPanel = function(menuPanelId)
{
    // Display off menu panel is conditional of the main menu being displayed
    var menuPanelDisplayed = false;
    
    this.m_menuRenderer.showMenuPanel(menuPanelId);
}


/**
 * Method instructs menu renderer to hide a menu panel
 *
*/
MenuModel.prototype.hideMenuPanel = function(menuPanelId)
{
    this.m_menuRenderer.hideMenuPanel(menuPanelId);
}


/**
 * Method creates an instance of the menu model MenuPanel
 *
 * @param menuPanelId             The identifier for the menu panel
 * @param parentMenuPanelId       The identifier for the menu panel's parent
 *                                menu panel.
 * @param menuPanelXPath          XPath of node storing panel details in menu bar configuration
 * @param menuItems               Array of MenuPanelItems describing contents of menu panel.
 *                                The method adds extra details to these items before
 *                                they are passed to the menu bar renderer.
 * @param menuComponentEnablement Boolean flag indicating whether or not
 *                                menu panel items support enablement
 *
*/
MenuModel.prototype._createMenuPanel = function( menuPanelId, 
                                                 parentMenuPanelId,
                                                 menuPanelXPath,
                                                 menuItems,
                                                 menuComponentEnablement )
{
    // Create prefix for menu item identifiers
    var menuItemPrefix = menuPanelId + MenuModel.MENU_ITEM_ID_PREFIX;
    
    // Create empty menu panel definition
    var menuPanel = new MenuPanel( menuPanelId, 
                                   parentMenuPanelId, 
                                   this, 
                                   menuComponentEnablement );
    
    // Add menu panel items to menu panel
    var menuPanelItem = null;
    var type = null;
    var userAllowedAccess = null;
    var destination = null;
    var functionRef = null;
    var subformId = null;
    var panelXPath = null;
    
    var navigationComponent = null;
    var subMenuComponent = null;
    var quickLinkComponent = null;
    var functionComponent = null;
    
    var menuItemCounter = 0;
    
    // Loop through menu items adding components to menu panel
    for(var i = 0, l = menuItems.length; i < l; i++)
    {
        menuPanelItem = menuItems[i];
        
        type = menuPanelItem.m_type;
        
        if(type != MenuPanelItem.DIVISION)
        {
            if(type != MenuPanelItem.QUICK_LINK)
            {
                // Set menu item identifier
                menuPanelItem.m_id = menuItemPrefix + menuItemCounter;
            }
            
            if(type == MenuPanelItem.ITEM)
            {
                // Navigation component
                destination = menuPanelItem.m_destination;
                
                // Check user access to destination.
                userAllowedAccess = Services.hasAccessToForm(destination);
                
                if(userAllowedAccess)
                {
                    menuPanelItem.m_class = ActionComponent.ENABLED_ACTION_UNSELECTED;
                }
                else
                {
                    menuPanelItem.m_class = ActionComponent.DISABLED_ACTION_UNSELECTED;
                }
                
                navigationComponent = new NavigationComponent(menuItemCounter,
                                                              menuPanel,
                                                              destination,
                                                              userAllowedAccess);
                                                              
                menuPanel.addMenuComponent(navigationComponent);
                
            }
            else if(type == MenuPanelItem.PANEL)
            {
                // First synthesize XPath for sub menu definition
                panelXPath = menuPanelXPath + 
                             "/panel[@label='" +
                             menuPanelItem.m_label +
                             "']";
                             
                 // Check security. May need an unpleasant function here!
                 userAllowedAccess = this._hasAccessToSubMenu(panelXPath);
                 
                 // Set class on menu panel items
                 if(userAllowedAccess)
                 {
                     menuPanelItem.m_class = SubMenuComponent.ENABLED_SUBMENU_UNSELECTED;
                 }
                 else
                 {
                     menuPanelItem.m_class = SubMenuComponent.DISABLED_SUBMENU_UNSELECTED;
                 }
                 
                 subMenuComponent = new SubMenuComponent(menuItemCounter,
                                                         menuPanel,
                                                         userAllowedAccess,
                                                         panelXPath);
                                                         
                menuPanel.addMenuComponent(subMenuComponent);
                
            }
            else if(type == MenuPanelItem.QUICK_LINK)
            {
                destination = menuPanelItem.m_destination;
                subformId = menuPanelItem.m_subformId;
                
                if(null != destination)
                {
                    userAllowedAccess = Services.hasAccessToForm(destination);
                }
                else
                {
                    // Subform identifier identifies adaptor not actual sub form
                    var subFormAdaptor = FormController.getInstance().getAdaptorById(subformId);
                    if(null == subFormAdaptor)
                    {
                        throw new ConfigurationException( "Subform adaptor with identifier " +
                                                          subformId +
                                                          " defined in menu quick link configuration does not exist." );
                    }
                    // Retrieve sub form name from adaptor
                    var subformName = subFormAdaptor.subformName;
                    // Check user's access to sub form
                    userAllowedAccess = Services.hasAccessToForm(subformName);
                }
                
                // Check form context state of menu item
                isEnabled = this.isMenuComponentEnabled( menuPanelItem.m_id );
                
                // Set initial class for menu item
                if(userAllowedAccess && isEnabled)
                {
                    menuPanelItem.m_class = ActionComponent.ENABLED_ACTION_UNSELECTED;
                }
                else
                {
                    menuPanelItem.m_class = ActionComponent.DISABLED_ACTION_UNSELECTED;
                }
                
                quickLinkComponent = new QuickLinkComponent( menuPanelItem.m_id,
                                                             menuPanel,
                                                             destination,
                                                             subformId,
                                                             userAllowedAccess,
                                                             isEnabled,
                                                             menuPanelItem.m_guard,
                                                             menuPanelItem.m_prepare );
                                                             
                menuPanel.addMenuComponent( quickLinkComponent );
       
            }
            else if(type == MenuPanelItem.FUNCTION)
            {
                this._restrictFunctionalMenuPanelItemEntries(menuPanelItem.m_functionType);
                
                functionRef = this._defineMenuPanelItemFunctionRef(menuPanelItem);
                
                // RWW 03/08/05 At present, there are no security restraints
                // on function components
                userAllowedAccess = true;
                
                // Set class of menu panel item
                
                if(userAllowedAccess)
                {
                    menuPanelItem.m_class = ActionComponent.ENABLED_ACTION_UNSELECTED;
                }
                else
                {
                    menuPanelItem.m_class = ActionComponent.DISABLED_ACTION_UNSELECTED;
                }
                
                functionComponent = new FunctionComponent(menuItemCounter,
                                                          menuPanel,
                                                          functionRef,
                                                          menuPanelItem.getFunctionParamValuesAsArgumentArray(),
                                                          userAllowedAccess);
                                                          
                menuPanel.addMenuComponent( functionComponent );
            }
            else
            {
                // Unexpected menu item type
                throw new AppConfigError("Unexpected menu element type in node defined by xpath " + 
                                         menuPanelXPath);
            }
            
            menuItemCounter++;
            
        } // End of if(type != MenuPanelItem.DIVISION)
        
    } // End of for loop
    
    return menuPanel;
    
}


