// EditPanelGUIAdaptor.js
//
// Class for integrating a panel to edit users security roles with
// the Framework.
//
//==================================================================


/**
 * @constructor
 * @private
 */
function EditPanelGUIAdaptor() {}

/**
 * Logging category for the EditPanelGUIAdaptor
 *
 * @type Category
 * @private
 */
EditPanelGUIAdaptor.m_logger = new Category("EditPanelGUIAdaptor");

/**
 *  EditPanelGUIAdaptor components identifiers
 */
EditPanelGUIAdaptor.LEFT_ARROW = "_LeftArrow";
EditPanelGUIAdaptor.RIGHT_ARROW = "_RightArrow";
EditPanelGUIAdaptor.DOUBLE_LEFT_ARROW = "_DoubleLeftArrow";
EditPanelGUIAdaptor.DOUBLE_RIGHT_ARROW = "_DoubleRightArrow";
EditPanelGUIAdaptor.ASSIGNED_ROLES = "AssignedRoles";
EditPanelGUIAdaptor.AVAILABLE_ROLES = "AvailableRoles";
EditPanelGUIAdaptor.ALL_ROLES = "AllRoles";

/**
 * Assigned Roles modified flag
 */
EditPanelGUIAdaptor.MODIFIED_FLAG = "modified";

/**
 * EditPanelGUIAdaptor is a sub class of HTMLElementGUIAdaptor
 */
EditPanelGUIAdaptor.prototype = new HTMLElementGUIAdaptor();

/**
 * Set the constructor property so we can identify the type
 */
EditPanelGUIAdaptor.prototype.constructor = EditPanelGUIAdaptor;

/**
 * Add the required protocols to the EditPanelGUIAdaptor
 */
GUIAdaptor._setUpProtocols('EditPanelGUIAdaptor');
GUIAdaptor._addProtocol('EditPanelGUIAdaptor', 'DataBindingProtocol');
GUIAdaptor._addProtocol('EditPanelGUIAdaptor', 'EnablementProtocol');
GUIAdaptor._addProtocol('EditPanelGUIAdaptor', 'ReadOnlyProtocol');

/**
 * Create a new EditPanelGUIAdaptor
 *
 * @param e the outer DIV element of the form to manage
 * @return the new EditPanelGUIAdaptor
 * @type EditPanelGUIAdaptor
 */
EditPanelGUIAdaptor.create = function(e)
{
	if (EditPanelGUIAdaptor.m_logger.isTrace()) EditPanelGUIAdaptor.m_logger.trace("create()");

	var a = new EditPanelGUIAdaptor();
	a._initialiseAdaptor(e);
	
	return a;
}

/**
 * Initialise the EditPanelGUIAdaptor
 *
 * @param e the HTMLElement for the DIV element to be managed
 * @private
 */
EditPanelGUIAdaptor.prototype._initialiseAdaptor = function(e)
{
	if (EditPanelGUIAdaptor.m_logger.isTrace()) EditPanelGUIAdaptor.m_logger.trace("_initialiseAdaptor()");
	
	// Call parent class initialisation
	HTMLElementGUIAdaptor.prototype._initialiseAdaptor.call(this, e);
}

/**
 * Clean up after the component
 */
EditPanelGUIAdaptor.prototype._dispose = function()
{
	if (EditPanelGUIAdaptor.m_logger.isTrace()) EditPanelGUIAdaptor.m_logger.trace("dispose()");

	// Dispose of the renderer
	this.m_renderer.dispose();
	this.m_renderer = null;
}

/**
 * Perform any GUIAdaptor specific configuration - this also creates the config
 * objects for the sub-components dynamically
 *
 * @param cs an array of the the adaptor's configuration items 
 */
EditPanelGUIAdaptor.prototype._configure = function(cs)
{
	if (EditPanelGUIAdaptor.m_logger.isTrace()) EditPanelGUIAdaptor.m_logger.trace("_configure()");

	var fc = FormController.getInstance();
	var cm = fc.getFormView().getConfigManager();
	var epId = this.getId();

	// Assigned roles modified flag
	this._setModified(false);

	// Configure the Assigned Roles grid
	var gSrcData = this.dataBinding + "/" + EditPanelGUIAdaptor.ASSIGNED_ROLES;
	var gDataBinding = gSrcData + "Selected";

	var thisObj = this;

	cm.setConfig(
		epId + "_" + EditPanelGUIAdaptor.ASSIGNED_ROLES,
		{
			dataBinding: gDataBinding,
			srcData: gSrcData,
			rowXPath: "role",
			keyXPath: "id",
			columns: [{xpath: "."}],
			multipleSelection: true
		}
	);

	// On page load enable the button panel only if user has the required role(s)
	cm.setConfig(
		epId + EditPanelRenderer.BUTTON_PANEL,
		{
			enableOn: ["/"],		
			isEnabled: function() { return (thisObj._isButtonPanelEnabled()); }
		}
	);

	// Configure the action binding for the Right Arrow button
	cm.setConfig(
		epId + EditPanelGUIAdaptor.RIGHT_ARROW,
		{
			actionBinding: function() { thisObj._handleRightArrow(); },
			enableOn: [gDataBinding  + "//*"],
			isEnabled: function() { return (thisObj._isRightArrowEnabled()); }
		}
	);

	// Configure the action binding for the Double Right Arrow button
	cm.setConfig(
		epId + EditPanelGUIAdaptor.DOUBLE_RIGHT_ARROW,
		{
			actionBinding: function() { thisObj._handleDoubleRightArrow(); },
			enableOn: [gSrcData + "//*"],
			isEnabled: function() { return (thisObj._isDoubleRightArrowEnabled()); }
		}
	);

	gSrcData = this.dataBinding + "/" + EditPanelGUIAdaptor.AVAILABLE_ROLES;
	gDataBinding = gSrcData + "Selected";

	// Configure the action binding for the Left Arrow button
	cm.setConfig(
		epId + EditPanelGUIAdaptor.LEFT_ARROW,
		{
			actionBinding: function() { thisObj._handleLeftArrow(); },
			enableOn: [gDataBinding + "//*"],
			isEnabled: function() { return (thisObj._isLeftArrowEnabled()); }
		}
	);

	// Configure the action binding for the Double Left Arrow button
	cm.setConfig(
		epId + EditPanelGUIAdaptor.DOUBLE_LEFT_ARROW,
		{
			actionBinding: function() { thisObj._handleDoubleLeftArrow(); },
			enableOn: [gSrcData + "//*"],
			isEnabled: function() { return (thisObj._isDoubleLeftArrowEnabled()); }
		}
	);

	// Configure the Available Roles grid
	cm.setConfig(
		epId + "_" + EditPanelGUIAdaptor.AVAILABLE_ROLES,
		{
			dataBinding: gDataBinding,
			srcData: gSrcData,
			rowXPath: "role",
			keyXPath: "id",
			columns: [{xpath: "."}],
			multipleSelection: true
		}
	);

	// Get the available roles from Application Controller, format them, add
	// default values and then copy them into the adaptor's data binding
	var availableRoles = Services.getAppController().getAppRoles().getRolesNode();

	// Create all roles node
	var dom = XML.createDOM(null, null, null);
	var allRolesNode = dom.createElement(EditPanelGUIAdaptor.ALL_ROLES);

	// Copy <Role> nodes to all roles node
	var roleNodes = availableRoles.selectNodes("/Roles/Role");

	// Change each available role into the required format and add Date From/To
	// default values
	for (var i = 0, l = roleNodes.length; i < l; i++)
	{
		// Get <Role> node
		var node = roleNodes[i].selectSingleNode(".");

		// Create a <role> node with the name attribute as it's text
		var roleNode = dom.createElement("role");
		var textNode = dom.createTextNode(node.getAttribute("name"));
		roleNode.appendChild(textNode);

		// Copy the id attribute if it exists
		var text = node.getAttribute("id");
		if (text != null) {
			roleNode.setAttribute("id", text);
		}

		// Copy the parent attribute if it exists
		text = node.getAttribute("parent");
		if (text != null) {
			roleNode.setAttribute("parent", text);
		}

		// Add the <role> node to the all roles node
		allRolesNode.appendChild(roleNode);
	}

	// Set all roles node in the adaptor's data binding
	Services.replaceNode(this.dataBinding + "/" + EditPanelGUIAdaptor.ALL_ROLES, allRolesNode);
}

/**
 * Sets the data binding for this adaptor.
 *
 * @param db the data binding for this adaptor 
 * @private
 */
EditPanelGUIAdaptor.prototype._setAdaptorDataBinding = function(db)
{
	if (EditPanelGUIAdaptor.m_logger.isTrace()) EditPanelGUIAdaptor.m_logger.trace("_setAdaptorDataBinding()");

	this.dataBinding = db;
}

/**
 * Set the Assigned Roles grid modified flag.
 *
 * @param flag the value to set  
 * @private
 */
EditPanelGUIAdaptor.prototype._setModified = function(flag)
{
	Services.setValue(this.dataBinding + "/" + EditPanelGUIAdaptor.MODIFIED_FLAG, flag.toString());
}

/**
 * Handle a click on the Right Arrow button.
 * Move Assigned Roles grid selected item into Available Roles grid.
 *
 * @private
 */
EditPanelGUIAdaptor.prototype._handleRightArrow = function()
{
	if (EditPanelGUIAdaptor.m_logger.isTrace()) EditPanelGUIAdaptor.m_logger.trace("_handleRightArrow()");

	// Move Assigned Roles grid selected value(s) to Available Roles grid
	this._moveGridValues(EditPanelGUIAdaptor.ASSIGNED_ROLES, EditPanelGUIAdaptor.AVAILABLE_ROLES);
}

/**
 * Handle a click on the Left Arrow button.
 * Move Available Roles grid selected item into Assigned Roles grid.
 *
 * @private
 */
EditPanelGUIAdaptor.prototype._handleLeftArrow = function()
{
	if (EditPanelGUIAdaptor.m_logger.isTrace()) EditPanelGUIAdaptor.m_logger.trace("_handleLeftArrow()");

	// Move Available Roles grid selected value(s) to Assigned Roles grid
	this._moveGridValues(EditPanelGUIAdaptor.AVAILABLE_ROLES, EditPanelGUIAdaptor.ASSIGNED_ROLES);
}

/**
 * Handle a click on the Double Right Arrow button.
 * Move all Assigned Roles grid items into Available Roles grid.
 *
 * @private
 */
EditPanelGUIAdaptor.prototype._handleDoubleRightArrow = function()
{
	if (EditPanelGUIAdaptor.m_logger.isTrace()) EditPanelGUIAdaptor.m_logger.trace("_handleDoubleRightArrow()");

	// Move all Assigned Roles grid values to Available Roles grid
	this._moveAllGridValues(EditPanelGUIAdaptor.ASSIGNED_ROLES, EditPanelGUIAdaptor.AVAILABLE_ROLES);
}

/**
 * Handle a click on the Double Left Arrow button.
 * Move all Available Roles grid items into Assigned Roles grid.
 *
 * @private
 */
EditPanelGUIAdaptor.prototype._handleDoubleLeftArrow = function()
{
	if (EditPanelGUIAdaptor.m_logger.isTrace()) EditPanelGUIAdaptor.m_logger.trace("_handleDoubleLeftArrow()");

	// Move all Available Roles grid values to Assigned Roles grid
	this._moveAllGridValues(EditPanelGUIAdaptor.AVAILABLE_ROLES, EditPanelGUIAdaptor.ASSIGNED_ROLES);	
}

/**
 * Determines whether or not the Button Panel is enabled.
 *
 * @returns true if the user has the required role(s). Otherwise false.
 *
 * @private
 */
EditPanelGUIAdaptor.prototype._isButtonPanelEnabled = function()
{
	if (EditPanelGUIAdaptor.m_logger.isTrace()) EditPanelGUIAdaptor.m_logger.trace("_isButtonPanelEnabled()");

	var cm = FormController.getInstance().getFormView().getConfigManager();
	var ar = cm.getConfig(this.getId())[0].adminRoles;

	if (ar != null) {
		// Roles configured so check user has access
		return (Services.hasAccessToRoles(ar));
	}
	else {
		// No roles configured so always enabled
		return (true);
	}
}

/**
 * Determines whether or not the Right Arrow button is enabled.
 *
 * @returns true if one or more rows are selected in the Assigned Roles grid.
 * Otherwise false.
 *
 * @private
 */
EditPanelGUIAdaptor.prototype._isRightArrowEnabled = function()
{
	if (EditPanelGUIAdaptor.m_logger.isTrace()) EditPanelGUIAdaptor.m_logger.trace("_isRightArrowEnabled()");

	var n = Services.countNodes(this.dataBinding + "/" + EditPanelGUIAdaptor.ASSIGNED_ROLES + "Selected/id");

	return (n > 0);
}

/**
 * Determines whether or not the Left Arrow button is enabled.
 *
 * @returns true if one or more rows are selected in the Availables Roles grid.
 * Otherwise false.
 *
 * @private
 */
EditPanelGUIAdaptor.prototype._isLeftArrowEnabled = function()
{
	if (EditPanelGUIAdaptor.m_logger.isTrace()) EditPanelGUIAdaptor.m_logger.trace("_isLeftArrowEnabled()");

	var n = Services.countNodes(this.dataBinding + "/" + EditPanelGUIAdaptor.AVAILABLE_ROLES + "Selected/id");

	return (n > 0);
}

/**
 * Determines whether or not the Double Right Arrow button is enabled.
 *
 * @returns true if the Assigned Roles grid is not empty. Otherwise false.
 *
 * @private
 */
EditPanelGUIAdaptor.prototype._isDoubleRightArrowEnabled = function()
{
	if (EditPanelGUIAdaptor.m_logger.isTrace()) EditPanelGUIAdaptor.m_logger.trace("_isDoubleRightArrowEnabled()");

	var n = Services.countNodes(this.dataBinding + "/" + EditPanelGUIAdaptor.ASSIGNED_ROLES + "/role");

	return (n > 0);
}

/**
 * Determines whether or not the Double Left Arrow button is enabled.
 *
 * @returns true if the Available Roles grid is not empty. Otherwise false.
 *
 * @private
 */
EditPanelGUIAdaptor.prototype._isDoubleLeftArrowEnabled = function()
{
	if (EditPanelGUIAdaptor.m_logger.isTrace()) EditPanelGUIAdaptor.m_logger.trace("_isDoubleLeftArrowEnabled()");

	var n = Services.countNodes(this.dataBinding + "/" + EditPanelGUIAdaptor.AVAILABLE_ROLES + "/role");

	return (n > 0);
}

/**
 * Move value(s) from one grid to another.
 *
 * @param from the name of the grid to move a value from
 * @param to the name of the grid to move a value to
 * @private
 */
EditPanelGUIAdaptor.prototype._moveGridValues = function(from, to)
{
	var dataBinding = this.dataBinding + "/" + from + "Selected" + "//*";
	var selectedNodes = Services.getNodes(dataBinding);

	Services.startTransaction();
			
	for (var i = 0, l = selectedNodes.length; i < l ; i++)
	{
		// Get the selected row's key
		var roleId = selectedNodes[i].text;

		// Get the value for the selected row
		dataBinding = this.dataBinding + "/" + from + "/role[./id=" + roleId + "]";
		var value = Services.getValue(dataBinding);

		if (value != null)
		{
			// Get selected role node
			var roleNode = Services.getNode(dataBinding);
			
			// To prevent duplicate IDs remove the id node from the role node
			var id = roleNode.selectSingleNode("id");
			roleNode.removeChild(id);

			// Remove selected row
			Services.removeNode(dataBinding);
		
			// Add selected role node to the 'to' grid
			Services.addNode(roleNode, this.dataBinding + "/" + to);
		}
	}

	Services.endTransaction();

	// Clear out the 'from' grid selection data binding		
	Services.replaceNode(this.dataBinding + "/" + from + "Selected", null);

	// Flag change to roles
	this._setModified(true);
}

/**
 * Move all rows in a grid.
 *
 * @param from the name of the grid to move all values from
 * @param to the name of the grid to move all values to
 * @private
 */
EditPanelGUIAdaptor.prototype._moveAllGridValues = function(from, to)
{
	// Get all the <id> nodes for the grid
	var nodes = Services.getNodes(this.dataBinding + "/" + from + "/*/id");

	for (var i = 0, l = nodes.length; i < l ; i++)
	{
		// Add key to grid selection data binding
		Services.setValue(this.dataBinding + "/" + from + "Selected/id[position()=" + (i + 1) + "]", nodes[i].text);
	}

	// All rows selected, now move them
	this._moveGridValues(from, to);
}

/**
 * Get the roles assigned to a user and court
 *
 * @param userId the user id to get the assigned roles for
 * @param courtCode the court code to get the assigned roles for
 * @param db the data binding where the assigned roles returned are stored in the DOM
 */
EditPanelGUIAdaptor.getRoles = function(userId, courtCode, db)
{
	var params = new ServiceParams();
	params.addSimpleParameter("userId", userId);
	params.addSimpleParameter("courtId", courtCode);

	var callback = new Object();
	callback.userId = userId;
	callback.dataBinding = db;
	callback.onSuccess = EditPanelGUIAdaptor.ongetRolesSuccess;
	callback.onError = EditPanelGUIAdaptor.ongetRolesError;

	Services.callService("getRoles", params, callback, true);	
}

/**
 * getRoles service call success callback handler.
 *
 * @param dom the DOM object returned from the server
 */
EditPanelGUIAdaptor.ongetRolesSuccess = function(dom)
{
	// Create assigned roles node
	var assignedNode = dom.createElement(EditPanelGUIAdaptor.ASSIGNED_ROLES);

	// Copy role nodes to assigned roles node
	var roleNodes = dom.selectNodes("/roles/role");

	for (var i = 0, l = roleNodes.length; i < l; i++)
	{
		var node = roleNodes[i].selectSingleNode(".");
		assignedNode.appendChild(node);
	}

	// Set the assigned roles in the grid
	Services.replaceNode(this.dataBinding + "/" + EditPanelGUIAdaptor.ASSIGNED_ROLES, assignedNode);

	// Create available roles node
	var availableNode = dom.createElement(EditPanelGUIAdaptor.AVAILABLE_ROLES);

	// Copy unassigned role nodes from all roles to available roles in grid
	var roleNodes = Services.getNodes(this.dataBinding + "/" + EditPanelGUIAdaptor.ALL_ROLES + "/role");

	for (var i = 0, l = roleNodes.length; i < l; i++)
	{
		// Get role node
		var node = roleNodes[i].selectSingleNode(".");
		
		// Attempt to match this role node text with an assigned role because we
		// don't want to make a role available if the user already has it assigned
		var value = Services.getValue(this.dataBinding + "/" +
						EditPanelGUIAdaptor.ASSIGNED_ROLES +
							"/role[text()=\"" + node.childNodes(0).text + "\"]");

		// Check if we matched an assigned node
		if (null == value)
		{
			// No match, so add this role node as an available role
			availableNode.appendChild(node);
		}
	}

	// Set the available roles in the grid
	Services.replaceNode(this.dataBinding + "/" + EditPanelGUIAdaptor.AVAILABLE_ROLES, availableNode);
}

/**
 * getRoles service call error callback handler.
 *
 * @param ex the exception object 
 */
EditPanelGUIAdaptor.ongetRolesError = function(ex)
{
	Services.showDialog(StandardDialogTypes.OK, function(b) {}, "Error getting assigned roles from server: " + ex.message, "Error");
}

/**
 * Update the roles assigned to a user and court
 *
 * @param userId the user id to update the assigned roles for
 * @param courtCode the court code to update the assigned roles for
 * @param db the data binding where the assigned roles are stored in the DOM
 */
EditPanelGUIAdaptor.updateRoles = function(userId, courtCode, db)
{
	// Get number of assigned roles to update
	var noOfRoles = Services.countNodes(db + "/" + EditPanelGUIAdaptor.ASSIGNED_ROLES + "/role");

	if (0 == noOfRoles)
	{
		throw new ConfigurationException("No assigned roles to update, check data binding");
	}

	// Create and populate a DOM with the assigned roles
	var dom = XML.createDOM(null, null, null);

	// Create <Roles> node
	var rolesNode = dom.createElement("roles");

	for (var i = 0; i < noOfRoles; i++)
	{
		// Create <role> node
		var roleNode = dom.createElement("role");

		// Get assigned role value
		var value = Services.getValue(db + "/" + EditPanelGUIAdaptor.ASSIGNED_ROLES +
						"/role[position()=" + (i + 1) + "]");

		// Add assigned role value to <role> node
		var roleText = dom.createTextNode(value);
		roleNode.appendChild(roleText);

		// Add <role> node to <roles> node
		rolesNode.appendChild(roleNode);
	}

	// Add Roles XML to DOM
	dom.appendChild(rolesNode);

	var params = new ServiceParams();
	params.addSimpleParameter("userId", userId);
	params.addSimpleParameter("courtId", courtCode);
	params.addDOMParameter("roles", dom);

	var callback = new Object();
	callback.dataBinding = db;
	callback.onSuccess = EditPanelGUIAdaptor.onupdateUserRolesSuccess;
	callback.onError = EditPanelGUIAdaptor.onupdateUserRolesError;

	Services.callService("updateUserRoles", params, callback, true);	
}

/**
 * updateUserRoles service call success callback handler.
 *
 * @param dom the DOM object returned from the server 
 */
EditPanelGUIAdaptor.onupdateUserRolesSuccess = function(dom)
{
	// Reset assigned roles changed flag
	Services.setValue(this.dataBinding + "/" + EditPanelGUIAdaptor.MODIFIED_FLAG, "false");
}

/**
 * updateUserRoles service call error callback handler.
 *
 * @param ex the exception object
 */
EditPanelGUIAdaptor.onupdateUserRolesError = function(ex)
{
	Services.showDialog(StandardDialogTypes.OK, function(b) {}, "Error saving assigned roles: " + ex.message, "Error");
}


//==================================================================
//
// EditPanelRenderer.js
//
// Implementation of EditPanel rendering class.
//
//==================================================================


/**
 * EditPanelRenderer constructor - never used. Use factory methods
 * below to either render an EditPanel into an HTML page, or create
 * an EditPanel as a child of another element
 *
 * @private
 * @constructor
 */
function EditPanelRenderer() {}

/**
 * EditPanelRenderer is a sub class of Renderer
 */
EditPanelRenderer.prototype = new Renderer();

/**
 * Set the constructor property so we can identify the type
 */
EditPanelRenderer.prototype.constructor = EditPanelRenderer;

/**
 * Logging category for the EditPanelRenderer class
 *
 * @type Category
 * @private
 */
EditPanelRenderer.m_logger = new Category("EditPanelRenderer");

/**
 * CSS Class name of the outermost div of the edit panel component
 */
EditPanelRenderer.CSS_CLASS_NAME = "edit_panel";

/**
 * Edit Panel identifiers
 */
EditPanelRenderer.BUTTON_PANEL = "_epButtonPanel";

/*
 * Create an edit panel at the current location in the document while document
 * is parsing.
 *
 * @param id the id of edit panel being created
 */
EditPanelRenderer.createInline = function(id)
{
	// Create the outer div by writing to the document
	var e = Renderer.createInline(
		id,			// The id of the edit panel being created
		false		// The edit panel has an internal input element which can accept focus, so the div should not accept focus
	);

	return EditPanelRenderer._create(e);
}

/**
 * Create an edit panel in the document relative to the supplied element
 *
 * @param refElement the element relative to which the edit panel should be rendered
 * @param relativePos the relative position of the edit panel to "refElement".
 * Valid values are:
 *     Renderer.CHILD_ELEMENT    Created as a child of "refElement"
 *     Renderer.BEFORE_ELEMENT   Created as preceeding sibling of "refElement"
 *     Renderer.AFTER_ELEMENT    Created as following sibling of "refElement"
 * @param id the id of the edit panel being created
 */
EditPanelRenderer.createAsInnerHTML = function(refElement, relativePos, id)
{
	var e = Renderer.createAsInnerHTML(
		refElement,		// The element relative to which to create the outer div in the document
		relativePos,	// Relative position of the outer div to the reference element
		id,				// The id of the edit panel being created
		false			// The edit panel has an internal input element which can accept focus, so the div should not accept focus
	);

	return EditPanelRenderer._create(e);
}

/**
 * Create an edit panel as a child of another HTML element
 *
 * @param p the parent element to add the edit panel to
 * @param id the id of edit panel being created
 */
EditPanelRenderer.createAsChild = function(p, id)
{
	var e = Renderer.createAsChild(id);

	// Append the edit panel's outer div to it's parent element
	p.appendChild(e);	
	
	return EditPanelRenderer._create(e);
}

/**
 * Create the HTML elements for a edit panel component
 *
 * @param e the outer DIV of the edit panel component
 */
EditPanelRenderer._create = function(e)
{
	e.className = EditPanelRenderer.CSS_CLASS_NAME;

	var ep = new EditPanelRenderer();

	// Initialise sets main element and the reference to the renderer in the dom
	ep._initRenderer(e);	

	var epId = e.id;

	// Table for Assigned Roles grid, move buttons and Available Roles grid
	table = Renderer.createElementAsChild(e, "table");
	table.className = "roles_layout";
	tBody = Renderer.createElementAsChild(table, "tbody");

	// Grid titles row
	tRow = Renderer.createElementAsChild(tBody, "tr");

	// Assigned Roles title cell
	tCell = Renderer.createElementAsChild(tRow, "th");
	tCell.setAttribute("align", "center");
	tCell.innerHTML = "Assigned Roles";

	// Empty cell
	tCell = Renderer.createElementAsChild(tRow, "td");

	// Available Roles title cell
	tCell = Renderer.createElementAsChild(tRow, "th");
	tCell.setAttribute("align", "center");
	tCell.innerHTML = "Available Roles";

	// Assigned Roles grid, left/right arrow buttons and Available Roles grid
	tRow = Renderer.createElementAsChild(tBody, "tr");
	
	// Assigned Roles grid cell
	tCell = Renderer.createElementAsChild(tRow, "td");

	// Create Assigned Roles grid
	var gridId = epId + "_" + EditPanelGUIAdaptor.ASSIGNED_ROLES;
	Grid.createAsChild(tCell, gridId, ["Role Name"], 10, 1);

	// Left/right arrows cell
	tCell = Renderer.createElementAsChild(tRow, "td");

	// Create the buttons in a panel so we can apply an enablement rule
	var panel = Renderer.createElementAsChild(tCell, "div");
	panel.className = PanelGUIAdaptor.CSS_CLASS_NAME;
	panel.id = epId + EditPanelRenderer.BUTTON_PANEL;

	// Create the Right Arrow button
	button = document.createElement("input");
	button.setAttribute("type", "button");
	button.setAttribute("value", ">");
	button.id = epId + EditPanelGUIAdaptor.RIGHT_ARROW;
	button.className = "arrow_button";
	panel.appendChild(button);

	Renderer.createElementAsChild(panel, "br");	

	// Create the Double Right Arrow button
	button = document.createElement("input");
	button.setAttribute("type", "button");
	button.setAttribute("value", ">>");
	button.id = epId + EditPanelGUIAdaptor.DOUBLE_RIGHT_ARROW;
	button.className = "arrow_button";
	panel.appendChild(button);

	Renderer.createElementAsChild(panel, "br");
	Renderer.createElementAsChild(panel, "br");

	// Create the Left Arrow button
	button = document.createElement("input");
	button.setAttribute("type", "button");
	button.setAttribute("value", "<");
	button.id = epId + EditPanelGUIAdaptor.LEFT_ARROW;
	button.className = "arrow_button";
	panel.appendChild(button);

	Renderer.createElementAsChild(panel, "br");

	// Create the Double Left Arrow button
	button = document.createElement("input");
	button.setAttribute("type", "button");
	button.setAttribute("value", "<<");
	button.id = epId + EditPanelGUIAdaptor.DOUBLE_LEFT_ARROW;
	button.className = "arrow_button";
	panel.appendChild(button);

	// Available Roles grid cell
	tCell = Renderer.createElementAsChild(tRow, "td");

	// Create Available Roles grid
	gridId = epId + "_" + EditPanelGUIAdaptor.AVAILABLE_ROLES;
	Grid.createAsChild(tCell, gridId, ["Role Name"], 10, 1);

	return ep;
}

EditPanelRenderer.prototype.dispose = function()
{
}

EditPanelRenderer.prototype.render = function(disabled, focussed, mandatory, invalid, readonly, inactive)
{
}
//==================================================================
//
// GUIAdaptorFactory.js
//
// Class responsible for parsing the view (HTML Document) and 
// producing the controller components to manage the user interface
// components on the view.
//
//==================================================================


/**
 * GUIAdaptorFactory is responsible for parsing the view (HTML
 * Document) and creating the controller components to manage the
 * user interface components on the view.
 *
 * @constructor
 */
function GUIAdaptorFactory()
{
	this._initGUIAdaptorFactory();
}

GUIAdaptorFactory.m_logger = new Category("GUIAdaptorFactory");

/**
 * Array containing the list of adaptors for a particular 
 * bindView operation.
 *
 * @type Array[GUIAdaptor]
 * @private
 */
GUIAdaptorFactory.prototype.m_adaptors = null;

 

/**
 * Array containing external component factories.
 *
 * @type Map[GUIAdaptorRegistration]
 * @private
 */
GUIAdaptorFactory.prototype.m_externalComponents = null;


/**
 * Private initialisation function
 *
 * @private
 */
GUIAdaptorFactory.prototype._initGUIAdaptorFactory = function()
{
	this.m_externalComponents = new Array();
	this.m_adaptors = null;
}

/**
 * Bind a configuration to a view
 * @param htmlDoc the HTML Document to parse
 * @return an array of GUIAdaptors representing the managed
 *    components in the view (HTML Document)
 * @type Array[GUIAdaptor]
 */
GUIAdaptorFactory.prototype.bindView = function(htmlDoc)
{
	// Parse the whole document below the body tag.
	return this._parseElement(htmlDoc.body, null, false);	
}


GUIAdaptorFactory.prototype.parseElement = function(e, initialContainer)
{
	// Parse the supplied element and it's children
	return this._parseElement(e, initialContainer, true);
}


GUIAdaptorFactory.prototype._parseElement = function(e, initialContainer, parseSelf)
{
	// Create list of adaptors created during this parse
	this.m_adaptors = new Array();
	
	// Container stack used during this parse
	this.m_containerStack = new Array();

	// If there is an initial container
	if(null != initialContainer)
	{
		this.m_containerStack.push(initialContainer);
	}
	
	
	if(parseSelf)
	{
		// Parse supplied element and its children
		this._handleElement(e);
	}
	else
	{
		// Just parse the supplied element's children
		this.parseChildren(e);
	}
	
	var adaptors = this.m_adaptors;
	
	// Reset member variables used during recursion
	this.m_adaptors = null;
	this.m_containerStack = null;
	
	// Return list of adaptors
	return adaptors;
}


/**
 * Register an external GUIAdaptor to the GUIAdaptorFactory
 * allowing external components to integrated with the Framework
 *
 * @param registration the GUIAdaptorRegistration which binds the
 *   external adaptor to the framework.
 */
GUIAdaptorFactory.prototype.register = function(registration)
{
	if(GUIAdaptorFactory.m_logger.isInfo()) GUIAdaptorFactory.m_logger.info("GUIAdaptorFactory.register(" + registration + ")");
	var className = "" +  registration.getClassName();
	this.m_externalComponents[className] = registration;
}


/**
 * Parse the child of an element and create any adaptors required.
 *
 * @param p the parent element who's children to parse.
 */
GUIAdaptorFactory.prototype.parseChildren = function(p)
{
	// Look over each of the child nodes, recursing down through the tree as necessary
	var cNs = p.childNodes;
	for(var i = 0, l = cNs.length; i < l; i++)
	{
		// Record the current container for comparison at end of process
		var containerAtStart = this.m_containerStack[this.m_containerStack.length - 1];	
		
		var n = cNs[i];
		
		// Only care about element nodes - ignore the rest
		if(1 == n.nodeType)
		{
			this._handleElement(n);
		}
		var containerAtEnd = this.m_containerStack[this.m_containerStack.length - 1];
		if(containerAtStart != containerAtEnd)
		{
			/*
		 	 * This iteration of parseChildren has added an adaptor the container stack
		 	 * This must now be removed
		 	 */
			this.m_containerStack.pop(); 
		}
	}
}


GUIAdaptorFactory.prototype._handleElement = function(e)
{
	// Do not process elements without an ID set but examine children of those elements
	if(e.id.length == 0)
	{
		this.parseChildren(e);
	}
	else
	{
		switch(e.nodeName)
		{
			case 'FORM':
			{   
			    if (e.className != SubformElementGUIAdaptor.CSS_CLASS)
			    {
				   this._addAdaptor(FormElementGUIAdaptor.create(e));
				}
				else
				{
				   this._addAdaptor(SubformElementGUIAdaptor.create(e));
				}
				
				// Forms will generally have children so look for them...
				// The form is set as the container in order to catch
				// those adapters which do not support component containers
				// (i.e. externally registered components)
				this.parseChildren(e);
				break;
			}
			case 'INPUT':
			{
				this._handleInput(e);
				
				// INPUT elements don't have children, so don't look for them
				break;
			}
			
			case 'TEXTAREA':
			{
				// Re-use the Text Input Adaptor - at the moment these inputs are
				// handled identically.
				// E316 Enforce text area maximum length. Create new adaptor
				// for text area rather than use TextInputElementGUIAdaptor.
				this._addAdaptor(TextAreaElementGUIAdaptor.create(e));
		
				// Doesn't have children so don't look for them
				break;
			}
			
			case 'SELECT':
			{
				this._addAdaptor(SelectElementGUIAdaptor.create(e));

				// Doesn't have children so don't look for them
				break;
			}
			
			case 'DIV':
			{
				// ALL COMPONENTS MUST BE DIVs
				//
				// If DIV was not part of a component, then process it's children.
				// If the DIV has children that need handling, it must explicitly call
				// parseChildren
				this._handleDiv(e);
				break;
			}
			
			default:
			{
				// If no external GUIAdaptor is registered to handle this element,
				// then just parse it's children.
				// If the element is a component that is handled, then if the component
				// has children that need handling, it must explicitly call parseChildren
				this.parseChildren(e);
			}
		}
	}
}


GUIAdaptorFactory.prototype._handleInput = function(e)
{
	// Switch on the input element's type attribute
	switch(e.type)
	{
		case 'button':
		{
			this._addAdaptor(ButtonInputElementGUIAdaptor.create(e));
			break;
		}
		
		case 'checkbox':
		{
			this._addAdaptor(CheckboxInputElementGUIAdaptor.create(e));
			break;
		}
		
		case 'text':
		{
			if(e.className == "datetext")
			{
				this._addAdaptor(DateTextInputElementGUIAdaptor.create(e));
			}
			else
			{
				this._addAdaptor(TextInputElementGUIAdaptor.create(e));
			}
			break;
		}
		
		case 'password':
		{
			this._addAdaptor(TextInputElementGUIAdaptor.create(e));
			break;
		}
		
		case 'radio':
		{
			this._addAdaptor(RadioInputElementGUIAdaptor.create(e));
			break;
		}
		
		// Explicitly disallow reset and submit button types - they'll break the framework.
		case 'reset':
		case 'submit':
		{
			fc_assertAlways("Input element of type " + e.type + " not allowed on forms");
			break;
		}
		
		default:
		{
			// Don't handle the following input types by default in the framework at this
			// time:
			//     - file
			//     - hidden
			//     - image
			//
			// Will check to see if there is an external adaptor that matches...
			fc_assertAlways("Input element of type " + e.type + " not supported");
			break;
		}
	}
}


GUIAdaptorFactory.prototype._handleDiv = function(e)
{
	var cN = e.className
	if(cN != "")
	{
		// the css class is used to differentiate between different types of complex components
		// - remember that css classes in older browsers are case sensitive, therefore we assume
		//   that they are case sensitive here!
		// - remember that a element can have multiple css classes. Framework policy for internal
		//   components is that they should always have an external div with a single class for
		//   the purposes of recognising the component.
		switch(cN)
		{
			case PanelGUIAdaptor.CSS_NO_MARGIN_CLASS_NAME:
			case PanelGUIAdaptor.CSS_CLASS_NAME:
			{
				this._addAdaptor(PanelGUIAdaptor.create(e));
				this.parseChildren(e);
				break;
			}
			case FilteredGrid.CSS_CLASS_NAME:
			{
				this._addAdaptor(FilteredGridGUIAdaptor.create(e));
				this.parseChildren(e);
				break;
			}
			case GridRenderer.CSS_CLASS_NAME:
			{
				this._addAdaptor(GridGUIAdaptor.create(e));
				break;
			}
			case TabSelector.TABSEL_WRAPPER_CSS_CLASS_NAME:
			{
				this._addAdaptor(TabSelectorGUIAdaptor.create(e));
				break;
			}
			case PagedAreaGUIAdaptor.CSS_CLASS_NAME:
			{
				this._addAdaptor(PagedAreaGUIAdaptor.create(e));
				this.parseChildren(e);
				break;
			}		
			case PageGUIAdaptor.CSS_CLASS_NAME:
			{
				this._addAdaptor(PageGUIAdaptor.create(e));		
				this.parseChildren(e);
				break;
			}
			case DynamicPageGUIAdaptor.CSS_CLASS_NAME:
			{
				this._addAdaptor(DynamicPageGUIAdaptor.create(e));
				// DynamicPage GUIAdaptor will never have any children when it is first created
				break;
			}
			case LOVPopupRenderer.LOV_POPUP_CSS_CLASS:
			{
			    this._addAdaptor(LOVPopupGUIAdaptor.create(e));
				this.parseChildren(e);
			    break;
			}
			case DatePickerRenderer.CSS_CLASS_NAME:
			{
				this._addAdaptor(DatePickerGUIAdaptor.create(e));
				break;
			}
			case LogicGUIAdaptor.LOGIC_CSS_CLASS_NAME:
			{
				this._addAdaptor(LogicGUIAdaptor.create(e));
				break ;
			}
			case AutoCompletionRenderer.CSS_CLASS_NAME:
			{
				this._addAdaptor(AutocompletionGUIAdaptor.create(e));
				break;
			}
			case FwSelectElementRenderer.CSS_CLASS_NAME:
			{
			    this._addAdaptor(FwSelectElementGUIAdaptor.create(e));
			    break;
			}
			case PopupRenderer.CSS_CLASS_NAME:
			case PopupRenderer.CSS_CLASS_NAME_FULLPAGE:
			{
				// TODO - this is not really right, the popup has no container
				this._addAdaptor(PopupGUIAdaptor.create(e));
				this.parseChildren(e);
				break;
			}		
			case LoginRenderer.CSS_LOGIN_CLASS_NAME:		
			{
				this._addAdaptor(LoginGUIAdaptor.create(e));
				this.parseChildren(e);
				break;
			}
			case ZoomFieldRenderer.CSS_CLASS_NAME:
			{
				this._addAdaptor(ZoomFieldGUIAdaptor.create(e));
				this.parseChildren(e);
				break;
			}
			case WordProcessingGUIAdaptor.CSS_CLASS_NAME:
			{
				this._addAdaptor(WordProcessingGUIAdaptor.create(e));
				break;
			}
			case PopupSubformGUIAdaptor.CSS_CLASS_NAME:
			case PopupSubformGUIAdaptor.CSS_CLASS_NAME_FULLPAGE:
			{
				this._addAdaptor(PopupSubformGUIAdaptor.create(e));
				break;
			}
			case LOVSubformRenderer.LOV_SUBFORM_CSS_CLASS:
			case LOVSubformGUIAdaptor.LOV_SUBFORM_CSS_CLASS_NAME_FULLPAGE:
			{
				this._addAdaptor(LOVSubformGUIAdaptor.create(e));
				break;
			}
			case ManageUsersRenderer.CSS_CLASS_NAME:
			{
				this._addAdaptor(ManageUsersGUIAdaptor.create(e));
				this.parseChildren(e);				
				break;
			}
			case EditPanelRenderer.CSS_CLASS_NAME:
			{
				this._addAdaptor(EditPanelGUIAdaptor.create(e));
				this.parseChildren(e);				
				break;
			}
			case SearchPanelRenderer.CSS_CLASS_NAME:
			{
				this._addAdaptor(SearchPanelGUIAdaptor.create(e));
				this.parseChildren(e);				
				break;
			}
			// Handle some classnames used in the framework explicitly so that we
			// don't go looking for external adaptors to match. These div's don't
			// have corresponding adaptors to be created so we simply parse their
			// children.
			case TabSelector.TABBED_AREA_CSS_CLASS_NAME:
			case ActionBarRenderer.CSS_CLASS_NAME:
			{
				this.parseChildren(e);
				break;
			}
			
			case AsyncMonitorRenderer.CSS_CLASS_NAME:
			{
				this._addAdaptor(AsyncMonitorGUIAdaptor.create(e));
				this.parseChildren(e);
				break;
			}
			
		    case MenuBarRenderer.MENU_BASE_DIV:
			{
				var a = MenuBarGUIAdaptor.create(e);
			    this._addAdaptor(a);
			    
			    // Parse the quicklinks buttons
			    //this.parseChildren(a.getQuickLinksButtonContainer());
			    this.parseChildren(e);
			    break;
			}
			
			case MenuRenderer.MENU_BAR_BUTTON:
			{
			    var a = MenuGUIAdaptor.create(e);
			    this._addAdaptor(a);
			    break;
			}
			
			default:
			{
				// If this is a DIV which a registered external adaptor, then create an
				// adaptor instance now, otherwise simply continue parsing chilren.
				// NOTE: extenal adaptors cannot currently support child adaptors
				// This is enforced by the external adaptor interface
				var ret = this._handleExternalAdaptor(e);
				if(!ret)
				{
					this.parseChildren(e);
				}
				break;
			}
		}
	}
	else
	{
		this.parseChildren(e);
	}
}


GUIAdaptorFactory.prototype._handleExternalAdaptor = function(e)
{
	if(GUIAdaptorFactory.m_logger.isInfo()) GUIAdaptorFactory.m_logger.info("GUIAdaptorFactory._handleExternalAdaptor(id: " + e.id + ") looking for externally registered component " + e.className);
	fc_assert(e.nodeName == 'DIV', "Can only handle external adaptors of type DIV");
	
	var cN = e.className;
	if(null != cN)
	{
		var a = null;
	
		// See if we've got an externally registered adaptor
		var r = this.m_externalComponents[cN];
		
		if(null != r)
		{
			var f = r.getFactory();
			if(GUIAdaptorFactory.m_logger.isInfo()) GUIAdaptorFactory.m_logger.info("GUIAdaptorFactory._handleExternalAdaptor() found externally registered component, factory = " + f);
			
			var index = this._reserveAdaptorPosition(function(){});
	
			// Invoke the factory method passing the HTML element as an argument.
			var a = f.call(null, e, this);
			if(GUIAdaptorFactory.m_logger.isInfo()) GUIAdaptorFactory.m_logger.info("GUIAdaptorFactory._handleExternalAdaptor() factory created the following adaptor = " + a);
			
			this._addAdaptor(a, index);
		}
	}	
	// Return true if we created an adaptor
	return a != null;
}

// put an empty placeholder to reserve the position in the array
// this is in case the adaptor.create() calls this back to parse it's
// children which should appear after the controlling adaptor, in case
// the controlling component has to dynamically create configuration
// for the adaptor.configure method.
GUIAdaptorFactory.prototype._reserveAdaptorPosition = function(f)
{
	var index = this.m_adaptors.length;
	this.m_adaptors[this.m_adaptors.length] = f;
	return index;
}


GUIAdaptorFactory.prototype._addAdaptor = function(a, index)
{
	// Assign the adaptor to a parent container
	a.setParentContainer(this.m_containerStack[this.m_containerStack.length - 1]);
		
	if(null==index || index<0 || index >this.m_adaptors.length)
	{
		this.m_adaptors[this.m_adaptors.length] = a;
	}
	else
	{
		this.m_adaptors[index] = a;
	}

	var id = a.getId();
	// Add property to array storing reference to adaptor
	// Used for fast lookup of adaptors
	this.m_adaptors[ id ] = a;
	
	// If this new adapter is a container return it.
	if(a.isAContainer)
	{
		this.m_containerStack.push(a);
	}
}

/**
 * Dispose method cleans up external component references when
 * adaptor factory no longer required.
 *
*/
GUIAdaptorFactory.prototype.dispose = function()
{
    for( var i in this.m_externalComponents )
    {
        this.m_externalComponents[i].dispose();
        
        this.m_externalComponents[i] = null;
    }
    
    delete this.m_externalComponents;
}


/**
 * Class to represnent an error message
 *
 * @param errorId the id for the error. Must be unique
 * @param message the message corresponding to this error
 */
/*function ErrorCode(errorId, message)
{
  this.m_message = message;
  
  if (null == ErrorCode.m_errors[errorId])
  {
    ErrorCode.m_errors[errorId] = this;
  }
  else
  {
  	fc_assertAlways(
      "Duplicate error id '" + errorId +
      "' with message '" + message + 
      "'. Existing error had message '" + ErrorCode.m_errors[errorId] + "'."
    );
  }
}*/

function ErrorCode(errorId,message)
{
	this.m_message=message;
	this.m_errorId=errorId;
}

/**
 * Static array to hold all errors
 */
//ErrorCode.m_errors = new Array();


/**
 * Factory method to get an ErrorCode object
 *
 * @param the id of the ErrorCode to retrieve
 * @param variable number of parameters to replace ${1}, ${2} etc in the ErrorCode message
 */
ErrorCode.getErrorCode = function(errorId)
{
	var message = Services.getAppController().getErrorMsgForCode(errorId);
	var arguments = ErrorCode.getErrorCode.arguments;

	for (var i = 1, l = arguments.length, index = 0; i < l; i++)
	{
		index = message.indexOf("${" + String(i) + "}", index);
		if (index != -1)
		{
			var re = new RegExp("\\$\\{" + String(i) + "\\}", "i");
			message = message.replace(re, String(arguments[i]));
		}
	}

	return new ErrorCode(errorId, message);
}


/**
 * Get error message
 *
 * @return the error message
 */
ErrorCode.prototype.getMessage = function()
{
	return this.m_message;
}


/**
 * Class to represent an event queue
 */
function EventQueue()
{
}

EventQueue.m_logger = new Category("EventQueue");
EventQueue.prototype.m_queue = null;
EventQueue.prototype.m_processingQueue = null;


/*
 * @param queueName : The name of the queue, e.g. Validation
 */
EventQueue.prototype._initEventQueue = function()
{
	this.m_queue = new Array();
}


/**
 * Add event to queue
 *
 * @param a the affected GUIAdaptor
 * @param e the DataModelEvent
 * @param d additional detail associated with the event
 */
EventQueue.prototype.addEventToQueue = function(a, e, d)
{
	if(EventQueue.m_logger.isDebug()) EventQueue.m_logger.debug(this.getName() + " check queued for GUIAdaptor: " + a.getId());
	
	this.m_queue.push({adaptor: a, event: e, detail: d});
}


EventQueue.prototype.hasEvents = function()
{
	return this.m_queue.length > 0;
}

/**
 * Process event queue
 * recheckQueue = true;
 * @return the repaint queue
 */
EventQueue.prototype.processEvents = function(repaintQueue)
{
	var name = this.getName() + "_EventQueue_processEvents";
	/*(name)*/

	// Swap out current queue so that new events generated while
	// processing this queue are added to a new queue.
	var q = this.m_queue;
	this.m_queue = new Array();

	if(EventQueue.m_logger.isInfo())
	{
		EventQueue.m_logger.info(this.getName() + ".processEvents() number of events = " + q.length);
	}

	// Actually process the events in the queue
	repaintQueue = this._processEvents(q, repaintQueue);
	
	/*(name)*/

	return repaintQueue;
}


/**
 * Process the events in the supplied array. This method must be
 * recursively re-entrant.
 *
 * @param q the array containing the events to process
 * @param repaintQueue the list of items to repaint
 * @return the updated list of items to repaint
 * @type Array[GUIAdaptors]
 * @protected
 */
EventQueue.prototype._processEvents = function(q, repaintQueue)
{
	for(var i = 0, l = q.length; i < l; i++)
	{
		this._processEvent(q[i], repaintQueue);
	}
	
	return repaintQueue;
}


EventQueue.prototype._processEvent = function(queuedItem, repaintQueue)
{
	var adaptor = queuedItem.adaptor;
	var event = queuedItem.event;
	var detail = queuedItem.detail;
	
	// Retrieve adaptor id for registration in repaint queue
	var id = adaptor.getId();
	
	var debug = EventQueue.m_logger.isDebug();
	if(debug) EventQueue.m_logger.debug(this.getName() + " event not previously processed for field: " + id);
	
	if(this.processEvent(adaptor, event, detail))
	{
		if(debug) EventQueue.m_logger.debug(this.getName() + " requires repaint for field: " + id);
		repaintQueue[id] = adaptor;
	}
	else
	{
		if(debug) EventQueue.m_logger.debug(this.getName() + " no repaint required for field: " + id);
	}
}


/**
 * Handle the event for this particular queue type.
 *
 * Default implementation has no effect.
 *
 * @param adaptor the GUIAdaptor affected by the event
 * @param event the DataModelEvent which caused the adaptor to be on the queue
 * @return true if the field needs to be repainted due to the event
 * @type boolean
 */
EventQueue.prototype.processEvent = function(adaptor, event, detail)
{
	return false;
}

EventQueue.prototype.getName = function()
{
	return null;
}


EventQueue.prototype.removeEventsForAdaptor = function(a)
{
	// Run the the queue, removing events for the supplied adaptor
	var nq = [];
	for(var i = 0, q = this.m_queue, l = q.length; i < l; i++)
	{
		// If the event is not for the removed adaptor,
		// then add the adaptor back into the queue.
		var qi = q[i];
		if(qi.adaptor != a)
		{
			nq.push(qi);
		}
	}
	
	this.m_queue = nq;
}


function CompressedEventQueue()
{
}

CompressedEventQueue.prototype = new EventQueue();
CompressedEventQueue.prototype.constructor = CompressedEventQueue;


CompressedEventQueue.prototype._processEvents = function(q, repaintQueue)
{
	// Map containing the eventIds of processed events. If the queue contains
	// multiple events with duplicate eventIds, only the first event will be
	// processed with subsequent events being discarded.
	var processedEvents = new Object();
	
	for(var i = 0, l = q.length; i < l; i++)
	{
		var qi = q[i];
		var eventId = this._createEventId(qi);
		
		if(null == processedEvents[eventId])
		{
			// Record the fact that we've processed events for this eventId
			processedEvents[eventId] = true;

			if(EventQueue.m_logger.isDebug()) EventQueue.m_logger.debug(this.getName() + " event not previously processed for field: " + qi.adaptor.getId());
			
			this._processEvent(qi, repaintQueue);
		}
		else
		{
			if(EventQueue.m_logger.isDebug()) EventQueue.m_logger.debug(this.getName() + " event already processed for field: " + qi.adaptor.getId());
		}
	}
	
	return repaintQueue;
}


/**
 * Default method to create an id for the event being processed. Generally,
 * the id is simply the adaptor id as returned here. However, for some
 * queues a more complex identifier is required.
 *
 */
CompressedEventQueue.prototype._createEventId = function(queuedItem)
{
    return queuedItem.adaptor.getId();
}


